window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["sv"]={"ICON-0001":{"nm":"Fotspår","de":"Ett enda jordfärgat märke kvar på trägolvet. Någon gick fram och tillbaka länge, och tog till slut ett steg till. Vad ett fotspår ristar in är inte tiden som stannade kvar, utan just det ögonblick då någon bestämde sig för att gå."},"ICON-0002":{"nm":"Lykta","de":"När lågan når veken drar mörkret sig sakta tillbaka, tum för tum. I den lilla värmen som värmer fingertopparna skrev forna tiders människor sina önskningar och lät dem driva iväg. En lykta tänds inte för att lysa upp, utan för att hålla en sällskap."},"ICON-0003":{"nm":"Rosett","de":"Med en enda knut sveps hjärtat vackert in. Lätt att knyta upp för handen som ger, men långsam att lösa för handen som tar emot. Vad en rosett binder är inte lådan, utan fladdret av nervositet alldeles innan den räcks över."},"ICON-0004":{"nm":"Brevlåda","de":"Den står med sin röda mun vidöppen vid gränd­mynningen. Även i en tid då handskrivna brev blivit sällsynta väntar denna lilla låda till sista stund på någons nyheter. Ett vänligt kärl som lyser som starkast i samma stund det töms helt."},"ICON-0005":{"nm":"Minikarta över egna ön","de":"Ett enda pappersark: rymligt nog för fickan hopvikt, med hav och bergsrygg sida vid sida när det viks ut. För den som anländer första gången är varje hörn ett löfte som ännu inte öppnats. I samma stund det viks ut blir även en liten ö en vidsträckt värld."},"ICON-0006":{"nm":"Mikrofon","de":"Den halva takten av att hämta andan alldeles innan första tonen. Att veta att publikens blickar väntar på ditt enda ord får fingertopparna att darra. En mikrofon förstärker inte ljudet – den bär den darrningen hela vägen fram."},"ICON-0007":{"nm":"Klocka","de":"Sekundvisaren vilar aldrig, men ingen jäktar dig. Så många nätter till debuten, så många minuter till scenen – på urtavlan snurrar väntan och förväntan i samma takt. Att läsa av tiden är att trösta hjärtat."},"ICON-0008":{"nm":"Anteckningsbok","de":"Tinget med mest tomrum av alla. Danssteg, gryningens beslutsamhet, ord som aldrig riktigt skickades – allt samlas här. I samma stund den öppnas talar gårdagens jag stilla till dagens jag."},"ICON-0009":{"nm":"Stämpel","de":"Doppad i röd sigillpasta och tryckt fast en gång, ristas ett löfte tydligt in. Ett märke tyngre än skrift, klarare än ord. Vid slutet av varje dokument anförtrodde människor sitt hjärta åt denna lilla stämpel, i stället för sitt namn."},"ICON-0010":{"nm":"Sockel","de":"Den sänker sig själv så långt den kan för att bära upp något annat. Längst ner, i tysthet, håller den emot vikten så att det som vilar ovanpå inte vacklar. Den lyser aldrig, men här finns den omtanke som hindrar allt från att rasa samman."},"ICON-0011":{"nm":"Frimärke","de":"En liten bild man fuktade i ena hörnet och tryckte fast. Det ärligaste pris som sätts på ett hjärta skickat långt bort. Ett enda fyrkantigt landskap tar brevets hand och bär det ända över havet."},"ICON-0012":{"nm":"Flaggnål","de":"Sätt den i kartan och den säger: 'Jag kom hit.' Inte en erövring utan ett minnesmärke, och ett hejarop för den som kommer näst. Ett tecken som tyst knuffar dig i ryggen – se flaggan och ta bara ett steg till."},"ICON-0013":{"nm":"Gren","de":"En gren som en gång böjts glömmer hur man går av. Där den bugade sig för vinden sätter sig en hård, fast knut, och sann styrka kommer från spåren av att ha uthärdat – så viskar den gamla skogen i vinden."},"ICON-0014":{"nm":"Knapp","de":"Öppnad och knäppt igen om och om igen, sluter den kragen tätt. En enda liten cirkel håller stilla både gryningskylan och en plötslig rodnad av blygsel borta. Först när den knäpps av inser man hur stor dess lilla plats var."},"ICON-0015":{"nm":"Kuvert","de":"I samma stund munnen försluts blir det äntligen en hemlighet. Bara mottagaren vet vad som gömmer sig därinne. Ett enda lager papper lagt mellan hjärtat och världen – den tunnaste, mest ömsinta dörr som finns."},"ICON-0016":{"nm":"Låda","de":"Dess fyra hörn är räta, så den famnar allt med generositet. Minnen under flyttider, gåvor på högtider, skräp till vardags. Innanför det stängda locket är det alltid fullt av någons 'sen.'"},"ICON-0017":{"nm":"Handtag","de":"Mellan en dörr och en människa är det det första som sträcker ut en hand. Först när man drar en gång förenas insidan och utsidan. Varje beslut att gå in eller ut griper denna kalla hand en gång på vägen."},"ICON-0018":{"nm":"Sked","de":"Med sin urgröpta mun lyfter den stilla varm buljong. Ett redskap som minns värmen från den första skeden mamma blåste sval och räckte fram först. Vid bordet är den den mest ömsinta handen – den som oftast rör vid läpparna."},"ICON-0019":{"nm":"Tofflor","de":"I samma stund man kliver över tröskeln andas fötterna ut först. Kvällens ljud av mjuka steg, sedan en dag av klapprande skor lagts av. Ett par ställt prydligt vid dörren säger: 'Nu är du hemma.'"},"ICON-0020":{"nm":"Nyckel","de":"Man lär sig hur man öppnar innan man lär sig hur man låser. En liten metallbit som värms i handflatan, för att en dag stanna stilla framför en obekant, ny dörr. Tinget som längst bevarar värmen från den som gav sig av."},"ICON-0021":{"nm":"Glas","de":"Städat när det är tomt, varmare än något annat när det fylls. I den klara klangen av två glas höjda mot varandra och klingade samman ryms ett ordlöst löfte. Ett kärl fött att lysa mest när de är två, inte ett."},"ICON-0022":{"nm":"Tallrik","de":"Innanför sin runda kant ryms en hel dags omsorg. Tömd, torkad och fylld igen ett helt liv – det som glänser oftast och glöms oftast bland hushållets ting. Bordets scen dukas alltid upp här ovanpå."},"ICON-0023":{"nm":"Lampa","de":"En enda strömbrytare förändrar rummets uttryck. Starkt ljus är vardagen, dämpat ljus är tröst. En enda ljuspunkt lämnad tänd till sista stund för någon som kommer hem sent blir världens varmaste välkomnande."},"ICON-0024":{"nm":"Tesked","de":"Rör sakta ett varv runt i tevattnet, och blad och vatten smälter samman. En orädd, ohastig rörelse, en liten väntan tills doften sprider sig. En silverhand saktar ömt ner eftermiddagens tempo."},"ICON-0025":{"nm":"Bokmärke","de":"Ett löfte stoppat stilla in där läsningen stannade. Löftet 'jag stannade här, jag kommer säkert tillbaka' sover mellan sidorna. Berättelsen må stängas, men hjärtat är tydligt markerat på just den raden."},"ICON-0026":{"nm":"Dyna","de":"Den tar tyst emot en rygg och knän som behöver något att luta sig mot. Sjunker djupt och sväller sakta upp igen, suger den åt sig dagens trötthet. Tinget som mest generöst tillåter den lataste av ställningar."},"ICON-0027":{"nm":"Ram","de":"En fyrkantig kant binder en enda vy till evigheten. Just för det ögonblick den fångade bleknar tiden aldrig, hur mycket som än går. Ett ömsint val, mindre om vad man fångar än om vad man valde att bevara."},"ICON-0028":{"nm":"Karta","de":"I varje veck finns spåret av att ha gått vilse och hittat vägen igen. Vecklas kartan ut kan man med fingertopparna vandra även platser man aldrig besökt. Varje äventyr börjar med det lilla modet att vika ut detta enda ark."},"ICON-0029":{"nm":"Vykort","de":"Halva baksidan är ett foto, halva är tom. Den som rest långt bort skickar 'må väl' i några få tecken, med platsens landskap som följeslagare. Det ärligaste pappersarket, där hälsningen inte skäms utan kuvert."},"ICON-0030":{"nm":"Passerkort","de":"I samma stund du hänger det om halsen kliver du äntligen in i den inre världen. Ditt namn på det lilla kortet ger tyst sitt tillstånd: 'Här, det här är din plats.' Inte ett kvalifikationsbevis för att passera, utan ett bevis på att höra hemma någonstans."},"ICON-0031":{"nm":"Bokstaven B","de":"Bokstaven som ropas fram oftast mitt i ett ord. Man måste sluta läpparna en gång och sedan låta dem poppa upp innan ljudet kommer. Varken början eller slut, men en pålitlig andraplats som håller takten."},"ICON-0032":{"nm":"Visitkort","de":"Räckt fram med båda händerna, mottagen med blicken i ögonhöjd. En människas dag och stolthet komprimeras stilla i ett enda pappersark. I den smala marginalen mellan namn och titel bosätter sig sakta den dagens första intryck."},"ICON-0033":{"nm":"Omslag","de":"Längst ut på berättelsen möter det vind och regn först. I att skydda bokstäverna därinne nöts dess egna hörn ner. Den korta fladdringen av förväntan alldeles innan man öppnar börjar alltid med just detta ark."},"ICON-0034":{"nm":"Lärobok","de":"En människas kamp står tätt nedskriven med understrykningar och överstrykningspenna. Skrämmande som ny bok, blir den den mest pålitliga vännen när den är utläst. Spåren av att ha lärt sig det man inte visste ligger prydligt vikta på varje sida."},"ICON-0035":{"nm":"Dansbiljett","de":"Detta enda ark sparkar upp dörren till övningsrummet på vid gavel. Ett spegelfyllt rum, ljudet av stampande fötter, de första åtta räknade takterna någonsin lärda. Det gör inget om dansen ännu är klumpig – ett litet pappersark knuffar milt en darrande rygg framåt."},"ICON-0036":{"nm":"Pärm","de":"Lösa blad som drivit omkring träds prydligt på en enda ryggrad och får äntligen en ordning. Med ordning kommer en berättelse, och ju tjockare den blir, desto ömsintare beviset på att någon levt så mycket, sida för sida."},"ICON-0037":{"nm":"Provblad","de":"Fingertoppar som darrar ett ögonblick ovanför de tomma raderna. Skrämmande än ett felsvar är att möta det man inte vet rakt i ansiktet. När rättningen är klar återstår, vid varje felaktig plats, tyst en marginal att växa i nästa gång."},"ICON-0038":{"nm":"Bokstaven A","de":"Det första ljudet som bara kommer när man öppnar munnen vitt. Den står ofta i spetsen på en rad, allra först i ett namn. När man börjar med vad som helst börjar man med denna bokstav – därför är den alltid lite modigare."},"ICON-0039":{"nm":"Bokstaven D","de":"Med sin mjukt böjda rygg stöttar den varsamt ett ord. Dess runda sida hänger prydligt i slutet av någons namn. Inte flärdfull, men sorgligt saknad om den försvinner – en tyst följeslagare bland bokstäverna."},"ICON-0040":{"nm":"Övningsblad","de":"Det enda papperet i världen där misstag är tillåtna. Det låter dig skriva samma rörelse, samma mening, dussintals gånger om. För varje skrynklat ark som slängdes blev någon säkert lite bättre."},"ICON-0041":{"nm":"Notblad","de":"Klockan två på natten väcker ett enda nynnande dig ur sömnen. Pennan tvekar över notlinjerna för att melodin är snabbare än handen. I varje utsuddat och omskrivet spår växer sakta en ännu namnlös sång."},"ICON-0042":{"nm":"Backstagepass","de":"I samma stund du hänger det om halsen förvandlas en vanlig korridor till en annan värld. Kablar slingrar sig genom mörkret som ormar, och bortom scenen börjar en ohörbar nedräkning. Rätten att kliva in här talar detta enda ark om, i ditt ställe."},"ICON-0043":{"nm":"Kontaktkopia","de":"I varje liten ruta står ett annat uttryck fruset. Skrattande, med blicken vänd bort, med slutna ögon. Pekar man ut en bild i taget vänder den dagens fladder vid avtryckaren tillbaka till fingertopparna. Redan att välja en enda bild är i sig ett minnesmärke."},"ICON-0044":{"nm":"Dagsschema","de":"Imorgon, vilken tid, var och vad. Ett enda ark ritar upp en hel dags rutt i förväg. Bland de minutvis fyllda rutorna följer någon ordningen som står skriven här, och går steg för steg mot en dröm."},"ICON-0045":{"nm":"Prislapp","de":"Bakom prislappen hänger tyst tillverkarens tid. Först med det korta klippet blir det lilla pappret äntligen ditt eget. Kvar vid snittet finns doften av något nytt och en näve förväntan."},"ICON-0046":{"nm":"Portfolio","de":"Vänd på omslaget och vägen du gått breder ut sig på en gång. Bredvid en sida du är stolt över sitter det första klumpiga försöket blygt sida vid sida. När man för första gången räcker sig själv till någon finns det ingen ärligare presentation än denna."},"ICON-0047":{"nm":"Planeringsbok","de":"Skriv ner idag, rita upp nästa vecka, och ibland svärta en enda ruta helt. Även när inget går som planerat slutar aldrig handen som fyller rutorna. Ett litet ritual att leva framtiden en gång i förväg."},"ICON-0048":{"nm":"Spellista","de":"Mellan långsamma låtar och snabba takter radar man upp sångerna i en rad efter dagens humör, som väder. Tänk om någons hela dag flöt exakt i denna ordning, så blir till och med tystnaden mellan låtarna ömsint."},"ICON-0049":{"nm":"Studentkort","de":"Ett namn, ett foto och några siffror. Ett enda kort som bevisar tiden av att pendla mellan klassrum och övningsrum. I kortet, nött i hörnen av alla resor i fickan, är en oskyldig vardag som aldrig kommer åter inristad."},"ICON-0050":{"nm":"Armband","de":"Minns du stunden du knöt den dagens färg runt handleden? Ropen ni skrek tillsammans, konsertkvällen ni blev genomblöta av sida vid sida. Även när bandet nöts och färgen bleknar löser man inte upp det – man vill att den sommaren ska fortsätta leva på handleden."},"ICON-0051":{"nm":"Armbindel","de":"I samma stund du binder den runt armen läggs tyst tyngden av ansvar till. Märket för den som står först i ledet och lämnar sin post sist. En enda tygremsa får någon att växa en hand högre."},"ICON-0052":{"nm":"Ring","de":"En enda linje sluten till en cirkel utan avbrott. Eftersom dess början och slut möts ser människor i den evighetens form. Förenar man stilla två händer finns, innan orden, ett löfte kvar som en form."},"ICON-0053":{"nm":"Medalj","de":"På den lilla metallbiten fäst vid bröstet är de uthärdade dagarna ristade in. Det som glänser är inte metallen utan de otaliga övningsnätterna gömda bakom den. Det som stiger innan stoltheten är, på något vis, tacksamhet."},"ICON-0054":{"nm":"Förkläde","de":"Knyt banden runt halsen och båda händerna blir fria. En signal om att man är redo att kasta sig helhjärtat in i något – mjöl eller färg, spelar ingen roll. Ju fler fläckar som samlas en efter en, desto djupare blir också den omsorg som lagts ner den dagen."},"ICON-0055":{"nm":"Öronvärmare","de":"Sveper man in öronen tätt tar utejudet ett steg tillbaka. På den knivskarpa vindens skolväg, ett litet gömställe att smyga in i den mjuka insidan. Vinterns värme börjar ibland, precis så här, vid öronspetsarna."},"ICON-0056":{"nm":"Kostym","de":"Innan ridån går upp hänger en enda dräkt på galgen och håller andan. Koreografin är vikt in i varje söm. I samma stund armen glider igenom blir människan en roll, och scenen blir dräktens andra hud."},"ICON-0057":{"nm":"Krona","de":"I samma stund den vilar på huvudet rätar en böjd rygg ut sig av sig själv. Den gyllene glansen viskar om ansvar innan makt. Den svala tyngden mot pannan säger allt: ju mer strålande platsen, desto tyngre är den."},"ICON-0058":{"nm":"Cape","de":"Kasta den över axlarna och vinden fladdrar bakom ryggen. Känslan av ett tygstycke som jagar efter en vid varje löpsteg. Mindre en hjältes emblem än ett barnasinne som bara ville se cool ut."},"ICON-0059":{"nm":"Mask","de":"Dölj ansiktet, och man blir märkligt nog ärligare. Som i de gamla gårdsspelen där man skrattade och grät fritt bakom masken. Bortom det dolda uttrycket läcker den riktiga rösten, den man annars sväljer, ut ännu högre."},"ICON-0060":{"nm":"Läppstift","de":"Vrid av locket, dra ett enda streck, och ett litet beslut sätter sig vid läpparna. En sista kontroll framför spegeln, en röd linje målad över tvekan. I det korta ögonblick färgen läggs på viker rädslan stillsamt undan."},"ICON-0061":{"nm":"Jacka","de":"När axellinjen sitter precis rätt blir man lite stadigare. Kavla upp ärmarna för ett arbetande sinne, res kragen för ett sinne redo att gå ut. Ett enda plagg bestämmer tyst dagens hållning."},"ICON-0062":{"nm":"Taekwondobälte","de":"Varje gång färgen flyttas upp en grad förändras också mängden svett som lagrats därunder. Dojangens morgon av att dra åt knuten hårt och böja sig i respekt. Genom fingertopparna som knyter bältet samlas ett splittrat sinne åter."},"ICON-0063":{"nm":"Goggles","de":"Sätt dem på och världen skärps en nyans. Bortom den runda skölden som håller både vind och damm borta glittrar till och med den vanliga vägen man alltid går plötsligt som en startlinje."},"ICON-0064":{"nm":"Handske","de":"Ta på den och modet att gripa tag i vad som helst med fast hand växer fram. Fingrar som ryggat, rädda att tappa saker, sträcks äntligen ut vidöppna. Handen är det som skyddas, men det som egentligen bevaras är utmaningen som väntar därnäst."},"ICON-0065":{"nm":"Munskydd","de":"Täck den nedre delen av ansiktet, och ögonen talar desto mer. På en folkfylld gata, en liten frihet i anonymitet, njuten bakom en lätt slöja. Därför sprider sig leendet som blir kvar när allt tas av, desto ljusare."},"ICON-0066":{"nm":"Keps","de":"Fäll skärmen en aning nedåt, och både solen och blickarna viker av en handsbredd. Under det lilla taket som vilar på huvudet får man idag åtminstone gå med ett avslappnat ansikte. Den lättaste förvandlingen börjar alltid just här."},"ICON-0067":{"nm":"Skjorta","de":"Ett prasslande, nystruket krage doftar morgon. Medan man knäpper knapparna i ordning uppifrån blir också ett rufsigt hjärta redigt, en notch i taget. Ett enda vitt plagg öppnar dagens första mening."},"ICON-0068":{"nm":"Scarf","de":"Slå den ett varv runt halsen och vindens passage blockeras. Medan fransarna vaggar sakta vid axeln når kylan inte längre in. Ett tygstycke placerat någonstans mellan stil och värme."},"ICON-0069":{"nm":"Handskar","de":"Insvept tätt ända ut till fingertopparna fruktar man inte längre det kalla. Vinterns lilla lyx, när händer man blåst varma sakta blir mjuka och skyddade. Räcker man bort en enda handske kan den värma någon annans hand också."},"ICON-0070":{"nm":"Identitetsbricka","de":"Två tunna brickor möts stilla ansikte mot ansikte. Tre bokstäver i ett namn och några siffror – det är vad som gör att någon minns till sista stund. Kall metall, och ändå påminner den märkligt nog om det varmaste löfte som finns."},"ICON-0071":{"nm":"Greppring","de":"För in ett finger och oron för att tappa den försvinner sakta. En liten trygghet, nog för att hålla och vinka med bara en hand. När man sträcker armen långt för att fånga en enda bild stöttar den tyst handflatan."},"ICON-0072":{"nm":"Blomsterkrans","de":"Sätt den på huvudet och en famn av vår följer med. Blommor plockade på ängen och flätade till en ring omger pannan varsamt. Ovanför det ljusa leendet på fotot dröjer en svag doft av gräs kvar länge."},"ICON-0073":{"nm":"Sovmask","de":"Täck ögonen och både ljus och ljud drar sig undan på en gång. Kan man inte se hör man bara sin egen andning. Stäng av världen en stund och kliv in i den inre stillheten, så stängs en liten dörr tyst bakom ryggen."},"ICON-0074":{"nm":"Halsduk","de":"Ett varv, två varv – för varje sväng runt halsen blir vintern lite mildare. Någonstans bland ullgarnet kan ett hjärta någon stickat in ligga gömt. Begraver man sig ända upp till nästippen känns världen genast mysigare."},"ICON-0075":{"nm":"Halvmask","de":"Med bara halva ansiktet dolt börjar maskeradens natt. De blottade läpparna ler, de dolda ögonen bär en hemlighet. Det smala mellanrummet av att nästan känna igen vem det är får midnattens luft att fladdra till."},"ICON-0076":{"nm":"Basker","de":"Sätt den snett på, och en vanlig dag får sakta lite stämning. Ett runt, platt tygstycke klär axlarna varsamt i en konstnärs air. Till och med det korta ögonblicket av att välja vinkel framför spegeln är en glädje."},"ICON-0077":{"nm":"Choker","de":"Sluter man den tätt runt halsen samlas blicken naturligt uppåt. Ett enda smalt band förändrar hela stämningen. Litet men tydligt, som ett spänne som fyller på dagens självförtroende."},"ICON-0078":{"nm":"Parkas","de":"Dra upp blixtlåset ända till toppen, och även snöstormen viker undan. Sticker man händerna djupt in i det tjocka fodret tystnar hela världens larm. Ett litet hus som förblir varmt ända in i det sista, även i den råaste vind."},"ICON-0079":{"nm":"Byxor","de":"Trä på fötterna och knyt midjan, och först då är man redo att gå ut. För varje steg man tar rör sig tyget mjukt efter sin egen riktning. Någonstans mellan bekvämlighet och prydlighet börjar dagen."},"ICON-0080":{"nm":"Piercing","de":"Även att lägga till en enda liten punkt kräver lite mod. Ett glänsande stycke metall sätter en tydlig punkt vid ett vanligt öra. Mycket litet, men ett ljus som ändå speglar ett jag som verkligen förändrats idag."},"ICON-0081":{"nm":"Vågform","de":"För en ljudtekniker hörs inte en sång – den syns. Ur bergsryggen som stiger och sjunker på skärmen läser man var andan darrade den dagen. En röst som förut var osynlig ligger nu som en bergskedja och breder ut ett spårs hela terräng."},"ICON-0082":{"nm":"Stämapparat","de":"Precis innan föreställningen stryker man de sex strängarna en efter en och sätter förvildade toner på plats igen. Bara en halv grad fel, och publiken märker det som spöken. Att stämma så exakt att ingen kunde ana det – det är en omtanke riktad mot scenen."},"ICON-0083":{"nm":"Handledsrem","de":"Slå den ett varv runt handleden och oron för att tappa något löses sakta upp. Det läskigaste på scenen är att förlora greppet om något, så med denna enda lilla rem lugnar sig hjärtat äntligen."},"ICON-0084":{"nm":"Cymbal","de":"I det enda ögonblick de slår samman sätts en tydlig punkt vid sångens sista mening. Den gyllene skivan vet hur man klingar kortast och lämnar det längsta efterklanget. Ett slut ska stängas så här ljust, säger den."},"ICON-0085":{"nm":"Gitarr","de":"När fingrarna glider över de sex strängarna blir ett trångt rum plötsligt en hel scen. Någons första melodi, viskningarna från en sömnlös gryning – i denna runda trälåda drog de först andan."},"ICON-0086":{"nm":"Ljudmoln","de":"På en flik av himlen klumpar sig noter ihop som bomull och driver runt. Sveper vinden förbi en gång faller melodier i stället för regndroppar, säger man, och öns barn springer ut för att möta det utan ens ett paraply."},"ICON-0087":{"nm":"Steg","de":"Scenens rörelsemönster är matematik löst med tåspetsarna. Ett steg här, en halv takt där – det gör inget att fela, ta det lugnt. Rutorna som trampats hundratals gånger och ristats in i kroppen samlas till slut till kartan för en enda låt."},"ICON-0088":{"nm":"Förstärkare","de":"En låda som förvandlar en viskning till ett rytande jubel. Ändå tvekar handen alltid innan volymen vrids upp ett steg till. Att ett mer exakt ljud, inte ett högre, når ända till sista raden i publiken – det vet denna låda."},"ICON-0089":{"nm":"Notbomull","de":"När de rundhövdade noterna samlas till en bomullstuss blir den mjuk som en kudde. Lägger man sig stilla med huvudet på den strömmar en vaggvisa fram, knappt hörbar – öns mest ömsinta lilla rykte."},"ICON-0090":{"nm":"Kassettband","de":"Tryck på återspolningsknappen och – gnissel – bandet vrider sig sakta tillbaka till den sommarens första låt. I den lilla lådan där en hel epok är uppspolad sover tid man aldrig mer kan röra, fullständigt bevarad."},"ICON-0091":{"nm":"Stämgaffel","de":"Slå lätt på de två klorna av metall, och en enda referenston föds i luften. Vid denna lilla darrning böjer varje instrument tyst huvudet i takt. Allting börjar med en vibration så här skör."},"ICON-0092":{"nm":"Vågformschip","de":"Ett fragment av ljud stängs varsamt in i ett chip stort som en nagel. En utrop aldrig avsedd att spelas in, skrattet från någon man trodde var borta – här inuti lever och andas det fortfarande, lika varmt som förr."},"ICON-0093":{"nm":"LP","de":"När nålen tar sitt första steg längs spåret hörs först en svag, sprakande andedräkt. Så kär i till och med det lilla bruset att somliga aldrig, ända till slutet, kan släppa denna svarta skiva ur handen."},"ICON-0094":{"nm":"Ficka","de":"Det man värdesätter mest bär man alltid närmast bröstet. En enda handflatestor tygpåse blir en dag en handvärmare, en annan dag en amulett, och ännu en annan dag ett förvaringsställe för hemligheter."},"ICON-0095":{"nm":"Plåster","de":"På kvällar då övningen dragit ut fästs ett litet hedersmärke vid varje häl. Ett plåster satt för att svälja ordet 'det gör ont' – ett tyst löfte ingen känner till, om att dansa igen imorgon vad som än händer."},"ICON-0096":{"nm":"Kudde","de":"Platsen där man till sist lägger ner en hel dags scen är, när allt kommer omkring, detta enda mjuka fyrkantiga stycke. Lägger man huvudet stilla ner tystnar sakta applåderna som dröjt kvar vid örat, och även över ön faller äntligen natten."},"ICON-0097":{"nm":"Dörrklocka","de":"Ett kort, klingande 'ding' och någon knuffar upp dörren och kliver in. Ett tecken på att en gäst har kommit, en hälsning om att dagen har öppnat. Ett enda litet stycke metall ägnar hela dagen åt att bara ringa i välkomnande."},"ICON-0098":{"nm":"Fodral","de":"Ju dyrbarare något är, desto stadigare ett eget hus bygger man åt det. Att händerna som öppnar och stänger det blir försiktigare varje gång beror på att det som ryms därinne inte bara är ett föremål, utan ett hjärta man inte står ut med att förlora."},"ICON-0099":{"nm":"Borste","de":"Sveper man efter riktningen ända ner till sista borsthåret drar sig damm som fastnat i hörnen sakta undan. Tack vare en hand som inte drar sig för ens de osynliga platserna möter rummet en ny morgon varje dag."},"ICON-0100":{"nm":"Skiss","de":"Linjerna innan de är fullbordade döljer inte sin tvekan i onödan. I varje spår, utsuddat och draget igen, finns utan lögn kvar vad de ville bli. Ju klumpigare början, desto ärligare är den."},"ICON-0101":{"nm":"Docka","de":"Det finns väsen som tröstar bara genom att hållas tyst i famnen. Den bomullsmjuka vän som darrade bredvid kudden natten då dina händer skakade bakom scenen – var och en bär på en sådan djupt inom sig."},"ICON-0102":{"nm":"Ringklocka","de":"Tempelklockan i bergen ringer en gång och korsar en hel dal. Det är metallens hjärta som längtar efter att nå längre och längre bort och gråter ut i ett långt eko – så sjunker ljudet sakta ner i lyssnarens bröst."},"ICON-0103":{"nm":"Paraply","de":"Delar man ett är det ovisst vilken axel som blir våt. Under paraplyet som lutar en aning finns den våta axeln – det tydligaste beviset på ömhet. Den korta vägen man delat under samma tak dröjer sig kvar i hjärtat länge."},"ICON-0104":{"nm":"Matta","de":"Bred ut en matta på det bara golvet, och genast blir platsen en övningssal. En plats som tyst tar emot dig när du rullar och faller – otaliga rörelser fann för första gången sin väg in i kroppen just här."},"ICON-0105":{"nm":"Bjällra","de":"Skaka den försiktigt och ett klart, klingande ljud rullar fram i handen. Den lilla, runda glädje som förr tiders barn knöt fast i fållen på sina regnbågsrandiga jackor och sprang omkring gården med vaknar än en gång till liv i din handflata."},"ICON-0106":{"nm":"Leksaksorm","de":"Dess långa, hängande form skrämmer skälmskt slag på folk. Rädd, på flykt, och till sist ett utbrott av fnitter – även ett sådant skämt är i grunden en gren av omtanke om varandra."},"ICON-0107":{"nm":"Leksak","de":"Alla har en låda de inte riktigt kan förmå sig att slänga, även som vuxna. Inuti ligger skrattet från de ljusaste dagarna, fortfarande hårt uppspänt som en fjäder som aldrig fått rulla upp sig."},"ICON-0108":{"nm":"Fällbord","de":"Fäll ut de hopvikta benen, och genast blir vilken plats som helst familjens plats. Ljudet av skedar som klirrar mot varandra när alla samlas runt bordet – det anspråkslösa samspelet klingar varmast av alla dagens toner."},"ICON-0109":{"nm":"Tvål","de":"Den krymper bit för bit i handen och gör tyst någon ren. Att nöta ner sig själv för att tvätta någon annan – först långt efter att bubblorna har lagt sig syns äntligen det stilla hjärtat."},"ICON-0110":{"nm":"Kam","de":"Precis som den löser upp trassligt hår tråd för tråd, blir också en skrynklig dag så småningom rak. En kort beröring framför spegeln rätar sakta till, bortom håret, till och med hjärtats hållning."},"ICON-0111":{"nm":"Fågelbur","de":"Det finns en fågel som sjunger utan att flyga i väg, även när dörren står vidöppen. Ett hjärta som stannar inte för att det är instängt utan för att det önskar dröja kvar – den fina skillnaden märker buren före någon annan."},"ICON-0112":{"nm":"Handvärmare","de":"I vinterkön utanför konserthallen tinar en liten värme i fickan sakta upp stelnade fingrar. En handflatestor ömhet som någon skakat varm i förväg, med tanke på dig som huttrar i kylan."},"ICON-0113":{"nm":"Näsduk","de":"Ett enda tygstycke som tar emot både tårar och svett utan ett knot. Den lilla broderin i hörnet dröjer sig vackert kvar där, som en sista hälsning från någon som lämnade först och bad en att inte glömma."},"ICON-0114":{"nm":"Sprejflaska","de":"Ett enda pust och luftens struktur förändras på ett ögonblick. Dimman som sprider sig över scenen, växten vid morgonfönstret – i dessa fina droppar blir de för ett ögonblick en annan värld och glittrar till."},"ICON-0115":{"nm":"Doftremsa","de":"Att välja en doft liknar på något vis att välja ett minne. En enda tunn tråd av väldoft, struken på spetsen av en smal pappersremsa, för sakta en årstid man trodde glömd tillbaka till näsan."},"ICON-0116":{"nm":"Matbord","de":"I varje sliten träring finns antalet delade måltider tyst inristat. De högljudda middagarna, de sena kvällarna man mött ensam – detta fyrkantiga bord har tagit emot allt utan ett ord och blivit blankt av det."},"ICON-0117":{"nm":"Trådnystan","de":"Dra försiktigt i ena änden och den lossnar mjukt; ett enda stygn och den binds ihop igen. Att laga det som gått sönder börjar alltid tyst, precis så här, från en enda tunn tråd."},"ICON-0118":{"nm":"Regnrock","de":"Även på dagar med öst­regn är det just detta enda plagg som till sist får en ut genom dörren. Bara den som känner glädjen i att plaska genom regnet vägrar använda regnet som ursäkt för att stanna hemma."},"ICON-0119":{"nm":"Snörpåse","de":"Snör ihop öppningen till en cirkel, och det som finns däri blir äntligen tryggt. I en enda liten, nött säck skvalpar mynt, minnet av en dag och ord som aldrig riktigt sades tillsammans."},"ICON-0120":{"nm":"Bokhylla","de":"Låt fingret sakta glida längs bokryggarna, och årstiderna du passerat känns vid fingertopparna. Att man inte kan förmå sig att slänga en utläst bok beror på att jaget från den tiden fortfarande lever där."},"ICON-0121":{"nm":"Bokstapel","de":"Lästa böcker läggs på sidan, olästa böcker travas ovanpå. Även om löftet att en dag läsa dem alla vajar lite nära taket, älskar man just den vajningen så mycket att man i dag lägger på ännu en volym."},"ICON-0122":{"nm":"Löphjul","de":"Det kan kännas som att stå still hur ivrigt man än springer, men de små fötterna lär sig först tårnas rytm. De gårdagar som aldrig stannat samlas, och en dag lyser de klart på en verklig väg."},"ICON-0123":{"nm":"Överdrag","de":"Så att damm inte lägger sig, så att solen inte bleker – även att lägga på ett överdrag kräver fingertoppens omsorg. Ju mer man värnar om något, desto ömmare skyddas det på platser man inte ser."},"ICON-0124":{"nm":"Ullgarn","de":"En enda tråd som rullade fram, tumlande, från mormors knä. Den kan se trasslig ut, men hittar man änden och drar försiktigt följer den alltid med. Så växte vinterkvällarna långa, maska för maska."},"ICON-0125":{"nm":"Necessär","de":"Läppbalsam, ett hårband, ett prydligt vikt brev – liten som den ser ut rymmer den en hel dags hjärta. Med ljudet av dragkedjan som stängs blir alla de dyrbara småsakerna trygga på en gång."},"ICON-0126":{"nm":"Armstöd","de":"En eftermiddag man somnade mitt i en bok, en kväll man vandrade fram och tillbaka under ett samtal. På platsen som blir allt mer nött ju längre man sitter kvar, samlas tyst, en handsbredd djupt, alla de viloställningar armbågen minns."},"ICON-0127":{"nm":"Förpackning","de":"Fram tills den rivs upp tillhör den ännu ingen. En förseglad påse svämmar över av oöppnad förväntan, så fingertopparna som griper om hörnet darrar lätt till. Det är öppnandets rysning."},"ICON-0128":{"nm":"Presentpapper","de":"Ett hjärta som anländer ett steg före själva gåvan. Medan man viker hörnen jämnt och binder en rosett, breder mottagarens leende ansikte redan ut sig ljust i händerna."},"ICON-0129":{"nm":"Handkontroll","de":"Knappar tummarna minns före huvudet gör det. Förlorade, men bara en runda till – och den där rundan slutar med att man är vaken hela natten. Vikten som passar handen precis rätt lyfter tyst kvällens äventyr."},"ICON-0130":{"nm":"Trafikljus","de":"Rött betyder stanna en stund, grönt betyder att du får gå nu. Med ett enda enkelt löfte flyter otaliga vägar utan att trassla ihop sig. Att även väntan har sin tur berättar det blinkande ljuset ömt för dig."},"ICON-0131":{"nm":"Pil","de":"Den snällaste formen för den som gått vilse. När det känns hopplöst att veta vart man ska, gör en enda riktning som någon redan ritat ut de stannade stegen fasta igen."},"ICON-0132":{"nm":"Koordinater","de":"Med bara två siffror kan man peka ut vilken plats som helst i världen. Platsen ni bestämt att mötas på, sandstranden där skatten grävdes ner. Så att ett löfte inte ska tappa bort sig håller en enda liten punkt fast intill slutet."},"ICON-0133":{"nm":"Kakelplatta","de":"Ensam är den bara en fyrkantig bit. Ögonblicket de lägger sig sida vid sida, axel mot axel, blir de till golv och vägg. Små ting samlas och skapar en plats där någon kan sätta ner foten i trygghet."},"ICON-0134":{"nm":"Timglas","de":"När den övre kammaren töms fylls den undre sakta på. När vi ser sanden rinna mjukt nedåt tror vi att tiden flyter förbi. Vänd det upp och ner, och allt börjar om – det är sandens ömma lilla lögn."},"ICON-0135":{"nm":"Boll","de":"Kastar man den kommer den tillbaka, sparkar man den rullar den i väg. Att vara rund, att aldrig veta vart den studsar, är dess största charm. Mitt på skolgården har skratt alltid börjat runt, just från denna lilla sfär."},"ICON-0136":{"nm":"Strömbrytare","de":"Klick, tänds med ett enda tryck, släcks med ett enda tryck. Det lilla ljudet man gör när man kliver in i ett mörkt rum delar den spretiga dagens början och slut i en tydlig linje."},"ICON-0137":{"nm":"Frågetecken","de":"Att inte veta svaret är inget att skämmas för. Det är det välkomna beviset på att nyfikenheten fortfarande lever. När den här lilla kroken knackar på i huvudet, tar lärandet äntligen sitt första steg."},"ICON-0138":{"nm":"Tändsticka","de":"En enda sticka som stryker sin egen kropp för att lämna över elden. Den brinner kort och försvinner tyst, men i det korta ögonblicket tänds ett ljus och en spis värms upp. En liten gåva blir värmens första knapp."},"ICON-0139":{"nm":"Fotpall","de":"Kliv upp med en enda fot, och handen når till och med hyllan du förut inte kom åt. Att för en stund förlänga någons längd. Här finns en snäll plats som hukar sig lågt för att sakta lyfta oss högre."},"ICON-0140":{"nm":"Armbandsur","de":"Det första man spänner fast om handleden den dag man bestämmer sig för att träna. En liten coach som räknar hjärtslag och steg knackar till för att berätta att du gått lite längre i dag än i går."},"ICON-0141":{"nm":"Väckarklocka","de":"Den mest trofasta vän man ogillar varje morgon. Tack vare att den varje gång kämpar mot frestelsen av fem minuter till under täcket i ditt ställe, kommer varken löften eller drömmar för sent. Det där skoningslösa ringandet är i själva verket ett hejarop."},"ICON-0142":{"nm":"Kärna","de":"Det innersta som blir kvar sist, när allt yttre skalats bort. Äpplets kärnhus, hjärtats sanna känsla – vad det än är, håller själva mitten alltid det hårdaste. Den enda punkt som består till slut, även när allt skakar."},"ICON-0143":{"nm":"Penna","de":"Fläcken som smetade av sig på handens sida innan bläcket hann torka. Vare sig det skrivs lätt eller trögt, kräver alltid det första draget framför ett vitt papper en gnutta mod. Den är bron där tanken vandrar över till fingertopparna."},"ICON-0144":{"nm":"Pensel","de":"När den doppad i tusch far över hanji-papperet blir till och med en enda tveksam skälvning kvar, helt intakt. Blir man girig och skyndar sig att skriva avslöjas det på en gång. Penseln är den första som känner den ärlighet som bor i fingertopparna."},"ICON-0145":{"nm":"Pratbubbla","de":"Platsen som stiger fram, rund, ovanför huvudet innan orden hinner ut ur munnen. Det enda man vill säga ryms här. När den är tom väljer man fortfarande vad den ska fyllas med."},"ICON-0146":{"nm":"Kryssruta","de":"Rita två streck i den tomma rutan, och hjärtat blir så mycket lättare. En liten medalj man tilldelar sig själv för en avklarad uppgift. Vid dagens slut, när man ser de ifyllda rutorna, tröstar man sig med att man levt bra även i dag."},"ICON-0147":{"nm":"Surfplatta","de":"Bilder sprids ut och bokstäver flyter fram vart fingrarna än rör sig. Lägg den lugnt i knät, och en hel värld tänds upp klart. Lätt är den, men möjligheten som ryms däri är på intet sätt tunn."},"ICON-0148":{"nm":"Fjärrkontroll","de":"Den har en medfödd talang för att gömma sig i soffans springor. Makten att byta kanal tillhör alltid den som håller i den. Den minsta, kärvänligaste familjegräl utspelar sig alltid över den här handsbredden."},"ICON-0149":{"nm":"Motvikt","de":"En vikt som sänkt sig själv ner till den lägsta punkten för att hålla fast det som skakar. Hur mycket toppen än vajar, faller den till slut inte om botten är tung. Balans håller alltid stånd på platser man inte ser."},"ICON-0150":{"nm":"Pussel","de":"Kvällen då man trevade under soffan efter den sista saknade biten. Den ljudlösa njutningen i ögonblicket den passar precis. När det spridda hittar sin plats, är bilden till slut fullbordad."},"ICON-0151":{"nm":"Linjal","de":"Att mäta längd är också ett sätt att hålla ett löfte. För att en handsbredd ska vara densamma för alla ställer sig strecken ärligt på rad. En enda rak linje kan räta ut till och med ett skevt hjärta."},"ICON-0152":{"nm":"Målarduk","de":"En tom vit yta är det mest skrämmande, och det mest spännande. Fram tills den första punkten sätts kan den bli vad som helst. Tomhet är inget slut, utan ett annat namn för en början."},"ICON-0153":{"nm":"Rubiks kub","de":"Fler än en har vakat hela natten i försök att få alla sex sidor att stämma. De envisa fingertopparna som vrider och vrider igen. I ögonblicket de blandade färgerna hittar sin plats, faller ett litet universum prydligt på plats."},"ICON-0154":{"nm":"Handkonsol","de":"En liten skärm som kusinerna la huvudena ihop över under loven. En äventyrsvärld som får plats mitt i handflatan. Bara en enda ton av startmelodin räcker för att hela den sommaren ska strömma tillbaka."},"ICON-0155":{"nm":"Grepp","de":"Känslan av att den ligger tätt an mot handen när man greppar hårt ger tyst en gnutta självförtroende. Så att man inte halkar, så att man inte tappar taget. I det viktigaste ögonblicket är den länken som binder hand och redskap till en enda fast helhet."},"ICON-0156":{"nm":"Reservoarpenna","de":"Medan man skriver med påfylld bläck blir till och med handstilen lite mer prydlig. Man samlar sinnet till pennspetsens knastrande ljud, och den påminner stilla om omsorgen i att sakta börja första raden i ett handskrivet brev."},"ICON-0157":{"nm":"Palett","de":"Blått bredvid rött, grönt över gult. På den här lilla brickan där färgerna ligger prydligt sida vid sida får en bild äntligen sitt uttryck. Varje äventyr av att blanda och lägga lager på lager tar sitt första steg just här."},"ICON-0158":{"nm":"Uppsättning","de":"Var för sig är delarna kanske vanliga, men sida vid sida blir de en enda berättelse. Den tryggheten när ingenting saknas och allt är på plats. Att samla det utspridda på ett ställe bär på en liten fullbordans glädje."},"ICON-0159":{"nm":"Fjäderboll","de":"Det mjuka suset fjädrarna gör när den susar upp från racketen. Den verkar för lätt för att komma långt, men slår man till med vilja flyger den rakt till planens bortre kant. Även lätthet är en fullvärdig kraft."},"ICON-0160":{"nm":"Antenn","de":"Den står stilla mot himlen och försöker fånga osynliga signaler. Tålamodet att till slut dra in även avlägsna röster. På dagar när mottagningen är dålig, vinkla den bara lite, så klarnar den igen."},"ICON-0161":{"nm":"Stetoskop","de":"Den runda, kalla spetsen mot bröstet, och andetaget som håller inne för en stund. Samlar man örat kring en enda liten trumma, förs det äldsta av alla levande rytmer fram till fingertopparna. Ett redskap där lyssnandet kommer först."},"ICON-0162":{"nm":"Schackbonde","de":"En liten bonde som gick sakta, bara en ruta i taget. Ändå kan den, i samma stund den når sista raden, bli vad som helst. Det gamla schackbrädet vakar tyst över det enda draget som vänder hela spelet med ett klumpigt steg."},"ICON-0163":{"nm":"Spelkontroll","de":"Minns du nätterna ni for genom universum med bara två tummar? Det nötta greppet du kastade ifrån dig i nederlag och sedan generat plockade upp igen. Det längsta, varmaste samtal du delat tyst med någon på andra sidan skärmen."},"ICON-0164":{"nm":"Spelkonsol","de":"Sätt på strömmen, och en liten startsignal ljuder som en hälsning. Den fyrkantiga lådan man slog på och av under täcket hela lovet – barndomens första äventyr började alltid i skenet från den här skärmen."},"ICON-0165":{"nm":"Tidslinje","de":"Vänster ände är början, höger ände en dag som ännu inte kommit. Dra en enda punkt till valfri plats däremellan, och ett ögonblick man trodde glömt breder ut sig igen. En plats där tiden lagts ner i en enda rak linje."},"ICON-0166":{"nm":"Prisma","de":"Tänk att ljuset, som verkade så rent och klart, hela tiden bar på sju färger. Hemligheten som löses upp till en regnbåge i samma stund det passerar en glasskärva. Ju städigare något ser ut, desto fler färger döljer sig därinne."},"ICON-0167":{"nm":"Golftee","de":"Ett litet stöd att lugnt lägga bollen på. Ju längre man vill skicka något, desto mer behöver man först något som håller det stadigt. Denna lilla pinne i gräset bär upp det allra första steget."},"ICON-0168":{"nm":"Stickor","de":"En maska, sedan ännu en. Tappar man en enda måste man riva upp alltet och börja om från början. Halsduken som sakta växte i knät under en vinter, platsen där fingertopparnas tålamod stickades till värme."},"ICON-0169":{"nm":"Melodilinje","de":"En enda fras som läckte ut från läpparna som ett nynnande innan texten lades på. I den där disiga, ännu ordlösa melodin döljer sig sångens ärligaste, första ansikte."},"ICON-0170":{"nm":"Radar","de":"Den skickar en signal in i mörkret den inte kan se, och väntar tyst på en enda punkt som kommer tillbaka. Tålamodet hos det runda, gröna ljuset som tror att något finns där, även när inget syns."},"ICON-0171":{"nm":"Rytmplatta","de":"Knacka lätt, tock tock, och ljus och ljud studsar upp på samma gång. En plats som får händerna att minnas takten innan huvudet gör det. Den minsta, ömmaste scen, utbredd över handflatan."},"ICON-0172":{"nm":"Målarfärg","de":"Forna konstnärer malde sten och jord för att få fram färg. Indigo ur gräs, rött ur jord. Även i den här enda droppen som pressas fram vid fingertopparna i dag rinner den urgamla omsorgen att varsamt föra naturen över i ett kärl."},"ICON-0173":{"nm":"Linje","de":"Det som föds först i stunden man bestämmer sig för att förbinda punkt med punkt. Kort eller lång, böjd eller rak, det är det enklaste spår som lämnas av viljan att ta sig någonstans. Början på varje bild."},"ICON-0174":{"nm":"Slutare","de":"Klick, det enda korta mörkret håller kvar ett ögonblick för alltid. Även ett uttryck man nästan hade låtit glida förbi på ett ögonblink, skär den av en flisa ljus och stelnar till ett minne. Ett litet blad."},"ICON-0175":{"nm":"Säkerhetslina","de":"Linan som binds fast stadigt ett steg före den som klättrar högt. Den håller i ditt ställe hjärtat som oroar sig för att falla, vaktar din sida osedd, ett löftets band. Den finns alltid bakom din rygg."},"ICON-0176":{"nm":"Hänglås","de":"Det tunga järnhänglåset man låste på skafferiet. Det var inte för att stänga in något, utan en önskan att i trygghet lägga undan något dyrbart. Även handen som låste bar på omsorg, det gamla hemmets stadiga trygghet."},"ICON-0177":{"nm":"Våg","de":"Blir ena sidan tyngre, lättas den andra av sig själv. I ögonblicket av tvekan över vad man ska lägga på och hur mycket lär sig människan rättvisa. Två armar som lär ut balans genom att väga hit och dit."},"ICON-0178":{"nm":"Klyvare","de":"Även det som sitter hårt fast klyvs till slut om man följer fibrerna. Ett litet redskap som delar vad som helst i två och kikar in i det inre. Nyfikna fingertoppar som längtar efter att ta isär det som fogats samman och se på nytt."},"ICON-0179":{"nm":"Räknare","de":"Ett, två, tre. En liten vän som tyst räknar siffrorna åt fingrarna. Den ängsliga oron för att missa en räkning förvandlas, klick för klick, till trygghet av denna räknandets ömma följeslagare."},"ICON-0180":{"nm":"Markör","de":"En liten pil som blinkar någonstans på skärmen och väntar på nästa kommando. Även medan man tvekar lämnar den aldrig sin plats, ljusets spets som tyst vinkar och säger: nu börjar vi."},"ICON-0181":{"nm":"Klätterfäste","de":"Den enda punkt man griper sist, alldeles innan kraften rinner ur fingertopparna. Att det finns stunder man härdar ut på enbart viljan att inte släppa taget, det berättar den lilla utskjutningen på väggen tyst för dig."},"ICON-0182":{"nm":"Kiselsten","de":"En sten som rullat länge i bäcken och gett upp alla sina kanter. Att bli rund är ett annat namn för tid som slipats bort. Hålls den stilla i handflatan känns forsande vattnets tålamod."},"ICON-0183":{"nm":"Vapensköld","de":"Forna ätter ristade in djur och stjärnor på ett enda banér för att göra sig kända. En bild som förmedlade hjärtat innan orden hann. Ett urgammalt märke som varsamt packat en människas stolthet i en liten ruta."},"ICON-0184":{"nm":"Sköld","de":"Att ställa sig i vägen var alltid till för den som stod bakom ryggen. Genom att ta emot de flygande pilarna i någon annans ställe vaktade den en människas vanliga dag, en tung men ändå öm mur."},"ICON-0185":{"nm":"Återuppståndelse","de":"Det finns ett hjärta som slocknar och tänds igen. Först efter att ha fallit en gång lär man sig hur man reser sig på nytt. Ett andra andetag som tyst stiger fram just på den plats man trodde var slutet."},"ICON-0186":{"nm":"Pilbåge","de":"Handen som vill sända något långt bort drar först strängen hela vägen tillbaka. Att man för att släppa taget måste hålla det lika nära intill sig, det säger den spända, böjda pilbågen tyst utan ett ord."},"ICON-0187":{"nm":"Hjärttecken","de":"Orden 'jag tycker om dig' krymper ständigt till en liten form. Denna figur som ritas i smyg vid änden av en lightstick, eller mellan två fingrar som möts. Hjärtats vanligaste och ärligaste förkortning."},"ICON-0188":{"nm":"Moln","de":"Det driver sakta mot vinden och blir ett nytt ansikte varje gång. En kanin, sedan bomull, det håller inget länge utan låter allt flyta vidare – himlens allra lättaste sinne."},"ICON-0189":{"nm":"Labyrint","de":"En plats där man lär sig att vända om framför en återvändsgränds vägg. Även medan man irrar omkring växer stegen lite i taget mot utgången. Man måste gå vilse en gång för att få känsla för vägen."},"ICON-0190":{"nm":"Tand","de":"Det fanns en sed att kasta en lös tand upp på taket. En liten bön om att den nya tanden skulle växa rakt. Ett barndomens ömma löfte om att man, när man växer, måste förlora något en gång för att vinna något starkare."},"ICON-0191":{"nm":"Planet","de":"En rund kropp som kretsar kring en stjärna utan att någonsin lämna sin bana. Den kan verka ensam, men dess dragningskraft håller alltid något snurrande vid sin sida. Att tyst hålla sin plats blir i sig en hel värld."},"ICON-0192":{"nm":"Stjärna","de":"På nätter man gått vilse har människor sett upp mot den ljusaste punkten. Ett ljus för avlägset att nå, men tydligt nog att peka ut riktningen. Ett löfte som blir desto fastare av att vara långt borta."},"ICON-0193":{"nm":"Silhuett","de":"Ställ dig med ryggen mot ljuset, och bara konturen blir kvar av en människa. En enda svart form, dess namn och uttryck utsuddade. En ofylld plats som, just för att den är tom, får en att föreställa sig desto mer."},"ICON-0194":{"nm":"Öra","de":"För att sjunga väl måste man först lyssna väl. Både takt och hjärta börjar till syvende och sist med lyssnandet. En liten dörr, öppnad rund, dit världens alla ljud först anländer och dröjer sig kvar."},"ICON-0195":{"nm":"Höstlöv","de":"Det finns löv som lyser som vackrast just i fallets ögonblick. Lättheten i att bränna en hel säsongs grönska till rött och sakta lägga ner den. Att även ett slut kan vara så här vackert, det visar hösten oss."},"ICON-0196":{"nm":"Måne","de":"Det fanns nätter man knäppte händerna och önskade sig något under det runda skördeljuset. Ett ansikte som, genom att ständigt växa och avta, aldrig var detsamma två gånger. En lykta som förändras men alltid lyser upp samma plats."},"ICON-0197":{"nm":"Hjärta","de":"Även på scenen är det till syvende och sist denna puls som är den ärligaste. Den stannar inte trots att den darrar, och slår ännu hårdare när känslan svämmar över. En liten, röd trumma som bultar i ditt ställe det hejarop orden aldrig hann fullborda."},"ICON-0198":{"nm":"Skugga","de":"En följeslagare som aldrig faller ifrån så länge det finns ljus. Den mörknar ju ljusare det blir och bleknar ju grumligare det blir, ett annat jag som följt mig längst av alla. En människa som står bredvid mig även på ensamma dagar."},"ICON-0199":{"nm":"Svans","de":"Den viftar av sig själv när man är glad, och kryper undan sakta när man är rädd. Den ärliga lilla spetsen som, fast munnen hålls hårt stängd, ändå aldrig riktigt kan dölja hjärtat. Innerst inne läcker kroppen ut det först."},"ICON-0200":{"nm":"Svansband","de":"Ett litet snöre som knyts vid änden för att avsluta, likt en flätrosett. Hjärtat som knöt den en gång till, hårt, så att den inte skulle lossna. En öm avslutning som samlar och tröstar det som lätt skingras."},"ICON-0201":{"nm":"Pupill","de":"Man kan välja sina ord, men blicken går inte att dölja. Platsen dit ett avslöjat hjärta först läcker ut, inne i den där svarta cirkeln. Även om du sväljer orden 'jag gillar dig', darrar din pupill redan mot dig."},"ICON-0202":{"nm":"Hästsko","de":"En järnbit som blev hårdare ju mer dess spets slets ner av att springa långa vägar. Hängd upp och ner över dörren, sades det, samlas lyckan som kommer och går däri. Den bär tyst upp någons trygga hemkomst."},"ICON-0203":{"nm":"Vapensten","de":"Även när vind och regn nöter bokstäverna otydliga, kommer den ristade ådern levande tillbaka så fort man följer den med fingertopparna. Tyngden av ett hjärta som inte ville bli glömt. Så bär en sten ett enda namn länge."},"ICON-0204":{"nm":"Simhud","de":"Med en enda tunn hinna mellan tårna lär den sig att skjuta undan vattnet. En liten åra som naturen smugit i handen på en klen simmare. En öm konstruktion som, hur långsam den än är, till slut för dig över floden."},"ICON-0205":{"nm":"Glitter","de":"Alla klagar över att det följer med på händerna i flera dagar när det väl fastnat, ändå griper man först efter dessa ljuskorn på en festdag. Strö ut en handfull stjärnstoft och även vanligt papper glittrar till, och dagen blir speciell."},"ICON-0206":{"nm":"Klo","de":"Skogens djur river upp jorden med klorna för att lämna sin egen stig. Inte ett hot utan ett spår - en tyst signatur på att de passerat här. En vass spets kan för någon bli en öm vägvisare."},"ICON-0207":{"nm":"Blixt","de":"I det ögonblick himlen hastigt breder ut sina handlinjer, anländer ljuset före åskan. Som om man ombeds ta ett andetag innan det stora ljudet når fram. Fruktan och förundran föds alltid tillsammans ur samma blixt."},"ICON-0208":{"nm":"Amulett","de":"En enda rad av en önskan, fast intryckt med bläck på rött papper. Lagd under kudden, trodde man, skulle den styra bort onda drömmar. Ett hjärta som ber för någons trygghet är så här varmt, även i ett enda tunt pappersark."},"ICON-0209":{"nm":"Penselvinge","de":"Det finns ögonblick då penselspetsen blir en vinge. Den lätthet som glider över pappret när ett enda streck dras. Att skriva är i sig att flyga, det anade nog den gamla hand som malde bläck, dunkelt."},"ICON-0210":{"nm":"Ben","de":"Det som blir kvar först när allt kött smulats sönder. Det vita skelettet som höll ut längst av allt, för att det var hårdast. Ett tyst bevis som, trots att tiden tar allt annat med sig, ändå minns själva formen."},"ICON-0211":{"nm":"Näsa","de":"Doft är den snabbaste genvägen till minnet. Doften av olja i högtidens kök, den kalla luften en morgon efter första snön - näsan känner det först, och hjärtat följer en takt efter."},"ICON-0212":{"nm":"Rostat bröd","de":"En hektisk morgons snabbaste måltid att gripa tag i. Bit i den gyllenbruna, rostade ytan och en hel dags mod knastrar sönder. Sådant som inte behöver vara stort men som mättar, får en människa på fötter igen."},"ICON-0213":{"nm":"Kaka","de":"Den som väntat längst framför ugnen får den första biten. Värmen från en nybakad kant, en kort stunds sötma. De som bakats med någon i tankarna är, märkligt nog, alltid sötast."},"ICON-0214":{"nm":"Mellanmål","de":"En eftermiddag då träningen drar ut på tiden, en liten påse dras fram djupt ur ryggsäcken. Dela den på hälften och mättnaden fördubblas, märkligt nog. En handfull ömhet som fyller hjärtat innan hungern."},"ICON-0215":{"nm":"Kapsel","de":"Ingen kan veta förrän man vrider upp den. Det som finns i det runda skalet är alltid samma hjärtklappning. Den mest ärliga spänningen i världen, där man köper och säljer en liten slump."},"ICON-0216":{"nm":"Dörrhandtag","de":"Platsen som de otaliga händer som öppnar och stänger en dörr rör vid först. Hemmets första hälsning, kall till att börja med och varm i handflatan. Ju mer den hanteras, desto mer blir rummet, lite i taget, någons hem."},"ICON-0217":{"nm":"Promenad","de":"Även att gå utan mål har sin mening. En stund att nysta upp trassliga tankar, tråd för tråd, i sina steg. Kom tillbaka från ett varv och svaret är detsamma, men hjärtat ensamt är betydligt lättare."},"ICON-0218":{"nm":"Scooter","de":"Två hjul som skär genom trånga gränder. Inte snabbt, men vinden möts med hela kroppen. Det finns dagar då man bara vill köra iväg och känna sig fri idag, även om man inte kommer långt."},"ICON-0219":{"nm":"Säkerhetsbygel","de":"Innan man kliver på, en enda tvärstång som sänks stadigt ner framför bröstet. Ett tryggt löfte som håller ut den skrämmande sträckan tillsammans med dig, ända till slutet. Den säger, kallt och utan ord, att det är okej att hålla hårt."},"ICON-0220":{"nm":"Trappa","de":"Klättra ett steg i taget och innan man vet ordet av har utsikten förändrats. Fotsulorna lär sig först att ingen höjd nås i ett enda språng. Själva upp- och nedstigandet var, för någon, en hel dags steg."},"ICON-0221":{"nm":"Terrarium","de":"Det handlar inte om att fånga en skog i glas, utan om att odla en hel värld med omsorg. Ett handflatstort universum där mossa breder ut sig och vattendroppar bildas. Ju längre man kikar in, desto mer färgas hjärtat sakta grönt."},"ICON-0222":{"nm":"Podium","de":"Kliv upp på en plats ett handsbrett högre och utsikten förändras. En plats där rädsla och stolthet möts på samma höjd. Beroende på vem som står där blir det enda trappsteget en annan scen varje gång."},"ICON-0223":{"nm":"Flygplan","de":"I samma stund molnen breder ut sig under fötterna, börjar man äntligen sakna platsen man lämnade. Det handlar inte om att komma längre bort, utan om att världen blir vidare. Även en dröm som växt upp på en liten ö korsar himlen så här."},"ICON-0224":{"nm":"Skateboard","de":"En sak man bara kan åka på när man först lärt sig att falla. Varje gång knäna skrapas upp ristas balansen lite mer in i kroppen. Fyra ärliga hjul som rullar längre för varje bra fall man tagit."},"ICON-0225":{"nm":"Pass","de":"Slå upp pärmen och den är full av tomma sidor. Varje stämpel som ska fyllas i blir ett bevis på ett levt liv. En liten bok som bär inte hur långt du varit, utan möjligheten att kunna åka vart som helst."},"ICON-0226":{"nm":"Handritad karta","de":"Den har varken exakt avstånd eller skala, men eftersom vägen är ritad för hand finns ingen risk att gå vilse. Papper där gränder och butiksnamn trasslar sig samman på ett hjärtligt sätt. En vägledning med hjärta i är alltid varmare än vägen själv."},"ICON-0227":{"nm":"Rörelseschema","de":"Papper där varje steg på scenen är utritat som en linje. Var man ska stanna, var man ska vända, pilarna lovar det i förväg. Även en dans som ser fri ut börjar egentligen från detta enda blad."},"ICON-0228":{"nm":"Platsanvisning","de":"I ett obekant rum är det första man famlar efter sin egen plats. Raden och numret som till slut leder fram till just den rutan. Ett enda pappersark sätter ner tusentals hjärtklappningar, prydligt, var och en på sin plats."},"ICON-0229":{"nm":"Grändguidekort","de":"En vägledning som någon skrivit för hand åt dem som lätt går vilse i labyrintiska gränder. Den snälla handstilen som säger vilket hörn man ska svänga vid. En stadsdels värme, prydligt nedskriven på ett litet kort."},"ICON-0230":{"nm":"Passerkort","de":"Först när man hänger det här kortet om halsen öppnas dörren till den inre världen. En liten behörighet som ger tillträde, och ett tyst bevis på att man hör hemma här. Bara den som vet hur lång tid det tog att förtjäna det känner dess tyngd."},"ICON-0231":{"nm":"Dagarmband","de":"Sätt fast det en gång på handleden och man är medlem av den dagen tills man tar av det. Ett enda pappersband skiljer inne från ute och blir ett tecken på att man delat samma dag. Även sedan det klippts av dröjer märket kvar länge."},"ICON-0232":{"nm":"Gästbricka","de":"Med en enda liten namnlapp fäst på bröstet blir en obekant plats till ens egen. När ordet 'välkommen' bärs fram på ett enda pappersark, blir även den som kommer för första gången äntligen en gäst."},"ICON-0233":{"nm":"Postertub","de":"En stadig cylinder som håller en hoprullad poster skrynkelfri. Ju dyrbarare bilden är, desto rakare måste den skickas. Man ser inte vad som finns inuti, men den ger sig av med någons omsorg i famnen."},"ICON-0234":{"nm":"Dokumentomslag","de":"Det första bladet som sveper in en tjock bunt dokument. Ansiktet handen möter innan innehållet. När omslaget är prydligt ser även sinnelaget därinne prydligt ut - en öm början på en liten formalitet."},"ICON-0235":{"nm":"Minnesvykort","de":"Man skriver en hälsning på en flik av avlägsen natur och skickar iväg den. När det anländer har hjärtat som skickades åldrats en aning också, och blivit desto kärare. Den långsamma värmen från ett handskrivet brev som ett meddelande på en skärm aldrig riktigt hinner ikapp."},"ICON-0236":{"nm":"Presentlapp","de":"Ett litet pappersark knutet på en present. Med bara orden 'till dig' är inslagningen redan fullbordad. Världens kortaste brev, som skriver ner inte vad man ger utan vem man tänkte på."},"ICON-0237":{"nm":"Klistermärkesrulle","de":"Varje gång man river av en bit blir avslutningen betydligt snyggare. En liten knut som prydligt håller fast änden som vill lossna. Det sista greppet i en omsorgsfullt inslagen present kommer alltid från detta hoprullade band."},"ICON-0238":{"nm":"Genomskinlig brevficka","de":"Ett genomskinligt lager som sveper in ett handskrivet brev så att det inte bleknar med åren. Bokstäverna syns som vanligt, men handens slitage når det aldrig. En osynlig hinna vakar tyst över någons ömma hjärta."},"ICON-0239":{"nm":"Färgat sigill","de":"Den sista prick som stänger ett kuvert - ju klarare färgen är, desto mindre läcker hjärtat ut. Ett löfte om att ingen hand rörde det förrän det bröts upp. Även en hemlighet behöver en så vacker knut."},"ICON-0240":{"nm":"Meddelandelappbok","de":"En liten bok som binder samman korta lappar. Varje sida är ett ord att räcka fram till någon. Samlar man, lite i taget, orden man inte riktigt kunde säga, växer så småningom modet att en dag verkligen framföra dem."},"ICON-0241":{"nm":"Hopfällbar skylt","de":"Vik ut den och den säger 'hitåt', vik ihop den och den säger 'det var allt för idag'. Med benen isär vid gränds mynning står den en hel dag för någon som lätt går vilse. Kvällen då den viks ihop är, för mig, den ömmaste vilan."},"ICON-0242":{"nm":"Postband","de":"Sluter man en hög vykort om midjan blir hälsningarna som var på väg att skingras till slut en enda bunt hjärta. Ett enda lätt band binder prydligt samman orden som ska nå avlägsna platser, och vinkar tyst av den rygg som ger sig av."},"ICON-0243":{"nm":"Tacklappsbunt","de":"Eftersom ordet 'tack' ständigt glider bort från tungan, skriver man det på ett handflatstort papper och binder ihop det tyst. Ju tjockare bunten blir, desto tjockare växer, sida vid sida, tacksamhetsskulden till någon."},"ICON-0244":{"nm":"Hejaramsemall","de":"Ett provblad där det står 'ropa så här'. Ett hejarop som ännu inte fått en röst bär bara en tyst spänning, som ett tomt notblad som väntar på den första takten."},"ICON-0245":{"nm":"Förinspelningslapp","de":"En lapp där man ber om att få boka en förinspelning dröjer alltid kvar i femtiden på morgonen. Det lilla pappret tar tyst ner, som om det förstod alltihop, hjärtat som kortar sin sömn för att säkra en plats."},"ICON-0246":{"nm":"Fansignbiljett","de":"Ett enda ark som avgör i vilken tur man ska hälsa. Att stå i kö handlar inte om att vänta på sin tur, utan om att för en stund låna en ordning eftersom man inte kan sätta en siffra på hur mycket man bryr sig."},"ICON-0247":{"nm":"Könummerarmband","de":"En enda siffra avgör i vilken ordning man ställer sig i kö idag. Först eller sist i kön, de som bär detta lilla, lätta band på handleden är till syvende och sist likasinnade kamrater samlade för att se samma scen."},"ICON-0248":{"nm":"Fotokortsschema","de":"Trots att det är samma ansikte är de ändå alla olika, så man antecknar dem ruta för ruta. Ju fullare schemat blir, desto mer ordnat blir hjärtat, och den enda tomma rutan som blir kvar får bröstet att bulta av lusten att fylla i den idag."},"ICON-0249":{"nm":"Albumchecklista","de":"Version, fotokort, ja till och med om det är förseglat - en kärlekens lista nedskriven i siffror. Man föreställer sig i förväg stoltheten den dag allt är ifyllt, och ritar idag också en fin liten cirkel på en rad."},"ICON-0250":{"nm":"Hejaguidelapp","de":"Handrörelser, takten man ropar i, ja till och med var man ska andas. Så att även den som kommer för första gången snabbt smälter in i en enda röst, blir den lilla lappen en vänlig vägvisare som vandrar från hand till hand."},"ICON-0251":{"nm":"Privat anteckningsblock","de":"Man väljer ut bara de meningar man inte visar för någon och skriver dem här. Att den aldrig uppslagna sidan är den ärligaste, det vakar det här blocket tyst över, med pärmen stängd."},"ICON-0252":{"nm":"Jubileumsstämpelblad","de":"Man trycker till, och ännu en dag blir speciell. Med en enda liten stämpel tryckt på ett vanligt datum, smyger 'idag' sitt namn in på listan över dagar värda att minnas."},"ICON-0253":{"nm":"Skrivplattfodral","de":"Blåser det, eller slår regnet in, skyddar den ändå det fastklämda pappret ända till slutet. Jag har gjort mig själv till plattans rustning - en trygg livvakt åt de nedtecknade bokstäverna."},"ICON-0254":{"nm":"Filindex","de":"För att man inte ska gå vilse bland tjocka dokument sticker den fram en liten tunga och pekar 'här'. Ett enda färgglatt flikblad styr hundra sidor med en enda blick."},"ICON-0255":{"nm":"Kategoriflik","de":"Det här i den här rutan, det där i den där. Mitt jobb är att städa upp världens oreda, rad för rad. I samma stund en etikett sätts på hittar de rörigt utspridda sakerna äntligen sin plats."},"ICON-0256":{"nm":"Miniattestbräda","de":"I samma stund man trycker ner en stämpel känns det som om man blivit en riktig vuxen. Liten till storleken men med en käck auktoritet - en enda godkännandestämpel och det hopade arbetet avslutas raskt."},"ICON-0257":{"nm":"Genomskinlig dokumentficka","de":"Klar och genomskinlig, med inget att dölja. Med viktigt papper i famnen sveper den in det i sin egen genomskinliga kropp, av rädsla för regn eller skrynklor, och bär det ända fram till mötesplatsen."},"ICON-0258":{"nm":"Närvaroband","de":"Kom, och ännu en ruta fylls i. När varje dags fotspår travas upp i rad längs bandet blir en osynlig flit till slut ett mönster synligt vid en enda blick."},"ICON-0259":{"nm":"Felanteckningsbok","de":"Att skriva ner det man svarat fel på handlar inte om att samla skam. Det handlar om att, för att inte snubbla på samma ställe två gånger, skriva om gårdagens misstag till dagens vägvisare."},"ICON-0260":{"nm":"Schemastämpelplatta","de":"Stämpla en gång på ett tomt schema och en 'överenskommelse' föds. Magin i att en dag avgörs med en enkel rörelse av handleden - den magin är i själva verket bara ett annat namn för flitigheten att förbereda i god tid."},"ICON-0261":{"nm":"Ryggetikett","de":"Namnlappen på böcker som står med ryggen vänd mot hyllan. De korta bokstäverna skrivna på en smal rygg vinkar med en enda gång fram just den boken man letat efter bland hundratals andra."},"ICON-0262":{"nm":"Fotoskydd","de":"Bara händer nekas tillträde. Den ber en att inte lämna ens ett enda fingeravtryck, och lägger varsamt sin egen kropp över ett dyrbart ögonblick. Ett hjärta som håller kärt håller så här länge, genom en så varsam hantering."},"ICON-0263":{"nm":"Filmindexblad","de":"Sätter man ett nummer på varje remsa film återfår de skingrade ögonblicken sin plats i berättelsen. En liten vägvisare som vårdar minnena skrivna i ljus, så att de inte blandas ihop."},"ICON-0264":{"nm":"Fotoficka","de":"Ett genomskinligt hem där kvadratiska bitar av lycka hyses in en och en. Utan oro för skadade hörn lyser det käraste ansiktet prydligt härinne genom alla fyra årstider."},"ICON-0265":{"nm":"Minifotokuvert","de":"Innan värmen från ett nyframkallat foto ens hunnit svalna, öppnar ett litet kuvert sina armar och tar emot det. Ett enda kort som går in genom den handflatstora öppningen blir, innan man vet ordet av, en skatt i någons väska."},"ICON-0266":{"nm":"Lentikulärt fodral","de":"Mitt uppdrag är att, utan en enda repa, skydda ett kinkigt foto vars uttryck ändras när man lutar det. Att skydda varje olika ansikte i varje vinkel kräver att inte ens jag får vara annat än flitig."},"ICON-0267":{"nm":"Bildsorteringsetikett","de":"Vilken av de fyra bilderna som är bäst, det pekar etiketten ut åt en. Denna lilla syssla att skilja det lyckade från det roliga, sida vid sida, är hemligheten bakom att njuta av ett minne två gånger."},"ICON-0268":{"nm":"Fotoremseband","de":"Det sveper prydligt runt ett smalt, långt fyrabildsminne. Det kramar den dagens flyende skratt fast i en enda bunt och för det tryggt ända ner i väskans djup."},"ICON-0269":{"nm":"Fotohörnklistermärke","de":"När man fäster ett foto i ett album, en liten hand som varsamt håller i dess fyra hörn. Så att det inte lossnar utan att man klistrar över hela ytan med lim - så här börjar finkänslighet, från hörnen."},"ICON-0270":{"nm":"Bildkorrigeringsschema","de":"Lite varmare, en aning mindre ljust. Ett enda schema där man petar med siffrorna tills önskad färgton kommer fram, förvandlar stillsamt en vanlig bild till ett konstverk."},"ICON-0271":{"nm":"Kvittoklämma","de":"Den biter fast prydligt i de skrynkliga kvitton och släpper inte taget. Med sin lilla mun håller den ordning på en dags utgifter, så att månadens avstämning blir betydligt lättare."},"ICON-0272":{"nm":"Bokningsbekräftelse","de":"Vid en enda rad, 'din bokning är bekräftad', sjunker hjärtat sakta ner i ro. Ett pappersark blir bevis på ett löfte, och förvarar spänningen, lite i taget, ända fram till den efterlängtade dagen."},"ICON-0273":{"nm":"Återlämningskvitto","de":"Ett litet men hedervärt bevis på att man lagt tillbaka det man lånat på sin plats. I samma stund detta papper vilar i handen suddas en skuld som legat och tyngt ett hörn av hjärtat lätt bort."},"ICON-0274":{"nm":"Förvaringskvittohållare","de":"Så att du inte ska tappa bort biljetten till det du lämnat, håller jag den stadigt åt dig istället. För var en liten lapp befinner sig kan trots allt avgöra hur någons dag slutar."},"ICON-0275":{"nm":"Lånesedelssvans","de":"En liten lapp som fladdrar på varje utlånat föremål. Följer man denna svans avslöjas i en enda stund vem som tog vad, så även mysteriet om det förlorade löses snabbt upp."},"ICON-0276":{"nm":"Besiktningslista","de":"Man far över allt med blicken, en sak i taget, för att se att inget fattas. När bockarna fylls i på rad, en efter en, förtjänar en osynlig noggrannhet till slut namnet tillit."},"ICON-0277":{"nm":"Avräkningskuvert","de":"Skriver man pengarna som kommit in och gått ut på kuvertet, ställer sig de röriga siffrorna lugnt på rad. Avräkningens slut är alltid denna lilla lapp som stillsamt sätter den sista punkten."},"ICON-0278":{"nm":"Fraktetikett","de":"Med vart den ska och vem den ska nå skrivet på sin egen kropp ger den sig av. I samma stund denna etikett sätts på blir lådan en resenär med ett mål, och ger sig av med en förväntans rysning."},"ICON-0279":{"nm":"Mottagningsband","de":"Den binder samman orden 'mottaget med tack' i ett enda band och skickar dem tillbaka. Mottagarens lättnad och avsändarens sinnesro möts tyst och tar varandra i hand på detta lilla snöre."},"ICON-0280":{"nm":"Ordkortsring","de":"Orden som skulle gått förlorade om de skingrats som lösa blad, håller en enda liten ring samman och fast. Bläddra igenom dem om och om igen, och de en gång främmande orden blir, innan man vet ordet av, vänner man känner väl på tungan."},"ICON-0281":{"nm":"Uttalsanteckningsband","de":"Man fäster en liten lapp på stället där tungspetsen ständigt glider iväg. Även ett främmande ljud som gått vilse i munnen hittar, innan man vet ordet av, sitt rätta uttal om man följer denna lapp. Den första sidan i att sakta tämja ett klumpigt ljud."},"ICON-0282":{"nm":"Översättningsbrevlåda","de":"Små broar som korsar mellan ord och ord ligger prydligt hopvikta, en i varje fack. Skriver man ner en svårvald mening och skjuter fram den i smyg, kommer även hjärtan som inte nått fram till varandra närmare - med bara en liten lapp emellan."},"ICON-0283":{"nm":"Citatklippblad","de":"En mening som träffar hjärtat mitt i prick består bara om man skriver av den för hand. Klistrar man en rad klippt ur ett bokhörn upp framför skrivbordet, stöttar de bokstäverna tyst upp en dag som höll på att sjunka."},"ICON-0284":{"nm":"Anteckningsflikar","de":"Färgglada små flaggor instuckna för att man inte ska gå vilse i en tjock bok. Man kan bara vandra längre bort om man vet platsen att komma tillbaka till, viskar de utstickande flikarna tyst mellan sidorna."},"ICON-0285":{"nm":"Minnesmarkeringsbricka","de":"Ett enda märke prickat bredvid det man lärt sig utantill. Som ett litet ankare som håller fast sådant som en kort stund dröjer i huvudet innan det försöker försvinna, bär varje svartmarkerad ruta tyst med sig gårkvällens spillda möda."},"ICON-0286":{"nm":"Frågekuvertpaket","de":"Innan man river upp kuvertet vet ingen vad som kommer ut. De där få sekunderna man pillar vid den förseglade kanten med fingertopparna - ett paket med förväntan där en enda fråga ligger prydligt vikt, med hjärtklappningen förseglad tillsammans med den."},"ICON-0287":{"nm":"Grammatikflikbok","de":"Regler lär man sig inte utantill med huvudet, utan i handen. Från den färgade fliken på sidan man öppnar oftast till anteckningsboken som mjuknar och nöts, blir det slitna hörnet till en årsring för tiden du härdat ut."},"ICON-0288":{"nm":"Talövningsschema","de":"Ett enda schema för den som tycker att öppna munnen är det svåraste i världen. Följer man rutorna nedåt med fingret hittar även det första ordet som darrade i halsen, innan man vet ordet av, sin egen röst. Även modet har sin tur att komma."},"ICON-0289":{"nm":"Färgskissblad","de":"Färgerna ligger grovt utlagda innan de är färdiga och hämtar andan. Inte det rätta svaret utan fortfarande en möjlighet - på detta ännu opolerade blad guppar mer morgondag än något annat."},"ICON-0290":{"nm":"Moodboard-bit","de":"Samlar och klistrar man ihop intryck som skingrats bit för bit, på en och samma plats, framträder dunkelt konturerna av en stämning som annars aldrig riktigt gått att gripa. En känsla som ännu saknar namn - dit pekar bitarna tyst, lutade mot varandra."},"ICON-0291":{"nm":"Mönsterprovbok","de":"Rutmönstret i en bordduks tyg och flätningen i ett fönstergaller är prydligt ordnade, sida för sida, i en enda bok. Där samma mönster upprepas ända till slutet bor inte lättja utan ett löfte - ett fast hjärta som håller fast vid en enda ådra."},"ICON-0292":{"nm":"Kostymtygprov","de":"Fast det är samma ljus, fastnar hud och skugga olika på varje tygbit. Innan man väljer scenkostym är kvällen man tillbringade tvekande, strykande över tyget om och om igen med fingertopparna, bevarad hel i ett enda litet provlapp."},"ICON-0293":{"nm":"Logo-förbudsblad","de":"Papper som först, tydligt och klart, skriver ner det man inte får göra. Inom en kontur överstruken med ett rött kryss blir friheten bara tydligare, så en ny väg öppnas, just där man trodde det var en återvändsgränd."},"ICON-0294":{"nm":"Färgreferensbricka","de":"En provbit gjord för sig själv eftersom färg helt enkelt inte går att förklara med ord. Den fångar in ett visst ögonblick då solnedgången var som rödast på en handflatsstor yta, så att man exakt kan räcka fram 'just den här färgen' till nästa person."},"ICON-0295":{"nm":"Layoutskisskort","de":"En första teckning, lätt utritad, av vad som ska placeras var. Att bestämma platsen är i sig att bestämma hjärtat, så bland de klumpigt utspridda linjerna öppnar helhetens balans sakta sina ögon."},"ICON-0296":{"nm":"Materialanteckningstavla","de":"Trä, jord, sten - namnen på gripbara ting står tätt nedskrivna. En hemlighet som bara den känner till som börjar med att läsa ådran med handen först - vad man bygger med avgör redan, till hälften, vad det ska bli."},"ICON-0297":{"nm":"Kalkerpapper","de":"Man lägger tunt papper över underteckningen och följer stillsamt linjerna. Medan man för en stund lånar någon annans väg lär sig handen den vägen, och bland de kopierade linjerna växer, i smyg och innan man vet ordet av, en linje helt ens egen."},"ICON-0298":{"nm":"Entréband","de":"Utmed ett band draget i en lång remsa längs golvet strömmar människorna in i kö. En enda linje som stillsamt vägleder så att de upprymda stegen inte trasslar in sig - en osynlig, öm hand som stöttar upp spänningen så att den inte rasar samman."},"ICON-0299":{"nm":"Evenemangsskylt","de":"En skylt som står och håller upp orden 'hitåt' i någons ställe. En liten vänlighet uppställd vid varje vägskäl så att ingen ska gå vilse, som tar en förstagångsbesökares främmande dag vid handen och promenerar stillsamt vidare med den."},"ICON-0300":{"nm":"Monternummerlapp","de":"Ett enda nummer tilldelat varje monter avgör tydligt vem den rutan tillhör. En liten siffra, men eftersom den är löftet 'här är din plats', skapar den en plats att återvända till på en obekant evenemangsplats."},"ICON-0301":{"nm":"Medarbetaravtal","de":"En enda underskrift, lämnad där hjärtan enades om att arbeta tillsammans. Det är bara ett tunt pappersark, men det bär tyngden av att välja att lita på varandra, och varje hjälpande hand vid evenemanget börjar just här."},"ICON-0302":{"nm":"Provbiljettbunt","de":"En knubbig bunt provbiljetter, bunden så att den ligger skönt i en hand. Ju mer man delar ut, desto mindre krymper den inte – i stället växer den och ger fler och fler \"första gånger\" till andra, en bunt av godhet som blir varmare ju mer man rör vid den."},"ICON-0303":{"nm":"Kömarkeringsskylt","de":"Vänta här, viskar golvet stilla. När hjärtan som håller sin tur samlas blir även en lång kö till ett eget litet landskap, och en liten markering förvandlar otålighet till lugn."},"ICON-0304":{"nm":"Avhämtningslapp","de":"En liten lapp som fästs lätt där du hämtar det du beställt i förväg. I samma stund den ligger i din hand glider den där lätta lättnaden från dina axlar – en knut där ett länge väntat hjärta äntligen tar form."},"ICON-0305":{"nm":"Mysterielådebiljett","de":"Glädjen i att välja en låda utan att veta vad som finns inuti. Skaka den och hjärtat rusar först vid skallret därinne, och den korta stunden precis innan den öppnas blir dagens mest förväntansfulla ögonblick."},"ICON-0306":{"nm":"Bytesklistermärke","de":"En liten rund stämpel som meddelar att bytet gick smidigt. Den är den mjuka punkten kvar mellan händerna som gav och tog emot, och så fort den trycks fast rundas affären äntligen av med värme."},"ICON-0307":{"nm":"Förseglingsband","de":"En dyrbar ask virad en gång runt med ett band och stilla förseglad. En bön om att inte öppna den vårdslöst, och den tystaste artigheten att skatta det som finns inuti lika högt, allt samlat i ett enda band."},"ICON-0308":{"nm":"Hemlig anteckningskapsel","de":"Ett ord du ville säga, varsamt instängt i en liten behållare. Försegla det tätt som att begrava en känsla du inte kunde skicka, och ett litet kassaskåp i din handflata vakar över tiden till den dag du öppnar det igen."},"ICON-0309":{"nm":"Litet urklippskort","de":"En urklippt och uppklistrad bit bär dagens stämning i sig, sval och stilla. Lättare än en dagbok och mer handgjord än ett fotografi – ett handflatestort papper håller stadigt fast en dag som annars lätt skulle glida mellan fingrarna."},"ICON-0310":{"nm":"Förstabesöksblad","de":"Darrningen från den dag du först satte foten på ön dröjer kvar i en kort rad. Precis innan det främmande blev förtroget bevarar pappret den renaste första känslan i ditt ställe och håller den länge."},"ICON-0311":{"nm":"Minnessorteringsschema","de":"Ett schema där minnen sorteras efter art och gren, noga nedtecknade ett i taget. Häller man alla minnen huller om buller i en enda låda begravs till och med den mest älskade dagen, så ju dyrbarare något är, desto ömmare ges det sin egen plats."},"ICON-0312":{"nm":"Pratbubblebricka","de":"Orden du ville säga sväller runda som en ballong och svävar på pappret. Även en rad du inte kunde säga högt hittar tyst mod innanför den runda kanten – en liten, varm passage där hjärtat kan smyga sig ut."},"ICON-0313":{"nm":"Datumhållare","de":"En liten ställning som reser upp dagens datum så att det möter din blick. Plocka ut en enda dag ur alla dem som strömmar förbi och sätt den mitt i centrum, och även ett vanligt datum får en värme värd att fira."},"ICON-0314":{"nm":"Samlingsnummerlapp","de":"Ett unikt nummer tilldelat varje sak du håller kär. Att samla är att lova att kalla just den saken den enda i sitt slag i hela världen, så siffran på den lilla lappen bär hjärtats tyngd tydligt inristad."},"ICON-0315":{"nm":"Arkivficka","de":"Ett tunt innerfodral du för in varje länge sparad sak i, en i taget. Att lägga något bara ett skikt bort från ljus och tid – att älska något är, i slutänden, att bevara det väl."},"ICON-0316":{"nm":"Fotokortstoploaderrem","de":"En smal rem som gör att man kan hänga en toploader runt halsen. Det är ett sätt att leva sitt fandom, att gå genom dagen med sin favorit nära bröstet, och i denna enda tunna lina är en hel dags ömma sällskap knutet fast."},"ICON-0317":{"nm":"Fotokortsställnål","de":"Med en enda liten nål reser sig fotokortet rakt upp på skrivbordet. Liggande är det bara ett pappersark, men upprest blir det ett ansikte man möter öga mot öga, och stilla skapas en plats där blicken kan dröja länge."},"ICON-0318":{"nm":"Holografisk fotokortsfilm","de":"Ett enda tunt filmskikt där regnbågar strömmar fram med varje vinkel. Ett skikt som fångar en aning ljus klär ett vanligt kort i stjärnglans, en liten magi där ett nytt uttryck tindrar till liv varje gång du vickar på handleden."},"ICON-0319":{"nm":"Fotokortsskydd","de":"Ett enda tryck mot ett hörn, och det känns som om även hjärtat man håller kärt viks ihop. En genomskinlig rustning som stadigt omfamnar ett enda dyrbart ark – sådan varsamhet följer alltid med att verkligen hålla något kärt."},"ICON-0320":{"nm":"Sorteringsbricka för fotokort","de":"En grund bricka som lägger dussintals fotokort ner i prydliga rader, med fibrerna åt samma håll. Utspridda är de bara en hög, men lagda i rad blir de en samling, och i varje ordnande hand ristas kärlekens ordningsföljd steg för steg."},"ICON-0321":{"nm":"Fotokortsbytekuvert","de":"När du stoppar ett fotokort i ett kuvert för att lämna det ifrån dig, tvekar fingertopparna ett ögonblick. Det är inte att skicka bort det, utan att be det bli någons favorit. I samma stund du viker igen fliken byter en liten förbindelse stilla hand."},"ICON-0322":{"nm":"Dekorationspenna för fotokort","de":"Det som fyller det tomma utrymmet är inte skrift utan känsla. Var pennspetsen än rört sig gror små hjärtan och stjärnor fram, och ett vanligt pappersark vaknar som en hyllning utan like i hela världen. Att pyssla om är bara ett annat namn för en bekännelse."},"ICON-0323":{"nm":"Fotokortsklämma","de":"Klick, ljudet av en klämma som biter ihop. Med det enda lilla låset samlas kort som nästan skingrats i en enda rad. Även efter att ha skakats om hela dagen i en väska förblir inte ett enda hörn skadat. Styrka kan vara så här tyst."},"ICON-0324":{"nm":"Bärpåse för fotokort","de":"En vana har smugit sig in i handen som drar blixtlåset upp och igen. Genom ett plötsligt skyfall, genom en trängsel av folk, förblir bara insidan torr. Att hålla det man älskar mest på det djupaste stället, det är det bärandets ömma arbete."},"ICON-0325":{"nm":"Fanträff-armbandsrem","de":"En fan mindes länge hur varma personalens händer var när de knöt bandet runt handleden. En enda knut som markerar att man hör hemma här idag. Virat två varv så det inte ska lossna, håller det bandet fast en hel dags förväntan."},"ICON-0326":{"nm":"Inträdesarmband","de":"I samma ögonblick du passerar ingången delas till slut inne och ute tydligt åt. Buret hela dagen blir det snart förtroget mot huden, och när det tas av finns ett svagt märke kvar, som ett bevis på platsen där du stannade."},"ICON-0327":{"nm":"Samtalsbricka","de":"När samtalshörnan öppnar rullar en bricka iväg. Vem som talar först, vilken fråga som dras, den lilla slumpen förändrar hela stämningen. En enda brickas nyck är mer älskvärd än något nedskrivet manus."},"ICON-0328":{"nm":"Signeringskölapp","de":"Du ställer dig i kö med en numrerad lapp i handen. Nummer 142. Medan du räknar de 141 framför dig räknar hjärtat sin tur först. Väntan är lång, men tack vare denna enda lapp blir till och med den tiden en del av spänningen."},"ICON-0329":{"nm":"High touch-handske","de":"I samma stund handflatorna möts tar handsken emot den korta värmen i ditt ställe. En hand värmd hela dagen för en beröring på en halv sekund. Att bära tyg kan inte stoppa just den darrningen, och det inser alla först då."},"ICON-0330":{"nm":"Minnesfotonål","de":"Ett enda klick, och dagen bevaras precis som den var. Inne i ramen som hålls fast av en nål blir till och med ett generat leende med tiden den mest saknade bilden. Att dokumentera är den ömmaste girigheten – att hålla fast ett ögonblick."},"ICON-0331":{"nm":"Sittplatsband","de":"Ett litet band som hänger på en stolsrygg svajar trots att det inte blåser. En markering någon knutit fast, ett spår av att en människa varit här. Även i den tomma platsen efter föreställningen verkar bara bandet ännu minnas takten."},"ICON-0332":{"nm":"Gåvokontrolletikett","de":"En etikett fästs på varje enskild gåva. Har den skickats, har den kontrollerats, saknas något. Även att ta emot någons hjärta kräver ordning och reda, så denna lilla dekal knyter samman omsorg efter omsorg utan att missa ett enda steg."},"ICON-0333":{"nm":"Minneslapp","de":"Ett pappersark skrivet för att sparas och betraktas länge. Vädret den dagen, platsnumret, till och med titeln på sista låten. Minnet bleknar, men bara denna lapp bleknar inte. Även att bevara ett minne behöver sin lilla form."},"ICON-0334":{"nm":"Hejahandduksögla","de":"Trä en ögla på handdukens ände och den glider inte av axeln. Mellan att torka svetten, snurra den över huvudet och slänga den kring nacken igen, håller en liten koppling hejarörelserna obrutna."},"ICON-0335":{"nm":"Sloganklämma","de":"Klämmor griper stadigt tag i sloganens båda ändar. Så att bokstäverna inte viks eller fladdrar bort ens med båda armarna höjda. Här finns den mest ståndaktiga statisten, som rätar ut budskapet utom synhåll."},"ICON-0336":{"nm":"Ljuddämpande påse","de":"Blixtlåset glider sakta, ljudlöst. En tystnad konstruerad så att inte ett enda ljud läcker ut där stillhet utlovats. Hänsyn är ibland att göra sig ohörd, säger denna påse stilla."},"ICON-0337":{"nm":"Applådtaktbricka","de":"Varje gång handflatorna möts räknar brickan takten. Klapp, klapp, klapp – de spridda applåderna samlas plötsligt till en enda rytm. Magin i att tusentals applåder blir ett enda andetag, det hjälper en liten bricka stilla till."},"ICON-0338":{"nm":"Hejaguidemapp","de":"Öppna den och hejaguiden står nedskriven steg för steg. Vilken färg som lyfts vid vilken rad, när ett rop ska läggas till. Även en förstagångsbesökare blir en av familjen med denna enda mapp. En liten manual för att dela ett löfte."},"ICON-0339":{"nm":"Solfjädersrem","de":"Knyt en rem vid solfjäderns handtag och den faller inte även om den slinker ur greppet. På en het dag, när båda händerna blir fria för jubel efter att ha fläktat, dinglar den från handleden. En enda rem kyler både hettan och upprymdheten på en gång."},"ICON-0340":{"nm":"Glitterfilmbit","de":"Fångar den ljuset splittras det åt olika håll i varje liten bit. Lägg den i handflatan och en liten regnbåge skimrar, och färgerna vaknar till liv för varje skakning. Kanske är glitter bara att dela ljuset i tusen små delar."},"ICON-0341":{"nm":"Minibannerstång","de":"Fäll ut den lilla stången och tyget spänns hårt i vinden. Höj den med båda händerna och bokstäverna når bortom sittraderna, vik ihop den och den ryms i ett hörn av väskan. Hjärtats storlek mäts inte i stångens längd."},"ICON-0342":{"nm":"Hejadekalpaket","de":"Varje enskilt klistermärke bär en hejafras. På planeringsboken, på telefonen, i hörnet av en dator – var de än fästs färgas vardagen av hejarop. En kär känsla lämnar spår överallt på det här sättet."},"ICON-0343":{"nm":"Albumskydd","de":"Handen som sveper omslaget om albumet är försiktig. Så att hörnen inte nöts, så att det inte bleknar i solen. Musik hörs med öronen, men detta enda ark minns man med händerna. En rustning av hjärtat som håller det man älskar nära länge."},"ICON-0344":{"nm":"Skivfodralring","de":"Stoppa skivor i fodral och bind dem samman med en ring, och de blir en samlad album-bok. Det där prasslande ljudet varje gång man bläddrar en sida är underbart. Att samla spridd musik prydligt i handen, det är en samlares tysta lycka."},"ICON-0345":{"nm":"Förvaringsskiljevägg","de":"Med en enda skiljevägg hittar prylar som nästan blandats ihop sin plats. Här fotokort, där nyckelringar, bredvid dem ljusstavar. Att ordna är att bygga hem åt saker. I samma stund facken delas upp förvandlas oredan till ordning."},"ICON-0346":{"nm":"Förseglingssnöre för slumppaket","de":"Bind igen öppningen på ett slumppaket med ett snöre, och ingens öde är ännu avgjort. Innan du löser upp det är alla hjältar i sin egen förhoppning. Darrningen i fingertopparna som löser upp förseglingen är just den glädje detta snöre vaktat."},"ICON-0347":{"nm":"Bonusordningsbox","de":"Bonusar ställer upp sig efter typ inuti en box. Vykort med vykort, bokmärken med bokmärken. Se facken bli allt tätare fyllda ju fler de blir, och all tid du samlat på dig kommer i ett enda ögonkast. Att sortera är att lista minnen."},"ICON-0348":{"nm":"Versionsetikett","de":"Det finns saker som ser likadana ut men inte är det. En enda etikett skiljer version A från version B, förstatryck från omtryck. Tack vare en liten markering försvinner förvirringen, och en tydlig namnlapp fästs på samlarvärlden."},"ICON-0349":{"nm":"Förstaveckans säljanteckning","de":"Utgivningens första vecka, och en enda siffra får hjärtat att svaja. Bockmarkeringar prydligt nedtecknade på ett anteckningsblock. Samlas några dagars noteringar ihop blir det ett litet betygsblad för stödet. En omsorgsfull vana att översätta en kär känsla till siffror."},"ICON-0350":{"nm":"Posterhållarlock","de":"Trä ett lock på änden av en hoprullad poster, och den förblir stilla utrullad. Så att den inte skrynklas medan du funderar på om du ska hänga upp den eller rama in den. Ett litet lock som håller din favoritbild perfekt rak."},"ICON-0351":{"nm":"Fotoställ","de":"Ett foto står på snedden på stället. I ett hörn av skrivbordet, i precis rätt vinkel för ögonhöjd. En uppfinning som gör att blickarna möts varje gång du går förbi. Det enklaste sättet att föra ett älskat ansikte in i vardagens vy."},"ICON-0352":{"nm":"Repetitionstejp","de":"Tejp fästs på golvet för att markera var man ska stå. En ruta, två rutor, precis här. Genom att trampa på samma märken dussintals gånger ristas rörelsemönstret in i kroppen. Under en lysande scen ligger dessa ärliga tejpspår."},"ICON-0353":{"nm":"Scenmarkeringsnål","de":"En enda nål instucken i scengolvet berättar nästa steg. Även i mörkret hittar tårna platsen först. En exakt väg man inte kan se, en osynlig karta ritad av otaliga repetitioner."},"ICON-0354":{"nm":"Öronpropp för personal","de":"Sätt i öronproppen och publikens vrål dämpas ett skikt, medan bara rösten som ger signaler förblir tydlig. Backstagepersonalens öron hör alltid två världar samtidigt. Ett litet redskap för att plocka ut signalen ur oredan."},"ICON-0355":{"nm":"Logegalgmärke","de":"En namnlapp hänger på varje galge. Kostym 1, kostym 2, extranummer-kostym. Se på det schemat som listar ombytesordningen, och dagens föreställning ritas i förväg upp genom klädernas ordning. En tyst ordning som tyglar bruset."},"ICON-0356":{"nm":"Rekvisitakontrolltagg","de":"Innan man går upp på scenen fästs en tagg på varje enskild rekvisita. Saknas något, är allt helt. Publiken vet inte, men denna lilla kontroll förhindrar olyckor. Bakom en till synes felfri scen finns alltid en noggrann hand."},"ICON-0357":{"nm":"Signalbricka","de":"En signalbricka vandrar från hand till hand. Nu, gå in. Ett ögonblick när tajmingen förmedlas utan ett enda ord. I mörkret bredvid scenen håller denna lilla signal alla från att missa takten."},"ICON-0358":{"nm":"Backstagemärke","de":"Det finns en dörr bara de som bär detta märke får passera. Backstage, där jublet hörs genom väggen. En enda liten tygbit skiljer den bländande framsidan från den hektiska baksidan. Märket för de människor som bär upp scenen."},"ICON-0359":{"nm":"Prompterskärm","de":"En skärm håller prompterns ljus från att läcka ut mot publiken. Bara personen på scenen ser det, betraktarna anar ingenting. En artig väktare av scenens hemlighet, som stilla döljer en hjälp som inte får avslöjas."},"ICON-0360":{"nm":"Logespegelöverdrag","de":"I logen efter föreställningen täcks spegeln med tyg. Glaset som speglat otaliga uttryck hela dagen sluter ögonen en stund. Det ett smink-avtorkat, bart ansikte till sist möter är inte spegeln, utan en stilla mörk."},"ICON-0361":{"nm":"Förinspelningsarmband","de":"Ett litet band som, en gång fäst, inte lossnar förrän det klipps av. För den enda behörigheten att komma in på förinspelningens sittplatser klev någon på det allra första tåget i den kolsvarta gryningen. Vikten runt handleden blir en hel dags förväntan."},"ICON-0362":{"nm":"Inspelningsberedskapsetikett","de":"Precis innan den röda lampan tänds är det mitt jobb att binda allas andetag i en enda rad. I tystnaden som väntar på signalen håller jag stilla ut ända till slutet. I samma stund jag lossas höjs äntligen ridån för direktsändningen."},"ICON-0363":{"nm":"Kamerapositionsbricka","de":"En enda liten markering stämplad på golvet fastställer skickligt sex kameravägar. Var man ska fångas för att se som ljusast, det vet regissören redan innan repetitionen. En hand som ritar upp bilden i förväg, utifrån och in."},"ICON-0364":{"nm":"Ljudkontrolltagg","de":"Du knackar, knackar mikrofonen mot de tomma stolsraderna. Om ekot dröjer länge, ett skikt akustikskum till på taket. Omsorgen att finjustera ljudets fibrer medan publiken aldrig anar något börjar stilla från denna lilla tagg."},"ICON-0365":{"nm":"Stämpelbok","de":"Varje gång du besöker en plats samlar du en stämpel till i en ruta. I varje suddigt bläckmärke stämplades även den dagens väder och hjärtklappning. En helt fylld sida blir en karta över fotspår ingen annan kan efterlikna, bara min egen."},"ICON-0366":{"nm":"Besöksrem för TV-studio","de":"Utan denna rem öppnas inte lobbygrindarna. Buren runt halsen, medan du går genom korridoren steg för steg, kommer världen du fram till igår bara sett på skärmen sakta så nära att den nästan går att röra vid."},"ICON-0367":{"nm":"Studioskoöverdrag","de":"Studiogolvet är alltid kallt och halt. Ta av skorna, ta på tunna skoöverdrag, och fotstegen försvinner stilla. Kameran fångar dansen, inte fotstegen, så att sudda ut ljudet är också en artighet mot scenen."},"ICON-0368":{"nm":"Logesnackslapp","de":"Mellan repetition och direktsändning kommer hungern mest ärligt av allt. En liten namnlapp på varje mellanmål i logen som säger vems det är. Den omtänksamheten att lägga undan något är det som bär en genom den långa, långa dagen ända till slutet."},"ICON-0369":{"nm":"Granskningsband","de":"Du spelar upp inspelningen och skriver. En blick här, en halv takt där. Den tätskrivna handstilen är ett hemligt brev till morgondagens jag. Bandet fäst i slutet är ett stilla löfte om att bli ett handbredd bättre än igår."},"ICON-0370":{"nm":"Showcase-inbjudningslapp","de":"Ett enda pappersark kan för någon bli ett helt års väntan. En kort rad som bjuder in till en showcase, född som världens minsta inbjudan, som bär till och med darrningen i fingertopparna som öppnar kuvertet."},"ICON-0371":{"nm":"Pressnyckelband","de":"Hängande runt en reporters hals väver den sig genom hjärtat av slutarklickens sorl. Fotsteg som skyndar för att hitta bästa vinkeln, och just den farten blir passagen som för scenens hetta ut till den vidare världen."},"ICON-0372":{"nm":"Avslutningsordning","de":"Så att ingen tappar fattningen ens i stunden applåderna forsar fram, skrivs vem som är först och vem som är näst ner i en enda rad. Den sista hälsningens uppställning läggs upp lika omsorgsfullt som det första intåget."},"ICON-0373":{"nm":"Golvmarkering för fotovägg","de":"Framför fotoväggen är platsen för tårna inristad i förväg på golvet. Kliver du bara ett steg fel klipps bakgrundens logotyp av. Hemligheten bakom platsen som fångas allra ljusast är stilla markerad under fötterna."},"ICON-0374":{"nm":"Premiärarmband","de":"Ett litet band fäst runt handleden precis innan biosalongens ljus slocknar. När ridån går upp möter alla samma scen för allra första gången i samma mörker. Ett litet märke för att ha varit där i det första ögonblicket."},"ICON-0375":{"nm":"Minnesridåbit","de":"På sista föreställningens kväll sänktes ridån sakta efter den sista bugningen. En bit klippt ur den och inramad. I tyget dröjer ljusens hetta och applådernas dallring kvar ljummet, ännu inte svalnat."},"ICON-0376":{"nm":"Debutstämpel","de":"En stämpel graverad för den enda gången du visar dig för världen först. Det finns ingen andra första gång, så till och med den korta stunden bläcket torkar är en tid som aldrig kommer tillbaka."},"ICON-0377":{"nm":"Scenögonblickskort","de":"Den mest strålande enda bilden från en scen, urklippt och fäst på ett kort. Musiken och ljuset har tystnat, men i samma stund det ligger i din hand sväller den dagens jubel igen vid dina öron. En liten magi där en stillastående scen väcks till liv."},"ICON-0378":{"nm":"Avslutningsposeanteckning","de":"En anteckning som ritar upp vinkeln på fingertoppar och blick som måste frysa i samma stund den sista tonen tystnar. Bara den som vet att en enda avslutande bild kan avgöra dagar viker denna lilla teckning med omsorg."},"ICON-0379":{"nm":"Turnéstadsnål","de":"På kartan trycks en nål ner i varje stad du besökt. Busans havsbris och Gwangjus middagshetta sitter båda fästa på dessa små nålspetsar. Förbind prickarna stilla, och du ser den långa linjen av en resa som korsat en hel årstid."},"ICON-0380":{"nm":"Sittsektionsklämma","de":"Den delar tiotusentals sittplatser i sektioner och visar vägen. Så att ingen går vilse, så att ingen krockar med någon annan. Följ mig, och vem som helst når sin plats. Ordning är, i slutänden, en liten vänlighet för allas skull."},"ICON-0381":{"nm":"Ingångsgrindmärke","de":"Vid grinden passerar en person i taget en kontroll i sin tur. Den sista porten som släpper in en biljettklämmande hand och ett bultande hjärta. I samma stund du passerar mig tar den långa väntan slut och dagens föreställning börjar."},"ICON-0382":{"nm":"Armbandsminneskapsel","de":"Fastän färgen bleknar förblir den dagens vrål förseglat precis som det var. Utan att kunna få sig att kasta bandet från handleden rullar man in det varsamt i en liten kapsel. För att även ett dyrbart minne förtjänar en liten plats att lägga sig ner i."},"ICON-0383":{"nm":"Kontaktstång","de":"Mellan fan och scen förs något över, från hand till hand. Det kan vara ett brev, det kan vara en liten gåva. Jag banar väg för att den känslan ska nå fram tryggt, den mest upptagna bron på platsen."},"ICON-0384":{"nm":"Föreställningsdatumsigill","de":"Den dagens datum präglas fast inuti en rund sigill och stannar för evigt. Kalendern bläddrar vidare, men bara denna lilla cirkel stannar kvar i just den dagen. När det är en dag man inte vill glömma, förseglar människor alltid något."},"ICON-0385":{"nm":"Turnéväskemärke","de":"En väska som följt med på turné får ett märke till för varje stad. Ortnamnen sydda på tyget blir så småningom ett cv. Även de nötta, fransiga hörnen finns kvar som bevis på att ha rest överallt tillsammans."},"ICON-0386":{"nm":"Biljettskyltsnöre","de":"En skylt som svajar i slutet av entrékön, dess ände hårt knuten med ett enda snöre. Mitt i synen av händer som håller biljetter högt sträckta i en lång rad markerar jag stilla huvudet på en procession där förväntan står på led."},"ICON-0387":{"nm":"Extranummerets bandbit","de":"Den kvällen då rösten som ropade på extranummer var som högst föll en bit av bandet som prydde scenen. Som en sång sjungen längre för att det var synd att den skulle ta slut, bär även denna bit en knuten motvilja att gå."},"ICON-0388":{"nm":"Flaskpost","de":"Ett enda ord vikt fint och lagt inuti en glasflaska. Som en liten båt sjösatt i hopp om att en dag nå fram, bär jag ett hjärta och driver sakta genom tiden. Fram till den dag den öppnas sover löftet stilla därinne."},"ICON-0389":{"nm":"Liten bekännelselapp","de":"Ord man inte fick sig att säga högt, nedskrivna på en liten lapp och stilla instuckna. Handstilen darrade, men bara uppriktigheten var tydlig. Ibland bär det minsta papperet det största modet."},"ICON-0390":{"nm":"Anonym hejalåda","de":"Även utan att skriva ett namn når hjärtat fram. För varje lapp som kommer in i lådan samlas någons hejarop, en i taget, anonymt. En samling av ansiktslös ömhet, där bara värmen är tydlig fastän man inte vet vem som skrev."},"ICON-0391":{"nm":"Önskevikpapper","de":"Ett fyrkantigt papper blir en trana, blir en stjärna, i takt med fingertopparna. För varje vikning läggs även önskan ett skikt till. I en omsorgsfullt vikt form bor en uppriktighet som varar längre än ord."},"ICON-0392":{"nm":"Förseglingsvax","de":"Droppa vaxet och tryck stämpeln stadigt ner, och brevet är äntligen förseglat. Precis på det gamla sättet att stärka ett hjärta. Ovanpå det svalnande röda vaxet låses en hemlighet stilla in."},"ICON-0393":{"nm":"Presentskyddspapper","de":"Av rädsla för att gåvan ska ta skada sveper det mjukt runt hela dess omkrets. I varje skrynklad veck genomsyras en bön om att inte gå sönder. Ett skikt av försiktig omsorg på ett osynligt ställe som mottagaren troligen aldrig lägger märke till."},"ICON-0394":{"nm":"Färgat brevsnöre","de":"Även snöret som binder ett brev har en färg. Gult för hejarop, blått för längtan. Känslor ord inte helt räcker till väljs i nyans och knyts fast. Innan man ens hinner lösa upp det når hjärtats temperatur fingertopparna först."},"ICON-0395":{"nm":"Textdoljeband","de":"Ett enda band som döljer handstilen fram till precis den stund det lämnas över. Det vaktar en bekännelse ängslig över att bli avslöjad ända fram till sista sekunden. Uppriktigheten som avslöjas när man lyfter det en aning, den darrningens tyngd känner jag närmast av alla."},"ICON-0396":{"nm":"Hejafrasbricka","de":"En natt då ljusstavarna böljar är en enda fras att ropa i en enda röst inristad inuti brickan. Löftesord som samlar spridda hjärtan i en enda rad. När alla sjunger den tillsammans lyser den frasen som allra starkast."},"ICON-0397":{"nm":"Sliten övningsrumsnyckelring","de":"En nyckelring som öppnat och stängt övningsrummets dörr hundratals gånger. Färgen har flagnat och ringen har blivit lös, men i den finns svetten från de mest klumpiga åren kvar som handnött patina. Att vara sliten betyder att ha stannat just så länge."},"ICON-0398":{"nm":"Scensminksbit","de":"Scensmink blir bara fullständig under strålkastarna. En bit av den djupa färgen. I spåret som pressats fast stadigt så att det inte flyter ut med svetten, dröjer omsorgen om att bära ett uttryck ända till de bortersta sittraderna."},"ICON-0399":{"nm":"Öronproppsfodral","de":"De små öronpropparna som lät dig höra din egen röst uppe på scenen. När föreställningen tar slut lägger du dem varsamt ner i fodralet. Ju närmare något burit musiken fram till dig, desto mer omsorgsfullt vill man bevara det."},"ICON-0400":{"nm":"Personligt skåpmärke","de":"Längst ner i boendets korridor, en namnlapp på varje skåp. Liten text som talar om vems plats det är förvandlar ett främmande rum till ett hem. Att få sitt eget fack är ett ömt tillstånd att stanna här."},"ICON-0401":{"nm":"Halsvårdsflaska","de":"Mellan repetitionerna sväljer man långsamt en klunk ljummet vatten. Halsen är ett instrument sångaren bara lånar, så den här lilla flaskan, fylld innan vattnet svalnar, vakar i förväg över morgondagens första ton. En öm omtanke är alltid så tyst."},"ICON-0402":{"nm":"Schemapåminnelsenål","de":"Över en dag fullpackad minut för minut pekar en nål mot nästa ruta. Bland de täta raderna är det tomma facket det mest efterlängtade. Där gömmer sig, helt litet, den stund då man får se ut genom fönstret."},"ICON-0403":{"nm":"Filtklämma för loge","de":"En eftermiddag man slumrade till mot en stol med sminket redan klart, drapade någon varsamt en filt över axlarna. Den här klämman, som bet fast den så att den inte skulle glida av, håller stilla kvar den beröringens värme ända tills det är dags att gå upp på scenen."},"ICON-0404":{"nm":"Litet parfymprov","de":"Dabbar man det lätt på insidan av handleden blommar doften bara inom en handsbredd. Det gör inget om den inte når långt. Ett spår som bara den som kommit nära märker, desto hemligare, och därför desto mer jag själv."},"ICON-0405":{"nm":"Tvättlapp för träningskläder","de":"Hur många gånger man än tvättar den försvinner aldrig helt svettlukten som trängt djupt in i tyget. Medan man viker ihop de i solen upphängda, mjukt torkade träningskläderna tänker man - att det där märket som inte går bort faktiskt är det ärligaste spåret."},"ICON-0406":{"nm":"Ljusgelfilm","de":"Sätter man i ett tunt färgat filter blöder det vita ljuset ut i solnedgångsfärg, lägger man i ett till sänker sig gryningen. Bakom draperiet håller en hand andan, klär till och med ljuset i kläder, väljer vilken årstid scenen ska färgas i."},"ICON-0407":{"nm":"Objektivskydd för strålkastare","de":"Även när kameran är avstängd öppnar någon det här lilla locket för att rengöra linsen. För nästa scen som ännu inte filmats. Över den tid som aldrig fångas på bild ställer den mest upptagna handen i förväg in skärpan."},"ICON-0408":{"nm":"Reflexskärm för scen","de":"Det finns en skiva som, utan att själv lysa, skickar tillbaka det mottagna ljuset mot ett skuggat ansikte. Att mitten av scenen lyser så starkt beror på att någons arm i kanten tyst håller vinkeln och kastar tillbaka ljuset."},"ICON-0409":{"nm":"Färgfilterhylsa","de":"Skjuter man in blått ljus i den genomskinliga hylsan blir hela salongen ett hav, byter man till rött faller en solnedgång över samma plats. Magin i att samma scen blir en annan årstid med bara en färg börjar i detta tunna, enda skikt."},"ICON-0410":{"nm":"Ljusnummernål","de":"Varje lampa bland de många har ett litet nummer. Vilken som tänds och vilken som slumrar, kvällens föreställning är i förväg planerad efter dessa siffrors ordning. Bakom en bländande ridå ligger alltid en noggrann lista uppslagen."},"ICON-0411":{"nm":"Ljusande markeringstejp","de":"På det mörklagda scengolvet lyser fosforescerande tejp tyst upp platsen där foten ska stanna. Osynlig från salongen, men artistens tå famlar efter det svaga skenet för att hitta sin plats. Även i mörkret finns en öm vägvisare."},"ICON-0412":{"nm":"Skuggblockeringsskärm","de":"En skärm som stoppar läckande ljus så att en skugga faller skarpt avtecknad. Att hantera mörker är, i grunden, att hantera ljus, så vad som ska visas avgörs först av vad som stilla ska döljas."},"ICON-0413":{"nm":"Ljusstyrkemätarchip","de":"Ett litet chip som mäter rummets ljusstyrka läser av siffror i handflatan. För både för starkt och för svagt ljus gör ögonen illa till mods. Den osynliga, rätta balanspunkten där en människa trivs som bäst vakar det här chipet tyst över."},"ICON-0414":{"nm":"Skärm för punktbelysning","de":"En avskärmning som fästs så att en punktbelysning inte läcker dit den inte ska. Att samla ljuset kring bara en enda person är en öm sorts fokusering. I samma stund man kliver in i den runda ljuscirkeln ser hela världen, för en stund, bara på en."},"ICON-0415":{"nm":"Öronproppar","de":"Ett par öronproppar som sluter tätt om örat. Är storleken det minsta fel läcker ljudet, och i samma ögonblick det läcker tappar man takten. En sång utan minsta darrning på scenen börjar ibland faktiskt i denna lilla bit gummi."},"ICON-0416":{"nm":"Kardborreband för kablar","de":"Ett kardborreband som samlar trassliga sladdar i ett prydligt knippe. Ju mindre någon ser bakom scenen, desto mer lyser ordningen. Att en kabelbunt hålls så snygg bär tyst upp ljudet som strömmar obrutet fram på scenen."},"ICON-0417":{"nm":"Linjekontrolletikett","de":"Namnlappar handskrivna på dussintals sladdar som talar om vilket instrument som är vilket. Bara när varje krokig bokstav i den där handstilen håller sin plats flyter de spridda ljuden till slut samman i en enda låt."},"ICON-0418":{"nm":"Tystnadsmatta","de":"En enda tystnadsmatta som stilla sväljer både fotsteg och darrningar. Den läggs där stillheten verkligen behövs. Det klaraste ljudet föds ibland först på detta tysta golv där inget oljud alls läcker ut."},"ICON-0419":{"nm":"Soundcheck-bricka","de":"En bricka som blir varm i handen medan ljudet stäms av före föreställningen. Varje gång en mikrofon, en högtalare kontrollerats byter den grepp till en ny plats. Huvudscenens fulländning formas steg för steg i denna tysta repetition."},"ICON-0420":{"nm":"Mikrofonskyddshuv","de":"Eftersom det är platsen så många röster har rört vid rengör man extra noga huven som omsluter mikrofonens spets. Den är ett kärl som bär en sång, alltså på sätt och vis sångarens andra hand. Medan man torkar den ritar man i tankarna morgondagens första vers."},"ICON-0421":{"nm":"Popfilterklämma","de":"Ett tunt nät som hänger mellan läpparna och mikrofonen. Tack vare den lilla klämman som håller nätet på plats mjukas andetag som läckt rått snart om till en rund, mjuk röst som strömmar fram."},"ICON-0422":{"nm":"Ljudrackmärkning","de":"En liten etikett hängd för att inte gå vilse bland hyllor av staplad utrustning bakom den mörka scenen. Källan till det bländande ljud som fyller salongen ligger alltid prydligt ordnad, lager på lager, på just sådana dunkla platser."},"ICON-0423":{"nm":"Högtalargallernål","de":"En nål som håller högtalarnätet fast förankrat. Fönstret där ljudet lämnar är det första som möter damm, så ett tunt lager nät skyddar tonen. Allt som når örat bär ett osynligt lager av beskydd."},"ICON-0424":{"nm":"Stegmarkeringsklistermärke","de":"Klistermärken för koreografin, prickade fast på golvet en punkt i taget. Hemligheten bakom en gruppdans som klaffar som ett svärd döljer sig faktiskt under fötterna. Ovanpå otaliga överenskomna märken där dussintals kliver på samma prick, sprids och samlas åter."},"ICON-0425":{"nm":"Övningsskiva för piruetter","de":"En övningsskiva som snurrar runt, runt på stället. För att övervinna yrseln lär man sig först att fästa blicken på en enda punkt. Hur snabbt man än snurrar släpper man aldrig den punkten - balansen ristas långsamt in i kroppen."},"ICON-0426":{"nm":"Knätejprulle","de":"En rulle tejp som lindas stramt om knät. Leder som hoppat och landat tusentals gånger förblir till sist tysta, men detta enda lager bär stilla upp den tystnaden. Bakom en kropp som håller ut till slutet finns alltid någons omsorg."},"ICON-0427":{"nm":"Tåriktningsplatta","de":"En platta som prydligt ställer in tårnas vinkel. Man säger ju att dansen fullbordas i tårna snarare än i fingertopparna. Dussintals tår sträckta åt samma håll samlas och väver fram magin där många ser ut som en enda."},"ICON-0428":{"nm":"Halkskyddsmatta för replokal","de":"En halkskyddsmatta lagd på replokalens golv. För att våga hoppa fritt måste man först vara trygg. Bara på ett golv där man kan rulla utan att frukta att falla blommar till slut de djärvaste, mest orädda rörelserna ut."},"ICON-0429":{"nm":"Rörelseanalyskort","de":"Ett kort som bryter ner koreografin i små bitar, ett taktslag i taget. Hur svår en rörelse än är, delar man upp den ruta för ruta hittar man snart takten att följa. Det vattenmjuka flödet på scenen är byggt av just sådana uppdelade, utantillärda bilder sammanfogade."},"ICON-0430":{"nm":"Nål för spegeldraperi","de":"En nål som håller uppe draperiet som en stund täcker replokalens spegel. Även tid att dansa enbart genom kroppens känsla, utan spegelbild, behövs ibland. I samma stund spegeln täcks vet man att musiken äntligen tränger ända in i huden."},"ICON-0431":{"nm":"Taktmätarpärlor","de":"Klick, man skjuter fram en pärla i taget med fingertoppen för varje taktslag och räknar. Handgripligt, som en gammal räknemetod. Takten, musikens ryggrad, sätter sig verkligen fast i kroppen först när den lärs in genom något så påtagligt som detta."},"ICON-0432":{"nm":"Uppvärmningsband","de":"Ett kontrollband som visar om man värmt upp helt. Före den egentliga träningen kommer alltid en lugn förberedelse först. Hellre än att ångra sig efter en skada väcker man kroppen sakta genom att knyta ett band - i längden dansar man då längre."},"ICON-0433":{"nm":"Kostymnummerklämma","de":"En klämma som biter fast ett nummer på varje dräkt så att de många inte blandas ihop. I ett andlöst snabbombyte är det en katastrof om ens en enda dräkt förväxlas, så varje plagg har sin tur tydligt märkt. Även jäkt blir elegant när ordning bär upp det."},"ICON-0434":{"nm":"Nåldyna i syrummet","de":"En nåldyna som står i ett hörn av syrummet. Här dröjer den hand som tyst lagat sprickna sömmar och lösa knappar. Bakom den oklanderliga passformen på scenen döljer sig omsorgen hos stygn som aldrig en enda gång sett scenen."},"ICON-0435":{"nm":"Tygbitsring","de":"En ring som trär samman extra tygbitar till en enhet. Samma tyg sparas i förväg för det fall huvuddräkten skulle skadas. Denna lilla förberedelse, sparad i hopp om att inget ska hända, räddar just i den stund något stort inträffar scendräkten."},"ICON-0436":{"nm":"Snabbknappspaket","de":"Ett paket knappar man genast kan sy fast i en nödsituation. Ramlar en knapp av strax före föreställningen far en våg av oro genom hela loget. En liten men ovärderligt pålitlig förbandslåda som på ett ögonblick lugnar den korta, svindlande krisen."},"ICON-0437":{"nm":"Scenbälteshållare","de":"En hållare som håller scendräktens bälte stadigt på plats. Så att kläderna inte far ur led hur hårt man än hoppar och snurrar. Den frihet man fullt ut njuter av på scenen kommer, i grunden, från det som osynligt knutits stramt fast bakom kulisserna."},"ICON-0438":{"nm":"Fjäderdammvippa","de":"Eftersom även en enda liten luddtuss syns under strålkastarna sopar man mjukt över dräkten med en fjäderdammvippa. Precis innan man sätter foten på scenen är det alltid denna mjuka fjäder som ger klädernas sista, ömma justering."},"ICON-0439":{"nm":"Logetofflemärke","de":"En namnlapp på varje par tofflor i loget. I en liten lapp som anger vems den är ligger tyst tryggheten i att vi hör till samma lag. Rummet där man tar av skorna och sträcker ut fötterna blir den skönaste hemvisten bakom scenen."},"ICON-0440":{"nm":"Håluppsättningsklämmor","de":"En klämplatta som håller sektioner på plats medan håret läggs. Medan man slätar ut sträng för sträng anförtror fingrarna en stund det hår som vill spreta åt den här klämman. Prydlighet är, till syvende och sist, byggd av just sådana små pauser i samlad form."},"ICON-0441":{"nm":"Säkerhetsnålskapsel","de":"En gryning då en söm sprack, öppnar man kapsellocket och där ligger små, kalla silverglimtar prydligt i rad. En hand som från det osynliga innanmätet håller dräkten hårdast fast - säkerhetsnålen arbetar alltid tyst bakom scenen."},"ICON-0442":{"nm":"Linsputsduk","de":"Puh, en enda andedräkt och en cirkelrörelse - och den disiga världen klarnar. Man torkar linsen om och om igen bara för att den korta stunden känns så bra. En liten fläck vårsol som klarar upp någon annans syn i dennes ställe."},"ICON-0443":{"nm":"Gummifötter för stativ","de":"Sätter man gummi på de tre spetsarna slutar golvet skrika. Medan de små punkterna sväljer varje skakning blir bilden på skärmen stilla som genom en lögn. Stabilitet börjar alltid tyst nertill, vid fötterna."},"ICON-0444":{"nm":"Regnskydd för kamera","de":"Även när regndropparna rinner ner fångar linsen världen torr. En molnig eftermiddag under utomhusinspelning kläs kameran varsamt i en genomskinlig regnrock. Det dyrbara ska först svepas in, innan det hinner bli blött."},"ICON-0445":{"nm":"Filmmarkeringstejp","de":"Stå här, vänd dit - korta märken i olika färger pekar tyst, men tydligt, ut vägen. Även om de rivs bort utan saknad när scenen är över minns de fötter som vant sig vid dem den platsen länge, länge efteråt."},"ICON-0446":{"nm":"Klippdelningsklämma","de":"En liten klämma som biter tag i ark som håller på att spridas åt alla håll. Med ett enda friskt klick binds igår och idag prydligt samman. Att skapa ordning är en öm handvana - att stilla hålla fast det som nästan gått förlorat."},"ICON-0447":{"nm":"Vitbalansplatta","de":"Håller man upp en vit skiva mot bilden hittar färgerna sakta tillbaka till sin plats. Både den gula solnedgången och den blå gryningen, utan lögn. En enda platta som känner det sanna vita får resten av färgerna att tala ärligt."},"ICON-0448":{"nm":"Minneskortsburk","de":"Inne i en liten plåtburk sover minneskort i lugn ro. Öppnar man locket med ett klick forsar förra säsongens scener ut i handflatan. Minnet vilar så här, ömt förvarat i en enda stadig burk."},"ICON-0449":{"nm":"Monitorhuv","de":"Sätter man en svart skärm runt monitorn upphör reflexerna på fläcken. Även vid ett solöversköljt fönster tappar bilden aldrig sin färg. För att se väl måste man först skärma av det främmande ljuset, viskar huven stilla."},"ICON-0450":{"nm":"Ljudisoleringsnål","de":"En liten nål kilad i dörrspringan klipper tyst av allt oljud utifrån. Varken steg i korridoren eller skratt från rummet bredvid når hit. För att fånga ett rent ljud måste man nämligen först bygga upp tystnad."},"ICON-0451":{"nm":"Sminksvampspaket","de":"Ett prydligt buntat lager mjuka, fylliga svampar. Knackar man lätt med fingertopparna dyfts pudret på och ansiktet ljusnar en nyans. Bakom varje strålande leende på scenen döljer sig alltid dessa mjuka, små beröringar."},"ICON-0452":{"nm":"Hårnålsetui","de":"Ett prydligt hem för de små nålar som så lätt kommer bort. Öppnar man locket ställer sig silverglimmande rader upp och hälsar. Spridda syns de inte, samlade ger de trygghet - även de allra minsta tingen behöver ett eget hem."},"ICON-0453":{"nm":"UV-steriliseringsbox för penslar","de":"Penslar som burit färg hela dagen tar en UV-dusch inne i boxen. Medan det osynliga ljuset sköljer bort det gamla blir morgondagens borst mjuka som nya igen. Renlighet är också en fåra i omsorgen."},"ICON-0454":{"nm":"Nätpåse för puderdoppor","de":"Runda doppor hämtar andan stilla inne i nätpåsen. När luften strömmar fram och tillbaka genom nätet håller mjukheten längre. En väl torkad doppa bär redan i förväg på morgondagens lyster."},"ICON-0455":{"nm":"Sprayhätta för hårspray","de":"Psch, en enda spruta och inte ett strå rubbas i vinden. En liten hätta som håller den omsorgsfullt lagda frisyren genom hela natten. Över det stadigt fixerade håret forsar det klara ljuset ner som om det brast i bitar."},"ICON-0456":{"nm":"Läppenselfodral","de":"Ett litet lock som varsamt sveper om den smala penselspetsen. Skakas den runt hur mycket som helst i väskan hålls penseln ändå rak och ren. Omsorgen om en enda liten pensel fullbordar ett enda penseldrag färg på läpparna."},"ICON-0457":{"nm":"Nummerlappsspegel","de":"En liten spegel sitter tyst fäst intill numret som ropar upp ens tur. Precis innan man går upp på scenen, platsen för den sista justeringen av en yvig lock. Även nervositet blir lite lättare av en enda blick i spegeln."},"ICON-0458":{"nm":"Handledsband","de":"Ett mjukt band som med en enda svepning över pannan torkar bort svetten. Ju häftigare koreografin blir, desto oftare söker sig handen dit. En liten tröst på handleden, som håller sig nära genom varje andfådd stund."},"ICON-0459":{"nm":"Rekvisitaväskemärke","de":"Även om tio likadana väskor står på rad i loget blir det aldrig förväxlingar. Varje väska har ett namnband som tydligt talar om vems den är. Att skriva 'min' på något är ett litet men ömt märke."},"ICON-0460":{"nm":"Bokningsnål för replokal","de":"Vem ska använda den här replokalen idag? En liten nål fäst på tavlan vid dörren delar tyst upp tiden. Hjärtan som väntar på sin tur ställer sig stilla på kö bakom denna enda nål."},"ICON-0461":{"nm":"Skyddsring för väggklocka","de":"Ett genomskinligt skydd sänker sig varsamt över väggklockan och håller dammet borta. De tickande visarna grumlas aldrig och tiden rinner klart förbi. Det dyrbara behöver alltid ett osynligt lager beskydd."},"ICON-0462":{"nm":"Golvskyddsdyna","de":"En tunn dyna fäst under stolsbenet förhindrar i förväg skador på trägolvet. Släpas den repas inget, flyttas den lämnas inte ett enda märke. Att osynligt värna om golvet - det är hemligheten bakom att det håller länge."},"ICON-0463":{"nm":"Skylt: inga drycker","de":"Ställ undan drycken en stund här, ber det lilla chipet vänligt. Både noter och utrustning far illa av att bli blöta. Även ett ord som 'förbjudet' blir plötsligt en varm omtanke när det framförs så här."},"ICON-0464":{"nm":"Ventilationsknappsetikett","de":"Vill man byta ut den kvava luften, tryck här, visar vägen en liten etikett bredvid knappen. Att kunna andas ut igen börjar förvånansvärt ofta tyst, i en så obetydlig markering som denna."},"ICON-0465":{"nm":"Gummifot för högtalare","de":"En gummifot under högtalaren sväljer stilla det dova skallret. När basen inte längre sprider sig genom golvet blir ljudet betydligt klarare. Ett gott ljud klarnar först ovanpå ett stadigt fäste."},"ICON-0466":{"nm":"Skåpnummermagnet","de":"En liten sifferammagnet som klickar fast på skåpdörren. I vilket fack ska mina saker sova ikväll? Även om platsen byts varje dag ger en enda magnet snabbt ett skåp som är mitt. Tillhörighet kommer från ett så lätt märke som detta."},"ICON-0467":{"nm":"Spegelvipptorkare","de":"En enda svepning över spegeln och imman lättar helt. Stunden då mitt suddiga ansikte klarnar till skärpa. För att verkligen se sig själv måste man först stilla torka bort det som grumlar blicken."},"ICON-0468":{"nm":"Dörrdämpare","de":"Ett fluffigt stötdämpande material kilat in i dörrspringan mot den som slår igen hårt. Både smällen och en klämd hand fångas mjukt upp. En liten säkerhet som smyger in ett lager ömhet mitt bland de hårda krockarna."},"ICON-0469":{"nm":"Kabelskyddsblock","de":"Ett stadigt skydd bygger säkert en bro över kablarna som korsar golvet. Ingen fot snubblar, ingen sladd trampas på. Ett blocks tysta ståndaktighet - vaktar vägen utan att spärra den."},"ICON-0470":{"nm":"Varningskon för halt golv","de":"En gul kon står ensam på det våta golvet och varnar i det tysta. Var försiktig, trampa sakta. Bakom den ljusa scenen står en sådan liten väktare, tyst vakande över varje steg."},"ICON-0471":{"nm":"Nödljusstav","de":"En ensam ljusstråle tänds i den strömlösa korridoren. Så att man inte ska gå vilse ens i mörkret läggs nödskenet i handen. Det finns onekligen ting i världen som lyser starkast just i det mörkaste ögonblicket."},"ICON-0472":{"nm":"Räckesskydd","de":"En rundad hätta över trappräckets ände sveper mjukt om det kantiga hörnet. Även en oaktsam beröring med handen gör då aldrig illa. Att tyst täcka över det skarpa är också en form av omtanke om någon annan."},"ICON-0473":{"nm":"Kudde för scenkant","de":"En mjuk kudde omsluter scenens ytterkant. Så att en tå som nuddar den under en häftig koreografi inte blir blå. Bakom varje strålande rörelse dansar ett osynligt beskydd med."},"ICON-0474":{"nm":"Golvmarkeringsskiva","de":"En rund skiva på golvet säger tyst: 'Stå här.' Både den som köar och den som söker sin plats stannar stilla vid denna enda punkt. Ordning växer ur en liten markering."},"ICON-0475":{"nm":"Ficklampsrem","de":"Snurrar man remen i änden av ficklampan ett varv om handleden tappar man aldrig ljuset, inte ens i mörkret. Utan oro för att tappa den blir båda händerna fria - ett litet men pålitligt varv."},"ICON-0476":{"nm":"Avspärrningslina","de":"Kom inte längre än hit, ber ett enda rep vänligt genom att dra en linje. En mild gräns som stilla skiljer det farliga från det trygga. Att spärra av är också ett sätt att skydda någon."},"ICON-0477":{"nm":"Säkerhetskontrollnål","de":"Vid varje plats besiktningen godkänt lämnar en liten nål sitt 'kontrollerat'. En enda punkt, som ett sinnets sigill över en blick som inte missat något. Säkerhet är inget storslaget - det är summan av spår lämnade punkt för punkt så här."},"ICON-0478":{"nm":"Miniklappa","de":"Vid det knappa smällen som klipper av det första taktslaget finner alla på plats sin andning i samma ögonblick. Liten som den är, är varje scens startlinje alltid detta enda slag. Inspelningens spännande början öppnar sig just här."},"ICON-0479":{"nm":"Mikrofonskydd för bordsmikrofon","de":"Ett mjukt skydd glider varsamt över mikrofonen på bordet. Även ett skarpt andetag som brister fram förmedlas fint, utan brus. Det som mest ömt sveper om en röst är just detta lilla, mjuka lager."},"ICON-0480":{"nm":"Ljudabsorberande panelbit","de":"En bit ljudabsorberande panel i väggen samlar tyst upp ekot. När ljudet inte längre studsar och sprids samlas sången betydligt klarare. Ett gott ljud börjar med att omsorgsfullt förfina tystnaden."},"ICON-0481":{"nm":"Hörlurskrokshylsa","de":"Att hänga upp hörlurarna här är ett litet löfte. Reda ut sladden och lägg den prydligt, så att nästa person genast kan ta dem och gå. En enda krok för in tyst ordning i en hektisk bås."},"ICON-0482":{"nm":"Inspelningslampa","de":"I samma stund den röda lampan tänds stannar all andning inne i båset. En signal som stoppar till och med stegen bortom dörren. Att fånga ljud börjar med att bevara denna djupa tystnad."},"ICON-0483":{"nm":"Plektrumhållare","de":"Plektrum uppradade i fack efter färg. Tjocklek och vikt formar fingertopparnas vanor. Precis före scenen växer den precisionen - att kunna gripa rätt en på ett ögonblick, utan att ens titta - fram just här."},"ICON-0484":{"nm":"Kabeletikettskrivare","de":"För att inte gå vilse bland dussintals hoptrasslade sladdar på golvet måste man skriva ett namn i vardera änden. Bara den som antecknat varifrån och vart handen inte famlar ens i mörkret."},"ICON-0485":{"nm":"Miniatyrmixerratt","de":"Vrider man den ett fingers bredd förändras röstens klangfärg. Höjs den blir den skarp, sänks den drunknar den - man famlar efter just den punkten däremellan. Den finaste beröringen ger den största förändringen."},"ICON-0486":{"nm":"Låsbricka för stativ","de":"Det som bär upp scenen är inte den bländande belysningen utan denna lilla ring. Den håller stadigt fast skakningarna och står ut tyst på sin post, osedd av alla."},"ICON-0487":{"nm":"Nedmonteringsetikett","de":"Även att varsamt lägga ner allt som byggts upp följer en tydlig ordning. Ett enda blad som anger var man ska lossa och vart man ska flytta. Händerna som river ner är lika säkra som händerna som byggde."},"ICON-0488":{"nm":"Hittegodskuvertmärke","de":"Varje efterlämnat föremål bär på sin egen historia. Att lägga det i ett litet kuvert och vänta på ägarens namn är en ömhet som en stund också tar hand om den förlorande personens hjärta."},"ICON-0489":{"nm":"Städrutsmarkering","de":"Följer man pilarna dragna på golvet blir allt städat, utan en enda springa förbisedd. Även en kvast behöver en väg för att inte snurra förgäves. Den mest glänsande platsen ligger vid slutet av de bäst uppritade stegen."},"ICON-0490":{"nm":"Utgångsvisarstav","de":"När det sista handklappet tystnar öppnar denna stav vägen. En hand som sakta för ut hjärtan som fortfarande fladdrar, utan att göra dem illa. Även att visa vägen mot avslutningen bär på en varm omtanke."},"ICON-0491":{"nm":"Tejprestboll","de":"Rullar man ihop resterna som blivit över till en boll får de nytta igen. Precis som en ände som nästan kastats bort samlas till en fast boll, växer en sparsam omtanke ur en liten fingerspets."},"ICON-0492":{"nm":"Stolnummerhylsa","de":"Varje stol i salongen behöver ett nummer så att ingen går vilse. En liten hätta som tilldelar en plats förvandlar en förstagångsbesökares hjärtklappning till lugn lättnad."},"ICON-0493":{"nm":"Sopsorteringsnål","de":"En liten nål som delar upp papper och plast var för sig. Blandat är det bara skräp, sorterat blir det en resurs att använda igen. Att sortera är en öm handling som ger tingen ett andra liv."},"ICON-0494":{"nm":"Utrustningsåterlämningsmärke","de":"Det man lånat måste alltid komma tillbaka till sin plats. Med varje fingertopp som lämnar tillbaka utrustningen märkt, byggs förtroendet upp lager på lager. Den som lämnar tillbaka väl lånar med lätt hjärta nästa gång också."},"ICON-0495":{"nm":"Utcheckningsnyckel för loge","de":"När dagens smink och kostym är avlagt lämnar man till sist tillbaka denna nyckel. Att på vägen ut lägga tillbaka det man tog emot på vägen in. Dagens början och slut vilar i samma hand."},"ICON-0496":{"nm":"Etui för cushionpuff","de":"En mjuk doppa tappar sin struktur om den pressas ihop. Det är därför den läggs ömt till vila i ett runt litet hem. För att bevara mjukheten länge måste man först behandla den mjukt."},"ICON-0497":{"nm":"Ögonskuggschip","de":"En enda färgpunkt lagd på ögonlocket byter ut hela uttrycket. Färgen som slumrar i det lilla chipet vaknar först under strålkastarna och lägger djup i blicken riktad mot scenen."},"ICON-0498":{"nm":"Hätta för rougepensel","de":"Går penselspetsen sönder rasar färgåtergivningen med den. Att sätta på en liten hätta för att skydda dess struktur är den tysta vanan hos någon som vill ha sina goda redskap kvar länge."},"ICON-0499":{"nm":"Smal läppalett","de":"En tjock palett tar upp hela väskan. En hand som vet att en enda tunt tillskuren rad räcker. Stunden då att skala bort blir detsamma som att ta hand om det viktiga."},"ICON-0500":{"nm":"Maskaraskydd","de":"Så att de omsorgsfullt uppsvängda fransarna, en i taget, inte ska tovas ihop, skyddar en liten vaktare varsamt deras kurva. Det man lyft med omsorg måste också vaktas med omsorg, viskar stunden framför spegeln."},"ICON-0501":{"nm":"Topsetui","de":"Ett litet hem som håller de vita topsen samlade, så att de inte sprids åt alla håll. En handrörelse som alltid finns nära till hands för den allra sista justeringen. De små förberedelserna fyller igen sprickorna i en stor scen."},"ICON-0502":{"nm":"Reservgummi till ögonfransböjare","de":"När gummit hårdnar gör det ont och nyper när man lockar fransarna. Att alltid ha reservgummi till hands kommer ur en ömhet som tar hänsyn även till de minsta obehagen."},"ICON-0503":{"nm":"Concealerpensel","de":"En fin penselspets suddar försiktigt bort skuggorna. Den för ljus till platser som ljuset aldrig nått. En hand som tillför ljus istället för att dölja brister avslutar arbetet med långt större finess."},"ICON-0504":{"nm":"Pudersikt","de":"Sikta det fina pudret en gång, och det lägger sig jämnt och fritt från klumpar. Besväret med att sila det ännu en gång. Omsorg visar sig till syvende och sist i fingertoppen som tar ett extra steg."},"ICON-0505":{"nm":"Luggrullklämma","de":"En klämma som rullar luggen rund och håller den ett ögonblick. Medan man väntar sätter sig formen lugnt på plats. Prydlighet blomstrar där man kan vänta utan att stressa."},"ICON-0506":{"nm":"Hårvaxsked","de":"Skopa upp vaxet med den här lilla skeden innan det ens rör vid händerna. Måttfullheten i att ta precis det man behöver. En hand som vet hur man använder utan överflöd skapar den mest naturliga strukturen."},"ICON-0507":{"nm":"Underlägg för locktång","de":"Man kan inte bara ställa ifrån sig en glödhet locktång var som helst. Ett enda underlägg skyddar både skrivbordet och händerna. En plats som hanterar hetta behöver alltid en trygg plats att vila på."},"ICON-0508":{"nm":"Hårolja, provflaska","de":"En droppe räcker för att ge glans, så den ligger prydligt förpackad i en liten provflaska instoppad i ett hörn av väskan. En liten flaska, hellre än en stor, hamnar i handen mycket oftare."},"ICON-0509":{"nm":"Borstrensare","de":"Kamma sakta ut håret som trasslat sig i borsten med rensaren. Att sköta om sina verktyg är en tyst ritual efter att arbetet är gjort. En välskött borste formar morgondagens frisyr på ett vackert sätt."},"ICON-0510":{"nm":"Hårsnodds-spole","de":"Bara lindade runt en spole syns de alla på en gång. Det här lilla paketet, prydligt hoprullat, är en öm bit lättnad skänkt till hektiska morgnar då hårsnoddar annars rullade åt alla håll."},"ICON-0511":{"nm":"Färgningshandskar","de":"Tunna handskar som bärs så att händerna som lägger på färg inte blir fläckiga. En önskan att möta det som kommer härnäst med rena händer, även efter avslutat arbete. Skydd är bara ett annat namn för den sortens beredskap."},"ICON-0512":{"nm":"Hårnätspåse","de":"En liten påse för att prydligt vika ihop och förvara nätet som håller frisyren på plats. Ju mindre volym något har, desto lättare tappas det bort, så en omtänksam hand som ger det ett hem är något att uppskatta."},"ICON-0513":{"nm":"Penna mot flygigt hår","de":"En penna som med lätta tryck lägger tillbaka lösa hårstrån på plats. Den allra sista touchen efter att all den stora stylingen är klar. Avslutningen är alltid ett arbete med att smeka den minsta detaljen."},"ICON-0514":{"nm":"Doftprovlock","de":"När man väljer en doft ska man inte hålla den rakt mot näsan. Droppa den på ett litet lock och låt den sväva genom luften för att avslöja sin sanna karaktär. Även en doft är bara ärlig när den känns på lite avstånd."},"ICON-0515":{"nm":"Rollerdoftflaska","de":"En rund kula rullar fram och ritar doft tvärs över handleden. Till skillnad från de gamla droppflaskorna glider och sprids en enda linje. Doften lämnar en annan historia beroende på hur den vidrör huden."},"ICON-0516":{"nm":"Body mist-lock","de":"Ett litet lock som håller kvar en doft som annars sprids som dimma. Att stänga och bevara det som bara skingras när det öppnas. Ett litet hjärta som sparar lite gör att doften dröjer kvar längre vid din sida."},"ICON-0517":{"nm":"Handkräm-nyckelring","de":"Fäst en ring på den lilla handkrämen, så följer den med överallt. En följeslagare som dinglar och svänger utanpå väskan blir en öm hälsning till torra fingertoppar."},"ICON-0518":{"nm":"Duschpuff-krok","de":"Efter att ha skummat upp ett fradgigt lödder måste den torka ordentligt. Nätbollen som hänger på en krok i badrumshörnet skakar av sig vattnet och väntar på en fräsch morgondag."},"ICON-0519":{"nm":"Massagebollspåse","de":"En liten påse för den fasta bollen som löser upp spända axlar. En kort vila bakom scenen, en stund att tyst lugna en stel kropp. Omsorg börjar alltid med en själv."},"ICON-0520":{"nm":"Kylplåster-burk","de":"En burk som samlar plåster som svalkar när de sätts på. Natten då en het scen tar slut, sover en liten tröst därinne och lugnar sakta en kropp och ett hjärta som blivit varma."},"ICON-0521":{"nm":"Nagelojlepenna","de":"Tryck, gnid, glans. En droppe räcker för torra fingertoppar. Ingen storslagen behandling behövs; en mjuk lyster som sprids från spetsen på en liten penna sveper graciöst över naglarna. Omsorg börjar med en liten droppe som denna."},"ICON-0522":{"nm":"Doftpåseklämma","de":"En liten knut som binder doft till papper. Varje gång lådan öppnas hälsar en svag doft innan handen hinner göra det. En ömhet som dröjer kvar nära fastän osynlig - en enda klämma som tyst bär på en hel dags tröst."},"ICON-0523":{"nm":"Nageltippsbricka","de":"En liten scen där färgerna för alla tio fingrar läggs fram i förväg. Vilken nyans passar idag? En tyst audition öppnar på brickan. Det korta ögonblicket av att välja är på något sätt spännande, och fingertoppens dag börjar här."},"ICON-0524":{"nm":"Nagelbandsputsarlock","de":"Det finns ömhet även i att skjuta tillbaka. En enda nagelbandsflik, försiktigt med den rundade spetsen, aldrig i brådska. En stressad hand missar alltid något, så att ordna är närmare ett sinne som ser i lugn takt."},"ICON-0525":{"nm":"Mini nagelfil","de":"En grov sida och en fin sida, två ansikten i en och samma hand. Att försiktigt fila ner ojämna kanter är en liten sak, men fulländning kommer alltid från sådana små handgrepp. Det sista ordet tillhör till syvende och sist mjukheten."},"ICON-0526":{"nm":"Nagelklistermärkesark","de":"Stjärnor, blommor, hjärtan - välj bara det ark som passar dagens humör och tryck fast det. På ett ark fyllt med små bilder i nagelstorlek glittrar ett enda klistermärke som en öm signatur lämnad på en fingertopp."},"ICON-0527":{"nm":"Skärm till gellampa","de":"En tunn skärm som håller ljuset instängt en stund. Medan det härdar vilar ögonen och bara fingertopparna hårdnar tyst. Även väntan behöver en strimma skugga, och i den ohastiga tiden fulländas dagens fingertoppar."},"ICON-0528":{"nm":"Nagelkonst-tillbehörsburk","de":"Glittrande bitar sover fack efter fack. Strass, pärlor, stjärnstoft - man lyfter locket med samma spänning som att öppna ett omärkt smyckeskrin. Vilket ljus ska läggas på naglarna? Det ögonblicket av att välja glittrar mest."},"ICON-0529":{"nm":"Handvårdshandskar","de":"En kort semester som händerna tar medan man sover. Inuti handskarna blir torr hud sakta fuktig under natten. Omsorg är till syvende och sist något som sker osett, och på morgonen är fingertopparna de första att känna den ömheten."},"ICON-0530":{"nm":"Removerpumpflaska","de":"Ett enda tryck, precis lagom mycket. En sval doft dras in i bomullen och sveper i gårdagen ren från naglarna. Det finns en rytm även i att tömma, och en enda pumpning röjer tyst plats för att måla på nytt."},"ICON-0531":{"nm":"Strasspincett","de":"För att plocka upp en sten finare än en fingertopp behövs en ännu finare hand. Pincettens spets flyttar en enda punkt utan att darra - finkänslighet är lika mycket verktygets sak som hjärtats. Ett litet ljus finner sin plats."},"ICON-0532":{"nm":"Örhängesbricka","de":"Så att ett enda örhänge aldrig mer försvinner i en låda. Sätt varje par på sin plats, och morgonens stressiga val blir lättare. Att ordna är en liten vänlighet man skänker sitt framtida jag."},"ICON-0533":{"nm":"Ringstorleksmätare","de":"Ett litet knippe ringar som förvandlar fingrets omkrets till en siffra. Att prova storlek efter storlek liknar att sakta lära känna vad som passar en precis rätt. Som den lättnaden när något sitter perfekt."},"ICON-0534":{"nm":"Klockarmbandsstift","de":"När klockarmbandet lossnar fäster det här lilla stiftet tiden tillbaka på handleden. Den djupast gömda delen håller längst - något en länge buren klocka vet i tysthet."},"ICON-0535":{"nm":"Halsbandsbricka mot trassel","de":"Fack indelade så att tunna kedjor inte kan trassla in sig i varandra. En trasselfri morgon börjar med de små avdelarna som separerades kvällen innan. Lätthet är till syvende och sist ett sinne som ordnats innan handen ens når fram."},"ICON-0536":{"nm":"Broschlås","de":"Ju mer bländande framsidan är, desto tystare är baksidan. Ett litet lås som stadigt stöttar broschen fäst i tyget; bakom varje synlig glans finns alltid en namnlös hand som håller emot. En plats som är desto pålitligare för att den förblir osedd."},"ICON-0537":{"nm":"Solglasögonfodral","de":"Ett mjukt tyg sveper varsamt runt glasen som stängde ute sommarens ljus. Ett litet fodral som skyddar ett par glasögons utsikt från stötarna i en väska. Hjärtat som värdesätter något kommer alltid som ett mjukt lager som detta."},"ICON-0538":{"nm":"Bältesholktång","de":"För en midja som blivit ett hack smalare, eller en årstid som blivit ett hack rundare. Slå bara ett hål till, så passar bältet kroppen igen. Det är alltid jag som förändras, och att tyst anpassa sig efter mig är det här lilla verktygets uppgift."},"ICON-0539":{"nm":"Scarfring-klämma","de":"En klämma som samlar en glidande scarf till en punkt och håller kvar den. Stilen som ständigt lossnade i vinden finner äntligen sin plats. Även elegans lutar sig ibland mot den här lilla klämman, som gör en dag som nästan gick upp i sömmarna prydlig igen."},"ICON-0540":{"nm":"Charmringar, set","de":"Ett set av små ringar att hänga på sidan av en väska. Hjärtat i att hålla det man älskar nära till hands; att hänga dagens humör på en enda charm är en liten ritual bara man själv känner till, och på något sätt är det en glädje."},"ICON-0541":{"nm":"Luddborttagare","de":"När en tröja verkar åldras över en natt och ludd bildas, rulla den här behållaren varsamt över den, så bär den nytt ansikte igen. Det lätta surret som lyfter bort slitaget är på något sätt betryggande. Ett älskat plagg vaknar till liv en gång till."},"ICON-0542":{"nm":"Textildoftkort","de":"Stoppa det djupt in i garderoben, så fyller det tyst dagarna med doft. Ett brev skrivet i doft istället för ord, en sida som läses utan att vecklas ut. Varje morgon man tar fram ett plagg sprids gårdagens nedtecknade ömhet först."},"ICON-0543":{"nm":"Antistatnål","de":"En vintermorgon då kjolen klänger sig fast vid benen löser en enda nål varsamt upp den klängigheten. En liten frid som lugnar även osynlig friktion; när en liten irritation försvinner flyter dagen mycket smidigare."},"ICON-0544":{"nm":"Reseklädesborste","de":"Alldeles innan man går ut genom dörren har ett stänk damm lagt sig mjukt på axeln. Vik ut den hopfällda borsten, ett enda drag, och första intrycket är prydligt igen. Avslutningen sker alltid vid dörren, och prydligheten fulländas av den där enda touchen."},"ICON-0545":{"nm":"Tvättpåseetikett","de":"Bur in det som inte får blandas i en nätpåse, och en etikett skriver tyst deras namn. Även tvätt har sin plats, och en plats kommer med en liten markering. Ordningen i en lätt trasslad dag växer fram ur den här lilla namnlappen."},"ICON-0546":{"nm":"Fläckborttagningspenna","de":"Även märket en enda droppe kaffe lämnat på en skjorta glider tyst bort när man dabbar på det. En penna som inte döljer ett misstag utan varsamt suddar bort det. Alla behöver en chans att börja dagen rena igen."},"ICON-0547":{"nm":"Skoputsduk","de":"Ett enda drag med duken och läder vinner tillbaka sin glans. Ju längre skorna burits, desto djupare sätter sig glansen. Lystern är en belöning för tiden man vandrat tillsammans - skorna ristar tyst in de åren på vristen."},"ICON-0548":{"nm":"Skosnöreshätta","de":"En liten hätta fäst på änden av ett upplöst skosnöre. Så att blicken inte glider iväg innan mållinjen är änden tätt förseglad. Ett väl knutet skosnöre skickar ett steg längre; en liten försiktighetsåtgärd blir modet att springa ända in i mål."},"ICON-0549":{"nm":"Namnbricka för galge","de":"Bland likadana galgar viskar den här lilla brickan tyst 'min plats.' En tyst vägvisare som lugnar morgonens stressiga sammanblandningar; med mindre besvär att leta känns även dagens början lättare."},"ICON-0550":{"nm":"Linspincettburk","de":"Ibland behövs en spets mer exakt än en fingertopp. En pincett som lyfter en liten lins utan att darra väntar på sin tur inuti burken. Precision ligger alltid tyst redo, sovande tills den kallas, och sedan vaken på ett ögonblick."},"ICON-0551":{"nm":"Minipaket bomullsrondeller","de":"Ett litet paket som rymmer precis lagom för ett enda bruk. Det minskar volymen i väskan medan mjukheten förblir densamma. Att packa lätt är också en vänlighet, och en lätt dag flyttar in i utrymmet man skalat bort."},"ICON-0552":{"nm":"Fodral för oljeabsorberande papper","de":"Tryck bort glansen som spritt sig över näsan mitt på dagen med ett enda tunt ark. Papperen sover i prydliga rader inuti fodralet; i stunden man drar ut ett stannar vem som helst till kort för att ömt betrakta sig själv i spegeln."},"ICON-0553":{"nm":"Hopfällbar kam med spegel","de":"Hopfälld är den en handflata; utfälld är den spegel och kam. En liten allt-i-ett som klarar en snabb uppfräschning från ett hörn av väskan. Prydlighet är inget storslaget; det ligger närmare ett hjärta som kan vecklas ut var som helst för en snabb touch."},"ICON-0554":{"nm":"Rakhyvelhylsa","de":"Den lägger tryggt det vassa bladet till vila i reseväskan. Tack vare den här trubbiga men stadiga hylsan skär sig inte ens fingrar som famlar en hektisk morgon. Att se efter saker handlar alltid om att täcka över en fara ett steg i förväg."},"ICON-0555":{"nm":"Läppcerat-ring","de":"Ett litet skydd som dinglar från en väskrem. Ingen oro för att det ska rulla runt i en ficka och spricka; torra läppar har alltid det inom räckhåll. Att hålla något nära är till syvende och sist ett hjärta som placerar det man behöver på närmast möjliga avstånd."},"ICON-0556":{"nm":"Handspritshållare","de":"Tryck till med en hand så droppar en handfull renlighet ut. Häng den vid dörren, på skrivbordet, var som helst, så växer vanan med rena händer bara närmare. En god vana är inget storslaget; den börjar inom räckhåll."},"ICON-0557":{"nm":"Smal näsdukspåse","de":"Ett smäckert skal som håller en handfull näsdukar. Utan att göra en ficka buktig är den alltid tyst redo för en plötslig snorrig näsa eller några tårar. Ett ark att smyga över till någon; ju smalare beredskapen är, desto finare är den."},"ICON-0558":{"nm":"Minimunskölj-flaska","de":"En dag man måste möta någon efter att ha ätit stark ramen sköter den här lilla flaskan tyst en snabb uppfräschning. En enda klunk friskhet blir ibland ett stort mod, som gör en tveksam hälsning mycket lättare."},"ICON-0559":{"nm":"Glitterpuder-chip","de":"Doppa fingertoppen lätt och lägg den mot kinden, så sprids det som stjärnstoft under strålkastarna. En vanlig kind glittrar på ett ögonblick genom magin i den här lilla chipen. Ljuset anländer alltid så här, på puder dammat på en fingertopp."},"ICON-0560":{"nm":"Glitterdämpande klistermärke","de":"Där det glittrar för mycket för att kännas bekvämt dämpar den här klisterlappen försiktigt ljuset. Att ta bort ett lager bländande glans är också en del av utsmyckningen; den finess som lämnas kvar i det utrymmet blir ibland en känsla i sig själv."},"ICON-0561":{"nm":"Strass-plockpenna","de":"En liten sten som fastnat under foten på vägen. En penna som med avsikt böjer sig ner för att plocka upp den. Hjärtat som varsamt samlar med en fingertopp det man annars bara kunnat gå förbi; ömhet börjar alltid med att stanna upp."},"ICON-0562":{"nm":"Förvaringsbricka för lösögonfransar","de":"En liten bricka för att lägga lösögonfransarna prydligt, en efter en. Även efter att de tagits av går deras vackra kurva aldrig förlorad. Den tysta, prydliga tröst i förvaring som säger att även det som läggs undan ett tag minns sin plats."},"ICON-0563":{"nm":"Klipphylsa för dubbellocktejp","de":"Två blad möts och kapar en knut i ett enda drag. Ju renare snittet, desto prydligare blir nästa knut. Från en fingertopp som knyter väl och klipper väl löses även en ny början upp mycket lättare."},"ICON-0564":{"nm":"Ansiktskonturtejp","de":"En remsa längs käklinjen, försiktigt applicerad, med andan hållen. Konturering handlar inte om att rita en linje som inte fanns, utan om att följa en plats som redan var vacker. En beröring som ömt följer den struktur som alltid funnits där."},"ICON-0565":{"nm":"Ljusreflekterande puder","de":"Ett puder som dricker in ljus till fullo och ger tillbaka det med grace. Även om det inte lyser på egen hand, lyser det upp genom att sprida mottaget ljus i fina bitar. Precis som att föra vidare en lånad ömhet till någon annan växer glittret ju mer det delas."},"ICON-0566":{"nm":"Sminkfixeringsfläkt","de":"Fläktens bris håller samman ett mödosamt utseende ända till dagens slut. Så att det inte smulas sönder, så att det inte rinner, kyler och stelnar den tyst. Så att ett omsorgsfullt vårdat ansikte förblir klart tills scenridån faller."},"ICON-0567":{"nm":"Färgkorrigeringspalett-chip","de":"Små bitar som lugnar och rättar till en missriktad nyans, ett fack i taget. Även en färg som flöt ensam ljusnar äntligen med en kompletterande nyans vid sin sida. Bara när färg griper tag i färgs hand blir det till en klar och ren duk."},"ICON-0568":{"nm":"Halsscarf-set","de":"Linda den runt halsen, så mjuknar den kalla luften i ett gryningsövningsrum betydligt. Varm som en mormors hand som lindar den runt barnbarnets hals. Kylan når alltid de tunnaste ställena först, så den omfamnar nacken först."},"ICON-0569":{"nm":"Kuvert för värmande ögonmask","de":"Ett litet kuvert som håller en uppvärmd ögonmask. I stunden man öppnar fliken sipprar en dåsig värme sakta över ögonlocken. En öm ritual före sömnen, som förseglar bort en trött dag ett tag för att sedan släppa den fri."},"ICON-0570":{"nm":"Filter till bärbar luftfuktare","de":"Ett litet silande membran som återför fukt till ett uttorkat rum. Från det osedda inre filtrerar det tyst bort det som grumlar. Fuktigheten som fyller rummet är en klarhet upprätthållen av någons osynliga möda."},"ICON-0571":{"nm":"Vitaminask","de":"En ask som delar upp en dags piller fack för fack. Att troget ta dem är ett löfte om att stå på scenen även imorgon. I varje litet fack ligger ett hjärta som värnar om sig själv, ordnat i prydlig ordning."},"ICON-0572":{"nm":"Fodral för sovöronproppar","de":"Ett hem för öronpropparna som en stund stänger ute världens brus. Även tystnad behöver omvårdnad, så de vilar prydligt inuti fodralet. En djupt sovet natt är det som låter nästa dags röst vakna klar, vilket vilan vet så väl."},"ICON-0573":{"nm":"Kylhandduksklämma","de":"En klämma som biter stadigt fast vid axeln så att en kyld handduk inte glider av. På en kvav dag bär en enda strimma svalka mot nacken dig genom en lång eftermiddag. Även en liten svalka, hålls den på plats, dröjer länge kvar."},"ICON-0574":{"nm":"Stretchbollspåse","de":"En påse att lägga tillbaka bollen som löste upp kroppen i. Att sträcka ut helt och sedan dra ihop sig igen liknar en inandning och en utandning. Mellan att veckla ut och att samla in blir både kropp och sinne sakta stadigare."},"ICON-0575":{"nm":"Kompressionsbindelrulle","de":"Ett band som lindas runt och runt en vrickad vrist. Det klämmer inte, utan stöttar tyst. Ju mer ansträngt ett ställe är, desto mer behöver det en hand som tyst uthärdar vid dess sida, viskar rullen medan den lindas."},"ICON-0576":{"nm":"Måendetagg","de":"En bricka man skriver sitt mående på i en enda rad och hänger upp. Att ärligt markera det goda och det dåliga är ett litet mod. Skriv ner dagens jag istället för att låtsas må bra, så läser någon den där raden och tar tyst hand om en."},"ICON-0577":{"nm":"Skoduftkapsel","de":"En doftkapsel som stoppas in i en sko. En liten, svag tröst skänkt till fötter som vandrat scenen hela dagen. Den bästa doften till det ställe som arbetat hårdast; ömhet når ända ner till tårna, utan att missa något."},"ICON-0578":{"nm":"Storlekstabell för innersulor","de":"En tabell där fotstorleken är tydligt markerad även på en innersula. Ett par som passar perfekt gör stegen på scenen lätta. Att ta varje persons olika steglängd i beaktande; en bra passform är till syvende och sist ett hjärta som ser djupt in i den andre."},"ICON-0579":{"nm":"Skohornsnyckelring","de":"En nyckelring med ett skohorn krympt till handflatsstorlek. En liten hänsyn som gör det korta ögonblicket av att glida i en sko smidigare. Fötter som ger sig ut på en väg bär alltid med sig, dinglande varsamt vid sidan, någons ömma hjälpande hand."},"ICON-0580":{"nm":"Dammskydd för väska","de":"Ett tyg som varsamt täcker en älskad väska mot damm. Även när den inte används lägger det väskan mjukt till vila och vakar över dess struktur. De ting hjärtat dröjer vid, fastän de sällan rörs vid, bär på tyst omsorg som denna."},"ICON-0581":{"nm":"Remjusteringsstift","de":"Ett stift som får en lossnad rem att sitta tätt mot kroppen. För löst och den glider av axeln; för hårt och andan blir kort. I den lilla justeringen av att hitta det där precisa läget finner både en scendräkt och ett hjärta äntligen ro."},"ICON-0582":{"nm":"Blixtlåssmörjpenna","de":"Dra den en gång över ett trögt blixtlås, så glider det mjukt igen. Vad ljudet av något som fastnat men släpper är befriande. Det som får ett stillastående ställe att flöda igen är en enda strimma smidighet."},"ICON-0583":{"nm":"Rengöringsborste för sneakers","de":"En pensel-spets som torkar en dammig sneaker ren, punkt för punkt. Utanför scenen suddar den försiktigt bort de osynliga spåren av övning. När man ser tåspetsen vit igen känns det som att man imorgon kan springa med ett förnyat hjärta."},"ICON-0584":{"nm":"Lock till impregneringsspray","de":"Ett impregnerande lock som rullar regndroppar till kulor och låter dem falla av. Att lägga på ett lager i förväg så att inget blir genomblött är en ömhet som ser långt fram. Med vetskapen om att regniga dagar kommer, drar man en hinna över en klar dag idag."},"ICON-0585":{"nm":"Läderskyddsduk","de":"En duk lagd varsamt över läder för att hindra det från att skrynkla sig. Den vakar över strukturen som en gammal hand som svepte in en vikskärm i hanji-papper. Ju längre man ska hålla något nära, desto långsammare går man; att bruka in något är bara ett annat namn för tiden man ägnar åt omsorg."},"ICON-0586":{"nm":"Namnbälte för resväska","de":"Ett namnbälte som gör att man kan känna igen sin egen väska bland otaliga andra på en enda blick. Bland bagage som cirklar runt på bandet höjer det handen med en enda bokstav. Hur långt man än reser är ett namn tryggheten i att mötas igen."},"ICON-0587":{"nm":"Vakuumpåseklämma","de":"En klämma som pressar svällt bagage platt och förseglar det. Det är mindre tömt än prydligt hopvikt. Från fingertoppen som håller hushållet snyggt och prydligt krymper även girigheten, viskar det hårt hoppressade bagaget tyst."},"ICON-0588":{"nm":"Resetvättmedelsark","de":"Ett tvättmedelsark som klarar tvätten i ett handfat med bara ett enda stycke. Det liknar resenärens gamla visdom att handtvätta kläder långt hemifrån. Att resa lätt men ändå packa med sig prydlighet - en resenärs länge burna inställning på vägen."},"ICON-0589":{"nm":"Överdrag till nackkudde","de":"Ett rent överdrag nydraget på kudden som stöttade nacken. En plats att luta sig mot bör alltid vara ren för att sinnet ska finna ro. Att lämna en plats mjuk och fri så att någon kan luta sig bekvämt; gästfrihet börjar där."},"ICON-0590":{"nm":"Bagagevåg-rem","de":"En rem som hissar upp en väska för att mäta dess vikt. Innan man ger sig av håller man bagagets vikt i handen i förväg. Mellan det man ska ta med och det man ska lämna kvar - ett ögonblick av att tyst väga även hjärtats vikt."},"ICON-0591":{"nm":"Skopåspar","de":"Ett par påsar som håller två skor sida vid sida, vänster och höger. Lätt förlorade var för sig, men betryggande när de matchas ihop. Ting som alltid följs åt har kraften att tyst vaka över varandra."},"ICON-0592":{"nm":"Extra väskkrok","de":"En dag då en hand inte räcker till, en liten ögla att hänga en väska på ett ögonblick. En extra plats för dagar med mer bagage än man rimligen kan bära. Bara att ha en plats att hänga det på ett tag gör axlarna mycket lättare."},"ICON-0593":{"nm":"Reseschema-chip","de":"Rista dagens rutt tydligt in i en enda chip. Var man ska mötas och vart man ska ta vägen sedan - en riktlinje dragen i förväg för steg som är dåliga på att hitta rätt. En väg vandrad tillsammans, antecknad fack för fack, går sällan vilse."},"ICON-0594":{"nm":"Lock till reseadapter","de":"Ett lock som passar tätt även i uttagen i ett främmande land. Olika till formen, men förenade till slut som ett. Att foga samman ting som kommit från olika platser; harmoni börjar tyst med en liten omvandling."},"ICON-0595":{"nm":"Fodral för resekort","de":"Ett genomskinligt skynke som skyddar kortet varje gång det stryker vid spärren. Den dagliga pendlingen, varje nött avtryck av en pip, invept med grace. Även en vardaglig väg blir ett minne när den värnas om, vilket det här tunna lagret bevisar."},"ICON-0596":{"nm":"Biljettklämma","de":"En klämma som prydligt greppar en biljett så snar att skrynkla sig. Tappar man en biljett på vägen skakar även hjärtat loss. Ju mindre papperet är, desto stadigare håller man i det; en resas trygghet kommer från just den enda platsen."},"ICON-0597":{"nm":"Bytesanteckning-chip","de":"En liten chip med var man ska byta antecknat i en enda rad. Vid varje förvirrande vägskäl öppnar ett enda ord, nedtecknat i förväg, vägen klart och tydligt. En minnesanteckning är en öm vink tyst skickad till ens framtida jag som kanske tappar bort vägen."},"ICON-0598":{"nm":"Passertagg","de":"En passertagg som tyst känns igen när man går genom grinden. Även en väg som verkade blockerad glider upp så snart man bär sin egen behörighet. Att passera öppet är att kliva lätt in i nästa steg utan ett ögonblicks tvekan."},"ICON-0599":{"nm":"Kvittohållare för taxi","de":"Varje liten lapp bär det tydliga avtrycket av en väg färdad den dagen. Samla ihop kvittona som rullat åt alla håll och stoppa in dem prydligt tillsammans, så staplas till och med en obemärkt dag, lapp för lapp, till en riktig resa."},"ICON-0600":{"nm":"Cykelreflexband","de":"Ett band som fångar förbipasserande ljus på en dunkel väg och glittrar tyst. Fastän det inte lyser på egen hand, lyser det upp genom någon annans ljus. Att göra sig synlig är en nattlig vägs ömma bön om att man ska komma hem säkert."},"ICON-0601":{"nm":"Resväskehjulöverdrag","de":"Att resväskans hörn förblir hela efter tusentals varv på flygplatsens transportband beror på detta lilla överdrag som sveper hjulen. Platsen som först möter den grövsta vägen – att tyst skydda någon finns alltid gömd där ingen lägger märke till det."},"ICON-0602":{"nm":"Nackstödsöverdrag","de":"På en lång bussresa drar man ett över nackstödet och lutar sig mot fönstret. Den förra passagerarens doft, gårdagens trötthet – inget av det når så långt. En ren plats att vila huvudet mot är en förvånansvärt stor tröst på en främmande väg."},"ICON-0603":{"nm":"Parkeringsplatsnål","de":"\"Vilken våning, vilken ruta var det nu igen?\" Den som en gång vandrat runt i ett tomt parkeringshus vet hur betryggande den här nålen är. En enda markör instucken i stället för ett bleknande minne, som stakar ut vägen tillbaka i förväg."},"ICON-0604":{"nm":"Rumsnyckelband","de":"Hur kan ett rumsnyckelkort försvinna så lätt? Träd det på ett band och slå det runt handleden, så glömmer du aldrig bort rummet som väntar dig i natt. Även i en främmande stad hänger den lilla tryggheten av att ha sin egen plats runt handleden."},"ICON-0605":{"nm":"Dörrskyltbricka","de":"När repetitionen börjar hängs en bricka på dörren. Stör ej – nu är det dags för ren koncentration. Den djupa tystnaden bakom scenen vakas tyst över av just sådana här små signaler."},"ICON-0606":{"nm":"Necessär","de":"Tandborste, ansiktstvätt, en handduk stor som en handflata. Vart man än reser räcker det att packa just den här necessären, så ordnas varje dags slut och början av samma trygga händer. En liten handfull hushållning som gör en främmande säng hemtam på nolltid."},"ICON-0607":{"nm":"Handduksklämma","de":"Bredvid handfatet låg reservhandduken alltid fuktig, utan någon plats att ta vägen. Kläm fast den med en klämma och häng upp den, så hittar den äntligen sin plats. Att ge något en plats att torka på – vänlighet har oftast just den här storleken."},"ICON-0608":{"nm":"Grenuttagsfodral","de":"Varje gång man öppnade väskan låg laddarna hoptrasslade i en enda klump. Rulla ihop hela grenuttaget och stoppa in det, och allt faller på plats. En utrullad sladd betyder att ett litet hörn av hjärtat också löses upp innan resan."},"ICON-0609":{"nm":"Sängplatsetikett","de":"En nummerlapp på varje våningssäng i sovsalen. Med bara en etikett som visar vilken plats som är din, blir även ett nytt och främmande rum ditt hem redan till natten. Början är alltid så här liten."},"ICON-0610":{"nm":"Miniatyrtvättlina","de":"Häng upp båda ändarna mellan fönsterkarmarna, och det blir en tvättlina. En solig dag svänger några handtvättade sockor mjukt och luftigt i vinden. Även långt hemifrån torkar vardagen på en lina som denna."},"ICON-0611":{"nm":"Toffelbricka","de":"När tofflorna hopar sig vid dörren går det inte att avgöra vems som är vems. Sätt fast en liten bricka, och till och med skorna känner igen sin ägare. Att leva tätt inpå varandra kräver just sådana här vänliga markeringar."},"ICON-0612":{"nm":"Frukostkupongshållare","de":"En hållare att stoppa frukostbiljetten i. En hungrig gryning – den här enda lappen utlovar en ångande skål soppa. Resans dag öppnas alltid sakta med en varm måltid."},"ICON-0613":{"nm":"Vristreflexband","de":"Bind det runt vristen, och det kastar tillbaka ljus i mörkret. På en kvällspromenad viftar det tyst åt en bil som närmar sig på håll – \"här går någon\". Säkerhet glimmar lika anspråkslöst som detta."},"ICON-0614":{"nm":"Våtservettlock","de":"Ett lock som passar precis över öppningen på ett paket våtservetter. Ett ark i taget dras mjukt ut, och resten torkar aldrig ut. Det kan verka obetydligt, men saker man tar till varje dag har alltid sin goda anledning."},"ICON-0615":{"nm":"Picknickfiltrem","de":"Rulla ihop filten och bind den med en rem. Vid Han-flodens strand, i körsbärsblommornas skugga – i samma stund den vecklas ut blir platsen vår. En rem som bär med sig ett handflatestort revir av gräs vart man än går."},"ICON-0616":{"nm":"Myggplåsterfodral","de":"Sommarnattens nödvändighet – ett fodral för myggplåster. Omtanken om att förbereda innan kliandet börjar ryms i det här enda facket. Bakre raderna på en utomhusscen görs alltid tryggare av just sådana här små försiktighetsåtgärder."},"ICON-0617":{"nm":"Promenadflaskhake","de":"En hake som fäster vattenflaskan i väskan när man ger sig ut på promenad. Att ha vatten inom räckhåll när törsten kommer betyder att man orkar gå så mycket längre. En liten koppling som hindrar den gående från att stanna."},"ICON-0618":{"nm":"Hopfällbar shoppingkorg","de":"Vecklas ut blir den en shoppingkorg, viks ihop får den plats i handflatan. Perfekt för en bunt grönsaker man fattat tycke för på vandringen genom marknadens gränder. Hushållets visdom har alltid vuxit mot mindre volym, mot lättare att bära."},"ICON-0619":{"nm":"Vindskyddsklämma","de":"På en blåsig dag griper den tag i tältdukens fladdrande kant och håller den stadigt. En enda klämma trycker fast det som ständigt fladdrade löst. Utomhus är det förvånansvärt ofta något finstort som är det mest pålitliga."},"ICON-0620":{"nm":"Solskyddsnål","de":"En nål man sätter i fönstret för att vinkla bort solljuset. När middagsljuset blir för starkt breder den sakta ut en handfull skugga. Att lindra bländande ljus kan för någon vara den mest ömsinta beröringen."},"ICON-0621":{"nm":"Nödvisslelock","de":"Ett lock som täcker munstycket på en nödvissla. Håller dammet borta, så att den ljuder på en enda andetag när det verkligen behövs. Vissa saker ger ro bara genom att finnas nära, även om man hoppas att aldrig behöva använda dem."},"ICON-0622":{"nm":"Paraplyspetslock","de":"Ett litet lock att träda över paraplyets spets. När den vassa änden görs trubbig skadas varken personen bredvid eller den egna väskan. Regnvädrets etikett börjar tyst med att svepa in en vass spets, rund och mjuk."},"ICON-0623":{"nm":"Regnrocksfodral","de":"Ett fodral att rulla ihop den vikta regnrocken i och stoppa undan. Den väntar tyst i ett hörn av väskan tills nästa skyfall kommer. Förberedelse är, i slutänden, en flisa av hjärta som packar undan det man kanske aldrig kommer att använda."},"ICON-0624":{"nm":"Vattentäta skoöverdrag","de":"Dra dem över skorna, och regnvattnet tränger inte längre igenom. Även på en regnig skolväg under monsunen förblir strumporna torra. En dag utan blöta tår förändrar humöret betydligt mer än man kunde tro."},"ICON-0625":{"nm":"Halkskyddsdyna för snö","de":"Fäst under skorna, och den isiga vägen känns betydligt mindre skrämmande. Den där vintern man hasade fram genom snöhöljda gränder höll den här dynan en stadigt utan att man snubblade. En dold trygghet under försiktiga steg."},"ICON-0626":{"nm":"Kylhalsring","de":"Bind den runt halsen, och en sval fläkt lägger sig tyst kring nacken. Sommarens visdom att bära en strimma svalka på nacken även i den svettigaste hundhettan. År för år lär man sig att härda ut värmen lite klokare."},"ICON-0627":{"nm":"Handfläktsställ","de":"Ett ställ att resa upp handfläkten på. När båda händerna blir fria kan man bläddra i böcker och skriva i stället för att fläkta. En liten fläkt gör en lång sommar vid skrivbordet just precis uthärdlig."},"ICON-0628":{"nm":"Handvärmarfodral","de":"Ett fodral att bära en handvärmare i. När man stoppar de kalla fingertopparna i fickan för att tina upp dem väntar redan en liten värme där. Vinterns utflykter tar man sig igenom på just den här handfullen värme."},"ICON-0629":{"nm":"Öronvärmarfodral","de":"Ett fodral att förvara öronvärmarna i. En plats att vörda dem på tills nästa köldknäpp kommer. Saker man inte riktigt kan slänga när årstiderna växlar bär på en tyst tilltro till vintern man ska möta igen."},"ICON-0630":{"nm":"UV-mätarbricka","de":"Håll den lätt mot ljuset, och brickan berättar dagens UV-styrka i färg. Den gör äntligen den osynliga solstyrkan synlig. Man fäster liksom ett litet öga för att läsa himlen stilla runt handleden."},"ICON-0631":{"nm":"Grändstämpeltavla","de":"En tavla man fyller genom att samla stämplar från varje butik längs gränden. För varje ruta som stämplas ritas kvarterets karta tydligare i hjärtat. Minnen samlade till fots blir kvar som just sådana bläckmärken."},"ICON-0632":{"nm":"Resenålstavla","de":"En liten tavla där man sätter en nål för varje plats man besökt. Ju fler prickar, desto vidare blir omkretsen av ens egen värld. Varje nål är ett spår som tyst säger: \"jag var här.\""},"ICON-0633":{"nm":"Litet kompassnöre","de":"Hur länge man än vandrar vilse förblir norr alltid på sin plats, oförändrad. Den lilla kompassen som hänger vid bröstet lugnar först det vacklande hjärtat, när man inte alls vet vart man ska gå."},"ICON-0634":{"nm":"Vägbeskrivningsring","de":"Lapparna man klottrade ner under vägsökandet träs upp på en ring. \"Sväng vänster vid den röda brevlådan.\" Någons kluriga handstil vägleder tyst en främmande gränd. En väg bevarad på papper bleknar sällan."},"ICON-0635":{"nm":"Landmärkesklistermärkesbok","de":"En bok man fyller med ett klistermärke köpt på varje resmål. Torn, broar, gamla slottsmurar travas upp sida efter sida. Att samla platser man besökt liknar att med fingertopparna på nytt röra vid tiden man passerat."},"ICON-0636":{"nm":"Tunnelbanebytesbricka","de":"En bricka man håller hårt i vid bytesstationen där linjerna delar sig. Det korta ögonblicket av att välja vart man ska byta kan ibland vända hela dagens riktning. Med ett litet val visar staden ett annat ansikte."},"ICON-0637":{"nm":"Kvartersutforskningskort","de":"\"I dag, ända fram till bageriet i det här kvarteret.\" Dra ett kort, och dagens mål är bestämt. Även en gränd man alltid går förbi blir en ny väg så fort ett uppdrag dyker upp. Ett kort som påminner om att äventyret aldrig är långt borta."},"ICON-0638":{"nm":"Visitkortshållare","de":"En hållare att stoppa in visitkorten man fått från sina favoritbutiker. Det goda stället, den vänliga ägaren – de samlas fack för fack. Att fatta tycke för en stad börjar med just sådana här små papperslappar."},"ICON-0639":{"nm":"Ruttmärkestavla","de":"En tavla där man förtjänar ett märke genom att gå en promenadrutt hela vägen. Belöningen för att ha gått hela sträckan blir kvar i handen som en rund metallbit. Stoltheten som bara den som gått hela vägen känner till präglas tydligt här."},"ICON-0640":{"nm":"Väsklås med nyckelring","de":"Ett litet hänglås och nyckelring i ett, som fästs i väskans dragkedja. Det vaktar noga det dyrbara samtidigt som det skramlar muntert i väskans kant. En resenärs rätt så listiga följeslagare, där säkerhet och prydnad blir ett."},"ICON-0641":{"nm":"Spårningsbricka","de":"Den kurar ihop sig i väskans djupaste mörker, och just i den stund då alla gett upp blinkar den svagt till. \"Här är jag.\" Ljudet av något man trodde var förlorat som återvänder till fingertopparna. Liten som den är stannar den kvar hos sin ägare in i det sista."},"ICON-0642":{"nm":"Dragkedjelåsring","de":"Klick – väl fäst kan den inte öppnas av en vanlig hand. En envishet som lika gärna blockerar en hastig nagel som ett smygande finger. Säkerhet påminner med sin tunga vikt om att det är okej att vara lite trög ibland."},"ICON-0643":{"nm":"Stöldskyddsklockrem","de":"En osynlig grindvakt som ser till att varorna på hyllan inte lämnar butiken innan de betalats. När en ärlig hand stryker förbi förblir den tyst ända till slutet. En klocka som inte ringer är den fridfullaste klockan av alla."},"ICON-0644":{"nm":"Kontaktdöljande etikett","de":"Den lägger sig tyst som ett skikt över namnet och numret på en paketlåda. Vem som bor där, vart det ska – det räcker att mottagaren vet. Att dölja väl är också en sorts vänlighet, säger den och håller tyst sin plats."},"ICON-0645":{"nm":"Passomslagsband","de":"En främmande flygplats, dussintals identiska omslag som cirklar på bagagebandet i gryningen. Bland dem vinkar det \"hitåt\" i en färg bara du känner igen. En liten kappa man klär den avresande handlingen i. Även när omslaget nöts blir resan aldrig mindre ljus."},"ICON-0646":{"nm":"Kontantsorteringsfodral","de":"Sedlar till vänster, mynt till höger, en nödslant i ett fack ingen känner till. Det är den plats en hand nyss hemkommen från marknaden söker sig till först. Även en rörig dag finner ordning här inne, prydligt och med ett muntert klirr."},"ICON-0647":{"nm":"Säkerhetssigill","de":"Riv loss den en gång, och ett märke blir kvar. Ett litet, ärligt samvete som aldrig riktigt kan dölja \"någon har öppnat mig\". Under varje låda som anlänt förseglad och hel ligger den här vännens orubbliga tystnad."},"ICON-0648":{"nm":"Nödkontaktbricka","de":"Ett vilset barns ficka, insidan av en datorväska, änden på ett hundkoppel. Även när stunden själv inte kan tala ropar den tydligt ut numret i dess ställe. En enda liten bricka rymmer ett helt \"ta mig hem\"."},"ICON-0649":{"nm":"Selfiepinnefjärrlock","de":"Gruppfoton där någon alltid hamnade utanför bilden för att armarna inte räckte. Nu får ett enkelt tryck i änden hela familjen att rymmas i en enda ram. I det ögonblicket alla ler trycker jag stilla av och hoppar själv in i bilden."},"ICON-0650":{"nm":"Objektivfodralssnöre","de":"Ett snöre som håller reservobjektiven tätt samman så de inte skramlar mot varandra i väskan. Eftersom ett enda glas är ett helt landskap skakar man inte den vikten hur som helst. Fotografens omsorg är knuten i varje enda knut."},"ICON-0651":{"nm":"Filterfodralsring","de":"Ett enda tunt blad förvandlar samma himmel till ett annat ljus. En plats att förvara de där små trollformlerna prydligt i ett runt bo. Varje gång fodralet öppnas fladdrar fingertopparna till ett ögonblick – vilken solnedgång ska jag fånga i dag?"},"ICON-0652":{"nm":"Stativfodral","de":"Hopfällt bara ett handspann, uppfällt tre orubbliga ben. Man rullar varsamt ihop vännen som håller motivet stilla i de darrande händernas ställe. Ju tyngre utrustningen, desto mjukare tyg förtjänar den att vila på."},"ICON-0653":{"nm":"Kameraremsdyna","de":"Går man hela dagen kommer stunden då kameran tynger axeln. Då tar en enda dyna tyst över en del av den vikten. En liten, mjuk tröst lagd på axeln som vandrar långt för en enda bra bild."},"ICON-0654":{"nm":"Minneskortsindelare","de":"Nätter då man tappar räkningen på vilket kort som gömmer hundratals minnen visar de färgglada markörerna vägen. Vårresan i blått, den första scenen i gult. En liten, omtänksam bibliotekarie som ger även minnen sina egna hyllor."},"ICON-0655":{"nm":"Laddkabelrulle","de":"Innan sladdarna hinner sätta upp en knutshow i väskan rullas de ihop och läggs prydligt att sova. Ordnar man en sladd löses av någon anledning också en tråd i hjärtat upp samtidigt. Den hoprullade synen är rofylld bara att se på."},"ICON-0656":{"nm":"Fotobackupetikett","de":"\"De här bilderna – säkerhetskopierade jag dem?\" En liten lapp som svarar i förväg på den där sena kvällens oro. Ju dyrbarare ögonblicket, desto viktigare att det finns bevarat på mer än ett ställe, skriver etiketten tydligt ner."},"ICON-0657":{"nm":"Kompositionsram","de":"Ser man världen genom det fyrkantiga fönstret syns med en gång vad som ska tas med och vad som ska lämnas ute. En bra bild handlar inte om att lägga till mer utan om att skala bort väl – den tomma ramen lär det först av allt."},"ICON-0658":{"nm":"Myntplånbokscharm","de":"Den dinglar vid väskans kant och rymmer några enstaka mynt. Den lilla skattkammaren som öppnas allra först framför en läskautomat eller en ångande fiskbullestånd. Det där klirret är ljudeffekten för små stunder av lycka."},"ICON-0659":{"nm":"Kvittospett","de":"Papperslappar man nästan kastade träs upp en efter en. Vad man åt och köpte i dag – kvittot är en ärligare dagbok än vilken hushållsbok som helst. Samlar man ihop en hel månads värde blir det en ganska tjock uppteckning av livet."},"ICON-0660":{"nm":"Marknadskorgsbricka","de":"Den hänger på handleden på väg till marknaden och strövar med genom stånden. En bit tofu, en bunt salladslök, till och med vänligheten man fick på köpet. All den tyngden bär den utan ett knot. En vän som blir gladare av att fyllas än av att tömmas."},"ICON-0661":{"nm":"Souvenirmagnettavla","de":"Väljer man en på varje resmål och sätter upp den på kylskåpet blir köket en liten världskarta. Städerna man besökt hänger sida vid sida och viskar \"låt oss åka igen.\" Även vanlig plåt bär kraften att hålla fast minnen."},"ICON-0662":{"nm":"Regionstämpelbok","de":"En stämpel per sida, och gränderna man vandrat vaknar till liv igen i bläck. De röda märkena samlade på en resa runt hela landet är i sig en karta över fotspåren. Ju färre tomma rutor, desto tystare vinkar nästa resa."},"ICON-0663":{"nm":"Presentsnörerulle","de":"Ett långt, långt tålamod som rullas ut i det oändliga för att binda ihop en enda presentask. Den unnar en prydlig knut bara till händer som vet när man ska klippa av. Hoprullad väntar den tyst på sin nästa tur."},"ICON-0664":{"nm":"Presentskyddskudde","de":"Den sluter ett sprött hjärta i en mjuk omfamning. Även i en skumpande paketbil håller den stilla och skön – \"det är okej, jag stöttar dig.\" Den vakar i förväg även över det ljusa leendet hos den som öppnar lådan."},"ICON-0665":{"nm":"Prisdöljande klistermärke","de":"En liten, snäll vit lögn som tyst döljer priset på en present. \"Du behöver inte veta hur mycket – ta bara emot hjärtat,\" säger den och sätter sig mjukt över prislappen. Inte för att gömma, utan för att låta det där hjärtat lysa ännu klarare."},"ICON-0666":{"nm":"Liten kundvagnsbricka","de":"Man kan inte dra en riktig kundvagn, men den här lilla vännen som dinglar vid fingertoppen rymmer hela förväntan inför ett besök i affären. Liten som den är väger fjärilen av \"vad ska jag köpa i dag?\" lika tungt som den riktiga."},"ICON-0667":{"nm":"Lysande skoklämma","de":"En glimt vid tåspetsen på en sportsko ute på kvällspromenad, som skickar en förbipasserande bil signalen \"här går någon.\" Det första lilla ljuset som möter en i en mörk gränd. Säkerhet börjar alltid tyst vid tårna."},"ICON-0668":{"nm":"Minificklampslock","de":"Trä det över ficklampans huvud, och ljuset sprids längre bort, mjukare. En liten trollkarl som målar ett stjärnkluster i taket på ett becksvart tält. På nätter när mörkret är lite läskigt finns ingen bättre vän."},"ICON-0669":{"nm":"Hemkomstknapp","de":"Tryck på den, och raden \"jag kom hem tryggt\" flyger iväg till familjen långt borta. I stället för ljudet av ytterdörren sent på kvällen förmedlar en enda liten knapp nyheten. Någon somnar och väntar just på den här signalen."},"ICON-0670":{"nm":"Reflexklistermärkesrulle","de":"Klipp av en bit och fäst den på väskan, cykeln, paraplyet, och den mörka vägen blir betydligt mindre farlig. En sömntuta som vaknar upp klarlysande så fort den möter ett strålkastarljus. Hoprullad väntar den på att nästa mörker ska komma."},"ICON-0671":{"nm":"Nödtaxikort","de":"Stoppa det i ett fack i plånboken, och även en tom hållplats sent på kvällen känns mindre kuslig. Ett nummer, en adressrad skriven som ett löfte – \"jag kör dig hem.\" Vem visste att ordet nödsituation kunde kännas så tryggt."},"ICON-0672":{"nm":"Nattvägkartband","de":"Man går längs gator med glesa gatlyktor med det bundet runt handleden. Vilken gränd som är upplyst, var det är kolmörkt – det viskar fram en genväg bara natten känner till. Ett band som binder sig vid din sida så att du aldrig tappar riktningen i mörkret."},"ICON-0673":{"nm":"Trygghetslarmfodral","de":"Dra i den i en nödsituation, och den skriker så högt att hela gränden ryker till. Annars gömmer den sig stillsamt i fodralet och sparar rösten till just den enda stunden. Det största skriket, förvarat i den minsta väskan."},"ICON-0674":{"nm":"Dörrljusnyckelring","de":"Farväl till nätter av att famla efter nyckelhålet i den mörka änden av korridoren. Den hänger vid dörren och möter den hemvändande handen med ett runt ljussken. \"Bra jobbat, du är hemma,\" hälsar nyckelringen först."},"ICON-0675":{"nm":"Hemkomstlapp för boende","de":"\"Ta paraplyet, släck lyset innan du går.\" En kort påminnelse på kylskåpet vaktar det tomma rummet. En liten lapp för den som ska komma hem. Vänligheten i ett enda pappersark följer tyst hela vägen till dörren."},"ICON-0676":{"nm":"Kabelredningskam","de":"Den kammar trassliga sladdar mjukt och rakt, som att borsta hår. Kabeldjungeln bakom skrivbordet blir prydlig efter några penseldrag. Det är inte bara hår som trasslar till sig, viskar kammen stilla."},"ICON-0677":{"nm":"Pennhållarindelning","de":"Blyertspennan hitåt, överstrykningspennan ditåt, saxen i ändfacket. Den delar in en liten by inne i en enda mugg och ger varje penna sin plats. Med fack behöver handen aldrig famla mer. Början på en liten ordning på skrivbordet."},"ICON-0678":{"nm":"Skärmanteckningsklämma","de":"Den hänger på skärmens sida och håller \"dagens att-göra\" precis i ögonhöjd. En liten anslagstavla man ser rakt framifrån, ingen chans att glömma. En enda klämma fångar stilla ett sinne som ständigt försöker skjuta upp."},"ICON-0679":{"nm":"Lådsorteringsbricka","de":"Gem och gummiband, häftstift och suddgummi. Den ger varje liten stam i lådan sitt eget rum. När handen når ner i indelade fack krymper söktiden, och ett hörn av hjärtat blir lättare."},"ICON-0680":{"nm":"Dammborstetui","de":"Ett enda dammkorn på ett objektiv blir en jättefläck på bilden. Därför väntar borsten alltid redo och fläckfri inne i sitt etui. En flitig fingertopp som vaktar en renhet ingen någonsin lägger märke till."},"ICON-0681":{"nm":"Skrivbordsmattehörn","de":"Ett handspann mjukhet utlagt i ett hörn av skrivbordet. Pennor rullar inte av, och i stället för kallt glas stöder en varm textur handleden. En vänlig yta som ger sin plats allra först, så att en lång natts skrivande förblir stadigt."},"ICON-0682":{"nm":"Mussladdshållare","de":"Trasslar sladden till sig, trasslar hjärtat till sig någonstans också. En beröring som i förväg fångar en irrande tråd och lägger den prydligt ner. Knappt märkbar, men den ordnar tyst skrivbordets struktur – en liten, flitig prydnad."},"ICON-0683":{"nm":"Laddningsdockningsställ","de":"Res upp en apparat som legat plant, snett upprätt, och skärmen möter äntligen blicken. Även väntan medan den laddas blir en prydlig stund. Att stödja något är att ge även det som vilar en stunds ordentlig hållning."},"ICON-0684":{"nm":"Liten papperskorgsetikett","de":"Även den minsta korgen får sitt eget namn. Den enda raden \"släng här\" kallar fram en tyst ordning på ett stökigt skrivbord. En etikett är i slutänden en liten hälsning som berättar för ett föremål: din användning finns här."},"ICON-0685":{"nm":"Anslagstavlenål","de":"Den trycker fast ett pappersark på tavlan. Att för en stund lämna en känsla man inte vill glömma i väggens förvar. Dagens beslutsamhet, hängande vid nålens spets, svajar lätt i vinden och fångar dig varje gång du går förbi."},"ICON-0686":{"nm":"Etikettram","de":"En enda fyrkantig kant förvandlar vanlig text till en tydlig, sammanhållen mening. En bricka som sveper en prydlig värdighet kring lätt utspridda lappar. Inte för att stänga in, utan för att omfamna viktiga ord så att de inte går förlorade."},"ICON-0687":{"nm":"Genomskinligt lådhandtag","de":"Sätt ett handtag på en genomskinlig låda, och man kan se vad som finns i den utan att öppna den huller om buller. Ett handspann av avstånd – synligt, men inte inom räckhåll. Även genomskinlighet behöver takt, viskar lådan så."},"ICON-0688":{"nm":"Locklåsklämma","de":"Lämnas den öppen smiter både doft och färg sakta iväg. Med en enda liten klämma som biter fast locket ordentligt förblir gårdagens färg hel ända in i morgondagen. Att låsa är, i själva verket, att skydda det man håller kärt."},"ICON-0689":{"nm":"Fukttorkarhållare","de":"En liten vaktpost som avskyr fukt och tyst håller sin post. Att hålla torr luft nära är den första förutsättningen för lång förvaring, viskar den här prydliga hållaren stilla. Just så bevaras torrheten."},"ICON-0690":{"nm":"Förvaringskorgsbricka","de":"En liten namnlapp på varje korg. Bestäm vilket fack som rymmer vad, och tiden man annars lade på att leta blir raka spåret vilotid. Att organisera är en vänlig lapp man i förväg ger till sitt framtida jag."},"ICON-0691":{"nm":"Miniskärmvägg","de":"En liten skiljevägg som på ett kick reser upp ett mysigt litet rum på skrivbordet. Med bara den här ena skivan uppstår ett tyst hörn lite bortvänt från världen. En hemtrevlig plats helt för sig själv, där koncentration kan slå rot."},"ICON-0692":{"nm":"Påsställ","de":"Ett ställ som varsamt stöttar ryggen på påsar som annars ständigt vält omkull. Bara genom att stå prydligt i rad blir det mycket lättare att välja rätt. Att ställa saker upprätt är att i förväg ta hänsyn till nästa hand som ska komma."},"ICON-0693":{"nm":"Tomrutebricka","de":"En bricka som medvetet markerar tomhet. Att lämna en plats att fylla är i högsta grad också en plan. En tom ruta är inte lättja, utan ett handspann marginal artigt lämnat öppet för något som snart ska komma."},"ICON-0694":{"nm":"Tandborstskyddshuv","de":"Man blir mer noggrann med borsten som rör vid munnen. Ett litet lock som stänger ute även ett enda dammkorn. Att ta hand om en renhet ingen ser är just den lilla omsorg som öppnar varje morgon fräsch."},"ICON-0695":{"nm":"Tvålnät","de":"Ett nät som mjukt lyfter tvålen så den inte mjuknar av att stå i vatten. Principen att låta vattnet rinna av gör att den håller längre – det bevisas tyst varje dag från badrummets lägsta, minsta plats."},"ICON-0696":{"nm":"Schamponpumpklämma","de":"Den håller pumphuvudet stilla, så att ett enda tryck ger precis lagom mängd. Vanan att hushålla med det man använder är grunden för en hushållning som räcker långt. En enda liten klämma håller slöseriet vänligt i schack."},"ICON-0697":{"nm":"Rakhyvelskrokslock","de":"Vassa saker får sitt eget lilla hus. Trä rakhyveln i locket och häng upp den, och både fukt och fara rinner av tillsammans. Att hantera skärpa varsamt är, i grunden, också ett sätt att vara rädd om sig själv."},"ICON-0698":{"nm":"Duschhandduksslinga","de":"En långsträckt handduk formar en slinga och når ända till ryggen man annars inte kommer åt. Längs den enda strimman där löddret glider fram sprider sig en vänlig värme genom hela badrummet, som när man tvättar sin egen rygg helt själv."},"ICON-0699":{"nm":"Avloppssilspack","de":"Ett litet nät som släpper igenom vattnet men fångar upp resterna. På en plats ingen ser förhindrar det tyst stopp. Det som arbetar på den lägsta platsen håller husets flöde igång, viskar avloppet utan ett ord."},"ICON-0700":{"nm":"Sugkoppskrok","de":"Den skapar en ny plats på väggen utan att en enda spik behöver slås i. Tryck fast den, dra loss den, och inte ens ett märke blir kvar. Konsten att stanna en stund och lämna utan spår – sugkoppen kan den här lätta artigheten väl."},"ICON-0701":{"nm":"Namnbricka för badtofflor","de":"Ett par ställt prydligt framför tröskeln. Omsorgen i ett hem där man tar av sig skorna når varsamt ända fram till badrumsdörren. En liten namnlapp pekar stilla ut platsen för denna lilla gästfrihet som värmer kalla tår."},"ICON-0702":{"nm":"Liten sköljkopp","de":"En liten rund kopp som rymmer en klunk för tandborstningen. I det korta ögonblicket av att skölja munnen tar den tyst emot dagens början och slut. Inte flärdfull, men vid din sida varje dag – enkelhet är den mest varaktiga formen av hemmets omsorg."},"ICON-0703":{"nm":"Hylsa till dammvippa","de":"En hylsa som träs över fjädrarna på en borste som samlar damm som med en smekning. Likt en fågel som mjukt viker in vingarna när den inte flyger, är det ett redskap som vet var det ska vila som stannar länge vid din sida."},"ICON-0704":{"nm":"Refill till luddrulle","de":"Dra av ett lager och en ny, ren yta lyser fram därunder. De klibbiga inre bladen som samlar upp ludd och hårstrån. I en rund refill som fylls på igen när den tar slut, ligger den flitiga upprepningens dygd invirad."},"ICON-0705":{"nm":"Trasklämma","de":"En klämma som biter fast trasan lika stadigt som en hand. Den håller ett handsbrett avstånd mellan det kalla golvet och dina fingrar. Ett enda handtag som tar på sig det tråkiga arbetet gör den mödosamma städningen mycket lättare."},"ICON-0706":{"nm":"Skyddshätta för fogborste","de":"En liten hätta som skyddar den sköra spetsen på en smal borste gjord för att tränga in i trånga springor. Ett hjärta som sköter om även de hörn händerna inte når. Den som rengör det osynliga låter hemmets famn växa ett handsbrett vidare."},"ICON-0707":{"nm":"Etikettring för sprayflaska","de":"En liten namnlapp som vilar mjukt på sprayflaskans axel. Oavsett om det innehåller rent vatten eller rengöringsmedel talar den tydligt om det i en enda rad. En etikett som suddar ut förvirringen i förväg är en flitig hushållerskas gamla vana."},"ICON-0708":{"nm":"Refillband för toalettrulle","de":"Ett band som spänner fast en ny rulle på den tomma platsen och knyter den stadigt. Den enklaste beröring som återförenar det som klippts av. Någons omtanke om att fylla på innan det tar slut ligger rund och tyst virad kring denna lilla ögla."},"ICON-0709":{"nm":"Krok för städhandskar","de":"En krok som hänger upp våta handskar för att torka precis när det blöta arbetet är klart. Den ger de flitiga händerna en plats att vila en stund. Medan fukten sakta torkar hämtar en kort paus andan inför nästa syssla."},"ICON-0710":{"nm":"Hängpinne för sopkvast","de":"Häng upp kvasten upp och ner så bevarar borstet sin räta form istället för att böjas. En hållning som väntar upprätt på nästa gård att sopa. En liten men stadig plats som hjälper den behålla sin form även efter att arbetet är slutfört."},"ICON-0711":{"nm":"Klämma för soppåse","de":"Den biter tag om påsens mynning och försluter den stadigt så inget läcker ut. Ett enda grepp som knyter änden ordentligt gör städningen betydligt renare. Att avsluta något börjar till syvende och sist alltid med att stänga väl."},"ICON-0712":{"nm":"Burk för klädnypor","de":"En burk där klädnypor, som lätt går förlorade när de sprids ut, alla bor tillsammans. Den ger de små sakerna ett gemensamt hem att stanna i. Samla fingertopparnas små soldater på ett ställe, så hittar du dem med en enda blick när de behövs."},"ICON-0713":{"nm":"Sorteringsring för strumpor","de":"En strumpa utan sin partner försvinner alltid smygande någonstans. Bind ihop varje par med en ring innan tvätten, så skiljs de inte åt ens sedan de torkat mjuka och fluffiga. Att sortera är ett litet löfte man ger i förväg mot att förlora något."},"ICON-0714":{"nm":"Tvättbollspåse","de":"Den rullar runt, runt inne i tvättmaskinen och knackar liv i smutsen som fastnat i tygerna. En rytm som smeker tvätten med sin runda kropp. I det brusande vattnet bär den tvättens gamla instinkt – knackandet – rullande inuti en påse."},"ICON-0715":{"nm":"Doseringslock för ylletvätt","de":"Åt ömtåliga plagg ges en lika skonsam mängd. Ett doseringslock som mäter upp exakt en kapsyl med ylletvättmedel. I en enda liten markering ligger den varsamma hand som hanterar ull. Att spara på överflödet är också omsorg."},"ICON-0716":{"nm":"Lagningslapp för tyg","de":"En liten lapp som varsamt läggs över ett nött ställe. Fingertoppens hjärta som vårdar en sliten fläck istället för att slänga den obetänksamt. I varje lagad märke bevaras, fint tecknat, mönstret av de år som gått tillsammans med plagget."},"ICON-0717":{"nm":"Låspinne för torkställ","de":"En pinne som tyst håller fast torkstället så att tvätten inte flyger iväg i vinden. Även på dagar då tvätten böljar i solen hjälper den den hålla sin plats mitt i svajet. Rollen som en liten men pålitlig motvikt."},"ICON-0718":{"nm":"Namnbricka för underklädesnät","de":"Ömtåliga underkläder tvättas separat inuti ett nät. Ett nät som sluter de mjuka sakerna tätt om sig, skyddade från det svallande vattnet. En liten märkt påse påminner om att varsamt värna det ömtåliga också är hushållsarbete."},"ICON-0719":{"nm":"Hängare för tvättmedelsskopa","de":"Häng upp skopan för pulvertvättmedel prydligt på väggen. Slipp besväret att tappa den i tunnan och blöta ner handen. Den städade vanan att alltid ha samma redskap på samma plats vilar stadigt i denna lilla krok."},"ICON-0720":{"nm":"Stopp för klädlina","de":"Den biter tag om klädlinans ände så hårt att linan inte glider lös ens med tung tvätt på sig. Den sista knuten som håller ut till slutet så att en spänd lina inte hänger slak. Ett solitt avslut hänger på just detta."},"ICON-0721":{"nm":"Etikett i örngott","de":"Platsen kinden möter först varje natt, med en tumnagelstor etikett sydd fast på insidan. Vem läser egentligen den finstilta texten om tvättemperatur? Ändå är den den allra närmaste anvisningen, den som vakar bredvid ett sovande ansikte."},"ICON-0722":{"nm":"Täckesklämma","de":"En natt med fönstret öppet rymmer täcket ändå inte iväg när brisen kommer in. För en klämma med hårt slutna käftar håller fast i hörnet. En tyst hand som håller kanten på plats i sovarens ställe."},"ICON-0723":{"nm":"Bländskärm för nattlampa","de":"\"När ljuset når ögonen flyr sömnen.\" Med en enda skärm som någon tyst ställt upp drar sig ljuset tillbaka och fuktar bara svagt fotändan av sängen. En liten skiljevägg som lånar ut ett handsbrett mörker."},"ICON-0724":{"nm":"Ficka för sängspringan","de":"Tänk dig springan mellan madrassen och väggen, den handen aldrig kunde nå. Fjärrkontrollen som rullade bort, glasögonen med, samlas nu här. En ficka som sängen tyst viker upp för att fånga det du nästan förlorade."},"ICON-0725":{"nm":"Bricka för glasögonförvaring","de":"Ta av linserna och världen suddas mjukt ut, och en grund skål tar emot det korta ögonblicket av försvarslöshet. På morgonen, även utan famlande fingrar, väntar glasögonen alltid på samma plats."},"ICON-0726":{"nm":"Ställ för väckarklocka","de":"Klockan sex på morgonen, ovanpå det stadiga fundamentet där det mest hatade ljudet ringer ut. Orubbligt och stadigt bär det klockan och öppnar till slut någons dag. Det bär, utan ett ord, uppvaknandets kärva löfte."},"ICON-0727":{"nm":"Kabelhållare vid sänggaveln","de":"Laddningskabeln som brukade glida ner bakom huvudgärden faller inte längre till golvet. För en liten hållare griper varsamt om sladdens ände. Inom armlängds avstånd – en beröring som rett upp nattens väg."},"ICON-0728":{"nm":"Band för pyjamasförvaring","de":"Ett band som slår ett varv runt de prydligt vikta pyjamasarna och knyter dem samman. Även mjukhet som lätt kommer i olag behöver skötsel. För morgondagens jag rullar dagens jag ihop dem prydligt – en liten förberedelse."},"ICON-0729":{"nm":"Hållare för doftkort","de":"Ställ upp ett doftat kort på snedden, och likt att bläddra en sida bläddrar du årstiden med näsan. Från lavendel till citrus – det blir en dagbok över dagen, skriven i doft."},"ICON-0730":{"nm":"Dyna till nyckelfat","de":"Ett hörn vid hallen, platsen där nycklarna brukade skramla ner. Ett fat fodrat med en mjuk kudde sväljer det skarpa ljudet. En liten platta tar tyst emot den hemkomnes första rörelse."},"ICON-0731":{"nm":"Droppskydd för paraply","de":"Regnvatten droppar sakta från spetsen på paraplyet du bar in. Ett lock fångar den droppen prydligt, så någon har i förväg förutsett och stoppat den lilla pöl som annars spridit sig över golvet."},"ICON-0732":{"nm":"Munskyddskrok","de":"En tumnagelstor bricka fäst på väggen vid dörren. Som den sista ritualen innan man går ut hänger munskyddet just här. En liten minnesanordning som håller ögonhöjd vid dörren så du inte glömmer vad du behöver ta med."},"ICON-0733":{"nm":"Skyddshölje för paketkniv","de":"Ett skyddshölje som träs över bladet som skär upp paket. Det täcker tyst risken för ett skärsår gömt bakom uppackningens spänning. En osynlig omtanke som tryggt öppnar väntans slut."},"ICON-0734":{"nm":"Ställ för skoborste","de":"Platsen där skoborsten vilar, fortfarande fuktig efter putsningen. Även när den bär på fukt förblir golvet torrt. Att även ett redskap som skapar renlighet behöver en plats att vila, det säger den lilla stället tyst till oss."},"ICON-0735":{"nm":"Anteckningstavla för besökare","de":"\"Tittade bara förbi ett kort tag.\" En kort rad skriven på hallens anteckningstavla. Ett litet torg där människor som just missade varandra delar tvärs över tiden. På en enda ruta papper travas en hälsning, en önskan och ett hjärta på varandra."},"ICON-0736":{"nm":"Rulle mot dörrdrag","de":"Draget som smög sig in genom den fingerbreda springan under dörren. En hoprullad list spärrar tyst av den vägen. Den håller kvar ett lager värme extra i rummet, värme som annars läckt ut osedd."},"ICON-0737":{"nm":"Charm för dörrstopp","de":"En liten charm som stöttar foten på en vidöppen dörr så den inte slår igen på nytt. Den håller tyngden stadigt för brisen och fotstegen som passerar. En vänlig envishet som håller dörren öppen."},"ICON-0738":{"nm":"Skydd för hallens ljusströmbrytare","de":"Strömbrytaren i hallen som du famlade efter sent på natten. Ett självlysande skydd markerar dess plats med ett svagt sken i mörkret. Så att handen inte irrar – en liten vägvisare som lyser innan ljuset själv tänds."},"ICON-0739":{"nm":"Underlägg för kopp","de":"I stunden en kopp ställd på bordet börjar glida iväg, fångar en enda platta stilla dess fot. Ett underlägg som lugnt håller sin plats och inte lämnar ett enda märke ens när vattendroppar bildas."},"ICON-0740":{"nm":"Doftklämma för bilen","de":"En liten doftklämma hängande inne i bilen. Buren av fläktens luftström fyller en svag doft sakta det trånga utrymmet. En vänlig tröst i förarsätet, som värmer även tristessen vid ett rödljus med doft."},"ICON-0741":{"nm":"Skydd för säkerhetsbälte","de":"Ett mjukt skydd som träs över bältet som löper tvärs över axeln. Skavkänslan mot nacken smälter sakta bort. Även ett band avsett för säkerhet kan förses med värme, säger denna handsbreda tygbit."},"ICON-0742":{"nm":"Täckskylt för parkeringsnummer","de":"En skylt som tyst täcker skylten som visar din plats i ett underjordiskt garage, innan du tar en bild. Alla har information de hellre inte lämnar efter sig. Ett lager varsamt utsuddat ur en scen av vardagslivet."},"ICON-0743":{"nm":"Skydd för cykelklocka","de":"Ding-ding. Den klara hälsningen en cykel ger vid gatuhörnet. Ett skydd över klockan bevarar det ljudet även i regn. Vid en enda liten klocksignal ler människor och tar ett steg åt sidan."},"ICON-0744":{"nm":"Greppring för styre","de":"En ring som mjukt sveper in känslan av styret i handflatan. Även efter att ha hållit och cyklat länge domnar inte händerna. Ju längre vägen är, desto mer förkortar bekvämligheten där man håller den sträckan."},"ICON-0745":{"nm":"Namnklistermärke för hjälm","de":"Ett namnklistermärke på insidan av en hjälm. Bland identiska skyddshjälmar ropar det tyst \"den här är min.\" Det mest personliga märket, inristat ovanpå den hårdhet som skyddar huvudet."},"ICON-0746":{"nm":"Reflexskydd för hjul","de":"Ett skydd som först påbörjar sitt arbete när solen gått ner. Det fångar förbipasserande ljus och speglar hjulet tydligt tillbaka. I mörkret sänder det med ljus den lilla signalen: \"någon finns här.\""},"ICON-0747":{"nm":"Skyddsfodral för bilnyckel","de":"En bilnyckel som brukade repas mot andra nycklar i fickan. Ett mjukt fodral sluter tätt om den ytan. Önskan om att något man håller varje dag ska förbli repfritt och hålla länge ligger däri."},"ICON-0748":{"nm":"Sugfäste för hylla","de":"En sugkopp som utan en enda spik fäster en liten hylla på väggen med ett litet tack. Även en vägg man inte vill märka får därmed ett förvaringsfack. Konsten att hänga upp hushållet i ett rum man bara lånar, utan att lämna spår."},"ICON-0749":{"nm":"Hakskiva utan borrning","de":"Tänk att kunna hänga upp något utan att borra i väggen. En hakskiva utan borrning tar tyst på sig lätta laster. Önskan om att inte skada ett lånat utrymme ligger fint förvarad i en enda liten hake."},"ICON-0750":{"nm":"Magnetisk ordningsstång","de":"Ljudet av metall som klickar fast på plats. Dra samman de små verktyg som spritts åt alla håll med en magnet, och en kaotisk arbetsbänk ordnar sig i en rak rad – en liten tillfredsställelse följer med."},"ICON-0751":{"nm":"Förvaringsstång för trånga utrymmen","de":"Tänk dig den smala, bortglömda springan mellan kylskåpet och väggen. En smal stång fyller den springan med användbarhet. En sparsam idé som lockar fram förvaring ur ett utrymme man ansåg värdelöst."},"ICON-0752":{"nm":"Häftplatta","de":"En häftplatta som, en gång fastsatt, bär även tunga saker med lätthet. Dra loss den och märkligt nog finns inte ett enda märke kvar. En tyst, envis styrka som bär tyngd från en osynlig plats."},"ICON-0753":{"nm":"Krok för dörröverkant","de":"En krok som bara behöver hängas lätt över dörrens överkant. Väskor och handdukar dinglar rätt inom räckhåll. En hängare född utan en enda spik ger ett rum till, med lite extra andrum, i ett trångt utrymme."},"ICON-0754":{"nm":"Väggklämma för kablar","de":"En klämma som samlar sladdarna som hängde ner längs väggen till en enda ordnad linje. Nystet bakom skrivbordet rätas ut till en ren sträcka. Osynlig ordning gör till och med rummets luft en aning lättare."},"ICON-0755":{"nm":"Underlägg för bordslampans fot","de":"Ett underlägg man varsamt lägger under foten på en bordslampa. Det lämnar inga repor på skrivbordet och dämpar även den svagaste skakning. Även att resa ett ljus börjar med ett golv som inte vacklar."},"ICON-0756":{"nm":"Halkskyddande häftplatta","de":"Mattan som smygande gled undan under fötterna stannar äntligen på sin plats, för häftplattan biter fast i golvet. Ett osynligt skyddsnät som tyst tar bort de nästan-fallen innan de hinner ske."},"ICON-0757":{"nm":"Spetsskydd för precisionsskruvmejsel","de":"\"Just den här lilla skruven vill inte lossna.\" Ett skydd över spetsen på en precisionsskruvmejsel skyddar bladet. Fingertoppens mest finstämda redskap, som öppnar den handflatsstora världen inuti en maskin."},"ICON-0758":{"nm":"Ring för insexnycklar","de":"En ring som trär flera insexnycklar på en enda ögla. Metallen, ordnad efter storlek, fläktas ut som en solfjäder med ett sväng. Handens ordnade rytm när den med ett enda grepp plockar ut just den den behöver."},"ICON-0759":{"nm":"Charm med minimåttband","de":"En charm fäst vid ett minimåttband som får plats i handflatan. Den hänger på nyckelringen och följer med vart som helst. En liten vän som mäter och svarar på plats, på den längd som plötsligt väckt din nyfikenhet."},"ICON-0760":{"nm":"Sorteringslåda för skruvar","de":"En sorteringslåda där omaka skruvar var och en finner sitt eget fack. Även de små delarna som en gång rullade omkring i en enda röra får nu ordning. Handen som lär sig städa först, innan den lagar något."},"ICON-0761":{"nm":"Munstyckeslock för lim","de":"Stängd stelnar jag inte, öppen torkar jag ut – jag lever däremellan. Med varje droppe som faller lagas någonstans något trasigt ihop på nytt. Ett enda litet lock vakar tyst över gränsen mellan stillhet och flöde."},"ICON-0762":{"nm":"Nyckelring med vattenpass","de":"En handflatsstor ärlighet som dinglar i änden av en nyckelknippa. Det är alltid denna lilla luftbubbla som först märker en sned hylla. Jag bär i fickan en vän som tyst berättar att världen har blivit lite skev."},"ICON-0763":{"nm":"Spetsskydd för pincett","de":"Ju vassare något är, desto mer behöver det ett plagg som stillar det. Täck spetsen varsamt så skadas varken handen eller delarna. Den första artigheten i att hantera något vasst är att stilla täcka dess spets – detta lilla skydd tar på sig den vänligheten."},"ICON-0764":{"nm":"Liten skärmatta","de":"En skiva vars ärr läker av sig själva även efter tusentals passager av bladet. Nästa uppgift läggs ovanpå snittet, och åter läker det. En tyst botten som ger av sin egen kropp för att annat ska kunna skäras rent."},"ICON-0765":{"nm":"Påse för reservdelar","de":"En påse som knyter ihop munnen så en enda skruv, en enda fjäder inte försvinner för gott. De små sakerna som blir kvar efter en reparation väntar tyst här på sin nästa tur. Det är alltid sådana här obetydliga fack som förhindrar att något går förlorat."},"ICON-0766":{"nm":"Klämma för snackspåse","de":"Att bevara sprödheten i en öppnad påse handlar till syvende och sist om ett enda beslutsamt grepp. Ett litet löfte om att inte ge fukten en chans. Vanan att nypa ihop änden ordentligt räddar morgondagens mellanmål."},"ICON-0767":{"nm":"Portionsbägare för gelégodis","de":"För att dela en påse mellan flera måste man först dela rättvist. Hjärtat som skopar en lika stor andel i varje liten bägare. Att dela tror jag börjar med exakt samma mängd, så ingen känner sig förbisedd."},"ICON-0768":{"nm":"Chokladfolieskrap","de":"Det silver som svepte in sötman skrynklas lätt mellan fingrarna. Släta ut den och den glimmar ett ögonblick; vik den och den blir ett minne. En liten bit ljus som blir som vackrast först sedan allt är uppätet – ta en sista titt innan du kastar den."},"ICON-0769":{"nm":"Etikettband för snacks","de":"Vad som finns inuti, hur länge det håller sig gott – jag talar i den tysta påsens ställe. I samma stund ett enda band fästs får till och med ett mellanmål ett namn och ett löfte. Att sortera är i grunden det ömsintaste sättet att minnas."},"ICON-0770":{"nm":"Sorteringslåda för godis","de":"Det syrliga och det söta placeras inte i samma fack. Arbetet med att skilja dem åt i förväg så handen inte tvekar. När de små lådorna ställer upp sig på rad fördubblas glädjen i att välja, obemärkt."},"ICON-0771":{"nm":"Skyddspapper för kakor","de":"Tunt papper instucket mellan kakorna så de inte blir bucklade på vägen. Ju sköraro en sak är, desto mjukare sällskap behöver den. Ibland skyddar mjukhet bättre än hårdhet."},"ICON-0772":{"nm":"Snöre till donutlåda","de":"En enda korslagd knut ansvarar för att tårtan i lådan kommer fram helskinnad. Den blir ett handtag, en försegling, ett tecken på förväntansfull väntan. Ögonblicket detta snöre knyts upp är någons födelsedag."},"ICON-0773":{"nm":"Klämma för brödpåse","de":"Vrid en gång, vik, och sätt mig på, så förseglas brödets fuktighet ända till nästa morgon. En liten, envis beslutsamhet att stänga ute luften. Att länge bevara något mjukt är alltid uppgiften för något stadigt."},"ICON-0774":{"nm":"Bytesbricka för mellanmål","de":"Din andel till mig, min andel till dig. Minns du spänningen den dagen ni skrev namn på små brickor och bytte mellanmål? På papperet som fästs vid ett delande hjärta står alltid en väns namn skrivet tydligt."},"ICON-0775":{"nm":"Sugrörslock","de":"När du gör en paus mellan klunkarna stänger du mig. Så att inget spills, så att det inte kallnar, så att det väntar stilla just där. Det är en liten propps uppgift att vakta öppningen tills läpparna återvänder."},"ICON-0776":{"nm":"Namnring för termosmugg","de":"En liten ring som säger \"den här är min\" bland en rad termosmuggar som står sida vid sida. En enda färg, och förväxlingen löses sakta upp. En enda ring räcker för att tydligt markera vad som är ditt."},"ICON-0777":{"nm":"Kopphylsa","de":"Ett enda lager wellpapp som smyger sig in mellan den varma koppen och handflatan. En omtänksamhet instucken så du varken bränner dig eller tappar greppet. Att vaka över utrymmet däremellan är just det som fulländar en olycksfri kopp."},"ICON-0778":{"nm":"Etikett för isbricka","de":"Det finns de som skriver datum på varje omgång is de gjort. I tron att även kylan har en ordning. En enda liten etikett låter tiden i frysen flyta ärligt, i sin tur, det ena efter det andra."},"ICON-0779":{"nm":"Tetång","de":"Man vakar över dragtiden och lyfter upp den vid precis rätt ögonblick. Handlaget att veta när man ska sluta innan det blir för starkt. Teets djup avgörs mindre av hur länge det dras än av tidpunkten man drar upp det."},"ICON-0780":{"nm":"Ställ för dropfilter","de":"Det bär upp filtret och står tyst så att det heta vattnet kan rinna långsamt ner. Det vet väl att brådska gör doften tunn. Även arbetet att bära upp tålamod kräver en orubblig hållning."},"ICON-0781":{"nm":"Flaskrem","de":"En rem som hänger vattenflaskan vid handleden eller axeln för att vandra tillsammans. Ett sätt att hålla sällskap som gör att den alltid finns nära utan att man behöver tänka på att packa den. Ibland är en lätt knuten rem det ömsintaste sättet att inte glömma."},"ICON-0782":{"nm":"Locköverdrag för läskburk","de":"Det täcker mynningen på en burk man druckit av för att hålla damm ute och kolsyran kvar. En liten hatt som ansvarar för friskheten fram till nästa klunk. Även handlingen att stilla täcka något som stått öppet en stund bär omsorg i sig."},"ICON-0783":{"nm":"Hållare för dryckeskupong","de":"Den tionde koppen gratis – kortet med stämplar bärs varsamt så det löftet inte går förlorat. Så att dagarna, ifyllda ruta för ruta, inte skrynklas ner. I denna hållare samlas stamkundens flitiga fotsteg."},"ICON-0784":{"nm":"Band för matlåda","de":"Ett band som kramar matlådan ett varv om så locket inte poppar upp. En liten trygghet om att ingen soppa läcker ut i väskan. Den trygga vägen fram till lunch vilar i detta ena stadiga varv."},"ICON-0785":{"nm":"Set med tillbehörskoppar","de":"Ge varje tillbehör sin egen plats och smakerna blandas inte. Kimchi förblir kimchi, grönsaker förblir grönsaker, var för sig tydliga. Fackindelningen som dessa små koppar skapar är matlådans ordning, och en ömhet ovanpå matlagningens handlag."},"ICON-0786":{"nm":"Ätpinnefodral","de":"Ett litet hem som håller rent och bär med sig de ätpinnar som delat dagens alla tre måltider. Ett tyst sällskap som håller sin prydlighet även inuti en skolväska. Omsorgen att bära dem med sig är, till syvende och sist, det som skapar en ordentlig måltid."},"ICON-0787":{"nm":"Etikett för såsflaska","de":"Sojasås eller vinäger? Den ger tydlighet åt flaskan man brukade förväxla. I samma stund en enda rad fästs försvinner fingertopparnas tvekan. Ett hektiskt kök får sitt tempo tyst format av just sådana här små markörer."},"ICON-0788":{"nm":"Rullmatta för gimbap","de":"Ett tunt blad av tång som rullar ris och fyllning till en enda kropp. Vira det stadigt så det inte faller isär vid skärningen. Förväntan en utflyktsmorgon rullas rund och fram just ur detta enda lager."},"ICON-0789":{"nm":"Hållare för spett och tandpetare","de":"Ställ upp spett och tandpetare på ett ställe, så famlar handen inte i det avgörande ögonblicket. Att ge även de vassa sakerna ett eget hem. Att städa är, till syvende och sist, en liten vänlighet för nästa hand som ska ta tag."},"ICON-0790":{"nm":"Överdrag för kylklamp","de":"Man sveper ett lager till om kylklampen för att hålla kylan lite längre. Samtidigt håller det väskan från att bli fuktig av kondens. Att bevara svalkan ända till slutet är alltid detta tjocka enda lagers uppgift."},"ICON-0791":{"nm":"Avdelare för matlåda","de":"En liten mur rest så att ris och tillbehör inte inkräktar på varandras plats. Friden i ett fack där soppan inte flödar över. En matlåda uppdelad i fack bär, orört, den varsamma omtanken hos den som lagade maten."},"ICON-0792":{"nm":"Kort för måltidsordning","de":"Soppa först eller ris först? Ett kort som mjukt antyder dagens gång. En vänlig anvisning om att det smakar bättre ätet i ordning. Det berättar stilla att även en måltid har ett flöde, likt en berättelse."},"ICON-0793":{"nm":"Klistermärke för måttbägare","de":"Ett litet klistermärke bredvid skalan pekar exakt ut \"hit och inte längre.\" Ett märke som i ett enda drag ger rätt mängd, den man alltid tvekade om. Precision springer, just så, ur en enda liten guidelinje."},"ICON-0794":{"nm":"Silikonhandtag för lock","de":"Ett litet handtag som låter dig lyfta ett hett lock utan att bränna fingrarna. Det lånar dig tyst modet att öppna en ångande gryta. Trygghet kommer alltid av att i förväg ordna en plats att greppa."},"ICON-0795":{"nm":"Liten klämhängare","de":"En liten klämma som ger en plats åt disktrasor och påsar som annars saknat nånstans att hänga. Den förvandlar en stökig bit vägg till en ordnad utsikt. En enda vana att hänga upp saker gör köket betydligt lättare."},"ICON-0796":{"nm":"Skydd för oljepensel","de":"Täck spetsen på oljepenseln, så går både damm och intorkning den förbi. En hatt som bevarar den mjukheten fram till nästa maträtt. En liten omtanke om redskapet är, till syvende och sist, det som bevarar smaken länge."},"ICON-0797":{"nm":"Saltkruka med sked","de":"En liten sked som bor fast instucken i saltkrukan. Den skopar noggrant upp precisionen av en enda nypa, varje gång. Handlaget att smaksätta rätt är just den omtanke denna lilla sked minns."},"ICON-0798":{"nm":"Magnetisk timertavla","de":"Fäst på kylskåpsdörren räknar den ner 3 minuter för nudlar och tar tid på 30 sekunder träning. Med en enda magnet dröjer tiden som håller på att glida bort framför dina ögon. En flitig liten cirkel som en stund fäster det förbiilande på väggen."},"ICON-0799":{"nm":"Överdrag för grythandtag","de":"Ett lager som sveper om så du slipper ta i ett hett handtag med bara handen. En liten sköld som ställer sig mellan hettan och handflatan. Att flytta en gryta oskadd börjar alltid med denna mjuka omslutning."},"ICON-0800":{"nm":"Halkskyddsgummi för skärbräda","de":"När jag läggs under den glider skärbrädan inte längre. En bit gummi som håller emot underifrån varje gång knivarbetet skakar. Stabilitet är arbetet att bita fast stadigt på en plats ingen ser."},"ICON-0801":{"nm":"Köksvantklämma","de":"En plats där handen som rört sig oavbrutet framför lågan äntligen får vila en stund. Nypa fast en flaxande vante på väggen, och en kort andhämtning inleds innan nästa måltid. Att städa undan är, i grunden, bara ett annat namn för ömhet."},"ICON-0802":{"nm":"Kaffepinnhållare","de":"Bredvid disken, en plats där smala pinnar lutar sig mot varandra, prydligt travade. Redo att rita en virvel i någons morgonkopp, uppradade som en kör alldeles innan de stämmer upp."},"ICON-0803":{"nm":"Underläggsband","de":"Ett band som mjukt fångar det lilla klirret när ett glas möter bordet. Bunta ihop de runda underläggen, och gästfriheten står redo. Värdskap börjar alltid, precis så här, i de minsta av platser."},"ICON-0804":{"nm":"Sirapsetikett","de":"Ett enda namn på flaskan. Sött, kraftigt — det där korta ordet lugnar en hektisk morgon till något lite mer ordnat. En etikett är papper där ett litet löfte skrivs ner i förväg."},"ICON-0805":{"nm":"Dessertpinnburk","de":"En burk där de spetsiga pinnarna som spetsar upp en fruktbit bor tillsammans. Innan de planteras som flaggor på en dessertassiett väntar de tyst här på sin tur. Även sötma har sin ordning."},"ICON-0806":{"nm":"Muddlerskydd","de":"En papperskappa som omfamnar en handfull rörpinnar. Den suger upp fukten som en kall dryck lämnar efter sig, och håller fingertopparna som håller glaset torra. Osynlig omtanke kommer alltid från kanterna."},"ICON-0807":{"nm":"Take-away-bärarlapp","de":"När två händer inte räcker till bär ett litet handtag koppen åt dig. Det håller den inpackade värmen så att inte en droppe spills, och följer den värmen ända till hörnet av någons gränd."},"ICON-0808":{"nm":"Kafépagerskydd","de":"En kappa som tyst sveper in väntan tills pagern surrar till. Den vakar över den lysande könumret i ett hörn av kaféet, och bär också med sig spänningen inför att ditt nummer snart ska ropas upp."},"ICON-0809":{"nm":"Stämpelkupongring","de":"Papper där man får en kopp på huset när alla tio rutor är fyllda. För varje stämpel som läggs till växer även namnet ”stamgäst” lite till. En anspråkslös liten glädje, trädd på en liten ring."},"ICON-0810":{"nm":"Kaffebönsprovpåse","de":"En påse som rymmer en handfull bönor och bjuder på doften först. Syrligheten och sötman som stryker förbi näsan, det första intrycket avgör en kopps öde. Doften anländer alltid snabbare än någon förklaring."},"ICON-0811":{"nm":"Kylskåpsetikettmagnet","de":"En liten magnetisk namnlapp som klickar fast på kylskåpsdörren. Anteckna vad som kom in och när, och även en tillbehörsrätt som nästan glömts bort får tillbaka sin tur. Hushållsarbete är att fånga in ett minne som annars flyter iväg."},"ICON-0812":{"nm":"Förvaringsdatumbricka","de":"En liten bit som tydligt ristar in dagen något packades ner. Ett litet vittne som tyst intygar att detta fortfarande är gott, även dagar senare. Färskhet bevaras av fingertoppar som minns datumet."},"ICON-0813":{"nm":"Portionsburksband","de":"Ett band som sluter sig helt runt midjan på en uppdelad burk. Det håller det skramlande locket stadigt på plats och bevarar en liten ordning inne i kylskåpet. Att knyta ihop något liknar arbetet med att ordna upp hjärtat."},"ICON-0814":{"nm":"Färgade förslutningsklämmor","de":"Färgglada klämmor som biter fast stadigt om en påses mynning. Rött för starkt, gult för sött — handen vet redan bara av färgen. Kökets trafikljus visar vägen, precis så här, utan ett ord."},"ICON-0815":{"nm":"Frysförpackningsnamnlapp","de":"En namnlapp som läggs försiktigt ovanpå något fryst. Den tröstar den rimfrostiga påsen så att den inte glömmer vad den en gång var. En liten hälsning till ingredienser som gått in i sin vintersömn."},"ICON-0816":{"nm":"Grönsaksnät","de":"Ett glest nät som generöst tar emot jordiga grönsaker. Mormors kök visste sedan länge att de håller längre om de får andrum. Genomluftning är en öm marginal skänkt åt grönsakerna."},"ICON-0817":{"nm":"Flasklockssorterare","de":"En sorteringskork som parar ihop lock efter storlek, ett och ett. Att hitta en förlorad partner igen är ömmare än man tror. Ett rätt matchat par gör köket lite mer ordnat."},"ICON-0818":{"nm":"Äggbrickeetikett","de":"En markering prydligt tilldelad var och en av de tio små bona. Hushållets visdom som säger åt dig att använda de äldre äggen först. Även en enda morgonstekt ägg bär på omtanken om ordning."},"ICON-0819":{"nm":"Rester-klistermärke","de":"Skriv ”det här är mitt!” och sätt fast det, och även kylskåpet får en stunds fred. En gullig krigsförklaring som i förväg utser ägaren till nattmackan. Familjen rullar vidare, även idag, tack vare sådana obetydliga små fördrag."},"ICON-0820":{"nm":"Bestickställ","de":"En liten bit som mjukt håller upp sked och ätpinnar så att de inte rör bordet direkt. Denna lilla prydlighet höjer omärkligt en måltids elegans. Bordsskick växer tyst fram på just sådana platser."},"ICON-0821":{"nm":"Servettring","de":"En ring som tyst kläms fast och håller kvar en servett som annars skulle flaxa i vinden. Den samlar det vita pappret som väntar på sin tur att vecklas ut, och ristar in en liten ordning på bordet."},"ICON-0822":{"nm":"Bordstablett-hörn","de":"En bit som mjukt trycker ner och lugnar tablettens upplyfta hörn. Bordet lär oss varje dag att helheten först ligger plant när en ände hålls fast. Även ett hörn bär sin del av ansvaret."},"ICON-0823":{"nm":"Liten kryddbricka","de":"En liten bricka som håller en skål sojasås och en nypa salt sida vid sida. Bordets vida famn som ger även ett tillbehör sin egen plats. Koreansk matlagning fördjupas i omtanken om de små detaljerna."},"ICON-0824":{"nm":"Bordsnummerbricka","de":"Numret som ropas ut som ”bord si och så!” på en hektisk restaurang. Det ger väntan en ordning och bevarar rättvisan för alla. Vad denna enda bricka bär på är ett litet löfte, och en varm skål som snart kommer."},"ICON-0825":{"nm":"Vattenglasmarkeringsband","de":"Ett band som viras runt ett vattenglas och tyst avslöjar vems det är. En liten flagga som märker ut din plats bland likadana glas. Vid ett delat bord förhindrar just sådan omtanke onödiga missförstånd."},"ICON-0826":{"nm":"Assiettsorteringsnål","de":"En nål som sorterar assietterna man tar mat på efter färg. Den drar en vänlig gräns mellan ditt och mitt, och gör glädjen av att dela måltid ännu renare. Dela värmen, men håll hygienen prydlig."},"ICON-0827":{"nm":"Menyskärm","de":"Betänketiden som skymtas bakom en uppslagen menytavla. Även den korta tvekan om vad man ska äta är, i själva verket, en del av måltiden. Vad blir det till idag — den tavlan skymmer stilla den lilla spänningen."},"ICON-0828":{"nm":"Bordsplaceringshållare","de":"Ett litet ställ som håller en namnlapp upprätt. Vare sig det är på ett evenemang eller vid en fest, kungör det tydligt att här finns din plats. Gästfrihet fullbordas först i det ögonblick ett namn ropas upp."},"ICON-0829":{"nm":"Muffinsomslag","de":"En papperskappa som tätt sveper in den nybakade muffinens rundade midja. Den håller den varma kroppen så att den inte glider ur handen, och bevarar värmen ömt ända till första tuggan. Även efterrätter behöver en kappa."},"ICON-0830":{"nm":"Spritspåsehatt","de":"En propp som håller spetsen på en gräddspritspåse tätt tillsluten. Den försluter mynningen stramt så att inte en droppe läcker ut medan den vilar. Den lilla blomman ovanpå en tårta blommar ur denna återhållsamhet."},"ICON-0831":{"nm":"Kakformsring","de":"En rund uppsättning formar som skär ut deg i stjärnor och björnar. Samma mjöl vaknar till dussintals uttryck genom fingertopparna. Vad man än bakar är det alltid omsorgen som först rör vid degen."},"ICON-0832":{"nm":"Degskrapecharm","de":"En platt hand som sparsamt samlar ihop degen och delar den rent. Den flitigheten att ta hand om även den handfull som fastnat i skålen avgör volymen på en limpa. Bakning är en sparsam hands verk."},"ICON-0833":{"nm":"Måttskedsbräda","de":"En bräda som lägger ut måttskedar prydligt, utan att vackla — en tesked, en halv matsked. En exakt sked sätter smakens balans i rät position. Bakom uttrycket ”handlag” gömmer sig, i själva verket, noggrann mätning."},"ICON-0834":{"nm":"Ugnsvantekrok","de":"En krok att hänga vanten som stod vakt framför en het ugn på. Den tjocka handen som höll brännskador borta dröjer sig kvar inom räckhåll även under vilan. Säkerhet börjar alltid med det som stannar på sin rätta plats."},"ICON-0835":{"nm":"Svalningsgallerklämma","de":"En klämma som prydligt biter fast vid gallret där nybakat gods svalnar. Den håller dem stilla medan ångan avdunstar, och väntar tillsammans med dem på att knaprigheten ska fullbordas. Även svalning kräver en handfull tålamod."},"ICON-0836":{"nm":"Tårtdekorpinne","de":"En pinne som reser upp de fem bokstäverna i ”Grattis på födelsedagen” ovanpå en tårta. Alldeles innan ljusen slocknar lyser denna lilla flagga upp någons dag som starkast. Firande syns bäst när det höjs."},"ICON-0837":{"nm":"Florsockerstrilare","de":"En strilare som rymmer en sista lätt strilning. Den lägger sig som vit snö över en nybakad efterrätt, och förvandlar en vanlig bit till en liten gåva. Den sista touchen kommer alltid från den lättaste handen."},"ICON-0838":{"nm":"Triangelgimbap-etikett","de":"Skala av plasten i ordningen 1, 2, 3 och sjögräset återfår sin krispighet på den triangeln. En enda rad som gör att man på en blick känner igen en trofast vän från närbutiken i gryningen. De hungriga kvällarna efter sena pluggpass klänger fast just här."},"ICON-0839":{"nm":"Cupnudel-lockhållare","de":"En stödplatta som tyst trycker ner så att locket inte lyfter sig under de tre minuternas väntan. Den ersätter platsen där ätpinnarna en gång lades ovanpå för att hindra ångan från att fly. Den korta stunden nudlarna kokar är nattmackans mest spännande ögonblick."},"ICON-0840":{"nm":"Grillspettskydd","de":"En liten hatt som greppar stadigt om änden på ett spett. Den skyddar så att det är lätt att bita i, utan en droppe sås på handen. Glädjen i att småäta utanför en gatukökskiosk fullbordas alltid av just sådana småsaker."},"ICON-0841":{"nm":"Plastpåsehandtag","de":"Häng den på fingrarna och plasten knirkar svagt. Vikten av matvarorna lutar åt ena sidan, och vägen hem lämnar ett rött märke i handflatan. I det där lätta ljudet gungar en hel dags hushåll tungt."},"ICON-0842":{"nm":"Kvittovikningsklämma","de":"Vik ett långt utrullat kvitto på mitten och knäpp fast det, och dagens utgifter blir ett prydligt litet knippe. Medan pappret, doftande av bläck, staplas allt högre, faller även hushållets små minnen i prydlig ordning."},"ICON-0843":{"nm":"Mikrolapp","de":"Innan pling-ljudet hörs räknar lappen tyst ut uppvärmningstiden. En liten guide som anger minuter, sekunder och namnet på det som ska värmas. Även hjärtat som väntar på sin tur att bli varmt har sådana markeringar."},"ICON-0844":{"nm":"Rabattklistermärkesrulle","de":"Varje gång man river loss en ruta kittlar ett klibbigt litet knirr fingertopparna. När de röda siffrorna rullas ut på rad blir någons matkasse lite lättare. En rulle av liten vänlighet, hoprullad och väntande."},"ICON-0845":{"nm":"Såspåsering","de":"Något syrligt spricker till i mungipan och en vanlig dag blir lite sötare. När påsen som hänger från en rund ring svänger vid varje steg följer en liten sötma med mig hela dagen i fickan."},"ICON-0846":{"nm":"Närbutikskorgbricka","de":"Greppa den och plasten böjer sig lätt. En butik ljust upplyst sent på kvällen, djup nog för ett par triangelgimbap och en dryck. Ett omtänksamt kärl för precis en måltid, där man inte är ensam ens när man är det."},"ICON-0847":{"nm":"Makronaskband","de":"Ett enda band omfamnar lådan lugnt så att de färgglada makronerna inte skingras. Den som fått en present vet med fingertopparna att spänningen alldeles innan bandet knyts upp faktiskt är det sötaste av allt."},"ICON-0848":{"nm":"Fruktnätsklämma","de":"Samla ihop nätets mynning och nyp till, och doften av äpplen sipprar mjukt genom maskorna. En liten hand som håller dem så att de inte rullar ut. En tyst, öm uppmaning att äta upp dem snart, innan de blir mjuka."},"ICON-0849":{"nm":"Sylttygslock","de":"Det för tankarna till mormors sommarkök, där man täckte syltburkslock med en rund tygbit och band fast den med ett gummiband. Ett enda rutigt tygstycke förseglar in både den söta tid och den omsorg det tar för sylt att mogna. Handlaget förvaras på detta sätt, övertäckt."},"ICON-0850":{"nm":"Kakknytband","de":"Lägg nybakade kakor i cellofan och vrid fast bandet, och doften av smör tränger ända ut i bandets ändar. Handen som räcker fram något hemmagjort till någon darrar alltid lite. En knut som binder ihop även hjärtat."},"ICON-0851":{"nm":"Chokladavdelare","de":"Ruta för ruta ger den varje chokladbit en egen plats så att de inte rör vid varandra. Så att de inte smälter, så att de inte krossas. Vad en liten avdelare vakar över ända till slutet är, i grunden, en hel och odelad bit hjärta att räcka till någon."},"ICON-0852":{"nm":"Tegåvoetikett","de":"Ovanpå etiketten som viras runt en tepåse, ett namn prydligt handskrivet. Den lilla lappen viskar i förväg att bryggningen kommer föra med sig doften av gräs som stiger med ångan. En kopp som värmer händerna redan innan man dricker."},"ICON-0853":{"nm":"Godisflaskhalsband","de":"Ett halsband gjort genom att sno ett snöre runt halsen på en flaska full av färgglatt godis. Vid varje steg rullar ett litet pärlliknande ljud runt inuti. En stolt barndomsskatt, att bära sötma runt halsen."},"ICON-0854":{"nm":"Presentskedcharm","de":"Med en enda liten berlock hängande i skaftets ände blir en vanlig sked innan man vet ordet av en present. Ett lätt, klart pling vid varje skopa. Ett litet smycke som ger den skänkta känslan en extra finess."},"ICON-0855":{"nm":"Godisgåvotackbricka","de":"Önskan att ge tillbaka åtminstone lite av vad man fått. En tacklapp knuten löst fast på en godispåse. I stället för det ”tack” man inte riktigt hann säga färdigt, vandrar en liten hälsning tyst från hand till hand."},"ICON-0856":{"nm":"Maskeringstejpprovring","de":"Mönster klippta och fästa ett tumgrepp i taget radar upp sig i en liten remsa. Medan man med fingertopparna långsamt väljer vilken färg man gillar, färgar redan tanken på att pyssla dagen i många nyanser. En provrad där även tvekan är en glädje."},"ICON-0857":{"nm":"Klistermärkespincetthatt","de":"Sätt en hatt på pincettens spetsiga topp, och även ett spikstort klistermärke förblir oskadd. En precis hand som mjukt lyfter hörn fingrarna aldrig skulle nå. Att hantera det man älskar kräver alltid lite försiktighet."},"ICON-0858":{"nm":"Dagbokshörnsigill","de":"Sätt sigill på dagbokens fyra hörn, och de flaxande sidorna lugnar ner sig som genom magi. Känslan av papper som trycks lätt samman, ett litet ritual som prydligt förseglar dagen. Anteckningar blir stadiga med start från hörnen."},"ICON-0859":{"nm":"Hålslagsguide","de":"En bräda som i förväg visar var hålet ska slås. Passa in den lugnt längs den prickade linjen, och inget hamnar snett. Hjärtat som mäter en gång till utan att skynda — precisionen kommer alltid tyst ur just den där lilla stunden av lugn."},"ICON-0860":{"nm":"Pappersavklippsbricka","de":"Pappersbitarna som blir kvar efter sax-arbetet samlas mjukt in i brickan. Ett kort tillhåll för de små bitarna, så att skrivbordet inte skräpas ner. Efterspelet av pysslandet ordnas upp, precis så här, utan ett ljud."},"ICON-0861":{"nm":"Färgstämpeldyna","de":"Tryck lätt på dynan och lyft, och färg sprids fuktigt över fingertopparna. Rött, gult, blått — en liten regnbåge som fastnar i ett enda stämpelavtryck. En mjuk liten plats för att plantera färg, tapp för tapp, på vitt papper."},"ICON-0862":{"nm":"Dekortejprulle","de":"Mönstret som rullas ut, runt och runt, tar aldrig slut. Riv av en bit och fäst den, och blommor slår ut på en förut enkel plats. En rulle av liten magi, hoprullad och väntande, som blir vackrare för varje gång handen rör vid den."},"ICON-0863":{"nm":"Temastämpelhatt","de":"En liten mössa som tätt sveper in stämpelhuvudet så att bläcket inte torkar. Den vakar tyst så att nästa mönster förblir skarpt. En färg som förvarats väl blommar lika levande upp igen på nästa pappersark."},"ICON-0864":{"nm":"Dekorhålslagsbitar","de":"De små bitarna som hålslaget släpper med ett klick. Konfetti av färgat papper klippt till stjärnor, hjärtan och kronblad samlas i en mjuk hög i handflatan. Små juveler alltför vackra för att slänga, så man klistrar fast dem någon annanstans igen."},"ICON-0865":{"nm":"Trådrulle-etikettring","de":"En liten etikett med namnet på varje färgad tråd skrivet på varje trådrulle. En öm markör som pekar ut sin plats innan den trasslar till sig. Trassligt garn, och hjärtat med, blir så mycket lättare att reda ut med bara en enda namnlapp."},"ICON-0866":{"nm":"Nålboksfodral","de":"Ett mjukt fodral till filtboken där nålar sitter tätt instuckna. Öppna det, och sytillbehören ligger prydligt i rad och möter mig. En liten volym som ömt lullar de spetsiga sakerna till sömns, så att fingertopparna inte ska skadas."},"ICON-0867":{"nm":"Tygprovring","de":"Grovt eller mjukt, den långsamma stunden av att med fingertopparna känna sig fram, en efter en, genom tygets struktur för att välja. Bland tygbitarna samlade prydligt efter färg väntar tyget, innan det blir ett plagg, tyst på att först bli berört."},"ICON-0868":{"nm":"Broderiramring","de":"Sätt i tyget i den runda ramen och dra åt, och det blir spänt som ett trumskinn. Ett litet tecken på att allt är redo för att brodera, stygn för stygn. Vad ringen håller stadigt är inte tyget, utan den koncentrerade viljan."},"ICON-0869":{"nm":"Knappsorteringskapsel","de":"Knappar som brukade rulla hit och dit slår sig lugnt ner efter färg i varje kapselfack. Hushållets visdom att dela upp dem i små portioner så att inga går förlorade. Även att samla ihop det utspridda kräver denna mängd omsorg."},"ICON-0870":{"nm":"Skräddarkrit-hållare","de":"En hållare som greppar skräddarkritan, den som ritar linjer på tyg, bekvämt i handen. Den stöttar stadigt något som lätt går sönder. Det lugna första beslutet innan saxen lyfts — att en rak första linje gör plagget rakt med."},"ICON-0871":{"nm":"Knappnålsburk","de":"Inuti den genomskinliga burken skramlar och klirrar knappnålarna mot varandra. Håll den mot ljuset och en liten glimt lägger sig på varje nåls spets. Ett städat litet kärl som samlar på ett ställe, och lugnt lullar till sömns, det som är farligt när det är utspritt."},"ICON-0872":{"nm":"Lagningstejprulle","de":"En magisk remsa som tyst fastnar när man stryker den över ett sönderrivet ställe. Utan ett enda stygn läks ett slitet plagg tyst ihop. Sinnet som lagade och fortsatte bära i stället för att slänga bort ligger hoprullat, varv på varv, inuti den runda rullen."},"ICON-0873":{"nm":"Lappmönsterpapper","de":"Ett ark mönsterpapper där formen på en lapp ritats i förväg. En prickad linje visar vänligt vägen saxen ska gå. Att först skissa konturen av det man vill skapa — spänningen börjar alltid i just denna vaga underteckning."},"ICON-0874":{"nm":"Vattenfärgsburklock","de":"Sätt det på burkens mynning, och inte en droppe rinner ut, hur mycket det färgade vattnet än skvalpar. Det täcker till och med oron för att grumligt sköljvatten ska spridas över skrivbordet. En tyst propp som stilla vakar över platsen där man målar."},"ICON-0875":{"nm":"Pastellkritsskydd","de":"Vira ett band runt en pastellkrita som lämnar ett pudrigt smetigt spår, och fingrarna blir mindre smutsiga. Papper som mjukt sveper in den mjuka färgen så att den inte smulas sönder. Ju mjukare den är, desto varsammare måste man hålla den, så att den även målar mjukt på pappret."},"ICON-0876":{"nm":"Färgpennsförlängare","de":"Sätt en hatt på änden av en nednött färgpenna, och en stump blir lång igen. Sinnet som inte lätt slänger något bara för att det blivit kort. Från fingertopparna som använder den ända till slutet blir teckningens färg djupare, ända fram till den sista lilla rutan."},"ICON-0877":{"nm":"Penseltvättmugg-krok","de":"Häng sköljmuggen på en krok, och vattendropparna som fallit från penseln rinner sakta ner. Innan nästa färg målas, den korta, klara stillheten av att skölja penseln. Även i ljudet av att bli ren flyter en tyst rytm."},"ICON-0878":{"nm":"Palettkniv-hylsa","de":"En liten hylsa som tätt täcker bladet på kniven som breder ut och skrapar färg. Den vakar tyst så att den skarpa spetsen inte blir slö. Strukturen av tjockt pålagd färg föds ur denna enda väl omhändertagna egg."},"ICON-0879":{"nm":"Duk-klämma","de":"En stadig klämma som drar canvasduken spänd över en ram och håller den fast. Bit den hårt, och målningsytan sträcks trumtight. Bara med en obevekligt stadig grund kan penseldragen som löper över den röra sig helt fritt."},"ICON-0880":{"nm":"Ritbrädesrem","de":"Slå remmen över axeln, och brädan följer efter på ryggen. Slå dig ner var som helst, och just där blir din alldeles egna ateljé. En liten ateljé buren på ryggen, som lätt beger sig ut på jakt efter ett motiv att teckna."},"ICON-0881":{"nm":"Akrylfärgtub","de":"Lägg till en droppe vatten och det blir gryning, en droppe mindre och det blir midnatt. Samma blå öppnar en annan himmel varje gång vid fingertopparna. I stunden man klämmer ur en tub sprider sig dagens hjärtefärg över pappret."},"ICON-0882":{"nm":"Gradientprovark","de":"Detta papper visste först att en solnedgång inte rodnar på en gång. Små trappsteg som korsar från blekt till djupt. Ögat vandrar sakta mellan dem och följer stilla den tid det tar för färgen att mogna."},"ICON-0883":{"nm":"Virknålshatt","de":"Ett fingerborgsstort skydd man sätter på innan garnet skär in i fingret. En hand van vid stickning vet det. Bara genom att förbli oskadd kan man bära det ömt ända till den sista maskan."},"ICON-0884":{"nm":"Stickmarkeringsring","de":"En enda markör, och var man kommit blir tydligt igen. Tryggheten i att aldrig behöva räkna samma maska två gånger. Hjärtat med, bara på det viset — när man mjukt markerar platsen man kommit ifrån — tappar man inte bort vägen."},"ICON-0885":{"nm":"Varvräknarcharm","de":"Ett tyst bevis på en färdig varv travas upp, ruta för ruta. Även ett arbete som verkade oändligt är plötsligt förbi halva vägen när man räknar det bit för bit. En liten uppräkning bär dagens hjärta hela vägen fram."},"ICON-0886":{"nm":"Trådändeordnare","de":"Lämna en lös trådände som den är, och man vet aldrig var nästa knut trasslar till sig. En hand som i förväg ordnar upp en plats som ändå inte kommer synas. Ömhet rör sig oftast, precis så här, först på platser utom synhåll."},"ICON-0887":{"nm":"Knytövningssnöre","de":"Rak knop, rosettknop, ringknop. Man binder och löser upp samma snöre tills handen memorerar formen. När klumpiga fingertoppar plötsligt blir mjuka en natt, är det just den där strängen som vet det först."},"ICON-0888":{"nm":"Garnnystanetikett","de":"En liten remsa som antecknar tjockleken och färgen för varje nystan. Det är en vana född ur nätter av förgäves letande efter samma garn först efter att det tagit slut. En anteckning är ett ömt meddelande till ens framtida jag."},"ICON-0889":{"nm":"Maskprovbit","de":"Hur många maskor som ryms på 10 centimeter — den lilla siffran avgör storleken på ett helt plagg. Att en handflatestor bit bär hela måttet är, när man lyfter den, faktiskt ganska tungt."},"ICON-0890":{"nm":"Knapphålsmarkör","de":"Innan man syr fast en knapp märks en enda prick ut där hålet ska göras först. Tack vare den snart försvinnande markeringen blir inte kanten sned. Omsorg dröjer sig oftast kvar, tyst, på en plats som till slut aldrig syns."},"ICON-0891":{"nm":"Liten tofsring","de":"Precis som tofsen i änden av en norigae skapar en liten ring en svängning. Blicken dröjer alltid vid det som hänger och stilla guppar. En textur som tyst vaknar till liv varje gång vinden drar förbi."},"ICON-0892":{"nm":"Miniatyrfärgflaska","de":"Att hantera färg rätt handlar inte om att spara på den, utan om att använda den exakt. En färg där en enda droppe räcker, avvägd med en hand hållen intill den lilla flaskan. Måttfullhet kommer av att en gång lägga girigheten åt sidan."},"ICON-0893":{"nm":"Liten slippinne","de":"Man börjar på den grova sidan och flyttar sig gradvis mot den fina. Det finns ingen yta någonstans som blir slät på ett enda drag. Från fingertoppar som sänker kornet steg för steg blir en tidigare skrovlig plats sakta mjuk."},"ICON-0894":{"nm":"Modellklämställ","de":"Håll en limmad del i handen och man lämnar fingeravtryck. Kläm fast den försiktigt, och händerna blir fria medan torkningen tyst avslutas för sig själv. Även väntan blir lättare när någon stöttar upp den åt en."},"ICON-0895":{"nm":"Limarbetsplatta","de":"Låt en droppe lim falla på skrivbordet, och märket dröjer sig kvar länge. Vanan att lägga ut en platta i förväg. Kanske börjar hälften av allt arbete just i den önskan att inte smutsa ner platsen."},"ICON-0896":{"nm":"Delsorteringsfack","de":"Blanda ihop dussintals likadana delar, och monteringen blir snart en labyrint. Handlaget att dela upp dem i varje fack skär i förväg ner på tiden man annars skulle gå vilse. Ordning är en vänlighet given till ens framtida jag."},"ICON-0897":{"nm":"Monteringsordningsbricka","de":"En liten bricka som anger vilken numrerad del som ska fästas först. Håll ordningen, och det rasar inte lätt samman. En modell, och vilken dag som helst byggd steg för steg, blir stadig på det tysta löftet."},"ICON-0898":{"nm":"Minipenselkrok","de":"Lägg en använd pensel ner, och borsten trycks samman och böjs. En plats att hänga den upp och ner på för att låta fukten rinna av. De som håller sina redskap nära sig länge är, om något, ännu flitigare och ömmare efter att arbetet är klart."},"ICON-0899":{"nm":"Plastspillburk","de":"En burk där avklippen som knipsats loss från ramen tyst samlas. De verkar bortkastade, men blir en dag en liten detalj som kommer tillbaka. Burken vet, medan den tyst väntar, att även det som blir över har sin tur."},"ICON-0900":{"nm":"Finishspray-hylsa","de":"Det sista lagret rinner rakt ner om det sprejas för nära. Från ett spanns avstånd, lätt, lätt. Att lägga på en glans är, kanske, också en övning i att en gång lägga hjärtats girighet åt sidan."},"ICON-0901":{"nm":"Stiftetui","de":"Tunna blyertsstift går lätt sönder i fickan. Läggs de prydligt i ett litet rör går inte en enda stiftbit till spillo. Att ordna är i grunden ett tyst sätt att redan nu ta hand om morgondagens jag."},"ICON-0902":{"nm":"Suddgummifodral","de":"En liten papperskappa klädd över ett suddgummi. Ju svartare den blir av användning, desto fler spår av rättelser har den samlat. Att sudda är också ett ömt tillstånd att få börja om från början."},"ICON-0903":{"nm":"Pennspetsrör","de":"Pennspetsar spricker när de torkar och böjs när de stöts till. Ett litet rör att lägga dem i var för sig bevarar skriftens karaktär länge. Ett redskap som hanteras varsamt glider varsamt tillbaka i gengäld."},"ICON-0904":{"nm":"Bläckprov","de":"Bläck man testar droppe för droppe. En färg man trodde var turkos blir ett djupt hav på pappret. Färg är något man alltid måste möta på riktigt – nyansen man föreställer sig i tanken missar så ofta målet."},"ICON-0905":{"nm":"Bokpilsburk","de":"En liten flagga man varsamt sticker in där man slutade läsa. Öppnar man boken nästa gång vinkar gårdagens jag och väntar. Även platsen där man pausade blir ett löfte, det lilla märkets ömma uppgift."},"ICON-0906":{"nm":"Markeringsflikar","de":"Riv loss ett blad och fäst det, så börjar historien om direkt därifrån. När de små flaggorna radar upp sig längs bokens kant samlas spridda tankar prydligt till en enda karta."},"ICON-0907":{"nm":"Gemsamlarmagnet","de":"En liten magnet som sopar upp spridda gem på en gång. Ju mindre en sak är, desto lättare tappas den bort, så en enda samlande kraft räddar tyst ett rörigt skrivbord. Det finns ömhet även i att dra saker samman."},"ICON-0908":{"nm":"Pennhattssats","de":"Små hattar som täcker pennspetsen och skyddar väskans insida. Något vasst sticker alltid hål på något, så det behövs en hand som varsamt täcker över. Hållas vass, men aldrig såra."},"ICON-0909":{"nm":"Namnskyltklistermärke","de":"I samma stund man skriver sitt namn och fäster det på skrivbordet blir platsen äntligen någons egen. När till och med ett utrymme på en handsbredd får en ägare förändras rentav sättet man slår sig ner med hjärtat."},"ICON-0910":{"nm":"Hopprepshandtagskåpa","de":"En kåpa man sätter på innan handtagets ände nöts och spricker. Rytmen av ett rep snurrat tusen gånger minns handflatan förr än huvudet. En takt inpräntad i kroppen glöms sällan bort."},"ICON-0911":{"nm":"Yogaringrem","de":"Håll i ringen och öppna kroppen sakta. Ju stramare remmen dras, desto mer löser de stela axlarna upp sig, lager för lager. Att sträcka ut handlar mindre om att tvinga fram ett drag och mer om att tyst vänta tills kroppen öppnar sig."},"ICON-0912":{"nm":"Bordtennisbollfodral","de":"En vit boll så lätt att den rullar långt bort, och trycks platt i samma stund man trampar på den. Ett litet fodral skyddar den ömtåligaste bollen fram till nästa match. Fasthet kommer ofta av att bli mjukt omsluten."},"ICON-0913":{"nm":"Badmintongreptejp","de":"Ett prydligt varv lindas runt ett handtag som glider av svett. På ett väl lindat grepp blir racketen en del av handen. Hemligheten att slå med känsla snarare än kraft gömmer sig i detta tunna enda lager."},"ICON-0914":{"nm":"Liten poängbricka","de":"En poäng, sedan en till. Genom att flytta små brickor byggs poängen upp bit för bit. När räkningen syns blir matchen tydligare, och modet att kapa in ett enda poängs skillnad stiger sakta fram också."},"ICON-0915":{"nm":"Skoriktningsklämma","de":"Prydligt uppställda skotår pekar alltid åt samma håll. En liten vridning av handen när man tar av dem. Ett litet mått av ordning gör morgondagens steg så mycket lättare."},"ICON-0916":{"nm":"Visselpipssnodd","de":"Häng en visselpipa om halsen och man får rätten att säga stopp. Synen av en hel skolgård som stannar tvärt vid ett enda kort ljud. Hjärtan som litar på det lilla ljudet samlas och blir ett löfte."},"ICON-0917":{"nm":"Bollpumpsnålsrör","de":"Även en tömd boll spänns åter med en enda tunn nål. Den nålen, varsamt förvarad i ett litet rör, gör hela pumpen värdelös i samma ögonblick den försvinner. När den minsta saken betyder mest."},"ICON-0918":{"nm":"Minitrafikkon","de":"Härifrån till dit, en liten kon ritar upp en gräns man annars inte kunde se. Utan någon linje alls faller människor ändå naturligt in i led efter markeringen. Ordning växer tyst ur just sådana små signaler."},"ICON-0919":{"nm":"Polettpåse","de":"En påse som samlar klirrande polletter på ett ställe. Dras snöret åt skingras ingenting. Även små, obetydliga ting behöver ett ställe att förvaras på innan de kan göra sin del, det visar påsen utan ett ord."},"ICON-0920":{"nm":"Kortblandningsmatta","de":"På ett halt skrivbord ligger korten inte bra i handen. En matta gör både blandning och plockande så mycket smidigare. Även i att leka väl finns en öm förberedelse: att först välja underlaget."},"ICON-0921":{"nm":"Hörnskydd för spelplan","de":"När en spelkväll tar slut är det alltid någon som tyst ser till spelplanens fyra hörn först. För de vet att ett djupt veck skevar nästa omgång. I fingertopparna som slätar ut kanterna ligger önskan att leka tillsammans igen imorgon."},"ICON-0922":{"nm":"Tärningsbägarlock","de":"Det korta ögonblicket då alla skakar, rullar och håller andan tillsammans. Det är ett litet tak som hindrar tärningarna från att hoppa ut. Under locket hämtar dagens tur andan ett ögonblick innan den skramlar sig ut."},"ICON-0923":{"nm":"Brickjusteringsplatta","de":"Ju mer hänförd någon är av spelet, desto skevare blir raden. Att tyst knuffa lutande brickor tillbaka i en prydlig linje. Att räta upp är en hand som ömt tar emot någons upprymda otålighet."},"ICON-0924":{"nm":"Poängbrickeburk","de":"Ju fullare en burk med brickor blir, desto hetare blir också spelet. När de runda poängen skramlar mot varandra i handflatan blir just det ljudet en glädje innan vinst eller förlust ens hinner betyda något."},"ICON-0925":{"nm":"Turmarkeringsring","de":"En liten ring som visar att det nu är din tur. Just i det ögonblicket man flyttar den ett hack samlas allas blickar stilla på mig. En ring som sakta snurrar mellan väntan och förväntan."},"ICON-0926":{"nm":"Spelpjässockel","de":"Ju lättare en pjäs faller omkull, desto stadigare måste dess fot vara. En sockel håller sin plats även på en lätt vinglig spelplan. Det lilla måste hålla stånd för att det stora ovanpå ska stå rakt."},"ICON-0927":{"nm":"Spelregelklämma","de":"Ett regelhäfte som lämnas uppslaget bläddrar sig alltid smygande vidare. Innan vinden låter sidorna springa sin väg biter denna klämma varsamt fast en sida. Reglerna måste hållas kvar för att leken ska räcka ända till slutet."},"ICON-0928":{"nm":"Plektrumfodralssnodd","de":"Ett gitarrplektrum glider alltid ur fingrarna just vid det mest spännande partiet. Ett band som hänger från fodralet stoppar den lilla flykten. Bara den som upplevt en kväll då musiken tystnade vet att uppskatta detta band."},"ICON-0929":{"nm":"Rörbladsrör","de":"Ett rörblad förlorar sin röst i samma stund det torkar. Inne i ett fuktigt rör väntar ett smalt vasstrå på nästa föreställning. En plats att först vila andan på, innan man blåser den tillbaka."},"ICON-0930":{"nm":"Strängvinda","de":"När en sträng slaknar sjunker tonen tyst med den. Att långsamt vrida handtaget och återfå spänsten – omsorgen kommer alltid från handleden. Ett prydligt ljud börjar just i sådana små handlingar av ordning."},"ICON-0931":{"nm":"Instrumentputsduk","de":"När ett framträdande tar slut lämnar det en svag svettdoft kvar även på instrumentet. Ett svep med en mjuk duk för tillbaka glansen och låter dagens toner sjunka lugnt till ro. Ett omtänksamt hjärta visar sig alltid i avslutningen."},"ICON-0932":{"nm":"Stämskruvsskydd","de":"Lämnas stämskruvarna bara nakna rostar de innan man vet ordet av. Ett litet skydd bromsar metallens årstider med en takt. Den som tar hand om de osynliga hörnen först är den som spelar längst."},"ICON-0933":{"nm":"Notställsklämlampa","de":"Bakom en mörk scen finns stunder då bara noterna måste lysa. En liten lampa fäst på notstället som varsamt låter ljuset sila ner. En handfull sken som lyser vägen så att tonerna aldrig tappar bort sig."},"ICON-0934":{"nm":"Dämpningskåpa för övning","de":"Gryningsövningen tvistar alltid tyst med grannens sömn. Sätt på en kåpa och det mäktiga ljudet krymper till en viskning. Det finns musik som växer just genom att vaka över någons ljuva sömn."},"ICON-0935":{"nm":"Trumpaddklistermärke","de":"Små markeringar fästa på en trumpad. Var man ska slå för vilket ljud – ögonen lär sig vägen innan händerna minns den. En takt inpräntas så här sakta i kroppen."},"ICON-0936":{"nm":"Melodianteckningsbricka","de":"En nynnad melodi försvinner fort om man inte fångar den. Några takter hastigt klottrade på en bricka växer ibland en dag till en hel sång. Inspiration återvänder alltid till den hand som flitigt antecknar."},"ICON-0937":{"nm":"Bokomslagsband","de":"Det är besvärligt när en halvläst bok viker upp sig av egen kraft i väskan. Ett band knyter försiktigt ihop sidorna så de blir stillsamma. Ett löfte om att vika undan prydligt inför nästa sida."},"ICON-0938":{"nm":"Sidhållarring","de":"En dag man vill hålla upp en bok med ena handen och dricka varm kaffe. En ring man träder på fingret håller sidorna åt en. Lite ledighet börjar just i sådana små uppfinningar."},"ICON-0939":{"nm":"Lästidsbricka","de":"Bara ett kapitel till, tänker man, och plötsligt är natten sen. Trycker man på brickan och ställer in en tid får även läsningen ett kommatecken. Ju kärare saken man älskar, desto mer behövs modet att ömt kunna sluta."},"ICON-0940":{"nm":"Bokhörnskydd","de":"Ju kärare en bok är, desto tidigare nöts hörnen tyst ner. Sätt på ett skydd och pärmens hörn hålls runda och hela. En liten rustning man träder på för att hålla nära det man vill bevara länge, länge."},"ICON-0941":{"nm":"Läsanteckningsband","de":"Det finns stunder då en enda mening plötsligt sjunker tungt i bröstet. En reflektion nedskriven på ett band stannar kvar på den sidan som ett bokmärke. Understrykningens varma temperatur, känd bara av den som läst."},"ICON-0942":{"nm":"Återlämningsbricka","de":"Återlämningsdagen kommer alltid en dag för tidigt. När datumet på brickan tyst puttar en i ryggen får även en lånad bok avslutningens artighet. För nästa persons händer väntar biblioteket så."},"ICON-0943":{"nm":"Läslampa med klämma","de":"En natt man ligger vaken och läser ensam bredvid sovande familj. Ett litet ljus klämt fast på bokens kant räcker gott. Man behöver inte skjuta undan hela mörkret; för en sida räcker en stunds stillhet."},"ICON-0944":{"nm":"Bokdoftkort","de":"Gamla böcker doftar av solljus och papper i förening. Detta kort, sagt att bära den doften på ett enda blad, öppnas och väcker för ett ögonblick en antikvariatsgränd till liv vid nästippen. Minnet lägger bokmärke även med doft."},"ICON-0945":{"nm":"Lässidesnål","de":"Hur långt hade jag läst? En liten nål som suddar bort den hjälplösa frågan. Fäst den vid den sista meningen och morgondagens jag vandrar inte längre vilse. En öm markör som minns platsen man pausade vid, i ens ställe."},"ICON-0946":{"nm":"Mobilbandsberlock","de":"En berlock på ett mobilband får en person att se lite annorlunda ut. En favoritfärg, en favoritform. En liten smak man håller i handen gungar mjukt dagens humör."},"ICON-0947":{"nm":"Objektivskydd","de":"Reseresans fotons öde vilar på en enda lins. Ögonblicket man lyfter av skyddshatten är hjärtats beredskap att trycka av. Ett litet ritual, det första att öppna ögonen innan man fångar ett landskap."},"ICON-0948":{"nm":"Laddningsportplugg","de":"Damm i väskan siktar alltid först på laddningshålet. Täpp till den lilla öppningen med en plugg och porten hålls ren länge. Här finns en flit som tar hand om även de osynliga springorna."},"ICON-0949":{"nm":"Mobilringstöd","de":"Att ställa mobilen på sned bara för att se en video bekvämt. Fäll ut ringen på baksidan och både hand och skärm andas lättare. Ett litet upphöjt stöd förlänger en avslappnad kväll."},"ICON-0950":{"nm":"Skärmtorkarlapp","de":"En skärm full av fingeravtryck gör på nåt sätt även hjärtat grumligt. Ett svep med en lapp och världen blir klar igen. Renlighet är ibland en kort syssla för ett enda finger."},"ICON-0951":{"nm":"SIM-nålsetui","de":"En SIM-utmatningsnål är ett väsen som bara försvinner precis när man verkligen behöver den. Förvara den i ett fack i ett etui och man behöver aldrig mer leta genom hela huset efter en hårnål. Lite ordning räddar tyst en brådskande stund."},"ICON-0952":{"nm":"Klistermärke för laddningsplatta","de":"En natt då den fylls av sig själv medan man vilar den varsamt på plattan. Ett fastklistrat märke visar precis var telefonen ska ligga. En osynlig ström fyller tyst på en hel dags energi."},"ICON-0953":{"nm":"Aviseringstäckare","de":"Vissa aviseringar är skönare för hjärtat övertäckta. Ett enda klistermärke tystar gryningens lilla sken. Ibland är det att inte se ett ömt sätt att skydda sig själv också."},"ICON-0954":{"nm":"Objektivskyddsring","de":"I det ögonblick en kameralins vidrör golvet hoppar hjärtat till med ett ryck. En ring virad runt om avvärjer tyst det lilla fallet. En kant som skyddar, först av allt, ögat som fångar minnen."},"ICON-0955":{"nm":"Kabeletikett","de":"Att äntligen plocka ut sin egen ur en trasslig, hoptovad hög av kablar. En liten etikett ger till sist laddsladden ett eget namn. En liten flagga som visar vägen bland rörigt slingrande sladdar."},"ICON-0956":{"nm":"Laddarpåse","de":"Laddare i en reseväska tvistar alltid, hoptrasslade med varandra. Samla dem prydligt i ett fack i en påse och de sluter äntligen fred. Konsten att packa ligger i att ömt kalla samman det som spritts åt olika håll."},"ICON-0957":{"nm":"Grenuttagsetikett","de":"Grenuttagets hål ser alla likadana ut och förvirrar varje gång. Sätt etiketter och fastställ vems plats som är vems, så blir en stressig morgon mycket smidigare. En liten namnlapp minskar vardagens små tvister."},"ICON-0958":{"nm":"Sladdvinda","de":"Lindad av för att användas, vunnen tillbaka igen, en sladds prydliga dag. Rullas den lager för lager på en spole försvinner trasslet helt rent. Handen som lägger tillbaka det man använt gör morgondagen lättare."},"ICON-0959":{"nm":"Skydd för magnetkontakt","de":"En magnetisk kontakt drar till sig fint metalldamm innan man vet ordet av. Täck den med en kåpa och det kladdiga dammet fastnar inte. En apparat rörd av en extra omtänksam hand lever längre vid ens sida."},"ICON-0960":{"nm":"Powerbankband","de":"Lämnas ett powerbank och dess sladd åtskilda försvinner alltid den ena. Bind ihop dem med ett band och de blir äntligen ett par. En liten knut man varsamt knyter precis innan man går ut, för att be dem följas åt."},"ICON-0961":{"nm":"Uttagsdammskydd","de":"Ett tomt eluttag låter dammet tyst flytta in redan efter några dagar. När denna lilla kåpa vaktar platsen i dess ställe kan nästa laddare som ansluts dra ett rent första andetag. En dörrvakt som håller den tomma tiden fläckfri."},"ICON-0962":{"nm":"Kabelfärgring","de":"En natt då man famlade efter sin egen bland trassliga sladdar, vem var det som sa att vi skulle färga dem? Blått är du, gult är jag. Med en enda liten ring blandade vi aldrig mer ihop varandra. Ett spår av ett ömt löfte kvarlämnat i ett hörn av replokalen."},"ICON-0963":{"nm":"Adaptersorteringsbricka","de":"Runda stift och platta stift, 110 och 220. En bricka som tyst memorerat ansiktena på eluttag som skiljer sig land för land. I ett hörn av resväskan för den första resan över havet till scenen låg alltid detta lilla sorteringskort med."},"ICON-0964":{"nm":"Sorteringsbricka för öronproppar","de":"Man säger att öronkanaler skiljer sig i djup och bredd från person till person. Att lägga stora, medelstora och små sida vid sida och välja ut det enda par som passar precis ens öra. En öm procedur att först anpassa kroppen, innan man lyssnar på ljud."},"ICON-0965":{"nm":"Silikonring för mobilskal","de":"Scenkläder får omsorg ända ner till varje stygn, medan ett skals hörn alltid slår i bart. När denna tunna silikonkant varsamt omsluter kanten möter skärmen morgonen oskadd, även den gryning den gled ur handen."},"ICON-0966":{"nm":"Klistermärke för brusreducering","de":"Det finns dagar man vill stänga av världens ljud en stund. Detta lilla klistermärke på hörlurens öra är en markering som slår på tystnaden. En amulett som bär bort publikens jubel och tunnelbanans buller på avstånd, bara tills en låt tar slut."},"ICON-0967":{"nm":"Öronkrokset","de":"Dansar man rusar alltid den ena hörsnäckan iväg först. Häng på dessa krokar som varsamt omfamnar örats yttre kant, och även mitt i häftig koreografi stannar bara musiken kvar i örat ända till slutet. En liten upptäckt som övningsrummets folk delade med varandra."},"ICON-0968":{"nm":"Borstkåpa","de":"En liten hatt man sätter på så att dammet på borststråna inte flyger upp igen. Att även ett städredskap behöver städas visste redan för länge sedan den hand som ställde kvasten upp och ner efter sopningen."},"ICON-0969":{"nm":"Bottenplatta för laddningsdocka","de":"Att laddningsdockan ständigt gled på skrivbordet berodde på att den saknade fötter. När denna tunna platta på undersidan tar fötternas plats stannar apparaten stilla på plats och fyller tyst på energin hela natten."},"ICON-0970":{"nm":"Vänster-höger-markering","de":"Vänster L, höger R. En extra prick märks ut så man känner igen den även trevande i mörkret. Önskan att aldrig en enda gång förväxla vänster och höger fot på scenen finns instämplad, orörd, på denna lilla markör."},"ICON-0971":{"nm":"Ljuddelarkontaktskåpa","de":"Den kontakten där ett enda flöde av ljud delades av flera, dess ände bör täckas medan den vilar. Så att damm inte tränger in i kretsen. En liten, försiktig hand som önskar att sången man lyssnade på tillsammans ska flyta lika klart nästa gång också."},"ICON-0972":{"nm":"Hörlurskabelvinda","de":"Likt det gamla handlaget att nysta ett garnnystan blir en hörlurssladd prydlig när den lindas rund här. Ögonblicket då musik som vält trasslig runt i en väska ställs i ordning. Morgondagens uppnystning blir så mycket lättare."},"ICON-0973":{"nm":"Hållarsnodd för objektivlock","de":"Varje gång man öppnade objektivet tappade locket alltid bort sig. Bind det med en snodd fäst intill kameran, och man behöver inte längre famla förgäves i fickan. Att inte tappa bort något handlar om att binda det nära; det lärde sig handen först."},"ICON-0974":{"nm":"Berlock för blixtsko","de":"I den tomma blixtskon ovanpå kameran skjuter man diskret in en liten prydnad. Den där ena berlocken utan någon som helst funktion får plötsligt den tunga, kärva utrustningen att se lika kär ut som ens egen tillhörighet. Konsten att fästa sig vid ett redskap."},"ICON-0975":{"nm":"Remjusteringsspänne","de":"Varje gång väskremmen skär in i axeln lossar och drar man åt detta spänne lite grann. Ett enda handgrepp för att välja en längd som passar kroppen. Även att bära en börda är i grunden att ta hand om sig själv, viskar spännet stilla."},"ICON-0976":{"nm":"Filterförvaringsetui","de":"Ett litet hem där glasbitar som delar ljuset läggs lager på lager. Dis och klarhet, solnedgång och natt. Likt en låda där vädret väljs och förvaras i förväg, öppnar fotografen alltid detta etui först innan hen ger sig av."},"ICON-0977":{"nm":"Dammskydd för blåsboll","de":"En gummiboll som blåser ut luft för att jaga bort damm är, vid sin egen mynning, precis lika svag för damm. Medan den vilar sätts denna kåpa på. Att ett redskap som torkar av andra tyst täcker sin egen mun först har något ömt över sig."},"ICON-0978":{"nm":"Slutarknappsskydd","de":"Att slutaren trycks av sig själv i väskan och tar hundra bilder av tom himmel är något alla råkar ut för minst en gång. Detta lilla skydd över knappen förhindrar det bortkastade slitet. Ett litet lås, för att bara bevara de ögonblick man verkligen vill hålla kvar."},"ICON-0979":{"nm":"Batterisorteringsmärke","de":"Det blir alltid trassel när de förbrukade och de fulladdade blandas i en och samma ficka. Ett färgat klistermärke på varje batteri reder tyst ut den villervallan. Rött är tomt, grönt är pålitligt. Ett tyst trafikljus tänt på en inspelningsplats."},"ICON-0980":{"nm":"Skiljevägg för kameraväska","de":"Dela in väskan så att lins, kamerahus och reservbatteri inte slår i varandra. Konsten att bygga flera små rum inuti en enda last. Varje plats har sin ägare, så inget tappar sin plats även om det skakar om."},"ICON-0981":{"nm":"Fotohandskdyna","de":"En vinterfotografering utomhus, där bara fingertoppen som trycker av slutaren inte får bli stel av kyla. En tjock dyna i handflatan, handskar som lämnar känsel kvar i fingertopparna. Fältets ömma kompromiss, att hålla värme och precision i samma hand."},"ICON-0982":{"nm":"Pennspetsrör för ritplatta","de":"Att en pennspets nöts precis som en blyertsstift vet den som länge hållit i en ritplatta. Detta lilla rör där reservspetsar samlas rullande är som fingertoppens reservkassa, som fyller på linjerna som aldrig får brytas av."},"ICON-0983":{"nm":"Bricka för tangentknoppar","de":"Den dag man drog av varje tangentknopp för att tvätta och sätta tillbaka dem blev denna bricka en liten tidvattenstrand. Synen av konsonanter och vokaler liggande fack för fack och torkande. Det finns omsorg man bara ser sedan man tagit isär något."},"ICON-0984":{"nm":"Musfotssats","de":"Hemligheten bakom att musen glider över skrivbordet som i en dans ligger i dessa små fötter fästa på undersidan. Ett knippe man byter ut när de nöts. Mödan hos det som tyst bär upp mjukheten från en osynlig plats."},"ICON-0985":{"nm":"Datorstöd i gummi","de":"Det liknar ett anteckningsblock, men är i själva verket ett gummistöd som lyfter upp en bärbar dator. Att lyfta skärmen lite till ögonhöjd och räta ut en böjd nacke. En omtanke som rättar hållningen, för den som skriver och stirrar länge."},"ICON-0986":{"nm":"Webbkameraslider","de":"Skjut ett finger för att täcka linsen, skjut igen för att öppna. Önskan att bara synas när man själv vill synas. I denna enda lilla slider bor den stora tryggheten som kallas privatliv. Ljudet när den stängs känns märkligt betryggande."},"ICON-0987":{"nm":"USB-sorteringsetikett","de":"Fem likadana svarta stavar, och inget sätt alls att veta vad som ligger lagrat på vilken. Sätt en liten etikett och ge den ett namn, och först då blir den en av ens egna. Ett ting måste ha ett namn att ropa för att lätt hittas."},"ICON-0988":{"nm":"Skrivbordsunderläggshörn","de":"När skrivbordsunderläggets hörn ständigt rullar sig uppåt blir till och med handstilen skev. Dessa små delar som varsamt trycker ner de fyra hörnen vaktar den plana friden på skrivbordet. Ytan måste vara stilla för att fingertopparna också ska bli lugna."},"ICON-0989":{"nm":"Hubstativklämma","de":"En klämma som reser en hubb, där många sladdar möts, på snedden vid skrivbordets kant. Synen av oroliga sladdar som samlas och ordnas till en enda punkt. Handlaget att binda ihop det trassliga till en enda sträng lever kvar även här."},"ICON-0990":{"nm":"Sprejkork för skärmrengöring","de":"En liten propp för mynningen på en sprej som torkar bort fingeravtryck från en skärm. Håll den alltid stängd så vätskan varken läcker ut eller torkar in. För att se klart måste man först vårda medlet man rengör med; hushållets anspråkslösa ordning."},"ICON-0991":{"nm":"Minneskortsplånbok","de":"Flera dagars scenupptagningar sover stilla inuti ett kort inte större än en nagel. Tappas det bort försvinner en hel dag i ett enda slag, så man samlar det ömt i en liten plånbok. Ett hem som rymmer det minsta men ändå det största av minnen."},"ICON-0992":{"nm":"Hårddisketikett","de":"Fem svarta externa hårddiskar sover i en låda med identiska ansikten. Att sätta på en etikett och döpa dem till \"den sommaren\", \"opublicerade klipp\". Ett arbete med att fästa ett tydligt register vid ett disigt minne."},"ICON-0993":{"nm":"Säkerhetskopieringsbricka","de":"Om säkerhetskopian är klar eller inte, den där hårfina skillnaden gör hjärtat oroligt. Denna lilla bricka, insatt vid det avslutade stället, säger \"hit är det säkert\". Trygghet kommer av att lämna kvar ett märke."},"ICON-0994":{"nm":"Molnanteckningstoken","de":"En token som skickar upp en enda anteckningsrad till ett förråd som svävar någonstans på himlen. En liten magi där, var man än slår på, den där texten kommer emot en. Nattens himmel där man en gång flög en drake och skrev en önskan tycks nu ha sänkt sig varsamt ner mot handflatan."},"ICON-0995":{"nm":"USB-skyddskåpsset","de":"Rullar den runt i väskan med kontakten blottad nöts kontaktpunkterna med tiden. Sätt en liten hatt på varje ände och håll dem samlade som ett set. Att låta den oanvända tiden vila ömt. Den tystaste förberedelsen inför nästa anslutning."},"ICON-0996":{"nm":"Dataskyddsband","de":"Ett band som omsluter och sluter tätt runt en apparat som bär värdefull data. Slå en enda vändning och bind det stadigt så inget slår emot i en skakig väska. Handen som en gång knöt ett knyte med omsorg lever kvar precis likadant i det digitala."},"ICON-0997":{"nm":"Filsorteringsetikett","de":"När hundratals filer travas upp namnlösa blir sökandet i sig ett vandrande. Ögonblicket man fäster färgglada etiketter och öppnar upp förgreningar bryter en väg genom den röriga högen. Att ordna är i grunden att bana en väg."},"ICON-0998":{"nm":"Lösenordsledtrådskort","de":"Skriver man ner lösenordet i sin helhet är det farligt; skriver man det inte alls glömmer man det. Så lämnar man bara kvar en ledtråd som enbart en själv förstår. Som \"den staden vid den första scenen\". En smart, öm minnesteknik som skriver ner vägen, inte svaret."},"ICON-0999":{"nm":"Förvaringsdatummärke","de":"Skriver man inte ner dagen man ställde undan något blir förvaring snart glömska. Ett datummärke på varje låda ristar tydligt in \"sedan när\". Hjärtat hos det gamla skafferiet som skrev ner dagen sojabönpastan lades in lever vidare, på detta lilla papper."},"ICON-1000":{"nm":"Skydd för minicirkellampa","de":"En kåpa som täcker ljushålet på en liten lampa som ger ett runt sken. Lägger ljuset till vila en stund så linsen inte repas i en väska. Att varsamt bevara mörkret innan man slår på ljuset är också ett sätt att vårda ljusstyrkan."},"ICON-1001":{"nm":"Stativskruv","de":"Bara ett varv till. Det glappande mellanrummet försvinner, och en tung trygghet sjunker ner under handflatan. Bakom en scen som inte vacklar finns alltid någons skickliga handledsvridning. Det en liten skruv bär upp är en osynlig fasthet."},"ICON-1002":{"nm":"On Air-bricka","de":"Så snart den röda lampan tänds reser sig stegen i korridoren tyst på tå. Inför orden 'sänder nu' håller alla andan. Att till och med tystnaden bortom dörren är en omtanke riktad mot någon, det är vad denna lilla bricka tyst kungör."},"ICON-1003":{"nm":"Chattanteckningsblock","de":"Med fingertopparna fångar man hejaropen som annars skulle glida förbi skärmen. En stund då varje ord som annars runnit bort stannar kvar, tydligt och prydligt, på pappret. Att anteckna är en plats där ömheten att vilja nå fram, även sent, får dröja kvar."},"ICON-1004":{"nm":"Tyst tangentbordsöverdrag","de":"Klockan två på natten försvinner ljudet av tangenttryckningar som genom ett trollslag. Ett tunt skikt, till för att inte väcka andetagen hos en rumskamrat som sover djupt. Den tystaste omtanken börjar alltid på en ljudlös plats."},"ICON-1005":{"nm":"Mikrofonarmsklämma","de":"Mellan läpparna och mikrofonen, precis det avstånd där en sång inte vacklar. Denna lilla klämma håller det löftet stadigt. Bakom scenen finns alltid en hand som denna, redan där för att hålla allt stilla."},"ICON-1006":{"nm":"Bakgrundsdukklämma","de":"Även när vinden blåser rör sig inte bakgrundsduken. För en liten käft som biter hårt i hörnet håller hela scenen på plats. Bakom en orörlig vy finns alltid någon på en osynlig plats som biter ihop."},"ICON-1007":{"nm":"Stream Deck-etikett","de":"Ovanpå dussintals knappar hindrar små namnlappar handen från att tappa riktningen. En rad text på en etikett suddar i förväg ut ett misstag i den direktsända sändningen. Lugnet kommer från bokstäverna som skrevs ner innan darrningen började."},"ICON-1008":{"nm":"Tidsstämpelknapp","de":"Tryck ner den, och en liten flagga planteras i den strömmande tiden. Handlingen att stämpla nuet som aldrig kommer tillbaka. Ser man tillbaka långt senare har det märket blivit en dörr in i minnet."},"ICON-1009":{"nm":"Taggläsar-nyckelring","de":"Håll den nära och pip, informationen vaknar till liv. En liten följeslagare som dinglar från en nyckelring och skramlar i fickan. En vanlig dag går tryggt vidare tack vare små signalljud som detta."},"ICON-1010":{"nm":"Smart plugg-etikett","de":"Ge varje uttag ett namn, så slipper man längre gå vilse i vilken sladd som är vilken. Hjärtat i att ge ett namn även åt osynlig el. Ordning är ett annat ansikte som ömhet lånar för en stund."},"ICON-1011":{"nm":"Temperatur- och fuktsensorstativ","de":"En handflatestor väktare som tyst vakar över rummets temperatur och fukt. Komforten öppnar aldrig munnen, men detta stativ vårdar stilla ditt tillstånd i varje stund. Så bevaras välbefinnandet, tyst, precis så här."},"ICON-1012":{"nm":"Dörrsensorkåpa","de":"Ett litet öga som inte missar ögonblicket då en dörr sakta öppnas. Det förmedlar ljudlöst tecknet att någon kommit hem. Det som vakar över ett tomt hus är alltid, som detta, de tysta tingen."},"ICON-1013":{"nm":"Fjärrkontrollhållare","de":"Fjärrkontroller som rullat omkring hit och dit hittar äntligen sin egen plats. En liten plats som stilla håller fast det som nästan gick förlorat, en hand som i förväg ristar in löftet att mötas igen."},"ICON-1014":{"nm":"Sömnapp-token","de":"Varje natt du sover gott rullar en rund belöning in och samlas på hög. Även sömn samlas bit för bit som övning, berättar appen ömt. Världens minsta pris, räckt till dig som vilat väl."},"ICON-1015":{"nm":"Timerkub-underlägg","de":"Medan tre minuter ticker jämnt förbi räknar kuben sin tid utan att vackla. En handflatestor plats som stilla bär den underifrån. Även väntan behöver ett golv den kan stå tryggt på."},"ICON-1016":{"nm":"Notislampa-överdrag","de":"Så att det inte blir för starkt sveper det mjukt ljuset i ett lager. En avisering må vara brådskande, men låt bara ögonen få vara i fred. Omtanke är ett hjärta som stilla mäter till och med ljusets styrka."},"ICON-1017":{"nm":"Batteribyteskort","de":"När detta kort syns betyder det att det är dags att byta det lilla hjärtat inuti apparaten. En vänlig vink om att ta hand om det innan det stannar. Hemligheten bakom ett långt samliv ligger alltid i en vaksamhet som ligger ett steg före."},"ICON-1018":{"nm":"Joystickhattar","de":"Små hattar som träs på så att tummen inte glider. Känslan i fingertoppen blir så mycket tydligare. Denna lilla hatt kan till och med avgöra vinst eller förlust i en runda spelad med svettiga händer."},"ICON-1019":{"nm":"Switch-dockskydd","de":"Den täcker mjukt konsolens viloplats mot damm. För även en kort stund sovande apparat behöver ett täcke. En omtänksam känsla syns tydligast, faktiskt, när något inte används."},"ICON-1020":{"nm":"Handkonsolfodral","de":"På resande fot alltid härinuti. Ett fodral som mjukt sveper om en handhållen konsol i sin famn. Så den klarar sig oskadd trots stötar hit och dit i väskan; det bästa är att svepa in det som är dyrbart en gång till."},"ICON-1021":{"nm":"Knappdekalsrulle","de":"Lägg bara en liten bild ovanpå en enkel knapp, och i det ögonblicket blir den helt din egen. Att lämna sitt eget märke på en identisk apparat. Personlighet blomstrar alltid tyst ur sådana obetydliga hörn."},"ICON-1022":{"nm":"Spelkassettfodral","de":"Ett spel du sjönk in i en hel natt sover djupt inuti detta lilla fodral. Öppna locket igen, och den natten vaknar till liv, orörd. Minnen ryms förvånansvärt ofta i en ask inte större än en handflata."},"ICON-1023":{"nm":"Kylfläktsstativ","de":"Medan brisen kyler av hettan, en plats som håller upp apparaten i en lätt lutning. Den ger en överhettad kropp rum att hämta andan. För att springa långt måste man också kunna stanna upp ett ögonblick och svalka sig."},"ICON-1024":{"nm":"Handledsremspinne","de":"Slå den runt handleden och fäst pinnen, och hur våldsamma rörelserna än blir lämnar kontrollern aldrig din sida. Detta band som ser besvärligt ut är i själva verket tryggheten som låter dig leka med ett lugnt hjärta."},"ICON-1025":{"nm":"Analogspakshätta","de":"Klä ett nytt plagg över ett grepp som blivit slitet och blankt av lång användning. Lämna känslan handen känner igen som den är, och låt bara ytan bli som ny. Ett ögonblick då förtrogenhet och en liten rysning vilar sida vid sida i en hand."},"ICON-1026":{"nm":"Sparfacksetikett","de":"Vid varje sparplats skrivs tydligt vems äventyr det är. En rad på en etikett vaktar tyst resan från de senaste dagarna. Dyrbara minnen mår bäst av att få ett namn inristat, så de inte skrivs över."},"ICON-1027":{"nm":"Inspelarfodral","de":"En maskin som bär ljud blir mer dyrbar för det den bär på inuti. Man bär den försiktigt insvept i ett mjukt fodral som skyddar mot stötar. Kanske sover någons röst därinne, så varsamheten blir ännu större."},"ICON-1028":{"nm":"Vindskyddshätta","de":"Sopa bort vindens brus och lämna bara rösten kvar. En luddig huva som mjukt träs över en mikrofon vid utomhusinspelning. Ett litet såll som plockar ut bara uppriktigheten ur det stökiga bruset."},"ICON-1029":{"nm":"Röstmemo-etikett","de":"Det här är en text som kom till en, det här en nynnad melodi. Man klistrar en färgad namnlapp på varje röstmemo. De kringspridda skärvorna av inspiration hittar äntligen sina platser och ställer upp sig på rad."},"ICON-1030":{"nm":"Samplingsknapp-chip","de":"Tryck ner den, och en flisa förinspelat ljud poppar fram. En regndroppe, applåder, någons skratt, världens fragment vaknar vid fingertoppen. Musik är den ömma kören av små chip som dessa."},"ICON-1031":{"nm":"Ljudsamlarkuvert","de":"Man samlar varsamt in i detta kuvert de ljud man råkar plocka upp under en promenad. Vindens textur, till och med tystnaden i en gränd i gryningen. Materialet som en dag blir en sång samlas alltid blygsamt, precis så här."},"ICON-1032":{"nm":"Ministativfötter","de":"Tre ben fäller upp en liten scen ovanpå skrivbordet. I stället för en darrande hand står de stadigt och håller scenen på plats. En skarp enda bild föds, till slut, ur tre fötter som tyst står orörliga."},"ICON-1033":{"nm":"Inspelningsfil-tagg","de":"På hundratals inspelningsfiler fäster man en kort tagg, en i taget. Så man på en blick ser vilken som är den första strofen som först strömmade fram, och när. Ett litet vägmärke som hjälper en hitta tillbaka till kringspridda röster."},"ICON-1034":{"nm":"Vågformsdekalband","de":"Ett vågmönstrat band format efter själva formen av ljud. Linda det runt en anteckningsbok eller ett fodral, och det är som om musiken blir synlig framför ögonen. En öm illusion som gör det hörda sett."},"ICON-1035":{"nm":"Headsetkrokpinne","de":"När övningen är slut förbereder den stilla en viloplats åt det trötta headsetet. En liten krok fast förankrad i skrivbordets kant. Ett ordnat skrivbord är en plats där morgondagens driv hängs upp i förväg."},"ICON-1036":{"nm":"Presentaskband","de":"Det sista varvet lindat runt presentaskens midja. Med bara detta band blir känslan äntligen fullständig. Omsorgen förmedlas ofta först genom handen som stryker över utsidan, mer än genom det som finns inuti."},"ICON-1037":{"nm":"Bandsvanshätta","de":"Man sveper varsamt om bandets ände och avslutar så det inte rispas upp. En detalj som knappt syns förändrar tyst ett första intryck av en present. När avslutet är fint når även känslan fram fint."},"ICON-1038":{"nm":"Sigillvax","de":"Släpp en het droppe för att försegla kuvertet. Som ett gammalt brev, ett tungt löfte om att inte öppnas oaktsamt. Formalitet bär ibland, som detta, en varm tyngd."},"ICON-1039":{"nm":"Tackkortshållare","de":"Den håller upp rakt ett kort med tacksamma ord så det inte veckas. Så att hjärtat framförs stående rakt upp. Tacksamhet stannar längre i hjärtat när även dess form är prydlig."},"ICON-1040":{"nm":"Stjärnformat fyllnadspapper","de":"Papper klippt i stjärnform fyller mjukt ut springorna i en låda. Bomullen av ett hjärta som önskar att inget ska ta skada även vid skakningar. Även i mörkret inuti förpackningen svävar på så vis en liten stjärna."},"ICON-1041":{"nm":"Presentlistetagg","de":"Framför fältet för mottagarens namn stannar pennan en lång stund. Ansiktet som dyker upp medan man skriver namnet, årstiderna man delat. I samma stund den knyts fast blir detta lilla papper en hemlighet ingen kan läsa förrän den lösts upp."},"ICON-1042":{"nm":"Gratulationsstämpel","de":"Tryck ner den, och en rund gratulation trycks tydligt fram. Medan man väntar den korta stund det tar för bläcket att torka är hjärtat som föreställer sig vem den ska ges till som varmast. Om det finns en brist är det att man vill stämpla en gång till."},"ICON-1043":{"nm":"Presentsnörerulle","de":"Lindad med omsorg, för att sedan glatt rullas upp vid någons fladdrande fingertoppar. I den korta stunden av lindning och avlindning blir ett hjärta bundet till tråden till slut en gåva."},"ICON-1044":{"nm":"Knutberlock (ingen blomma)","de":"Ingen efterhärmning av en blomma, utan en form där en enda tråd omfamnar sin egen kropp om och om igen och blommar av egen kraft. Tålamodet hos fingertoppar som valde knutar hela natten finns kvar som en så liten knopp."},"ICON-1045":{"nm":"Lyckomyntpung","de":"Hjärtat i att smyga ner några mynt i fickan hos den som ger sig av på en lång resa. En handling att fylla den inte med tyngd utan med ömhet. Skramlet vid varje steg får stå i stället för en önskan om en lyckad resa."},"ICON-1046":{"nm":"Önskekapselberlock","de":"Inuti ett runt skal sover en hopvikt önskan sött. Att den går i uppfyllelse om man öppnar den är en lögn, men att den lever vidare för evigt om man bär den oöppnad är sant."},"ICON-1047":{"nm":"Skyddsknutssnodd","de":"En snodd flätad hårt av femfärgade trådar, som vänder onda krafter bort bakom ryggen. Som mormors hand som knöt en knut runt handleden i barndomen, i varje knuten plats sitter fint någons bön insatt."},"ICON-1048":{"nm":"Origamitranfodral","de":"Ett litet hem som håller just en enda papperstrana oskadd, av de tusen som måste vikas för att bli en önskan. För om ens en vinge skrynklas löses hela den hängivenhet som lades ner den natten stilla upp."},"ICON-1049":{"nm":"Glitterstenspung","de":"Små glimmande flisor som fallit av en scendräkt, en plats att sopa upp det man inte kan förmå sig att slänga. Även glittret som en gång fastnade och följde en i en hel vecka sover här lika stillsamt som på en handflata."},"ICON-1050":{"nm":"Lyckotecken-stämpelbricka","de":"En liten bricka man tyst lägger till när man väljer en god dag. Inte vid en spådams tröskel, utan på det egna skrivbordet, en skärva öm vidskepelse man varsamt stämplar, med önskan om bara goda ting denna enda dag."},"ICON-1051":{"nm":"Önskearmbandskort","de":"Ett enda pappersark tryckt i form av ett armband bär på någons tysta önskan. Även om det inte kan spännas fast runt handleden, lägg det djupt i plånboken, och just den känslan förblir bunden vid din sida, vandrandes med dig hela tiden."},"ICON-1052":{"nm":"Dörrsaltkrus","de":"Grovt salt hälls i en liten burk och ställs stilla vid dörren. En gammal beräkning som vänder bort onda krafter och bara släpper in välkomna gäster. Varje saltkorn är en liten dörrvakt som vakar över vårt hem."},"ICON-1053":{"nm":"Lyckonummer-täckbricka","de":"Precis innan man skrapar är alla vinnare för ett ögonblick. Denna bricka, som mjukt döljer lyckonumret, vaktar den sista sekunden då förhoppningen sväller som mest. Även om skrapande fingrar darrar låtsas den inte märka och håller ögonen stängda."},"ICON-1054":{"nm":"Födelsedagsljushållarkåpa","de":"Ett prydligt hjärta som håller även ett en gång tänt ljus säkert fram till nästa födelsedag. Om förra årets önskning ännu inte gått i uppfyllelse kan man i år helt enkelt fortsätta där man slutade och önska igen, en öm liten beräkning."},"ICON-1055":{"nm":"Nedräkningsring","de":"En fräck liten sak som träs som en D-dag på fingret. Varje gång antalet återstående dagar tickar ner ett steg dras hjärtat lika mycket närmare. Den envisas, helt på egen hand, med att den kommer att lysa den dag den når noll."},"ICON-1056":{"nm":"Partyhattssnodd","de":"Ett smalt snöre som håller en partyhatt stadigt fäst på huvudet. Hedersgästen klagar snart att den kliar och river av den, men på fotot sitter den kvar för alltid i just den bilden. Det uppdraget räcker gott och väl."},"ICON-1057":{"nm":"Liten tårtpinne","de":"Ett litet märke stucket i en tårta stor som två fingerleder. Även ovanpå en sötma som försvinner i en enda tugga står firandet rakt och stolt. Liten som den är, en födelsedag är ändå en födelsedag, och dagens stjärna är du."},"ICON-1058":{"nm":"Partysmällsdekal","de":"En papperssmäll utan smäll men den mest praktfulla att se på. I samma stund den fästs på blir en vanlig postförsändelse förvandlad till ett brev från en fest. Många lämnar den kvar, för motvilliga att dra loss den."},"ICON-1059":{"nm":"Fotoupphängningsklämma","de":"Rädd att tappa minnena som hänger på snöret håller jag alltid munnen stadigt hopbiten. Så länge ett foto hålls fast i mitt grepp kan inte ens brisen genom fönsterspringan få de dagarna att falla."},"ICON-1060":{"nm":"Datumballongmärke","de":"Ett ballongformat tygmärke med en siffra på. Fäst det på kläderna, och hela grannskapet får veta vilken dag i följd som är speciell idag. Dras det loss lämnas ett märke kvar, och till och med det bleka märket blir ännu en minnessak."},"ICON-1061":{"nm":"Presentbytesmärke","de":"Ett skälmskt märke som mjukt förvirrar vilken hand som tog emot och vilken som gav. En liten, öm regel vid presentbytesbordet, som ber en minnas inte så mycket vem som gav som vad som gick mellan er."},"ICON-1062":{"nm":"Festbordsnummer","de":"Ett litet nummer rest vid varje festbord. Att i förväg bestämma vem som sitter var så ingen känner sig besvärad bär med sig den varma visdomen hos dem som anordnat många fester."},"ICON-1063":{"nm":"Dörrhandtagspresentpåse","de":"Ett sätt att räcka fram sin omtanke utan att ringa på. Häng den lömskt på dörrhandtaget och försvinn som på flykt, och det förvånade ansiktet hos den som hittar den blir den största gåvan som återvänder till givaren."},"ICON-1064":{"nm":"Hemlig leveransetikett","de":"Ingenting står skrivet på framsidan. Att hålla avsändaren dold ända till slutet är denna etiketts lilla stolthet. Ju längre mottagaren lutar huvudet undrande och ler, desto mer fulländat blir det hemliga uppdraget."},"ICON-1065":{"nm":"Dörrklockelapp","de":"En liten lapp lämnad i stället när man inte samlar mod att knacka på. En kort rad som 'tittade bara förbi' dröjer sig kvar längre än ett dörrklockeljud. För en krokig, kladdig handstil har ett eget ansikte."},"ICON-1066":{"nm":"Brytknivsskydd","de":"När en brytknivs blad ouppmärksamt siktar mot ett finger kliver en liten hjälte tyst in framför. Den skyddar tryggt fingertopparna, skyndade av förväntan på det nya, ända fram till sista snittet."},"ICON-1067":{"nm":"Bubbelplastbit","de":"Jag föddes för att tryckas på. På något vis löses dagens spänning upp med det där lilla pop-ljudet. Ibland finns det dagar då jag blir älskad längre än själva föremålet jag var inpackad kring."},"ICON-1068":{"nm":"Ankomsttidsnål","de":"En nål som pekar ut exakt vilken tid det anländer. Även en vag väntan blir lättare att bära när den får en enda koordinat. Hur många gånger man kikar ut mot ytterdörren fram till dess är helt och hållet upp till en själv."},"ICON-1069":{"nm":"Paketboxnyckelring","de":"En liten följeslagare för den som ständigt glömmer koden till paketboxen. Den hänger dinglande i nyckelringen, och dess tysta talang är att locka fram ett 'åh just ja' i det avgörande ögonblicket."},"ICON-1070":{"nm":"Hallkorgstagg","de":"En namnlapp fäst på korgen i hallens hörn. På den står det tysta löftet: 'lämna det här.' Även tom är en plats som väntar på någons omtanke aldrig ensam."},"ICON-1071":{"nm":"Adresstäckningsdekal","de":"På en låda man slänger lämnar man namnet men suddar snabbt bort adressen. Att namnet får bli känt av alla är okej; var man bor förblir ens egen hemlighet. I samma stund man drar av och klistrar fast detta enda skikt föds en liten trygghet."},"ICON-1072":{"nm":"Snackburksetikett","de":"En etikett som på en blick visar vad som finns i burken. Men fällan är att bara det att skriva 'tilltugg' på något vis känns tryggt, även utan att öppna locket. Etiketten kan dock inte ta ansvar för matlusten."},"ICON-1073":{"nm":"Litet halsbandshänge","de":"Ett litet berlock som stilla delar din kroppsvärme under kläderna. Alltid i beröring med en plats ingen kan se, och just därför desto kärare. Den närmsta vän som vandrar tillsammans vid ditt bröst."},"ICON-1074":{"nm":"Tassavtrycksstämpelmatta","de":"Tryck den mot en tass, och en rad små avtryck lämnas kvar. En daglig promenaddagbok, prydligt noterad på papper om vem som gick vart. Det första bläckfärgade steget är alltid det tydligaste."},"ICON-1075":{"nm":"Pälsborsthätta","de":"En liten hätta som prydligt tar hand om pälsen som fastnat i borsten. Under fällningssäsongen, när en enda dragning samlar en näve päls, skulle hela huset bli ett fluffigt snötäcke utan denna hätta. En flitig städare som arbetar utan att synas."},"ICON-1076":{"nm":"Promenadpåsefodral","de":"Ett litet hem som prydligt bär med sig påsarna man behöver på en promenad. Detta fodral bevisar tyst varje dag att bara den som packat i förväg får gå avslappnat. Den enda påsen man hamnar i knipa utan."},"ICON-1077":{"nm":"Namntäckningstagg","de":"En tagg som lömskt döljer det riktiga namnet och lämnar bara smeknamnet kvar. Det finns i världen en sorts ömhet man hellre inte visar för vem som helst. Den där tilltalet som bara de invigda känner till, gömmer sig varsamt just här."},"ICON-1078":{"nm":"Vattenskålsunderlägg","de":"Utlagd under vattenskålen är jag alltid fuktig. Genom att fånga upp de droppar som stänker åt alla håll håller jag golvet torrt. Ingen berömmer mig, men jag klagar inte heller."},"ICON-1079":{"nm":"Leksakslagningstråd","de":"En docka med spruckna sömmar slängs inte, den sys ihop igen. Vid varje plats man fyller igen, stygn för stygn, blir tiden man delat med den lilla vännen stark på nytt. Att laga är, i grund och botten, att stilla skjuta upp ett farväl."},"ICON-1080":{"nm":"Minnesfotohalsband","de":"Hjärtat i att bära den bild där man log som mest strålande runt halsen. Den dagen på fotot förblir inte uppstoppad och stilla, utan svänger med vid varje steg och når ända fram till idag. Det goda ögonblicket slutar aldrig."},"ICON-1081":{"nm":"Humörfärgbricka","de":"Om hjärtan också hade färger, vilken färg vore din idag? I samma stund du väljer en bricka och lägger den på skrivbordet sprider sig tyst de känslor orden inte riktigt räckte till. Solnedgångsljus eller gryningsljus, båda är fina, för det är en liten spegel som stilla speglar den du var den dagen."},"ICON-1082":{"nm":"Dagens minneskula","de":"När dagen går mot sitt slut samlas idag runt inuti kulan. Både det du lyckades med och det du klantade dig med rullar in tillsammans och packas undan. Lägg den i handflatan, och gårdagens du känns lite varm, klappar dig på ryggen och säger att du levde bra idag också."},"ICON-1083":{"nm":"Berömlappsburk","de":"Vänliga ord skingras alltför lätt, så man viker ihop dem en och en och lägger dem i denna burk. När beröm samlas som doft öppnar man locket de nätter hjärtat känns tomt. Dra fram en bit ömhet någon räckt fram och läs den igen, och den dagens värme väcks till liv på nytt."},"ICON-1084":{"nm":"Försoningsbandsnöre","de":"Ett tilltrasslat hjärta liknar en knut; att lösa upp den kräver också omsorg. När två personer griper var sin ände av snöret och drar långsamt bildas innan man vet ordet av en vacker rosett. Försoning är inte att klippa av, utan att knyta ihop igen, det är vad detta snöre stilla berättar."},"ICON-1085":{"nm":"Tacksamhetstoken","de":"De dagar 'tack' inte riktigt vill lämna läpparna räcker man i stället fram en token. Handen som tar emot läser hela hjärtat ur just den lilla tyngden. En uppriktighet som anländer före orden, ömhet buren över i ett enda runt korn."},"ICON-1086":{"nm":"Rastmärke","de":"Även ett övningsrum som sprungit på hela dagen behöver ett andetag att hämta sig. Häng detta märke på dörren, och tiden saktar ner en stund. Att en sång behöver en paus för att andas vet var och en som levt igenom en andfådd dag."},"ICON-1087":{"nm":"Hemlig känslolåda","de":"Det finns dagar man inte kan lägga fram allt inombords. De dagarna lägger man stilla ner både sorg och fladdrande känslor i en liten låda i sinnet och stänger den. Det är okej att låta dem ligga kvar nu, för en dag kommer man att öppna den långsamt och sortera allt."},"ICON-1088":{"nm":"Leendedekalrulle","de":"Riv loss en ruta i taget, och ett leendemärke fastnar på fingertoppen. Ett litet muntert inslag att klistra varsamt i hörnet av ett anteckningsblock eller på en väns skåp. När en liten sol går upp på pappret blir dagen lite ljusare för den som hittar den."},"ICON-1089":{"nm":"Hälsningsklockberlock","de":"Önskan om att nå fram till dig långt borta har samlats i en enda liten klocka. Skaka den, och ett klart ljud för hälsningen i ditt ställe. De dagar man inte fått fram orden 'hur mår du', rider detta lilla ljud på vinden och når fram först."},"ICON-1090":{"nm":"Vårregnsomslagsnål","de":"På regniga vårdagar blir det man värnar mest om det som blir blött lättast. Fäst omslaget med denna nål, och regndropparna glider av och förbi. Känslan av att vagga en dyrbar bok i famnen, en liten nål står i stället för den ömheten."},"ICON-1091":{"nm":"Sommarkyldekal","de":"Ett snabbt tryck på handryggen som tröttnat i högsommarhettan. En sval känsla sprider sig som mentol och svetten lättar en aning. Den svalkan av att ligga på verandan och vifta med en solfjäder efterliknar ett handflatestort pappersark troget."},"ICON-1092":{"nm":"Höstrutig tygbit","de":"En bit rutigt tyg som liknar ett höstfält. Det är spåret efter någon som varsamt lappat ett slitet ställe. Hjärtat som lagar i stället för att slänga, små tygbitar som samlas och värmande väcker liv i det som nötts."},"ICON-1093":{"nm":"Vintervantsklämma","de":"Vintervantar tycks ständigt smita iväg, en i taget. Länka ihop paret med denna klämma, och de kylslagna händerna tappar inte bort vägen. Önskan om att inte tappa bort dem bor i en liten metallbit, och håller de två sida vid sida."},"ICON-1094":{"nm":"Vattentät regnsäsongstagg","de":"Under regnperioden suddas till och med en namnlapp ut av regnvattnet. Denna vattentätade tagg skyddar sin skrift även i ösregn. En rad som förblir tydlig även efter att regnet klarnat, så att vems detta är aldrig glöms bort."},"ICON-1095":{"nm":"Förstasnökrus","de":"Det första snöfallet försvinner i samma stund det rör vid handen, så man sparade åtminstone den där rysningen i en burk. Det som fångats i glaset är inte snö utan hjärtat som slog extra den dagen. Skaka den, och en hel vinter virvlar upp igen, och bär en tillbaka till den morgonen."},"ICON-1096":{"nm":"Högtidskuvertband","de":"Ett enda rött band lindat runt ett högtidskuvert. Alla vet att ömheten i den räckande handen väger tyngre än det som ligger inuti. Hjärtat som viker in önskningar om lycka tillsammans med hälsningar om välmående är fint knutet inuti detta smala band."},"ICON-1097":{"nm":"Picknickmatlådeband","de":"Bred ut filten och packa upp matlådan, och vinden fortsätter lyfta på locken. Fäst kärlen stadigt med detta band, och picknicken går inte i olag. Omtanken om att skydda en medhavd måltid ända till sista tuggan finns i ett litet band."},"ICON-1098":{"nm":"Årstidsdoftprovkort","de":"Så att man kan känna igen årstiden utan att ens öppna det bär ett enda kort doften från den tiden på året. Blommor om våren, doften av torra löv om hösten. I samma stund det stryker förbi näsan väcks hela årstiden till liv, 'det här är aprils luft.'"},"ICON-1099":{"nm":"Prislappklämbräda","de":"Denna enda klämbräda lade en gång för alla marknadsståndets huvudvärk med prislappar som ständigt flög iväg. Den håller siffrorna stadigt fast och räcker fram dem rakt framför kunden. Handelns första hälsning börjar med en ärlig rad som aldrig kommer på sned."},"ICON-1100":{"nm":"Öppet-vändskylt","de":"Vänd denna skylt och häng den vid dörren, och butiken vaknar äntligen till liv. Från 'förbereder' till 'välkommen.' En liten signal som kungör dagens början, platsen ägarens hand når först varje morgon."},"ICON-1101":{"nm":"Stämpeldyna","de":"Fyll alla tio rutorna och något gott kommer förr eller senare din väg. Varje stämpel är en stamkunds fotsteg, tillgivenhet som byggts upp med tiden. I varje avtryck, tryckt tills bläcket torkat, lever och andas ett litet löfte om att komma tillbaka."},"ICON-1102":{"nm":"Handtagshylsa för papperspåse","de":"En papperspåses handtag är alltid svagt inför tyngden. Träd på denna hylsa och det nästan avslitna snöret blir stadigt. Önskan att bära det som ligger inuti helskinnat hem – en liten detalj som bär den resan hela vägen."},"ICON-1103":{"nm":"Myntbricka","de":"Denna bricka lindrar stilla tvekan när växelpengar räcks från hand till hand. Ljudet av mynt som klirrar på plats. Att ge och ta emot blir varmare tack vare denna runda lilla omtanke."},"ICON-1104":{"nm":"Poängchip","de":"Dagens steg samlas prydligt i en enda bricka. En märklig räkning där hjärtat blir lättare ju mer man samlar. Glädjen av att fylla på lite i taget liknar glädjen av att se en tom kruka sakta bli full utan att man märker det."},"ICON-1105":{"nm":"Hyllnummerpinne","de":"På varje hylla sitter ömt fäst en liten siffra. En tyst vägvisare som talar om var allting finns. Omtanken att märka ut platsen i förväg så att man inte ska gå vilse – även ordning kan bära på sådan värme."},"ICON-1106":{"nm":"Smakprovsbägare","de":"En liten bägare som räcker fram en tugga att smaka. Även en tveksam kund öppnar sakta sitt hjärta vid denna enda munsbit. Frikostigheten i att uppmana 'prova en' hänger vid spettets spets och håller kvar den förstagångsbesökandes steg."},"ICON-1107":{"nm":"Namnlistehållare","de":"Dagens gästers namn står prydligt uppradade i denna hållare. Ett ömt löfte om att även väntan har sin tur. Att ställa upp ett enda pappersark rakt blir den första omsorgsfulla förberedelsen inför att välkomna någons dag."},"ICON-1108":{"nm":"Fotoklämma för väggsnöre","de":"Fäst ett snöre på väggen och klipp fast foton ett efter ett. Leende ögonblick hänger sida vid sida och torkar som tvätt. Häng minnena där solljuset faller, och varje gång du går förbi fladdrar den dagens skratt igen."},"ICON-1109":{"nm":"Liten hörnmatta","de":"En liten matta lagd vid rummets kant. En plats som sprider värme först ut på det kalla golvet. Det handsbreda ställe de bara fötterna rör vid först – där tårna på den som kommit hem äntligen slappnar av och blir sömniga i trygghet."},"ICON-1110":{"nm":"Namnskyltsskynke","de":"Ett stycke tyg som sakta skymmer namnskylten. Att gömma namnet en stund är också sin egen sorts hemtrevnad. Ett vackert draperi över gränsen mellan inne och ute, hängt mjukt med önskan om att få vila i lugn och ro idag."},"ICON-1111":{"nm":"Lampsladdsklämma","de":"Denna klämma håller en hängande lampsladd prydligt på plats. En hand som rätar ut vägen så att ljuset inte ska skingras. Räta ut en enda stökig sladd när kvällen faller på, och både rummets ljus och sinnet blir lugnare."},"ICON-1112":{"nm":"Postermagnet","de":"En liten magnetknopp för att sätta upp en poster på väggen. Papperet håller sig på plats utan ett enda häftstiftshål. Handen som hanterar det den värdesätter är alltid mjuk – omtanken om att låta det förbli oskatt bevaras här."},"ICON-1113":{"nm":"Gardintofssnöre","de":"Ett tofsprytt snöre som binder tillbaka gardinen åt ena sidan. Det öppnar en vacker väg för morgonsolen att komma in. Dra en gång i det tofsade snöret, och en ljus dag forsar rakt in i rummet och stannar."},"ICON-1114":{"nm":"Doftljusetikett","de":"En liten etikett fäst på en ljushållare. Den antecknar prydligt vilken doft som brinner och när den tändes första gången. Att ge ett namn åt en doft man älskar – den prydligheten gör luften i rummet ännu ömmare."},"ICON-1115":{"nm":"Gummifötter för hylla","de":"Fyra gummifötter som stöttar en hylla så att den inte vinglar. Från en osynlig plats bär de vikten i tystnad. Små och lågt belägna, lätta att förbise, men det som håller stadigt allra längst ner är det som varar längst i slutänden."},"ICON-1116":{"nm":"Riktningspilhänge","de":"För den som tvekar om vilken väg att ta pekar en enda pil stilla ut riktningen. En öm gest som säger: tappa inte bort din väg. Tack vare hjärtat någon satte upp först vid varje vägskäl går man än idag vidare utan att gå vilse."},"ICON-1117":{"nm":"Inbjudningsnyckelband till ön","de":"Ett nyckelband som läggs i handen på den som bjuder in dig till ön. Ta emot det, och nu är även du en av familjen här. Gästfriheten i att välkomna en främmande gäst in i det varma inre hålls stadigt fast i det lilla löfte som hänger vid snörets ände."},"ICON-1118":{"nm":"Relationstemperaturchip","de":"Ett enda chip avslöjar slugt temperaturen mellan två personer. Om det fortfarande är ett besvärat blått, eller om det omärkligt vänt till ett varmt karmosinrött. Hastigheten med vilken tillgivenhet fördjupas är svår att mäta, men handflatan känner den värmen först."},"ICON-1119":{"nm":"Smakprovlåda","de":"När man ännu inte vet vad någon tycker om samlar man små prover i en låda och räcker fram den. I glädjen av att välja växer smaken sakta fram. Vilken som blir din egen – lådan är fylld av spännande möjligheter."},"ICON-1120":{"nm":"Omsorgsbokningsnål","de":"Löftet om att ta hand om någon fästs tydligt i denna enda nål. Skriv ner namnet och tiden, och hjärtat tappar inte bort vägen. Den ömma gemenskapen av att turas om att vakta varandras barn lever och andas just här."},"ICON-1121":{"nm":"Tillväxtminneskapsel","de":"Precis som märkena efter uppmätt längd samlas rad för rad på en dörrkarm, förseglar denna kapsel stilla gårdagens du. Öppna locket långt fram i tiden, och du kommer att förstå hur långt de en gång så små stegen har vandrat."},"ICON-1122":{"nm":"Minnesband från första mötet","de":"Darrningen från när man första gången höll varandras hand knyts mjukt in i ett enda band. Knuten är inte till för att lösas upp, utan för att låta den dagens värme fortsätta leva vid handleden."},"ICON-1123":{"nm":"Mitt Rum-etikett","de":"\"Det här är min plats.\" I samma stund en liten etikett fästs i skrivbordets hörn andas det en gång främmande rummet ut och blir Mitt Rum. En namnlapp är den första platsen hjärtat slår sig ner."},"ICON-1124":{"nm":"Vänskapskulburk","de":"Skaka den och hör kulan rulla, ljudet av att de två kommer ett steg närmare varandra rullar iväg. När burken är nästan full räcker det att ropa ditt namn för att skrattet ska hinna fram och möta dig först."},"ICON-1125":{"nm":"Debutsigill","de":"Det sista arket som sluter kuvertet. Hittills har varit förberedelser; vänd nästa sida och det är scenen. Med fingertoppen tryckt fast lugnar praktikanten sin andning. Äntligen, nu börjar det."},"ICON-1126":{"nm":"Vatten","de":"Det vanligaste, och därför det dyrbaraste. I en övningslokal i gryningen med släckta lampor lyfter en enda klunk upp den som sjunkit ihop. En ömhet utan egen form som tränger in i vilket kärl som helst."},"ICON-1127":{"nm":"Klart vatten","de":"En genomskinlighet som lyser klart ända ner till stenarna på botten. En källa i bergen skryter aldrig med sin egen klarhet. Ett hjärta utan något att dölja är alltid så här – synligt ända ner till botten."},"ICON-1128":{"nm":"Havsvatten","de":"I samma stund det når tungspetsen forsar avlägsna vågor in. I en enda salt klunk smälter horisonten, måsarna och hamnen man lämnat samman till en helhet. Havet dröjer sig alltid kvar i minnet med en smak av salt."},"ICON-1129":{"nm":"Is","de":"Den krymper sakta i handflatan, försvinner i takt med att man griper om den. Hur hård den än verkar vet den att den till slut blir vatten igen. Isen är en flod som för en stund hållit andan."},"ICON-1130":{"nm":"Snöboll","de":"En hårt hoppressad klump flyger vit tvärs över gränden. Gapskratt och kinder rodnade av kylan. Vinterns allra vitaste leksak, den den smyger ner i barnens händer."},"ICON-1131":{"nm":"Jord","de":"Den famnar frön, dricker regnvatten och tar tyst emot förbipasserande fotspår. En svart hud som omfamnar allt. Vid begynnelsen av allt som växer finns alltid denna enda näve."},"ICON-1132":{"nm":"Bördig jord","de":"Stick ner fingrarna och en svart fetma sluter sig mjukt om dem. Hemligheten bakom att mormors köksträdgård grönskade varje år låg just här. Väl mognad jord viskar om en riklig skörd med doften av gödsel."},"ICON-1133":{"nm":"Lera","de":"I samma stund den tar upp fukt underkastar den sig lydigt vilken form som helst. Ett ömt kött som blir fågel, blir skål, efter handens vilja. Medan drejskivan snurrar börjar en näve jord äntligen drömma."},"ICON-1134":{"nm":"Sand","de":"Fina korn som sipprar bort mellan fingrarna. Ju hårdare man håller fast, desto snabbare rinner de ut, alltmer likt tiden själv. I en enda näve strand ligger otaliga gårdagar och sover."},"ICON-1135":{"nm":"Rullstenar","de":"Stenar slipade runda vid bäckens kant. De är spåren av vatten som smekt dem länge, länge, tills de skarpa kanterna försvann. Ju längre en sten har rullat, desto mjukare vilar den i handen."},"ICON-1136":{"nm":"Sten","de":"En klump slängd oaktsamt vid vägkanten. Någon sparkar till den i förbifarten, någon annan plockar upp den stilla och bygger ett torn. Samma sten blir en börda eller en önskan, beroende på hjärtat."},"ICON-1137":{"nm":"Flisa","de":"En bred, platt sten som korsar en gammal palatsgård. Hundratals år av skor som trampat över den har slitit en svacka i mitten. Var och en som sätter foten där, ett steg i taget, lägger till ännu ett lager av tid."},"ICON-1138":{"nm":"Kalksten","de":"Musslorna från dess tid som hav stelnade lager på lager till en vit sten. Lägg den i en ugn och den löses upp till kalk som målar murar snövita. Stilla som den verkar bär den på en hel tidsålder inom sig."},"ICON-1139":{"nm":"Kol","de":"En gammal skog som fallit i en kolsvart sömn. Ormbunkar från hundratals miljoner år sedan, hoppressade hårt djupt under jorden. Tänd på den, och solljuset som legat begravet så länge flammar åter till liv."},"ICON-1140":{"nm":"Träkol","de":"Den bär elden inom sig men sväljer röken i tysthet. Trä som pressats svart i ugnen blommar tyst rött ovanpå glödpannan. Ju tystare något är, desto längre håller det sig varmt."},"ICON-1141":{"nm":"Kvist","de":"En gren som tyst böjt sig hellre än att brytas känner konsten att ge efter. Vid varje ställe som stått emot en hård vind bildas en kvist – och sann styrka är, till syvende och sist, spåret av att ha böjt sig väl."},"ICON-1142":{"nm":"Stock","de":"I de avsågade årsringarna vilar hundra vårar och vintrar samlade i runda lager. Åren ett enda träd levt igenom ligger nu där i sin helhet, och väntar stilla på sin tur att bli husets bärande pelare."},"ICON-1143":{"nm":"Virke","de":"Varje gång hyveln far förbi blottas en doftande ådring, lager för lager. Medan det grova träet blir slätt, tornar sågspånet upp sig på golvet som gul snö. Den finslipande handen väcker dess nytta till liv."},"ICON-1144":{"nm":"Bräda","de":"Den läggs som golv, timras till en bänk, reser en stängsel. När de rakt sågade brädorna samlas, en efter en, reser sig äntligen en plats för människor att bo. Vardagliga ting travas upp och blir ett hem."},"ICON-1145":{"nm":"Bambu","de":"Ihålig inuti, men rak inför vinden. Gamla lärde önskade likna dess beslutsamhet, som bryts vid varje led och skjuter nya skott. Här står något som blir desto rakare av att vara tomt."},"ICON-1146":{"nm":"Kork","de":"Tryck ihop den och släpp, och den sväller tillbaka till sin ursprungliga tjocklek. Se på denna ådring, lätt men seg, och man förstår att mjukhet aldrig är detsamma som svaghet. Från flaskproppar till anslagstavlor stöttar den stilla upp."},"ICON-1147":{"nm":"Gräs","de":"Trampat ner reser det sig igen vid nästa regn. En grön envishet som täcker ett helt fält utan ett enda namn. Förringa inte dess litenhet – det som först kungör våren är alltid denna låga plats."},"ICON-1148":{"nm":"Halm","de":"Det som blir kvar gult på fältet efter höstskörden. Flätat blev det ett tak, utlagt blev det en varm bädd. Ett hjärta som, efter att ha gett bort varje sädeskorn, ändå täcker människor in i det sista."},"ICON-1149":{"nm":"Vass","de":"När vinden stryker förbi, ett sus, ett sus, sjunger hela flodstranden i kör. En stjälk som, ihålig inuti, gråter desto längre. Vassen skäms inte det minsta över att just sitt eget vajande är dess sång."},"ICON-1150":{"nm":"Bomull","de":"När den mogna kapseln knäpper upp blommar ett litet moln fram. Denna lätta, mjuka fluff blir tråd och blir tyg, och värmer stilla någons axlar en kall vinternatt."},"ICON-1151":{"nm":"Ull","de":"Gnid den mot handen och en fetma sprider sig medan värmen stilla dröjer kvar. Rocken ett får svepte om sig för att uthärda de kalla bergen. Den avklippta värmen vandrar nu vidare in i människans vinter."},"ICON-1152":{"nm":"Tråd","de":"Tunn som den är, knappt synlig, är det alltid den som återförenar två skilda ändar. Svag som en enda tråd, men vävd samman blir den ett helt tygstycke. I arbetet att foga samman spelar tjockleken ingen roll."},"ICON-1153":{"nm":"Tyg","de":"Väft och varp korsas otaliga gånger och bildar en enda bredd. Det är resultatet av trådar som skulle rispa upp sig var för sig, men som håller varandra stadigt fast. Att ju tätare vävnaden, desto varmare den är – det gäller lika mycket mellan människor."},"ICON-1154":{"nm":"Läder","de":"Ju mer det används, desto mer sjunker handens spår in i det, och det liknar sakta sin ägare. Medan den första stelheten mjuknar upp fördjupas färgen och ådringen blir mjuk. Den glansen som tiden ristat kan inget annat efterlikna."},"ICON-1155":{"nm":"Fjäder","de":"Så lätt att man inte känner någon tyngd ens när den vilar i handflatan. En enda strimma som bär minnet av att ha flugit genom himlen, alldeles som det var. Glöm för allt i världen inte att det lättaste steg allra högst."},"ICON-1156":{"nm":"Snäckskal","de":"Mormors ord om att hålla den mot örat dyker plötsligt upp i minnet. På dess inre regnbågsskimmer är havet man lämnat inristat i sin helhet, så att även ett tomt skal bär klangen av en svunnen tid."},"ICON-1157":{"nm":"Korall","de":"Hård som sten, men en gång var den utan tvekan en andande koloni. I det långsamma havet tar den hundratals år på sig att sträcka ut sina grenar. Den stadigaste grenen växer först efter den längsta väntan."},"ICON-1158":{"nm":"Pärla","de":"Ur stånd att uthärda irritationen av ett enda sandkorn svepte musslan det stilla in i ljus. Omfamna smärtan och runda av den, så blir den så här skimrande – en liten tröst havet räcker fram."},"ICON-1159":{"nm":"Sjögräs","de":"Ett grönt band som ligger halkigt utsträckt över klipporna vid ebb. Ta tag i det och en frän havsdoft slår emot en. Rotlöst, med kroppen överlämnad åt strömmen, sköter havet stilla sin egen trädgård."},"ICON-1160":{"nm":"Nori","de":"Håll ett svart ark en kort stund över elden, och det grönskar medan en rostad doft sprider sig. Den morgonen då man rullade det runt nykokt ris. Hur tunt det än är omfamnar det gott och väl en hel måltids lycka."},"ICON-1161":{"nm":"Salt","de":"Jag är den vita kristallen havet lämnat kvar i solen. En enda nypa fördjupar en smaklös soppa, men slinter handen till täcker jag över all smak. Bara en fingertopp som känner den rätta måttan kan bruka mig rätt."},"ICON-1162":{"nm":"Glasskärva","de":"Först på det ställe där den gick sönder böjer den äntligen ljuset till en regnbåge. En konst den aldrig kände till medan den var hel. Att även något trasigt har en andel solljus kvar att ge, det berättar skärvan som ligger vid fönstret stilla."},"ICON-1163":{"nm":"Glas","de":"Att vara genomskinlig betyder inte bara att inte ha något att dölja. Det har suddat ut sin egen form för att låta ljuset passera helt igenom. Även i att uppehålla sig där osedd finns en sval prydlighet när en hand rör vid den."},"ICON-1164":{"nm":"Glasflaska","de":"Den måste vara tom inuti för att kunna rymma något. Sylt, en näve vilda blommor eller ett hopvikt brev – dess namn ändras med det som kommer in. Ett kärl som inte fruktar tomheten är det mest generösa."},"ICON-1165":{"nm":"Tom flaska","de":"Jag älskar stillheten som infinner sig efter den sista droppen är urdrucken. Någon slänger mig, någon annan sköljer mig och ställer mig i fönsterbrädan för att fylla mig med solljus. Att finna ny användning där något tagit slut – det är de tömdas andra liv."},"ICON-1166":{"nm":"Papper","de":"Jag ligger utbredd vit, redo att ta emot vad som helst. Det är alltid jag som ser längst in i hjärtat hos den som tvekar inför den första raden. Det tomma bladets tålamod sträcker sig ett gott stycke djupare än bläcket."},"ICON-1167":{"nm":"Gammalt papper","de":"Att gulna är inte att åldras, utan att uthärda. I varje veck har värmen från de händer som vecklat upp och läst sjunkit in. Gammalt papper skriver, för att inte glömmas bort, ner den svunna tiden i sin egen färg."},"ICON-1168":{"nm":"Bläck","de":"Det börjar som en enda droppe, blir en mening, och förblir som ett löfte när det torkat. Har det runnit ut är det spåret av just den dagen, precis som det spreds. Eftersom mitt jobb är att göra saker oåterkalleliga trycker människor mig ner en gång till, med omsorg."},"ICON-1169":{"nm":"Järnmalm","de":"En sten som sov en röd sömn under jorden. Först efter att ha passerat genom eld ger den slutligen ifrån sig järnet inom sig. Hårdhet är inte hård från början – det är ett namn den fått efter att ha genomgått hettan."},"ICON-1170":{"nm":"Järntacka","de":"Först efter att malmen uthärdat elden svalnade den till en enda klump. Denna kalla, tunga form blir en bro, blir ett svärd, blir en hacka. Eftersom min användning ännu inte är bestämd kan jag bli vad som helst."},"ICON-1171":{"nm":"Kopparmalm","de":"Jag kom ut ur jorden klädd i en grönäppelfärgad rost. Smält mig, och klockor ringer, statyer reser sig, elledningar flödar. Även medan jag sov i den becksvarta jorden väntade jag alltid på min tur att kallas till något."},"ICON-1172":{"nm":"Koppartacka","de":"Håll den kvar tillräckligt länge, och den syr med egen hand en blå klädnad åt sig själv. Somliga kallar den nyansen en brist, andra smeker den som årens eget mönster. Metallen som inte skäms för sin föränderliga färg är den som älskas längst."},"ICON-1173":{"nm":"Guldmalm","de":"En enda flisa funnen genom att sålla flodsand om och om igen. Dyrbar inte för att den är sällsynt, utan för att den aldrig förändras. Gamla tiders folk tryckte den i händerna som ett minnesmärke, med önskan att man skulle likna ett hjärta som aldrig rostar."},"ICON-1174":{"nm":"Guldtacka","de":"Den ligger som en enda klump, varken matt eller rostig. Den har hört mest av människors girighet, men själv åtrår jag ingenting. Bara en tung tystnad, trogen enbart uppgiften att glänsa."},"ICON-1175":{"nm":"Skrot","de":"Den har inte tjänat ut sitt syfte – den väntar på nästa. Böjda spikar och intryckta konservburkar samlas ihop för att åter möta den heta elden. Ordet bortkastad betyder för mig bara att vila en stund."},"ICON-1176":{"nm":"Skruv","de":"Ensam kan jag ingenting göra. Först när jag vridits fast och håller två plankor tätt tillsammans spelar jag äntligen min roll. Konsten att en liten kropp håller fast något stort – även i den åtdragande kraften finns omsorg."},"ICON-1177":{"nm":"Spik","de":"Väl indriven backar jag sällan tillbaka. Vid varje hammarslag är det inte ett sår som fördjupas, utan ett löfte. Om det gäller att foga samman något stadigt ger jag gärna upp mitt huvud."},"ICON-1178":{"nm":"Kugghjul","de":"Jag trycker mot grannens tänder och snurrar tillsammans. Jag försöker inte rusa iväg ensam, utan vet hur man anpassar sig till tempot bredvid. Precis som en klocka vars tid bara flyter när tänderna griper i varandra, tror jag att samklang i sig är rörelse."},"ICON-1179":{"nm":"Spiralfjäder","de":"Ju mer den pressas ihop, desto mer samlar den inom sig kraften att fjädra tillbaka. Att böja sig är inte att ge upp, utan att göra sig redo att räta ut sig igen. En liten spiral som studsar tillbaka lika mycket som den tog emot stöten, där mjukhet i sig är styrka."},"ICON-1180":{"nm":"Elkabel","de":"Utanpå ett stillsamt hölje, inuti en väg som flödar utan rast. Från osedda platser bär den med sig ljus och ljud. Som en hand som tyst kopplar samman allt bakom scenen, en genomgång som litas på desto mer för att den aldrig syns."},"ICON-1181":{"nm":"Batteri","de":"Det samlar en halv dags klara ljus, bit för bit, inom sin lilla kropp. Är det tomt, fyll bara på igen, säger det, och ser aldrig tomheten som ett slut. Det bär på en liten kväll för att lysa upp någons långa natt."},"ICON-1182":{"nm":"Glödlampa","de":"En enda tunn glödtråd gassar rödglödgad och trycker undan mörkret. Den bränner sin egen kropp inte för att värma rummet, utan för att lysa upp det. Hetast i ögonblicket den tänds, och därmed ljusast, en liten sol under ett enda ögonblick."},"ICON-1183":{"nm":"Lins","de":"Den samlar spritt ljus och ställer det skarpt i en enda punkt. Den kallar tyst fram både stjärnan långt borta och de små bokstäverna i handflatan. Genom att hjälpa seendet döljer den sin egen gestalt, en klar, rund äktenskapsmäklare."},"ICON-1184":{"nm":"Gummi","de":"Press den eller sträck den, till slut återvänder den till sin plats. Även de som hånade dess mjukhet väljer mig ändå att bära en regnig dag. Konsten att mjukt ta emot en hård stöt – seghet lever även i denna mjukhet."},"ICON-1185":{"nm":"Plastbit","de":"En liten bit som lossnat från huvudkroppen. Den var nära att slängas, men samlas många ihop blir de något nytt igen. Inte lätt för att den är liten, utan en del av något som kan färdas långt just för att den är lätt."},"ICON-1186":{"nm":"Rep","de":"Först när flera trådar tvinnas samman blir de en enda lina. Ensam repar den lätt upp sig, men flätad drar den ett skepp och binder en last. En gammal knut av samarbete, sträv mot handflatan, gjord segare av att ha vridits tillsammans."},"ICON-1187":{"nm":"Segelduk","de":"Den hatar inte vinden utan tar emot den med öppen famn. Bara spänd och svällande skickar den skeppet långt, så till och med motvind blir en styrka för mig. Konsten att gå framåt genom att omfamna det häftiga i stället för att stå emot det – den lärde den sig till havs."},"ICON-1188":{"nm":"Ankarbit","de":"Den är bara ett hörn av ett ankare, men minns dess tyngd i sin helhet. Dagarna då den grep tag i det djupa havsbottnet och stannade ett skepp. Även nu, avbruten, är den en tung bit som känner till vikten av att stanna kvar."},"ICON-1189":{"nm":"Skeppsspik","de":"En spik som höll fast ett däck som gungade i vågorna, punkt för punkt. Även rostad röd av saltet släppte den aldrig sin plats till sista stund. Att hålla fast något som driver kräver också ett gott mått envishet."},"ICON-1190":{"nm":"Presenning","de":"Den klagar inte över uppgiften att stänga ute regnet. Den tar tyst emot det som forsar uppifrån och håller det som ligger under torrt. Inte pråligt, men ett stadigt lager som täcker någons last så att den inte blir blöt."},"ICON-1191":{"nm":"Färgämne","de":"Sjunk stilla in i vitt bomullstyg, och först då blir den till en färg. Indigo eller krapp, gamla tiders mödrar färgade sina fingertoppar när de klädde tyg i färg. Även i arbetet att sjunka in och genomsyra finns ett djup som knappt bleknar."},"ICON-1192":{"nm":"Doftolja","de":"En enda droppe, och ett vidsträckt fält breder plötsligt ut sig i hela rummet. En gäst som anländer först fastän osynlig för ögat. Ett landskap som når näsan först, som sakta drar i fållen på sovande minnen."},"ICON-1193":{"nm":"Vax","de":"Tar den emot värme flyter den, svalnar den stelnar den och behåller sin form. På vandring mellan mjukhet och fasthet formar den stilla vad som helst. Ett ömsint material som försluter, förseglar och polerar, och byter uttryck efter temperaturen."},"ICON-1194":{"nm":"Stearinljus","de":"Den smälter sakta sin egen kropp för att lysa upp en enda ruta mörker. När den brunnit ut återstår bara dess förkortade längd, men tiden den värmde någons natt försvinner aldrig. En rak veke som vet konsten att lysa medan den blir mindre."},"ICON-1195":{"nm":"Kompost","de":"Ruttnande ting samlas tillsammans och blir den mest fettrika jorden. Bortkastade skal och torra höstlöv blir på så vis vårens nya skotts måltid. På just den plats man trodde var över hämtar nästa liv stilla sitt första andetag."},"ICON-1196":{"nm":"Ris","de":"Det krävs åttioåtta beröringar av handen innan man håller ett enda korn i handflatan. Från plantering till tröskning ryms en bondes hela år fullständigt i detta lilla korn. En ångande skål ris är i sig själv någons fyra årstider."},"ICON-1197":{"nm":"Brunt ris","de":"Med bara det yttre skalet lätt avskalat bevarade det sin ursprungliga färg precis som den var. Att det blir nötigare ju mer man tuggar är smaken av en ärlighet som inte skyndade sig. Kornets fasta envishet, som avvisar att slipas fint och behåller sin grova struktur."},"ICON-1198":{"nm":"Vete","de":"Det minns det gyllene fältet som böjde huvudet i samma stund i vinden. Genom att bli bröd, nudlar och klimpar värmer det bord över hela världen. Ett sädesslag som, just för att det är så vanligt, sjunkit desto djupare in i människors liv."},"ICON-1199":{"nm":"Vetemjöl","de":"Först efter att ha blivit ett fint, vitt pulver gör det sig äntligen redo att bli vad som helst. Möter det vatten sväller det, möter det eld blir det tillagat. Utan bestämd form är det en foglig grund som antar den form händerna knådar den till."},"ICON-1200":{"nm":"Deg","de":"Mjöl och vatten smälter samman till en enda klump under handflatan. Ju mer man knådar den desto senigare blir den, ju längre man väntar desto rundare sväller den. Skynda på och den blir seg, så jäsningens tid ensam kan inte skyndas på, säger det gamla bageriet."},"ICON-1201":{"nm":"Ströbröd","de":"Man borstar bort det vita dammet som fastnar på fingertopparna, och innan man vet ordet av är till och med skjortärmarna vita. Som panering blir det knaprigt, i högar liknar det den första snön. Det är det lättaste spåret ett bröd lämnar efter sig från bakningen, men även i det lilla växer nyttan."},"ICON-1202":{"nm":"Pasta","de":"I samma stund som du sprider en näve som en solfjäder i det kokande vattnet korsar ett avlägset solsken in i köket. De långa strängarna är handledens arbete, och al dente är hjärtat som vet att vänta medan det är lite underkokt. Se den glansen som snurrar runt, runt gaffeln."},"ICON-1203":{"nm":"Instantnudlar","de":"I gryningen, sedan all scenmakeup torkats bort, smygs en påse upp på spisen. De tre minuterna det tar för nudlarna att mjukna är dagens mest privata stund. Spänningen svalnar tillsammans med andedräkten du blåser, och bakom immiga glasögon tar dagen tyst slut."},"ICON-1204":{"nm":"Riskaka","de":"Först när riset uthärdar mortelns slag blir det tteok. Som mere, som injeolmi, som songpyeon – samma sädeskorn får hundra namn beroende på händerna som formar det. När det ställs fram på festbordet är det ömheten, inte munnen, som kallar först – en mat som smakar bäst delad."},"ICON-1205":{"nm":"Sopprisskivor","de":"Skär en lång stång tteok snett och skivorna blir runda som små mynt. Är det riskaka som flyter i den vita buljongen, eller en rund liten önskan? Att tömma en skål på nyårsmorgonen lägger till ett år till ens ålder – en öm sed, detta lands sätt att räkna."},"ICON-1206":{"nm":"Potatis","de":"Skaka bort jorden och ett runt ansikte kommer fram. En rotknöl som tyst svällt i vindarna på Gangwons sluttningar – mjölig när den ångkokas, smakrik när den steks. En ärlig rot som fyllt familjens magar även på dagar med tunn plånbok."},"ICON-1207":{"nm":"Sötpotatis","de":"När tunnan med rostad sötpotatis dök upp vid gränden var det vinterns riktiga början. Skala bort folien och gul ånga värmer fingrarna först; sötman är rotens belöning för att ha uthärdat kylan. En värme perfekt att blåsa på, dela itu och dela med sig av."},"ICON-1208":{"nm":"Morot","de":"Ett enda orange spjut som sträcker sig rakt ner genom jorden. Man kunde tro att bara kaniner tyckte om den, men woka den och en gömd sötma vaknar, och i soppan bidrar den även med färg. De gamlas ord om att den är nyttig för ögonen hade, för det mesta, rätt."},"ICON-1209":{"nm":"Rättika","de":"En enda vit, tung rot räcker för att göra vinterbordet stadigt. Iskall som dongchimi, uppfriskande som rättiksoppa, knaprig som kkakdugi. Inget går till spillo – till och med de gröna topparna torkas under takskägget och sparas som siraegi – en sparsam grönsak."},"ICON-1210":{"nm":"Lök","de":"Skala den och en tår rullar ner. Det skarpa, stickande köttet blir sött som en lögn så fort det möter het olja. Dess namn skrivs på första raden i nästan varje koreansk rätt – huvudrollsinnehavaren som tyst lägger grunden för smaken."},"ICON-1211":{"nm":"Salladslök","de":"Strö den finskurna vita basen och de gröna topparna över buljongen, och först då känns skålen verkligen fullbordad. Ställ den kvarvarande roten i ett glas vatten och den skjuter upp igen – ett litet fönsterträdgårdsland för den hushållskloka."},"ICON-1212":{"nm":"Vitlök","de":"Sex klyftor samlas i en ring och bildar en klase. Den skarpa rot som, sägs det, förvandlade en björn till en kvinna. Krossa den med knivbladets flata sida och doften flammar genast upp; utan en näve av den blir varken kimchi eller gryta meningsfullt."},"ICON-1213":{"nm":"Ingefära","de":"En liten, knölig rot lik en trasslig knut. Bara en enda skiva räcker för att stilla fisklukten och värma en frusen kropp inifrån. Den varma koppen, brygd med honung, som du drack de nätter du låg och stönade av förkylning, började med denna skarpa lilla styrka."},"ICON-1214":{"nm":"Kinakål","de":"Salta de tätt packade bladen, och först då öppnas kimchins första kapitel. Sent på hösten travades den som berg på varje gård. Att hela familjen samlades för att lägga in en sats var ett löfte om att ta sig igenom den långa vintern tillsammans."},"ICON-1215":{"nm":"Vitkål","de":"Skala de runda, lagervis rullade bladen ett i taget och det tar aldrig slut, så förr eller senare lugnar sig sinnet. Blancherad blir den mör, wokad blir den söt. Under sitt enkla yttre döljer denna grönsak en oväntad ömhet."},"ICON-1216":{"nm":"Isbergssallat","de":"Lägg en bit kött i det urholkade bladet, toppa med en klick ssamjang och stoppa in en full munsbit. Vid ett bord där alla sitter i ring och äter insvept lägger var och en sakta av sig formaliteterna – detta är inget mindre än det grönas gästfrihet."},"ICON-1217":{"nm":"Bladsallat","de":"Det första bladet som skjuter upp i ett hörn av köksträdgården. Plocka det och det växer ut igen, och fyller bordet hela sommaren. Den friska, gröna doften – sköljd i kallt vatten och insvept för hand – är för en del hela smaken av hemmet."},"ICON-1218":{"nm":"Spenat","de":"Det där tecknade grönet som gav en kraftskur när burken tömdes. Blancherad krymper den till en näve, men doften och kraften finns kvar. God både knådad för hand med krydda och rörd ner i sojabönssoppa – en grönsak man aldrig ska underskatta bara för att den är vanlig."},"ICON-1219":{"nm":"Ormbunksskott","de":"Bryt de sköra skotten som vårberget bjuder på, koka dem och torka dem sedan. Först efter all den långa mödan kommer de upp på förfäderaltaret och i bibimbap-skålen. Lika mycket omsorg som möda är inbäddad i den – en dyrbar ört som berget fostrat under en säsong."},"ICON-1220":{"nm":"Vilda bergsgrönsaker","de":"Till synes namnlösa, men var och en bär sin egen doft – vårens gåva. Mormors händer känner på en enda blick igen vilket blad på bergsstigen som går att äta. I en enda korg med grönt följer en hel årstid med, doft och allt."},"ICON-1221":{"nm":"Gråbo","de":"Den bittert doftande örten som allra först bryter genom den frusna jorden. Formad till riskaka går vårens ljus rakt in i munnen. I den första månaden trodde man att en soppa kokt på den höll årets olycka borta, så våren kom alltid med denna doft."},"ICON-1222":{"nm":"Perillablad","de":"En doft som färgar hela munnen djupt med bara ett enda blad. Servera det till gyllenbrynt sidfläsk eller lägg in det lager på lager i sojasås, och en skål ris är borta på ett ögonblick. Denna säregna arom känns rätt bara vid detta lands bord."},"ICON-1223":{"nm":"Grön paprika","de":"En ihålig grön frukt som knastrar sönder friskt. Den lätta bitterheten väcker en avtrubbad smak, och wokad i olja blir färgen ännu klarare. Finhackad och strödd över gör den vilken rätt som helst friskare på ett ögonblick."},"ICON-1224":{"nm":"Paprika","de":"Rött, gult, orange – färger som trafikljus fyller en hel korg. Bit i den rå och söt saft rinner fram; enbart färgen lyser upp bordet. Ordspråket om att vacker mat väcker aptiten stämmer precis här."},"ICON-1225":{"nm":"Tomat","de":"Den runda rödheten man alltid tvistat om – frukt eller grönsak? Kokt länge fördjupas smaken, äten rå är den ojämförligt frisk. Den frukt som samlat midsommarsolen mest ärligt, så ett enda bett spränger loss en hel middag."},"ICON-1226":{"nm":"Gurka","de":"Det gröna som svalkar sommarhettan mest uppfriskande. Låt den flyta i kall soppa och munnen blir sval; lägg in den som sobagi och knapret vaknar till liv. På kvava dagar kan den till och med skäras tunt och läggas över ögonen – en grönsak sval både in- och utvändigt."},"ICON-1227":{"nm":"Pumpa","de":"Den hänger rund i änden av rankan och fylls sakta med sötma ända in i sen höst. Kokt mjuk blir den till gul gröt som lugnar magen, stekt blir den till gyllene jeon. Hängd under takskägget tjänar den som ett pålitligt skafferi hela vintern."},"ICON-1228":{"nm":"Squash","de":"Den ljusgröna som sväller för varje dag i sommarträdgården. Grovhackad i sojabönsgryta, gyllenstekt som jeon – så mör att den är mild även för ett litet barns mun. Vanlig, och desto mer värdesatt för det: en stamgäst vid midsommarbordet."},"ICON-1229":{"nm":"Aubergine","de":"En avlång frukt med en jämn, lila glans. Suger den upp olja blir den oändligt mjuk, ångas den igenom blir strukturen fin som siden. Den ser oansenlig ut men passar bra ihop med vad som helst – bordets vänliga biroll."},"ICON-1230":{"nm":"Majs","de":"Gula korn ställda prydligt på rad, det ena vid det andra. Ett sommarmellanmål ångat i grytan, blåst på och bitet i; också den välkomna signalen att fälten har mognat. Inuti det luddiga knippet med silke är sötman fullt packad."},"ICON-1231":{"nm":"Sojaböna","de":"Små, hårda korn dricker vatten under natten och sväller runda. Malda fint blir de till sojamjölk, jästa mjuka blir de till jang – det mesta av proteinet vid detta lands bord började just här. Gräv ner ett enda frö i jorden och det återvänder som en hel planta."},"ICON-1232":{"nm":"Tofu","de":"När sojabönor dricker vatten, mals och stelnar blir de till ett vitt block med raka, jämna kanter. Mjukt och anspråkslöst insisterar det aldrig på sin egen färg i någon soppa. Det faller sönder skört redan vid en sked – en mat vars dygd är just enkelheten."},"ICON-1233":{"nm":"Adzukiböna","de":"Koka de små röda kornen grundligt och en mörkröd sötma dras fram djupt. Under den längsta natten drev en varm skål med adzukigröt en gång bort både kylan och onda andar – den känslan bor kvar här. Lager på lager i den ångade kakan var det röda inget mindre än omsorg."},"ICON-1234":{"nm":"Adzukipasta","de":"En mjuk fyllning gjord av kokta adzukibönor, mosade fint och sedan inkokta gång på gång. En sked mellan bröd, inuti riskaka, ovanpå iskrossen – en enda tråd av sötma värmer även gamla minnen. All den långa tiden av silande och inkokning blir själva sötman."},"ICON-1235":{"nm":"Svamp","de":"Efter att regnet klarnar sticker den tyst upp huvudet i skogens skumma skugga. Jordens hantverk, som odlar fram sin egen doft utan en enda handfull sol. Lägg bara en näve i soppan och en djup umami dras fram utan kött – en hemlighet skogen håller gömd."},"ICON-1236":{"nm":"Shiitakesvamp","de":"Ett brunt paraply med hatten helt utfälld. Torkad knastertorr i solen blir doften mångdubbelt djupare, så en enda torkad hatt räcker gott och väl för att bära en hel gryta buljong. En stadig pelare på det vegetariska bordet, och en gammal favorit hos den som känner till djup smak."},"ICON-1237":{"nm":"Tallmusseron","de":"Djupt inne i en höstlig tallskog reser den sakta huvudet, bara vid sidan av tallarna. Den kan inte odlas av människohand utan måste sökas upp till fots, vilket gör doften desto dyrbarare. Lätt grillad med bara en nypa salt, och en flik av skogen kommer in i munnen."},"ICON-1238":{"nm":"Kungsmusseron","de":"Riv den tjocka stjälken längs fibrerna och tuggmotståndet kommer rakt i handen. Den växer stadigt året runt, så den är aldrig långt från bordet. Grillad eller wokad – i sitt frikostiga kött är en obesvärad mättnad fullt packad."},"ICON-1239":{"nm":"Jordgubbe","de":"Längst inne i ett vinterhärdat växthus mognar den röd allra först. Ett enda bett är sött och syrligt, precis som vårens första hälsning. Lägg ett enda runt bär ovanpå en tårta, och till och med en helt vanlig dag blir genast en högtidsdag."},"ICON-1240":{"nm":"Blåbär","de":"Ett litet knäpp och en klar syrlighet sprider sig genom hela munnen. Plocka de små lila kulorna en och en, och innan man vet ordet av är burken tom; strö dem över vit mjölk och en liten nattsvart himmel breder ut sig med detsamma."},"ICON-1241":{"nm":"Äpple","de":"Bit i det och med ett knastrande knäpp splittras hösten. Det röda som fruktodlingens mormor torkade av med sitt förkläde och räckte fram är en färg som bara kommer av att länge ha hållit om solljuset. Ju hårdare det är, desto bättre vet det hur man förblir sött ända till sista tuggan."},"ICON-1242":{"nm":"Päron","de":"Skala det och fingertopparna blir svala först. I frontraden på Chuseoks förfädersbord – i samma stund som den kalla, söta saften fyller munnen, sätter sig en flik av höstens nattvind sakta ner intill dig."},"ICON-1243":{"nm":"Persika","de":"Där varje persikoblomma fallit tar en luddig sommar form. Tryck lätt på den och doften sprider sig först; i samma stund du biter i den följer hela årstiden med in i munnen."},"ICON-1244":{"nm":"Vindruvor","de":"Lila bär hänger som en enda klase och lutar sig axel mot axel. Knäpp ett och det sura kommer först, det söta en halv takt efter – som en prydlig kör sjungen av sommarens sista dagar."},"ICON-1245":{"nm":"Gröna vindruvor","de":"Det ljusgröna släpper solljuset rakt igenom, så en lampa tänds i varje bär. Kärnfri och ren uppfriskande, en sötma utan ett enda överflödigt drag, som en nyss framdragen första fras."},"ICON-1246":{"nm":"Citron","de":"Skrapa det gula skalet med en nagel och doften väcker näsan med ett knäpp. En enda droppe får mungiporna att dra ihop sig av sig själva, men i slutet av den där surheten finns ett underligt hörn där hela dagen ljusnar."},"ICON-1247":{"nm":"Lime","de":"Mindre och djupare grön än en citron, denna lilla frukt hälsar först med sin skarpa, snärtiga doft. En enda klyfta väcker till och med ljummet vatten på ett ögonblick – en liten, men beslutsam näve friskhet."},"ICON-1248":{"nm":"Apelsin","de":"I samma stund du skalar den fastnar doften av solsken på fingrarna. Lägg en klyfta i taget i munnen och pop, pop – små ballonger av söt saft brister, och det runda rullar även humöret runt och mjukt."},"ICON-1249":{"nm":"Mandarin","de":"Minns du den smaken – att skala dem med fötterna instoppade under det varma golvets täcke om vintern? Doften som spred sig under naglarna färgade hela rummet gult. En enda påse räcker som förevändning för familjen att samlas."},"ICON-1250":{"nm":"Banan","de":"Det fanns dagar då jag stillade hungern i ett hörn av övningsrummet i gryningen med en enda gul frukt som rullade fram ur väskan. Mjuk, söt och mättande – den ömsintaste av nödlösningar."},"ICON-1251":{"nm":"Ananas","de":"Man måste ta sig förbi ett lager taggigt skal innan det gula köttet visar sig. Håll en bit i munnen och det sötsura sticker till på tungan, medan doften av ett sydligt hav sakta lägger sig kring läpparna."},"ICON-1252":{"nm":"Mango","de":"Dela det mogna köttet för hand och en klibbig, söt doft väter fingrarna. När det djupa gula smälter och försvinner mjukt i munnen, glider en söt dröm förbi, likt en kort sommarsiesta."},"ICON-1253":{"nm":"Kokosnöt","de":"Skaka det hårda skalet och man hör vatten skvalpa därinne. Krossa det och det vita köttet och den svalkande saften kommer fram – en liten kruka där ett avlägset hav vaggar, helt och odelat."},"ICON-1254":{"nm":"Drakfrukt","de":"Det rosa, fjällika yttre får en att tveka först, men dela den och det vita innanmätet är prickat med små svarta frön. Anspråkslös i smak men flärdfull i klädsel – en listig bedragare, precis tvärtom in- och utvändigt."},"ICON-1255":{"nm":"Kiwi","de":"Skär den luddiga bruna frukten itu och en grön juvel visar sig. Skopa upp ett snitt där svarta frön sitter inbäddade som stjärnor, och en enda syrlig sked skakar en vaken ur sömnen."},"ICON-1256":{"nm":"Kyckling","de":"Lägg den i en oljad panna och det gyllene fräset lagar sig först. Mild och mör slinker den obehindrat in vid vem som helst bord – en stamgäst för en enkel måltid."},"ICON-1257":{"nm":"Fläskkött","de":"På grillplattan väser den, fettet knastrar och stänker medan den blir gyllenbrun. De där personalmiddagskvällarna då man stoppade en full munsbit inlindad i ett salladsblad med en klick ssamjang – smakrikheten värmer hela bordet."},"ICON-1258":{"nm":"Nötkött","de":"I varje röd fiber sitter fettet fint marmorerat och glänser. Lägg den på en het stenplatta och doften fyller rummet först; i samma stund en bit kommer in i munnen löses dagens tyngd sakta upp."},"ICON-1259":{"nm":"Bacon","de":"På morgonens stekpanna knastrar det och fettet dansar. Bara den där salta doften får familjemedlemmar som sovit länge att gnugga sig i ögonen och samlas i köket – en måltid som doften kallar till först."},"ICON-1260":{"nm":"Korv","de":"De inskurna snitten flänger upp sig och köttsaften spricker ut. Den röda bläckfiskformen som ansvarade för ett fack i matlådan var en liten lyx som barndomens luncher fick njuta av."},"ICON-1261":{"nm":"Pepperoni","de":"En rund, stark skiva krullar sig från kanten och inåt ovanpå den heta osten. När lite olja samlas i mitten, det är precis pizzans höjdpunkt – liten, men rund och djup i sin närvaro."},"ICON-1262":{"nm":"Hamburgerbiff","de":"Forma den tjock och lägg den på grillen, och den bryns från kanterna och inåt. Kläm in grönsaker mellan en pressgrillad skiva, och en mättnad som får plats i en enda hand är fullbordad."},"ICON-1263":{"nm":"Ägg","de":"Knäck det och gulan glider ut som en rund liten sol. Lika gott blandat i nykokt ris som den gula strimman inuti gimbap – det vanligaste och därför det ömsintaste proteinet."},"ICON-1264":{"nm":"Mjölk","de":"En kall flaska ställd vid dörren i gryningen – dagen brukade öppnas av just den svalkan mot handflatan. Ångande när den värms, smakrik när den kyls – ett vitt ljus som alltid finns vid din sida."},"ICON-1265":{"nm":"Ost","de":"En gul skiva rasar sakta samman ovanpå varmt bröd. Hjärtat som väntar på det ögonblicket den töjs ut – ju mer den smälter, desto djupare och rikare blir smakrikheten."},"ICON-1266":{"nm":"Cheddarost","de":"Den djupa orangea färgen förebådar en salt smak på en enda blick. Skär den tunt och lägg den i en toast, och umamin sprider sig genom hela munnen – lika tydlig i smaken som i färgen."},"ICON-1267":{"nm":"Smör","de":"Släpp en bit i en het panna och den smälter mjukt medan smakrik ånga stiger upp. Bredd på bröd, rörd ner i ris – en gul magi som gör allt den rör vid en aning mjukare."},"ICON-1268":{"nm":"Vispgrädde","de":"Ju mer man vispar, desto mer sväller det rinniga vita till fasta moln. I samma stund en sked läggs ovanpå tårtan ljusnar en helt vanlig eftermiddag som en liten födelsedag."},"ICON-1269":{"nm":"Yoghurt","de":"Sänk ner en sked och den syrliga vitheten lyfts mjukt upp. Blanda i en bit frukt och morgonen blir lättare; en kopp och magen ordnas lugnt till ro – en mild starts smak."},"ICON-1270":{"nm":"Makrill","de":"Lägg den på grillgallret och fettet fräser och stänker, medan en rök både fiskig och smakrik fyller köket. De händer som plockade ur benen och lade den ovanpå riset – den djupaste omsorgen som bor i ett vardagligt bord."},"ICON-1271":{"nm":"Lax","de":"Rosa fibrer ligger staplade lager på lager. Ätet kallt löses det mjukt upp i munnen, grillat sipprar fettet ut smakrikt – en fast smak som simmat hem mot strömmen från ett avlägset hav."},"ICON-1272":{"nm":"Tonfisk","de":"Öppna konservburkens lock och en salt doft stiger upp med en gång. Det fanns nätter i ett litet studentrum då en enda burk, blandad i ris och inlindad i sjögräs, blev en riktig måltid."},"ICON-1273":{"nm":"Torsk","de":"Det klara köttet är så milt att en uppfriskande buljong dras fram redan från början när den kokas. En vit fisk som uthärdat vinterhamnens skärande vind – en enda skål het soppa och även frusna händer töar sakta upp."},"ICON-1274":{"nm":"Räka","de":"Den kröker ryggen rund, och när den tillagas färgas det grå rosa. En knäckande spänst och en smakrik doft – skala och ät dem en och en, och tallriken är på något sätt redan tom."},"ICON-1275":{"nm":"Krabba","de":"Att plocka ut det vita köttet ur det hårda skalet är en liten stund av tålamod. Biten man till sist stoppar i munnen efter all den mödan är söt – ett helt höstligt hav kommer in i munnen."},"ICON-1276":{"nm":"Bläckfisk","de":"På grillen krullar den sig rund och sprider en smakrik doft. En seg, tuggmotståndig bit, doppad i chilisås och stoppad i munnen, och ett salt hav följer med."},"ICON-1277":{"nm":"Musslor","de":"I den klara buljongen öppnar de sig sakta och ger tyst ifrån sig sin doft. Vid det puttrande ljudet sprider sig havets lukt, och en enda klunk löser upp en frusen mage varmt."},"ICON-1278":{"nm":"Fiskkaka","de":"Doppa den, spett och allt, i het buljong och ångan stiger i lockande virvlar. Framför en gatustånd på en kall dag, de händer som höll en pappmugg med buljong och blåste på den – en liten tröst som gränden bjuder på."},"ICON-1279":{"nm":"Kimchi","de":"Inuti krukan mognar den sakta och odlar en syrlig, djup doft. Riv den för hand och lägg den ovanpå nykokt ris, det räcker – smaken som skiljer sig från hus till hus är just det hemmets egen historia."},"ICON-1280":{"nm":"Inlagd rättika","de":"En gul skiva knastrar lätt och muntert sönder i munnen. Den trogna följeslagaren vid sidan av en rulle gimbap eller en tallrik gatumat – det sötsura sköljer en flottig mun fräsch."},"ICON-1281":{"nm":"Pickles","de":"Gurkan håller andan en stund i saltet och öppnar sedan ögonen i ättikan. För att inte missa ögonblicket då knapret återvänder lämnar glasburken aldrig den solbelysta fönsterbrädan. Tiden som sakta förlöper genom inläggningen är det som för med sig smaken."},"ICON-1282":{"nm":"Röd chilipasta","de":"En rödhet som uthärdat ett helt år inuti krukan. Bakom hettan gömmer sig sakta sojabönans sötma, så en enda sked löst upp gör att grytan äntligen blir vårt eget hems ansikte. Ett djup som gårdens jang-krukor fostrat fram med solljus."},"ICON-1283":{"nm":"Sojabönspasta","de":"Meju-blocket omfamnade sin mögel och levde igenom en hel vinter. Den nötiga djupheten är en vansklig lindans mellan just mogen och övermogen – mormor kände igen den gränsen på en enda doft från fingertopparna. En smak som fördjupas i takt med väntan."},"ICON-1284":{"nm":"Sojasås","de":"Ju mörkare sojabönorna blir, desto djupare blir deras inre. En enda droppe väcker liv i en grönsaksrätt och ger glans åt en gryta, så alla färger i köket börjar till sist i just denna varma bruna ton. En umami bortom det salta."},"ICON-1285":{"nm":"Svart bönpasta","de":"Även samma svarta har olika struktur. Ett sötsalt eftersmak som stekts en gång till med karamell – blanda den i nudlar och den svarta glansen skakar aptiten vaken. Den första knappen där den kinesiska wokelden tar sin början."},"ICON-1286":{"nm":"Currypulver","de":"Ett gult pulver där många kryddor samsas fredligt i en enda sked. Löst upp i vatten bubblar det upp och värmer hela huset – det blir förhandsvisningen av kvällens mest mättande skål på en regnig kväll."},"ICON-1287":{"nm":"Peppar","de":"Bara nymald hel förblir doften levande; malen i förväg smyger den sig sakta iväg. Det sista varvet kommer alltid strax innan man släcker elden – en liten punkt som den lagande handen sparsamt sätter dit."},"ICON-1288":{"nm":"Chilipulver","de":"Solmogna chilifrukter torkade under höstsolen fullbordar äntligen sin rödhet. Om de mals fint eller grovt avgör kimchins karaktär, så en kocks personliga touch kommer, till syvende och sist, från valet av detta pulvers grovlek."},"ICON-1289":{"nm":"Salt","de":"Att smaka av handlar om att nypa för nypa närma sig den underkryddade sidan. Salt som väl tillsatts kan inte tas tillbaka, så en van hand lägger alltid i lite mindre på slutet och smakar av. Det man håller tillbaka är utrymmet att andas."},"ICON-1290":{"nm":"Socker","de":"Det lugnar bitterhet och rundar av surhetens skarpa kanter. Men sötman får aldrig avslöja sin egen närvaro, så ju bättre kryddningen är, desto tystare försvinner sockret ur syn på slutet. En sötma som vet hur man gömmer sig."},"ICON-1291":{"nm":"Honung","de":"En burk som bina samlat genom att flyga tusentals gånger fram och tillbaka över blomsterängen. Stelnar den, väcks den till liv igen i ett vattenbad; löst i te sveper den mjukt om halsen. En gyllene sked där en hel årstid kokats ihop."},"ICON-1292":{"nm":"Matolja","de":"Ringla den runt en het panna en gång och ingredienserna glömmer att fastna. Häller man i för tidigt bränns den vid, för sent klibbar den fast, så just den takten då röken börjar stiga är stekningens grundregel. Man mäter ögonblicket med ljudet."},"ICON-1293":{"nm":"Olivolja","de":"I den första pressningens gröna finns gräsdoft och en aning skärpa tillsammans. Ringlad över maten på slutet snarare än satt på elden överlever den doften ända till sista droppen, så det ärligaste sättet att använda den är att inte laga den alls."},"ICON-1294":{"nm":"Sesamolja","de":"Släpp en enda droppe på slutet och den kryddade grönsaksrätten förklarar sig äntligen fullbordad. Dess smakrikhet är av det slaget som lätt flyr över elden, så den blir alltid punkten som sakta läggs till efter att all tillagning är klar."},"ICON-1295":{"nm":"Vaniljstång","de":"Dela en balja och skrapa ut de svarta fröna, och desserten byter om till en dräkt av doft. Att inte kasta ens det uttömda skalet utan gräva ner det i socker – en gammal sparsamhet som konditorer ärvt."},"ICON-1296":{"nm":"Kakao","de":"Vitt fruktkött och bittra frön inuti frukten. Först efter jäsning och torkning i solen översätts de till den sötma vi känner till. Innan den blir choklad bär den sitt allra första ansikte, det som ligger närmast det vilda."},"ICON-1297":{"nm":"Choklad","de":"En kinkig natur som smälter bort av bara handflatans värme. Den måste stelna kring 28 grader för att den knäckande glansen ska bestå, så bakom sötman döljer sig, förvånande nog, en petig temperaturregel."},"ICON-1298":{"nm":"Kaffebönor","de":"Innan den mals är en enda böna nära en hård tystnad. Men möter den hett vatten sväller den upp och andas ut sin doft, så den första signalen som väcker morgonen börjar alltid med denna lilla böna."},"ICON-1299":{"nm":"Teblad","de":"Stannar de för länge i hett vatten blir de strävt beska, för kort och de blir smaklösa. Att stilla räkna tiden det tar för bladen att sakta veckla ut sig – att brygga te är att mäta väntan med fingertopparna."},"ICON-1300":{"nm":"Mynta","de":"Krossas den sipprar bitterhet fram, så det är ett skört blad som alltid måste hanteras varsamt. Knacka lätt på den för att väcka den sovande doften, och låt den flyta i ett glas på en kvav dag, och midsommaren sjunker en ton svalare."},"ICON-1301":{"nm":"Örter","de":"Lägger man i den med stjälk och allt blir doften djup, använder man bara bladen blir den ren och klar. Torkad blir den starkare, färsk blir den frisk och skarp — köksuttrycket vidgas lika mycket som doftomfånget i ett enda knippe."},"ICON-1302":{"nm":"Kastanj","de":"Inuti det taggiga skalet gömmer sig en glänsande, blank kärna. Skär man ett snitt och rostar den spricker den upp med ett litet knäpp och sprider en söt doft — värmen från en påse rostade kastanjer i en kall vindgränd känns nästan gripbar."},"ICON-1303":{"nm":"Jordnöt","de":"Sältan fulländas över den rostande elden. Ett litet frö man skalar korn för korn tills tiden glider bort — delar man den sittande i en ring på golvet, skalas historierna av lika sakta, tillsammans."},"ICON-1304":{"nm":"Mandel","de":"Blancherar man den lätt och skalar bort huden blir insidan vitare och mjukare. Krossad och malen blir den som mjölk, rostad hel blir den knaprig — spännvidden av förvandling i ett enda nötkorn vidgar konditorns fantasi till fullo."},"ICON-1305":{"nm":"Sesamfrön","de":"Skakar man dem försiktigt över svag värme börjar de vid någon punkt hoppa till med små knäpp. Ögonblicket alldeles innan ljudet tystnar är den mest smakrika stunden — att rosta sesam blir till slut något man gör med örat."},"ICON-1306":{"nm":"Sockerrör","de":"Tuggar man en led sipprar söt saft fram tillsammans med en grön, grässlig doft. En stjälk som måste kokas ner om och om igen för att bli den sötma vi känner — sockrets början är förvånansvärt grön och högrest."},"ICON-1307":{"nm":"Råsocker","de":"En rå sötma som bär sin egen färg, då den genomgått mindre raffinering. Ett svagt, jordigt djup dröjer sig kvar, så händer som älskar äktheten hos något innan det polerats slätt söker den upp med flit."},"ICON-1308":{"nm":"Kakaobönor","de":"Fröna som just tagits ur skidan är bittra och strama. De måste tyst uthärda flera dagars jäsning innan doften slår ut, så sötma är ett litet pris denna böna får ta emot efter lång tålamod."},"ICON-1309":{"nm":"Kakaonibs","de":"I bitarna av krossad, rostad böna finns inte ett enda sockerkorn. Lägger man dem i munnen kommer bitterheten först och sötman sist, så man möter kakaon innan sötman, på det ärligaste sättet."},"ICON-1310":{"nm":"Gröna kaffebönor","de":"Gröna korn som ännu bär en rå doft. Som de är ligger aromen i djup sömn, så tills de mottar eldens dop förblir de stilla en möjlighet som ännu inte vet vad den ska bli."},"ICON-1311":{"nm":"Rostade kaffebönor","de":"På den bruna ytan där oljan sakta trängt fram har doften samlats i fullhet. De måste malas innan de svalnar för att doften ska förbli hel, så en kopps öde avgörs tyst inom några dagar efter rostningen."},"ICON-1312":{"nm":"Vaniljstång","de":"En enda strimma doft färgar en hel gryta mjölk igenom. Stoppar man till och med den urtömda skidan i en sockerburk blir efter några dagar allt sockret doftande — en lyx utan en enda del att slänga."},"ICON-1313":{"nm":"Peppar","de":"Doften hos ett enda pepparkorn avtar från den stund det mals. Därför håller man det helt på bordet och krossar det efter behov — friskhet blomstrar ur ett hjärta som inte skjuter upp."},"ICON-1314":{"nm":"Vitpeppar","de":"Kornet, blivet slätare av att ha mist sitt skal, är dämpat snarare än skarpt. Fött ur omtanken att inte lämna en enda svart prick i en vit sås — en finess på en osynlig plats."},"ICON-1315":{"nm":"Kanel","de":"Drar man ur en bit sprids en varm skärpa sakta genom teet. I hel form snarare än malen håller doften längre, så vinterdryckens djup kommer ur denna torkade barks uthållighet."},"ICON-1316":{"nm":"Kryddnejlika","de":"I en enda blomknopp formad som en liten spik är doften tätt koncentrerad. Lägger man i för mycket sväljer den hela rätten, så återhållsamheten hos en enda knopp vakar tyst över smakens balans."},"ICON-1317":{"nm":"Muskotnöt","de":"Man behåller fröet helt och river en aning efter behov. Den har en natur att snabbt sprida bort sin doft om den malts i förväg, så den sista snabba rivningen fördjupar en mjölks arom ännu mer."},"ICON-1318":{"nm":"Kardemumma","de":"Knäpper man till den gröna skidan forsar en frisk, sval doft fram inifrån. Bara genom att krossa en eller två korn i teet får en vanlig kopp plötsligt doften av ett avlägset land."},"ICON-1319":{"nm":"Saffran","de":"Röda trådar, knappt tre insamlade från en enda blomma. Löser man upp dem i varmt vatten sprids det gula skenet sakta, så det dyrbara är också vikten av tid ägnad åt att plocka för hand, en i taget."},"ICON-1320":{"nm":"Gurkmeja","de":"Mal man roten ur jorden färgar den till och med fingertopparna gula. Den har en natur där doften vaknar först vid lätt sautering i olja, så currygrytans gyllene glöd är en färg denna lilla rot dragit fram över elden."},"ICON-1321":{"nm":"Lagerblad","de":"Bladet som sägs ha lagts på segrarens panna. Låt ett flyta i kokande vatten och genom ångan reser sig ett gammalt stadions jubel för ett kort ögonblick. Även på dagar man inte vann blir doften, indragen i andetagen, en grön tröst som tyst omfamnar dagens jag."},"ICON-1322":{"nm":"Kokosmjölk","de":"Den vita saften som först flyter fram när man spräcker det hårda skalet. I ett hörn av en marknad i ett hett land sätter man i ett sugrör och tar en klunk, och middagens törst kyls av helt och hållet. Den svala, söta doften som sprider sig i munnen bär med sig tropikernas skugga."},"ICON-1323":{"nm":"Kokosolja","de":"Stelnad är den vit som förstasnö, värmd i handflatan sprids doften mjukt ut. Ö-mormoderns varma, hushållskloka visdom — hon räckte fram den med orden att en burk räcker från topp till tå — bevaras hel i den runda burken."},"ICON-1324":{"nm":"Torkad banan","de":"Lagd i solen några dagar blir det gula fruktköttet segt. Tar man en bit i taget, sparsamt, väcks den klibbiga, söta doften från en regnig skördetid sakta till liv igen i munnen. Långsamt mognad sötma bär en årstid på det viset."},"ICON-1325":{"nm":"Torkad mango","de":"Det mjuka fruktköttet, koncentrerat i solen, återföddes som bärnstensgelé. Surt, sött och segt — alla tre smaker ryms i en enda bit, så rullar man den sakta i munnen förlängs eftermiddagen med en hel påse."},"ICON-1326":{"nm":"Torkad ananas","de":"Till skillnad från sitt taggiga yttre är fruktköttet inuti helt igenom gult och ljust. Torkad i solen koncentreras syrligheten, så en enda tugga får mungiporna att lyfta av sig själva. Den friska eftersmaken vid en bits slut dröjer sig länge kvar."},"ICON-1327":{"nm":"Tropisk fruktkorg","de":"Nyplockade färger smälter samman i en enda korg. Mangons orange, bananens gult, ananasens guld — innan man ens sträcker sig för att välja, når sommaren näsan först. En famn full som ljusnar sinnet bara vid åsynen."},"ICON-1328":{"nm":"Tångbunt","de":"Havets hår, insamlat från klipporna som ebben blottat. I den salta havsdoften trasslar vågornas ljud in sig, så blötlägger man det stilla i kallt vatten, och en svagt fiskig havslukt driver sakta ända in i köket. En näve breder ut en liten tidvattenäng på bordet."},"ICON-1329":{"nm":"Torkade havsprodukter","de":"En näve fast torkat hav. River man det för hand längs fibrerna löses saltheten upp tillsammans med en gammal hamns salta vind. En gammal vän vid det varmhjärtade bordet, som gör en sugen på en skål makgeolli helt av sig själv."},"ICON-1330":{"nm":"Torkad bläckfisk","de":"De tio armarna spreds ut jämnt och torkades i solen. Grillar man den lätt tills en smakrik doft stiger, river man den sedan längs fibrerna. Med den sega konsistensen stiger värdigheten hos en sen kvällsmacka ett snäpp."},"ICON-1331":{"nm":"Saltad fisk","de":"Begravd i grovt salt lär sig fisken att uthärda tiden. En enda bit av dess djupt saltade kött tömmer en skål ris på ett ögonblick — ett kärt hemligt knep som en mormor vid havet gav vidare med sina fingertoppar."},"ICON-1332":{"nm":"Saltade räkor","de":"Små räkor mognar sakta i saltet och återföds som umamidjup. I det ögonblick man rör ner en sked i kinakålen vid kimchisäsongen sprids den salta doften över hela gården. Den skeden avgör årets kimchismak."},"ICON-1333":{"nm":"Sardell","de":"En fingerstor kropp bär ansvaret för djupet i en hel gryta buljong. Barndomens kök, där man pratade sorlande medan man drog av huvuden och inälvor — liten men en tacksam fisk som stod stadigt mitt i hushållet."},"ICON-1334":{"nm":"Kombu","de":"Ett långt svart band, vuxet djupt under havet. Lägger man i det i kallt vatten och lyfter det försiktigt ur just innan uppkoket, är det ett löfte som buljongkokare hållit generationer igenom. Ett djupt umami har aldrig, aldrig bråttom."},"ICON-1335":{"nm":"Hijiki","de":"Den knottriga konsistensen poppar till på tungan. Tången som färgade tidvattensklipporna gröna om våren — kryddad och blandad för hand breder den ut ett litet, friskt hav i ett hörn av bordet. Smaken av att tugga vår."},"ICON-1336":{"nm":"Pärlmussla","de":"Ett runt sken format genom lång tids bärande mellan två fasta skal. Fram tills obehaget av ett enda sandkorn förvandlats till en juvel skyndade havet aldrig på. Lägger man den i handflatan vilar tyngden av det långa tålamodet där också."},"ICON-1337":{"nm":"Korallprydnad","de":"Havets trädgren, formad av vågorna under hundratals år. Berörd av ljus sprids den ut i rosa och orange, så bara genom att stå stilla på en hylla färgas ett helt rum till en varm ö. Även den grova strukturen mot fingertopparna känns kär."},"ICON-1338":{"nm":"Musselknapp","de":"Där musselköttet en gång fanns skars den skimrande insidan ut i en rundel. Sydd på ett kavajslag glittrar en liten regnbåge vid fingertopparna varje gång man knäpper igen. Den sista kära gåvan havet lämnade kvar när det gav bort allt och drog sig tillbaka."},"ICON-1339":{"nm":"Glaskula","de":"Rullar man den i handflatan följer det instängda ljuset med, rullande. De där tiderna av att sitta på huk i gränden och spela kula utan att märka solnedgången — fickan på det barn som vunnit en till kändes ovanligt tung och stolt."},"ICON-1340":{"nm":"Enträsnideri","de":"Ur varje snidad ådring tränger en svag doft fram. Forna tiders människor brände detta trä för att samla ett splittrat sinne. Håller man en bit stilla i handen stiger sakta ett lugn från fingertopparna."},"ICON-1341":{"nm":"Rökelse","de":"En tunn strimma brinner sakta och banar en väg uppåt. Följer man med ögonen den kurva röken tecknar, saktar snart ett sinne som skyndat hela dagen ner sina steg och dröjer stilla kvar på plats."},"ICON-1342":{"nm":"Färgblomma","de":"Löser man upp färgen gömd i kronbladen i en kokande gryta, färgas det klara tyget sakta av den nyansen. Att för en stund låna den färg naturen redan målat — färgning var i grunden en varm hälsning riktad till blomman."},"ICON-1343":{"nm":"Indigofärg","de":"Ett djupt, mjukt blått hämtat ur att jäsa indigoplantan om och om igen. Varje gång man doppar och lyfter upp tyget skiftar det sakta färg från himmelsblått till havsblått. En väntans färg, som blommar först när man lägger otåligheten åt sidan."},"ICON-1344":{"nm":"Karmosinfärg","de":"Drar man ur krapproten vaknar en solnedgång som legat och sovit i jorden till liv inne i grytan. Det var byns mest högtidliga, ljusaste färg, den som vackert färgade den nya brudens kjolfåll på bröllopsdagen."},"ICON-1345":{"nm":"Guldtråd","de":"Man drar guld finare än ett hårstrå och spinner det med omsorg, en enda tråd i taget. Var den än broderas håller den kvar ljuset, så till och med i ett mörkt rum med släckt lampa reser sig mönstret ensamt, mjukt lysande av sig själv."},"ICON-1346":{"nm":"Siden","de":"Tråden en silkesmask spinner fram måste vävas och vävas igen för att knappt bli en enda våd. En beröring som glider som vårvatten över handryggen — ett finkornigt tyg som forntidens människor bar genom en hel årstid och sakta odlade fram."},"ICON-1347":{"nm":"Pärlknapp","de":"Bara pärlans inre glans valdes ut och formades rund. Varje gång man knäpper igen en på ett jeogoris slag blir fingertopparna kort elegant. Liten, men ett prydligt korn som stillsamt lyfter dräktens värdighet."},"ICON-1348":{"nm":"Sjökortsfragment","de":"Bortom den slitna kanten bryts en okänd kustlinje abrupt av. Det sägs att bara den som samlar de återstående bitarna når skatten — men kanske var själva resan att irra runt och söka den i vinden redan skatten."},"ICON-1349":{"nm":"Gammalt sjökort","de":"Sjörutter uttvättade av havsvatten och en blekt teckning av en kompass. Följer man med fingertoppen linjerna en sjöman dragit efter enbart stjärnorna en becksvart natt, stiger en ö som försvann för länge sedan sakta fram igen på det gamla papperet."},"ICON-1350":{"nm":"Flaskpost","de":"Inuti en glasflaska som drivit iland med vågorna, ett enda hoprullat pappersark. En hälsning — ingen vet vem som skickade den eller när — har äntligen nått någons hand. Med hjärta nog blir till och med havet en så här långsam brevbärare."},"ICON-1351":{"nm":"Drivgodslåda","de":"Äventyret varar ända fram till stunden man bänder upp det saltvattensuppsvällda, styva locket. Vare sig det som väntar inuti är skatt eller bara tom sand, har en låda som drivit långt alltid en okänd persons berättelse fördriven med sig iland."},"ICON-1352":{"nm":"Liten nyckel","de":"En sliten metallbit som passar precis i handflatan. Även om man för länge sedan glömt vilken dörr den öppnar, dröjer en varm tyngd kvar vid fingertopparna, av det slag som får en att tänka på att låsa upp innan man låser."},"ICON-1353":{"nm":"Silvermynt","de":"En rund silverbit vars mönster bleknat under otaliga tummar. Ett enda mynt som en gång var någons färd eller en trött natts logi; stryker man över dess kalla yta väcks värmen från en gammal affär svagt till liv igen vid fingertopparna."},"ICON-1354":{"nm":"Guldmynt","de":"Lägger man den i handflatan är det den tunga vikten som först rör om i hjärtat. Ett enda mynt som glöder gult i solen verkar lova rikedom om man håller i det — men det som egentligen lyser klarast är fladdret alldeles innan det landar i handen."},"ICON-1355":{"nm":"Kaptenens sigill","de":"Kaptenens löfte, tryckt fast i rött lack. Ett enda märke kunde ge en order och staka ut en grov kurs. Auktoritet var, till syvende och sist, ett litet, fast stämpel som alla ombord på samma skepp gått med på att tro på tillsammans."},"ICON-1356":{"nm":"Handmikrofon","de":"I samma stund man griper om den fyller en märkligt trygg tyngd handflatan. Vare sig man bjuder på en darrande första hälsning eller till slut kastar ut en hög ton — denna lilla stav ger tyst röstens vingar."},"ICON-1357":{"nm":"Trådlös mikrofon","de":"När sladden försvann vidgades hela scenen på en gång. Springer man ända till salongens bortre kant avbryts rösten aldrig, som om någon tyst puttar en i ryggen och säger: spring och sjung av hjärtans lust."},"ICON-1358":{"nm":"Stativmikrofon","de":"Stående stadigt vid ens fötter väntar den tyst på sångaren. Blir båda händerna fria sprids sången genom hela kroppen istället för fingertopparna. Det finns en tydlig charm i att hålla en plats till slutet, säger denna stav stilla."},"ICON-1359":{"nm":"Poppfilter","de":"Ett enda runt lager tyg som spärrar av framför mikrofonen. Det filtrerar mjukt bort häftiga andetag och släpper bara den klara rösten igenom. Att göra någon hörd innebär att tyst skydda från en plats som förblir osynlig till sista stund."},"ICON-1360":{"nm":"In-ear-monitor","de":"Glider den precis in i örat väcks ens egen sång tydligt till liv igen bortom bruset av tiotusentals röster. Den minsta, mest hemliga följeslagaren, som håller en från att tappa takten på en scen översvämmad av ljus och ljud."},"ICON-1361":{"nm":"Hörlurar","de":"I samma stund de täcker öronen krymper världen ett snäpp och bara sången blir kvar stor. Ett runt litet rum ingen kan tränga sig in i. Ensam inuti hörlurarna är man, märkligt nog, inte ensam."},"ICON-1362":{"nm":"Notblad","de":"När de svarta prickarna lägger sig stilla på linjerna börjar det tysta pappret bära ljud. Skrift man lyssnar på snarare än läser. I samma stund man slår upp det andas en sång som stått stilla igen."},"ICON-1363":{"nm":"Sångnoter","de":"Vid varje plats att andas ritas en liten cirkel. Andas in här, släpp stilla där. Ett kärt kort som röjer en väg så rösten inte tar skada."},"ICON-1364":{"nm":"Pianonoter","de":"En sida där tio fingrar frågar efter vägen samtidigt. Vänster hand griper rötterna, höger hand tecknar sången. Två händer som berättat olika historier vecklas till slut samman till en enda i den sista takten."},"ICON-1365":{"nm":"Gitarrackordschema","de":"Fingrarnas första främmande språk, dess allra första ord står skrivet här. Samlas sex prickar i cirklar, klingar äntligen en enda ton. Natt efter natt av att trycka och trycka igen växer valkar på spetsarna."},"ICON-1366":{"nm":"Metronom","de":"Tick, tick — ett orubbligt steg slår vid ens sida. Skyndar hjärtat i förväg håller den sakta, sakta tillbaka bakifrån. Takten är, till syvende och sist, ett löfte om att gå tillsammans."},"ICON-1367":{"nm":"Stämapparat","de":"Glider nålen till mitten, hittar tonen äntligen sin plats. Den enda punkten, varken hög eller låg. Att stämma rätt är, visar det sig, detta: att inte längre darra, bara tyst komma till ro."},"ICON-1368":{"nm":"Pianotangentkort","de":"Bläddrar man ett blad i taget vandrar tangenterna rakt in i handflatan. Ett litet universum med sju fält, från C till H. Även på nätter utan ett riktigt piano växer sången stilla fram här."},"ICON-1369":{"nm":"Gitarrplektrum","de":"En liten, stadig flisa man klämmer mellan tumme och pekfinger. Tappar man den försvinner den för evigt under stolen, men i samma stund man håller den klingar alla sex strängarna ut på en gång."},"ICON-1370":{"nm":"Trumpinnar","de":"Möts de två i luften faller en signal just där. Ett, två, tre, fyra. Allas spridda hjärtan börjar slå i samma takt, avstämda efter dessa fyra slag."},"ICON-1371":{"nm":"Tamburin","de":"Ett enda slag och ett klart ljud sprids åt alla håll, som solsken som splittras i små bitar. Lätt som den ser ut är den ändå den första takt handen når efter när stämningen börjar falna. Ingen kan avfärda den för att vara liten."},"ICON-1372":{"nm":"Danssneakers","de":"För fötter som glider snurrande över golvet blir friktionen ett vapen. I varje sliten sula ristas snurr på snurr, upprepade om och om igen. Den snyggaste rörelsen börjar alltid i ett stadigt par skor."},"ICON-1373":{"nm":"Knäskydd","de":"Bara den som fallit på knä otaliga gånger och rest sig igen känner tacksamheten i detta enda tunna lager tyg. Något som gör att golvet inte längre skrämmer — mod är ibland just detta, virat runt knäna."},"ICON-1374":{"nm":"Handledsskydd","de":"Sveper man in leden i förväg blir även en ansträngd rörelse en aning mer förlåtande. Handleden säger inget, uthärdar ensam tills det gör ont. Den långa tystnaden tar ett enda lager på sig istället."},"ICON-1375":{"nm":"Fotledsskydd","de":"I slutet av ett högt hopp väntar landningen, och i slutet av den landningen väntar fotleden. Den lägsta platsen, som tar emot hela kroppens vikt. Detta lilla band vakar tyst över morgondagens övning."},"ICON-1376":{"nm":"Stretchband","de":"Drar man i det håller det emot, spänner sig för att återgå till sin plats. Medan man uthärdar det motståndet blir kroppen omärkligt lite längre. Att sträckas är, till syvende och sist, märket kvarlämnat av tiden man uthärdat."},"ICON-1377":{"nm":"Yogamatta","de":"I samma stund man rullar ut den uppstår en fläck mark på golvet, en enda persons andel. Ett litet territorium för att ligga, luta sig och jämna ut andningen. Dagens början och slut knyts stilla ihop på detta enda ark."},"ICON-1378":{"nm":"Skumrulle","de":"Trycker man stadigt på en knut gör det ont först, blir det snart skönt. Att lösa upp det som stelnat kräver alltid lite smärta. För både kropp och sinne måste tryckas en gång innan de kan släppa."},"ICON-1379":{"nm":"Hantel","de":"Man lyfter samma vikt, och lyfter den igen. Precis en gång till än igår, det är allt. I upprepning utan en gnista av glans förtjocknas armen utan ett ord. Ett klumpigt järnstycke som bara är ärligt."},"ICON-1380":{"nm":"Kettlebell","de":"Ett enda handtag svänger hela kroppen runt. När den runda vikten cirklar i en båge ställs den hållandes balans på prov. Vill man inte skaka, måste man först känna sitt eget centrum."},"ICON-1381":{"nm":"Hopprep","de":"Man hoppar över repet som viner förbi under fötterna, och hoppar igen. Precis som den lek man räknade i med vänner på gården, ju högre siffrorna klättrar, desto mer flåsar andan och desto mer växer skrattet."},"ICON-1382":{"nm":"Löparskor","de":"Ett par vars sanna värde man först känner uppe på vägen. Skär man genom gryningsluften och springer samma sträcka igen, är hörnet som kändes långt bort igår alldeles inpå idag. Fötterna minns avståndet."},"ICON-1383":{"nm":"Träningshandduk","de":"Torkar man svetten från pannan finns dagens ansträngning där, indränkt i en enda strimma. Tvättar man den försvinner spåret, men det man svettats ut samlas ändå prydligt någonstans. Den mest ärliga hejaklacken torkar alltid vid din sida."},"ICON-1384":{"nm":"Vattenflaska","de":"Töm den och fyll den, torka och ta en klunk. Den enkla tur och returen bär dagen tyst upp. Som en hink som steg och sjönk vid brunnen, börjar dagen på nytt ur akten att fylla på."},"ICON-1385":{"nm":"Proteinshake","de":"Skakar man den väl och sväljer en klunk, fylls den muskel man bröt ner idag upp igen imorgon. Smaken är inte flott, men kroppen vet att detta är återhämtningens språk. Tillväxt dricks alltid tyst."},"ICON-1386":{"nm":"Energibar","de":"En enda bar hoptryckt platt i fickan. Nödproviant som fyller de tomma stunderna mellan måltider. Inget storslaget, men denna lilla tugga håller ut till ännu en rörelse på eftermiddagen."},"ICON-1387":{"nm":"Halstablett","de":"Rullar man den runt i munnen stryker den svalkande mentolen mjukt över en sträv hals. På dagar man pratat mycket, på nätter man sjungit mycket — en enda liten tablett klappar den skrovliga vägen till ro. Även sötma har sitt tydliga syfte."},"ICON-1388":{"nm":"Sångte","de":"Varm ånga värmer halsen, och med en enda klunk lossnar spänningen i axlarna mjukt. Ett gammalt botemedel, likt ingefärsteet mormor brukade koka. En varm hälsning riktad till rösten innan man sjunger."},"ICON-1389":{"nm":"Honungsvatten","de":"En sked honung rörs sakta ner i ljummet vatten. Just det glas de vuxna brukade blanda till när halsen kändes skrovlig. Varken medicin eller dryck, bara en sötma som stilla smeker kroppen inifrån."},"ICON-1390":{"nm":"Luftfuktartank","de":"Ett kärl som släpper ut en liten dimma i rummet. På vinternätter när torr luft river i halsen delar den ut fukt osedd. Att ta hand om någon flyter oftast tyst så här."},"ICON-1391":{"nm":"Vilokupong","de":"Ett enda pappersark där det står att det är okej att vila. I samma stund man tar emot det i handen blir bördan på sinnet ett snäpp lättare. Att stanna upp är också en övning — denna lilla biljett ger tillåtelsen i ditt ställe."},"ICON-1392":{"nm":"Övningsschema","de":"Ovanpå tiden, nedskriven ruta för ruta, lägger sig dagen till ro, bit för bit. På morgonen sång, på eftermiddagen koreografi, på kvällen vila. Även en morgondag som kändes hopplös blir, väl indelad med streck, plötsligt något värt att gå emot."},"ICON-1393":{"nm":"Närvarostämpel","de":"Man trycker fast ett enda märke som visar att man kom igen idag. Allteftersom de svagt uttvättade cirklarna växer ruta för ruta, har en flit som verkade obetydlig omärkligt blivit en väg. Ett litet bevis för varje dag."},"ICON-1394":{"nm":"Berömklistermärke","de":"Istället för att säga bra jobbat fäster man stilla en enda stjärna. En glimt stor som en nagel, men i samma stund den slår sig ner i hörnet av ett anteckningsblock ljusnar hela dagen. Beröm är litet, men lyser märkligt länge."},"ICON-1395":{"nm":"Mentala anteckningar","de":"En sida där hjärtat som darrat bakom scenen löses upp i ord. Skriver man ärligt även om dagarna som inte gick bra känns det på något vis lättare. Hjärtat blir stadigare i takt med hur mycket man tittar in i det."},"ICON-1396":{"nm":"Visualiseringskort","de":"Blundar man och håller det i handen vecklar sig scenen stilla ut i sinnet. Att i förväg gå ett varv runt en plats man ännu inte stått på. En rutt tecknad i fantasin når fram ett steg före de verkliga tårna."},"ICON-1397":{"nm":"Uttrycksspegel","de":"Framför spegeln ler man, stelnar till, gör samma min hundra gånger om. Här lär man sig att både glädje och sorg kräver övning. För ett uttryck är att kopiera hjärtat ut till utsidan."},"ICON-1398":{"nm":"Koreografianteckningar","de":"En sida där vägen fötterna och armarna ska ta kopierats ner som teckningar. Vid varje åtta-taktsräkning visar pilar tyst vart kroppen ska. Även en rörelse som vägrat fastna lugnt tämjs sakta på detta blad."},"ICON-1399":{"nm":"Koreografivideochip","de":"I ett enda litet chip ryms hundratals rörelser intakta. Spelar man upp det en gång till innan sömnen rör sig fingertopparna av sig själva efter den vägen. Upprepning är ännu en journal, kopierad genom kroppen."},"ICON-1400":{"nm":"Scenrörelseschema","de":"En enda karta över scenen sedd uppifrån. Vem som möts var och sprids ut vart, förutbestämt med linjer och punkter. Vill flera tillsammans teckna en bild måste man först dela upp vägarna."},"ICON-1401":{"nm":"Repetitionspass","de":"Läktaren är tom och ljuset sover ännu. Detta enda pass släpper in dig i just den stillheten. Scenen när ingen ser dig – och just där börjar tiden då du möter ditt mest ärliga jag."},"ICON-1402":{"nm":"Stilbok","de":"Med vilket humör ska jag klä mig idag? Även en enda skjorta har en känsla som passar den, viskar boken tyst. Ju fler sidor man bläddrar, desto mer samlas en liten känsla för stil i fingertopparna som en gång tvekade framför spegeln."},"ICON-1403":{"nm":"Hårspray","de":"Ett enda pust, och inte ens vinden vågar rufsa till det. En liten ambition att hålla de där få minuterna på scenen fullkomligt orörda. Det perfekta ögonblicket fulländas alltid ovanpå en sådan obetydlig envishet."},"ICON-1404":{"nm":"Sminkpalett","de":"Tolv färgrutor är tolv olika sinnesstämningar. Vilket uttryck ska jag sjunga med idag – fingertopparna väljer först, och hjärtat följer efter. I varje ruta som tömts vilar tyst dagarna som lämnats kvar på scenen."},"ICON-1405":{"nm":"Kostymnål","de":"I det mest lysande ögonblicket finns, just på en plats ingen ser, en liten nål som håller tyget på plats. Så att det inte glider, så att det inte kommer i olag. Glansen på scenen vilar alltid på någons fasthet."},"ICON-1406":{"nm":"Namnskylt","de":"I samma stund en tom skylt fylls med ett namn blir ett dunkelt löfte plötsligt tydligt. Vem som ska stå på just den platsen avgörs av en enda rad text. Ett namn är det kortaste och fastaste beslut som finns."},"ICON-1407":{"nm":"Fanhälsningskort","de":"Mottagaren är bara en enda person, men för just den personen är det hela världen. Att pressa flera nätters tacksamhet in i en kort hälsning. Hjärtat svämmar över så här, även på ett papper inte större än en handflata."},"ICON-1408":{"nm":"Autografövningsblad","de":"Först ser ens eget namn nästan främmande ut när det tecknas. Genom gryningar av att dra strecket hundra gånger och slipa det tusen, tills handen minns flödet innan hjärtat gör det. Så blir ett namn till slut en signatur."},"ICON-1409":{"nm":"Intervjufrågeformulär","de":"\"Vad ska jag svara på den här frågan?\" Fingertopparna som håller i pappret darrar lite. Det handlar inte om att memorera svar utan om att ställa upp sin uppriktighet i ordning – för en intervju, precis som en bekännelse, är i grunden en fråga om hjärtats ordningsföljd."},"ICON-1410":{"nm":"Glosbok","de":"Det mest slitna hörnet visar vilket ord som betraktats längst. Lika lång tid som det tar för ett obekant ljud att sätta sig på tungan, lika mycket krymper avståndet till en värld man aldrig besökt, en handsbredd i taget."},"ICON-1411":{"nm":"Uttalskort","de":"Det rullande \"R\", det läckande \"S\". Det finns gryningar tillbringade med att bläddra korten ett i taget, att tämja tungan. Ju tydligare talet blir, desto tydligare blir också ansiktet på den man vill nå med de orden."},"ICON-1412":{"nm":"Livechecklista","de":"Mikrofon på, in-ears kontrollerade, gångvägar genomgångna. För varje ruta som fylls i töms oron i bröstet en ruta i taget. Innan man går upp på scen är noggrannhet den tystaste formen av mod."},"ICON-1413":{"nm":"Återhämtningsplåster","de":"Det finns en fläck som sprider sig varm i samma stund man sätter fast den. En ansträngd axel, en stel vad – en handflatestor tröst som tyst svarar på kroppens små signaler. Att vila väl är också en del av träningen."},"ICON-1414":{"nm":"Ispåse","de":"Läggs varsamt på en svullen fotled. Först när kylan sakta tränger in inser man äntligen hur mycket man sprang idag. Återhämtningen bakom scenen kommer alltid lika ljudlöst som detta."},"ICON-1415":{"nm":"Förbandspåse","de":"Plåster, smärtstillande, en liten spegel. Det kommer en stund då den här lilla påsen, fylld med sådant som verkar obetydligt, blir det mest betryggande av allt. Omtanke som förberetts i förväg lyser som starkast inför en oväntad kris."},"ICON-1416":{"nm":"Sufflörkort","de":"Någon lyfter det försiktigt bortom kameran. Den enda mening man nästan glömde står där, prydligt nedskriven. Bakom ett program som flyter utan avbrott finns alltid en hand som denna, aldrig synlig i bild."},"ICON-1417":{"nm":"Uppdragskuvert","de":"Ögonblicket precis innan man river upp kuvertet är det mest hjärtklappande. Vad som än ligger inuti, den korta stunden av spännande ovisshet. Underhållningens charm lever hel och odelad i just det förseglade ögonblicket."},"ICON-1418":{"nm":"Namnbricka","de":"Ett litet namn fäst vid bröstet ersätter den första hälsningen. Bland människor som ännu inte känner varandra spräcker en enda namnbricka pinsamhetens is. Från stunden ett namn ropas ut börjar en relation."},"ICON-1419":{"nm":"Straffklistermärke","de":"Ett enda klistermärke som smälls fast på förlorarens panna får skratten att välla fram. För vänligt för att kallas ett straff – även förlusten blir till slut ett minne man bär med sig. Ett litet, ömsint märke skapat för att alla ska få skratta tillsammans."},"ICON-1420":{"nm":"Slumpstraffkort","de":"Ingen vet förrän kortet dras. Tio varv med elefantsnabel, eller en omgång aegyo. I stunden man lägger hela sitt öde i en enda papperslapps händer är det skrattet som lossnar allra först."},"ICON-1421":{"nm":"Ledtrådskort","de":"Något likt en hand som tyst räcks fram mot en fastlåst punkt. Det ger inte hela svaret, men visar vägen. En bra ledtråd är inte facit, utan handlingen att stilla räcka fram modet att tänka en gång till."},"ICON-1422":{"nm":"Chanskort","de":"En enda möjlighet att vända en snedvriden ställning i ett enda drag. Vilken stund man väljer att dra det här kortet avgör hela matchen. Tur som sparats och sparats bevisar sitt värde först i det mest avgörande ögonblicket."},"ICON-1423":{"nm":"Timeout-kort","de":"Det är okej att stanna upp ett ögonblick, säger kortet i ditt ställe. Att djärvt räcka upp handen när man behöver hämta andan – att pausa är också en giltig strategi, och att vila väl är också ett slags skicklighet."},"ICON-1424":{"nm":"Skrattknapp","de":"Klick, och i samma stund man trycker på den forsar ett glatt fnitterskratt fram i sin fulla bredd. En riktigt rolig scen behöver ibland just den där ljudeffekten som ger en knuff på traven. Värmen i ett sällskap tänds av just ett sådant litet skämt."},"ICON-1425":{"nm":"Ljudeffektfjärr","de":"En knapp för applåder, en annan för burop. En trollkarl som formar stämningen med bara fingertopparna sitter tyst i kontrollrummet. Regi som aldrig syns i bild är det som får just den scenen att andas liv."},"ICON-1426":{"nm":"Klappbräda","de":"Klack, och med det där skarpa ljudet börjar en tagning. Mellan dussintals felttagningar och en enda godkänd räknar den här svarta brädan varje ögonblick tydligt och prydligt. Det är den första takten som inspelningen tar sitt steg med."},"ICON-1427":{"nm":"Markeringstejp","de":"I samma stund tårna vidrör den linjen sänker sig ljuset mjukt, som om det hade väntat. Den enda platsen man nött in i minnet – scenen blir till slut fulländad av en enda liten färgad remsa dragen på golvet."},"ICON-1428":{"nm":"Ljusfilter","de":"Samma ansikte förvandlas helt av ljusets färg. I det blå filtret bor gryningen, i det röda skymningen. Stämningen är aldrig långt borta – den ligger tyst vikt inuti ett enda tunt ark färgat papper."},"ICON-1429":{"nm":"Kamerabatteri","de":"I samma stund det röda ljuset börjar blinka blir hjärtat oroligt först av allt. För den bästa scenen kommer alltid, olyckligt nog, vid 1 procent kvar. Ett extra batteri i fickan blir snart lättnaden av att kunna andas ut."},"ICON-1430":{"nm":"Minneskort","de":"En hel dags skratt och svettdroppar packas tätt in i ett chip stort som en nagel. Så litet att det lätt går förlorat, och just därför oändligt dyrbart. Minnenas vikt kan aldrig mätas i storlek."},"ICON-1431":{"nm":"Polaroidfilm","de":"Klick, och sedan en stilla väntan. De få sekunderna då ett ansikte sakta stiger fram över den en gång vita ytan är märkligt hjärtklappande. Även ett ögonblicksfoto i handen behöver precis en sked tålamod."},"ICON-1432":{"nm":"Fotokortsfilm","de":"Vilket uttryck som ska framkallas på just detta ark förblir en hemlighet ända till stunden det trycks. Ansiktet som ska bli någons älsklingsmedlem föds precis här. Ett litet pappersark rymmer ett så stort hjärta."},"ICON-1433":{"nm":"Fotokortsficka","de":"Ett fotokort rörs aldrig med bara händer. Tryck till ett hörn och även den dagens leende värker till. Att svepa in sin älskling varsamt i ett enda genomskinligt ark – även omsorg kräver en sådan hängivenhet."},"ICON-1434":{"nm":"Toploader","de":"Skjut in det mellan två styva ark, och inte ens tiden kan skrynkla det vårdslöst. Inget böjande, inget vikande. Att vårda något dyrbart lånar alltid ett lager extra fasthet."},"ICON-1435":{"nm":"Klistermärkespaket","de":"Man drar av dem en och en, klistrar dem i dagbokens hörn, på baksidan av datorn. Med en enda liten bild färgas en gråskalig dag i alla nyanser. Viljan att pynta det som finns omkring en har ingen ålder."},"ICON-1436":{"nm":"Autografpenna","de":"Vid ljudet av bläck som viskande stryker över papper blir kön längre och längre. Över ett album räckt fram med en darrande hand dröjer sig ett möte på bara några sekunder kvar länge. Hjärtat vandrar över längs pennans spets."},"ICON-1437":{"nm":"Signerat album","de":"Öppna omslaget och en bekant, böljande signatur hälsar dig först. Ett band knutet genom musik kommer en handsbredd närmare på pappret. Att bevara något är att stilla hålla det ögonblicket stilla."},"ICON-1438":{"nm":"Lightstick-batteri","de":"\"Snälla, tänd.\" Händerna är upptagna med att byta batterier alldeles innan insläpp. Så att ens eget enda ljus inte slocknar bland tiotusentals andra – ett litet batteri lyser upp den stora natten klart."},"ICON-1439":{"nm":"Lightstick-fodral","de":"Prydligt förvarad utan en enda repa, sparad ömt även för nästa kvälls jubel. Även när den heta stunden svalnat helt bär man den varsamt hem. Även ett hejaredskap har sin plats, och det finns ett hjärta som ser till den platsen."},"ICON-1440":{"nm":"Sloganbanderoll","de":"En mening skriven på lång tygduk vecklas ut över läktaren. I stunden ett hejarop som var för svårt att säga högt öppnar sig helt blir en persons uppriktighet till allas rop. Det tyget blir självt en röst."},"ICON-1441":{"nm":"Minibanderoll","de":"Ett litet hejarop som ryms rakt i handflatan. Banderollen som hänger långt borta tillhör alla, men den här fladdrar bara vid kanten av ditt eget skrivbord. Genom att sakta vaja bevisar den att liten storlek inte betyder ett litet hjärta."},"ICON-1442":{"nm":"Fanbrev","de":"Jag skrev om mottagarens namn tre gånger och strök den första meningen sju. Att fingrarna darrar precis innan kuvertet försluts beror på att hjärtat är alltför uppriktigt. En uppriktighet tyngre än ett enda frimärke ligger vikt därinne."},"ICON-1443":{"nm":"Presentpapper","de":"Presentpapperet vet bättre än någon annan att den mest hjärtklappande sekunden är den precis innan det öppnas. Trots att det vet sitt öde är att snart rivas sönder sveper det ändå in sig i den finaste struktur, likt hjärtat hos den som ger bort det."},"ICON-1444":{"nm":"Rosett","de":"Bind den för hårt och den kväver, för löst och den glider upp, så att hitta precis mittemellan är själva omsorgen. Formen på ett hjärta hålls fast i en enda knut vald av fingertopparna. Den sista raden på en present skrivs alltid av rosetten i ens ställe."},"ICON-1445":{"nm":"Tackkort","de":"Ett tack sagt högt skingras för vinden, men skrivet för hand dröjer det sig kvar länge. Att skicka tillbaka den omtanke man fått, med lite extra ovanpå. Medan man trycker fram bokstav för bokstav fördjupas hjärtat dubbelt."},"ICON-1446":{"nm":"Lunchlådekupong","de":"Med den här enda papperslappen löses lunchoron sakta upp. För nykokt ris med ångande dis, en måltid med varje fack fyllt med tillbehör är utlovad. En liten amulett som troget vakar över en hungrig eftermiddag."},"ICON-1447":{"nm":"Mellanmålskupong","de":"Den finns till för att plockas fram klockan tre på eftermiddagen, när suget skickar en svag signal. En kupong som vet att en enda liten sötsak lyfter humöret en halv handsbredd. Ingen stor belöning, men den anländer stilla precis när man behöver den som mest."},"ICON-1448":{"nm":"Kaffekupong","de":"En varm kopp och en fönsterplats, det är allt den här kupongen lovar. Det verkar kanske obetydligt, men för någon blir det ett litet pris för att ha stått ut med dagen. Ett ömsint inbjudningskort vars doft anländer ett steg i förväg."},"ICON-1449":{"nm":"Städkupong","de":"Kasta upp fönstren på vid gavel, skaka ut täckena, en dag då inte ens ett dammkorn slipper undan. Vem visste att slippa göra det själv skulle vara en sådan lyx. När rummet glänser ordnar sig hjärtat stilla också."},"ICON-1450":{"nm":"Reparationssats","de":"En skruvmejsel, tejp, några obestämbara delar. Samlat ihop verkar det som ingenting den inte kan laga, men öppnar man den fattas det alltid en bit. Ändå en låda med självförtroende som på något vis känns betryggande bara man håller i den."},"ICON-1451":{"nm":"Lyckobiljett","de":"En tom biljett utan plats och utan nummer. Poängen är just att det inte står skrivet vilken lyckträff som väntar idag. Att fylla i den tomma rutan är upp till den som bär den runt i fickan."},"ICON-1452":{"nm":"Tärning","de":"En vän som känner ordet rättvisa bättre än någon annan. Den tar ingens parti och älskar alla sex sidor lika mycket. I just det ögonblicket den lämnar handflatan och rullar iväg avstår till och med skicklighet och kontakter tillfälligt sin plats åt turen."},"ICON-1453":{"nm":"Resebiljett","de":"Ett löfte om att härifrån till dit räcker ett enda steg. Ett magiskt papper som viker en lång väg liten och stoppar ner den i fickan. På dagar man tvekar att ge sig av finns ingen bättre spärr mot bortförklaringar än denna."},"ICON-1454":{"nm":"Omtagningskort","de":"I stället för att räcka en hand till den som fallit, ett kort som stilla knuffar en i ryggen och säger: försök igen. Det viskar tystast av alla att ett misslyckande inte är slutet utan bara ett kort kommatecken. Modet till en gång till fylls på just här."},"ICON-1455":{"nm":"Tidshoppskort","de":"En ömsint fusklapp som hoppar över väntan bara en liten smula. Vem kan klandra ett hjärta som inte pallar vänta ens tre minuter? Här finns en glädje som känns lite som fusk, likt att knäppa iväg timglasets sand med ett finger."},"ICON-1456":{"nm":"Produktionsbooster","de":"Samma händer, samma tid, ändå dubbla resultatet. Den snurrar glatt surrande på arbetsbänken, som om den ville säga: fråga inte om hemligheten. En liten apparat som tyst spänner ut vingar på två flitigt arbetande händer."},"ICON-1457":{"nm":"Vänskapsgodis","de":"Även generad tystnad, svår att lösa upp med ord, smälter bort framför något sött. Ett band som växer en handsbredd närmare än igår över ett enda godis man packat upp tillsammans. En gullig liten upptäckt: att sötma är hastigheten man blir närmare varandra med."},"ICON-1458":{"nm":"Humörjelly","de":"På en upprörd dag är något kallt och mjukt precis rätt medicin. Ta en tugga, och ett molnigt ansiktsuttryck löses sakta upp. Att laga ett hjärta är av naturen något dyrbart, och R-klassningen sitter inte där utan anledning."},"ICON-1459":{"nm":"Glitterdamm","de":"Strö det lätt över något vanligt, och plötsligt blir det speciellt. I grunden är det bara glittrande pulver, men i samma stund det faller ser världen lite mer upprymd ut – så märkligt det är. Som ett kryddstänk av lycka piskat in i vardagen."},"ICON-1460":{"nm":"Scentejp","de":"Ställ dig på scenen och otaliga ljus finner dig alla på en gång. Ett litet X på golvet markerar tyst just den platsen. Det som är mest exakt på en osynlig plats bär till slut upp den allra största scenen."},"ICON-1461":{"nm":"Buntband","de":"En liten hjälte som reder ut trassliga sladdar prydligt i ett enda grepp. Att det inte går att lossa igen när det väl dragits åt är både dess svaghet och dess charm. Ett måste för dem som tar ordning på allvar och tyst lägger undan."},"ICON-1462":{"nm":"Reservkabel","de":"En sak utan närvaro när man har den, men djupt efterlängtad när man inte har det. Sovande djupt nere i väskan bakom scenen vaknar den till med ett ryck i det avgörande ögonblicket. Den bevisar ordet beredskap med hela sin kropp."},"ICON-1463":{"nm":"Repetitionschecklista","de":"Ett papper tätpackat ruta för ruta med gångvägar, cues, till och med kostymbyten. Fattas det en enda bock här sjunker någons hjärta ner i skorna. En fullkomlig scen låter ridån gå upp först sedan den här listan blivit helt ifylld."},"ICON-1464":{"nm":"Kulissskylt","de":"Här är ett café, där en gränd, följ pilarna in i en helt annan värld. En lögn målad på plywood, men framför kameran blir den sann. En ärlig vägvisare som ägnat hela sitt liv åt att peka riktning."},"ICON-1465":{"nm":"Minipokal","de":"En gyllene bit som på något sätt får en att känna sig en handsbredd längre i samma stund man tar emot den. Den glimmar på skrivbordet och säger att det verkligen är okej att inte bli etta, att den vet allt man kämpat med idag. Den stora tröst en liten belöning kan ge."},"ICON-1466":{"nm":"Ryggsäck","de":"I samma stund den slängs på ryggen känns det som man kan ge sig av vart som helst. Det ligger kanske inte mycket i den, men möjligheter fyller den till brädden. Äventyret börjar alltid med att dra åt de här axelremmarna hårt."},"ICON-1467":{"nm":"Kompass","de":"Att man inte går i panik ens när man kommit vilse beror på att nålens spets alltid pekar mot norr. Sättet den vinglar länge för att till slut hitta sin plats liknar precis ett människohjärta. Det är okej att irra runt, säger den med sin darrande spets."},"ICON-1468":{"nm":"Anteckningsbok","de":"Första sidan är alltid tom. Bara den som håller pennan vet vad som ska skrivas. Jag väntar bara, på att dagens tankar ska bli text och stilla sänka sig ner över mig. R-klassningen är vikten av en möjlighet som snart ska fyllas."},"ICON-1469":{"nm":"Blyertspenna","de":"Att det är okej att ha fel är detta redskaps mest ömsinta sida. Så länge suddgummivännen finns nära kan man börja om hur många gånger som helst. Den blir kortare ju mer den vässas, men kortheten är bevis på hur länge den varit älskad."},"ICON-1470":{"nm":"Film","de":"I samma stund ljuset passerar igenom bränns den dagens färg fast, orörd. Att en tagning som väl passerat aldrig kan tas tillbaka är både spänningen och charmen. Valet för dem som medvetet vill minnas en takt långsammare i en snabb tid."},"ICON-1471":{"nm":"Direktkamera","de":"Klick, och sedan en kort väntan. Håll den i handen och skaka den lätt, och ett suddigt ögonblick klarnar sakta fram. En något magisk maskin som fångar just denna plats, orörd, på ett enda pappersark."},"ICON-1472":{"nm":"Gammalt fotografi","de":"Hur mycket färgen bleknat visar hur mycket tid som gått. Vid varje slitet hörn har någons hand dröjt kvar. Att det äldsta fotografiet bär det tydligaste minnet beror nog just på de där händerna."},"ICON-1473":{"nm":"Urklippsbok","de":"Bitar för dyrbara att slänga samlas och samlas till en enda volym. En blekt biobiljett, ett torkat kronblad, en kort lapp. Skräp i andras ögon, men för den som bläddrar igenom den väcks en hel tidsera helt till liv."},"ICON-1474":{"nm":"Loggbok","de":"Dagens vind och vågor, och en rad från hjärtat. Att skriva troget även på händelselösa dagar är sjöfartens regel. Beviset på att man kommit fram helskinnad står alltid någonstans nedskrivet i denna tjocka anteckningsbok."},"ICON-1475":{"nm":"Kartbit","de":"Bara ett hörn av helheten, men utan den hittar man till slut aldrig vägen. Den där njutningen när en söndriven kant passar perfekt ihop med en annan bit. R-klassningen har samma närvaro som pusslets allra sista bit."},"ICON-1476":{"nm":"Flaskpost","de":"Utan att veta vem som ska läsa den överlämnar den sig stilla åt vågorna. Den väntar sig inget svar, önskar bara att detta hjärta ska nå fram någonstans. Det långsammaste men mest romantiska sättet att skicka post."},"ICON-1477":{"nm":"Tärning","de":"Sex sidor som ler runt och brett, som för att säga: du igen? Att ge ett annat svar för varje kast, trots samma form, är denna väns oföränderliga nyck. I stunden den lämnar handen anförtror man valet en kort stund åt ödet."},"ICON-1478":{"nm":"Vindsnurra","de":"Den vaknar först till liv när vinden blåser. Lämnad i stillhet är den bara pappersvingar, men blås någon på den och den börjar snurra glatt. Att inte skämmas för att ta emot hjälp är den lilla blommans visdom."},"ICON-1479":{"nm":"Picknickkorg","de":"Öppna locket och doften av gimbap hälsar dig först. Grön gräsmatta, en utbredd filt, och händer som delar mat med händer. Dagarna den här korgen fylldes helt var, märkligt nog, alltid under klar himmel."},"ICON-1480":{"nm":"Vas","de":"Sätt bara en enda stjälk i den, och luften i hela rummet förändras. När den är tom är dess enda uppgift att vänta tyst. Rummets mest ödmjuka scenrekvisita, som sänker sin egen närvaro för att låta blomman lysa desto starkare."},"ICON-1481":{"nm":"Kronblad","de":"När vinden för bort ett enda blir våren precis så mycket lättare. Det gamla trädet på gården ger samma hälsning år efter år: att falla är också en del av det att blomma. Att virvla bort är inte slutet, utan ett brev skickat i förväg till nästa vår."},"ICON-1482":{"nm":"Ros","de":"Att resa taggarna först är ett löfte om att inte röras vid vårdslöst. Därinnanför gömmer sig det rödaste av hjärtan. Någon lade en enda stjälk stilla vid någons fötter och gick, och skrev sitt hjärta enbart i färg i stället för ett namn."},"ICON-1483":{"nm":"Lilja","de":"Bredvid det renaste vita porslinet stod alltid just den här vita blomman. Må doften nå långt, men hållningen aldrig svikta. Från den plats där den valde renhet framför prakt vakar liljan tyst över ett mått av värdighet."},"ICON-1484":{"nm":"Tulpan","de":"Att stå på rad med huvudet lätt böjt känns på något vis prydligt och ordentligt. Blomman som tar den främsta raden i vårrabatten. Dess ärlighet att blomma allihop på en gång och falla allihop på en gång färgar den korta säsongen som starkast."},"ICON-1485":{"nm":"Hyacint","de":"På en enda stjälk hänger den täta små klockor. Skaka den och det hörs inget ljud, men doften klingar genom rummet i stället. Vid vårens tröskel, en ömsint lyx som byter ut hela rummets luft med bara en enda vas."},"ICON-1486":{"nm":"Grodpreparat","de":"En liten kropp där tiden stannat inuti en glaslåda. Etiketten säger: \"Risfält och dammar, piggast dagen efter regn.\" Först efter att den stannat bevaras till och med temperaturen vid vattnet där en varelse en gång levde, som ett arkiv."},"ICON-1487":{"nm":"Ödlepreparat","de":"Även som preparat går inte kvickheten att bryta av svansen och fly att sudda ut. En liten gäst som älskade solvarma stenmurar. Anteckningen bredvid har prydligt skrivit ner riktningen mot den soliga fläck den gärna klättrade på."},"ICON-1488":{"nm":"Mullvadsjournal","de":"Dagboken för en som färdas under jorden skrivs i jordens ådror. Var den grävde och var den stannade, en karta över osynliga vägar. Även en tid levd med ryggen mot ljuset blir för någon till en oändligt trogen förteckning."},"ICON-1489":{"nm":"Skalpreparat","de":"Ett stadigt mönster som vågorna slipat fram genom tusentals omgångar. Folket vid tidvattenzonen kunde avgöra vilket hav den kom från enbart på skalets ådror. Formen av ett hav som en gång levde och andades bevaras intakt i ett handflatestort preparat."},"ICON-1490":{"nm":"Korallpreparat","de":"Djupt i havet växer den knappt en handsbredd över hundratals år. Den ser ut som grenar, men är i själva verket ett hus byggt tillsammans av otaliga små liv. Att det som är långsammare består längre – det bevisar korallen i tystnad."},"ICON-1491":{"nm":"Aidong-ledtråd","de":"En bit av en berättelse spridd någonstans på ön. En enda liten papperslapp pekar tyst mot nästa steg. Alla äventyr börjar till slut med att plocka upp just sådana obetydliga spår, säger den gamla vägvisaren."},"ICON-1492":{"nm":"Signaturbit","de":"När det spridda mönstret hittar sin plats fullbordas till slut ett enda märke. En bit inristad med någons alldeles egna karaktär. Den döljer sin mening tills den passas ihop, och i samma stund den passas ihop blir den äntligen ett namn."},"ICON-1493":{"nm":"Scenminnesskärva","de":"Även efter att en låt tagit slut dröjer kvarvärmen bland läktarplatserna. Skala av den värmen och låt den stelna, och det blir en sådan här liten skärva. Spridda splitter av applåder och jubel – samlas de stilla ihop återuppstår hela den natten."},"ICON-1494":{"nm":"Debutstämpel","de":"Dagen ens namn ropades upp för första gången, det bläckmärket stämplat på handryggen. Även omsorgen att försiktigt låta det torka utan att sudda ut var en del av startlinjen. En enda liten stämpel gör att en viss dag aldrig helt suddas ut."},"ICON-1495":{"nm":"Toppidolmedalj","de":"En tyngd som bara unnas den som når den högsta platsen. Men den här medaljen är inte tung på grund av metallen. Det är för att vikten av alla de otaliga händer som tillsammans fyllde scenen samlas hel och odelad i en enda punkt."},"ICON-1496":{"nm":"Liten nyckel","de":"Boendets första nyckel var alltid till det innersta rummet. En plats där man lärde sig att öppna innan man lärde sig att låsa. Den dag man ger sig av dröjer värmen en handflata lämnat kvar länge på det kalla metallstycket."},"ICON-1497":{"nm":"Skattkista","de":"Innan den öppnas vet ingen vad som ligger inuti. Just den ovissheten är skattkistans verkliga skatt. I den korta stund man lyfter locket återvänder vem som helst en stund till barndomens hjärtklappning."},"ICON-1498":{"nm":"Ritning","de":"På linjer dragna ruta för ruta bor en byggnad som ännu inte rests. Att rulla ut ritningen är att en gång i förväg vandra genom morgondagen. En enda väldragen linje bär upp en morgondag som inte rasar samman."},"ICON-1499":{"nm":"Receptkort","de":"På ett enda nött kort står mormors handlag nedtecknat i mått. Vaga ord som \"en nypa salt\" är det mest exakta hemlighetsreceptet. Ju blekare skriften blir, desto tydligare träder köket fram där just den rätten en gång puttrade."},"ICON-1500":{"nm":"Byggnadstillstånd","de":"Ett enda pappersark förvandlar en tom tomt till \"en plats man får använda\". En ny byggnad behövde alltid först byns stämpel. Tillstånd är, i grunden, ett varmt sigill som säger att det är okej att börja något just här."},"ICON-1501":{"nm":"Hamntillstånd","de":"Innan ett skepp kunde kasta ankar behövdes först detta enda pappersark. Hamnens bleknade sigill är den första hälsningen till dem som kommer långväga ifrån. Mellan avfärd och ankomst öppnar hamnen alltid sitt hjärta med ett enda pappersark."},"ICON-1502":{"nm":"Öbevis","de":"Ett litet intyg om att man blivit en av öns egna. När en ny granne flyttade in lade den gamla byn till namnet i rullorna och delade ut varma risbullar. Det är bara ett papper, men på det står den ljusa välkomsthälsningen: \"Nu är du en av oss också.\""},"ICON-1503":{"nm":"Namnskylt","de":"Med ett enda namn hängt bredvid dörren blir ett tomt rum äntligen någons hem. Även i de gamla gästrummen hängdes först en skylt inristad med husbondens namn. En namnskylt är liten, men i den finns hela värmen av \"här bor någon.\""},"ICON-1504":{"nm":"Fanpost-frimärke","de":"Även omsorgen att fukta det och trycka fast det ordentligt var en del av ett fullständigt brev. Handlingen att fästa en kär känsla på ett litet papper och skicka den långt bort. Även i den digitala tidsåldern skickar någon sitt hjärta för hand."},"ICON-1505":{"nm":"Glittrande ö-märke","de":"Fäst det i kragen, och ett litet ljus följer med vart du än går. Möt någon med samma märke på gatan, och ni förstår varandra utan ett ord. Glittret är ingen skryt, utan en tyst signal: \"Vi älskar samma ö.\""},"ICON-1506":{"nm":"Arbetsbänk","de":"En repig bänkskiva vittnar om de händer som skapat mest. Platsen där saker lagats, fogats samman och förfinats. Mer än ett rent skrivbord bär en stökig arbetsbänk i själva verket på långt fler historier."},"ICON-1507":{"nm":"Förvaringslåda","de":"Ju dyrbarare något är, desto tidigare bestämmer man dess plats. Även forna tiders människor förvarade dyrbara dokument för sig i kistor av paulownia-trä. Att förvara något väl är, i slutänden, att vika ihop dagen prydligt för någon i framtiden."},"ICON-1508":{"nm":"Förrådslåda","de":"När det finns gott om något samlar man det; när det tryter tar man fram det. Här finns visdomen från en tid då ett välfyllt förråd betydde ett tryggt hjärta. Att lagra i förråd är att i förväg räcka fram en kärleksfull måltid till sitt framtida jag."},"ICON-1509":{"nm":"Kyllåda","de":"En kista packad med is höll kylan kvar även mitt i sommaren. Det är som om iskällarens gamla visdom flyttats över, i handflatestorlek. Att hålla något kallt är att låta det färskaste ögonblicket dröja kvar lite längre."},"ICON-1510":{"nm":"Vattenpump","de":"Rör handtaget upp och ner, och vatten djupt under jorden stiger upp. En ärlig maskin som forsade fram först sedan en enda skopa spätt vatten hällts i. Att man måste ge innan man får – den sanningen lärde sig brunnskanten tidigt."},"ICON-1511":{"nm":"Vattenrenare","de":"Ett litet under där grumligt vatten blir klarare, lager för lager. Forna tiders människor renade vatten genom att lägga sand och kol i lager i lerkrukor. Klarhet fås inte gratis – det är omsorgen i att sila långsamt."},"ICON-1512":{"nm":"Vattenkannehållare","de":"I samma ögonblick vattenkannan får en plats att vila blir rabattens dag prydlig. Att bestämma var ett verktyg ska hänga är en vana hos den som älskar sitt arbete. När en enda plats är fastställd blir hela gården genast lite mer ordnad."},"ICON-1513":{"nm":"Fiskespöhållare","de":"Människor må gå ifrån innan napp kommer, men fiskespöt håller sin plats. Den tålmodiga hållningen av att fiska bort åren vid älven finns fastfrusen just här. En hållare är, i slutänden, en vilostund för att lägga ifrån sig otåligheten en stund."},"ICON-1514":{"nm":"Plockkorg","de":"Mors handfull, med en nypa vilda örter och en enda ängblomma buren hem. Genom springorna i den flätade bambun sipprar jorddoften sakta ut. Beroende på vad man fyller den med kan en tom korg bli antingen vår eller höst."},"ICON-1515":{"nm":"Mortel och stöt","de":"Dunk, dunk, i en jämn takt malde man säd och väckte byns dag. Ett redskap vars stampande en gång fyllde gränderna på högtidsdagar. Att göra det hårda mjukt kräver en arbetande hands stadiga rytm."},"ICON-1516":{"nm":"Skärbräda","de":"Varje märke kniven lämnar efter sig ristar in en måltids historia. En repig träskiva är köksets hederstecken för de flitigaste händerna. Att skära något börjar med önskan att bjuda på det med omsorg."},"ICON-1517":{"nm":"Gryta","de":"Det bubblande kokandet är mer ömsint än vilken musik som helst. En hungrig gryning, de tre minuterna man väntar på att nudlarna ska bli klara är den mest privata trösten. Över den runda botten värms omsorgen om att mätta någon."},"ICON-1518":{"nm":"Stekpanna","de":"Konsten att steka något klart på ett ögonblick över elden vilar på denna enda panna. Ju bättre inkörd ytan är, desto mindre fastnar det och desto mer glänser den. En länge använd gjutjärnspanna är i sig själv beviset på de år köket levt."},"ICON-1519":{"nm":"Ugn","de":"Medan du stänger luckan och väntar sker en tyst magi därinne. Tiden då degen jäser och färgen mognar. Även om man inte kan se det – om man väntar i tillit, öppnas luckan och ett varmt resultat kliver ut."},"ICON-1520":{"nm":"Mixer","de":"Lägg även något hårt häri, och på ett ögonblick blir det till ett mjukt glas. En liten virvel där olika ingredienser blandas och en ny smak föds. Samklang är, i slutänden, att var och en ger upp lite av sina egna kanter."},"ICON-1521":{"nm":"Visp","de":"Ett enda handledsflick fångar luft, och det tunna reser sig lika fast som takten man vispar med. Medan bubblorna stiger som toppar är det inte bara degen som sväller. Önskan att mätta någon idag sväller med den."},"ICON-1522":{"nm":"Kvarn","de":"Vrid handtaget på en handfull bönor, och doften bryts sönder först mellan tänderna. När armen värker är malningen äntligen fin, och den första klunken blir lika djup som mödan bakom den. Omsorg börjar alltid i handleden."},"ICON-1523":{"nm":"Mjölkvarn","de":"Kornet går in mellan stenarna och kommer ut som vitt mjöl. Det gör inget om det inte blir fint första gången – man kan bara mala det två gånger till. Att göra det grova fint har också sin ordning, påminner mjölkvarnen tyst om."},"ICON-1524":{"nm":"Sågbänk","de":"När en stock kommer upp läser sågen fibrerna först. Styr förbi kvistarna och skär bara efter den raka linjen, så att brädan inte slår sig. Att kapa trä är, i slutänden, att breda ut i ordning den tid ett enda träd levt igenom."},"ICON-1525":{"nm":"Symaskin","de":"Surr — ljudet av nålen som griper tyget och rusar fram fyller den sena natten. En enda söm fogar samman två stycken till en kropp, och i varje dold stygn inuti en scenkostym är någons sömnlösa timmar stadigt insydda."},"ICON-1526":{"nm":"Färgningsbord","de":"Doppa vitt tyg och lyft upp det: först är det ljusgrönt, men möter det luften blir det äntligen blått. Den färgen sägs bara komma fram efter att indigon dragits tre gånger. Att väntan i sig blir till färg lärde jag mig först framför detta färgningsbord."},"ICON-1527":{"nm":"Kamerastativ","de":"I samma ögonblick de tre benen fälls ut och möter marken stannar den skakande världen upp. En bild som skulle darrat i handen blir skarp på löftet från dessa tre punkter. För att betrakta något länge måste man först kunna stå still."},"ICON-1528":{"nm":"Ljusstativ","de":"Sätt ett ljus på en enda stolpe, och vilken plats som helst i rummet blir en liten scen. Vrid vinkeln lätt, och skuggorna förlängs, uttrycken vaknar till liv. Det suddar inte ut mörkret, utan sätter till och med mörkret vänligt på sin plats."},"ICON-1529":{"nm":"Mikrofonstativ","de":"I samma ögonblick höjden ställs in bestäms avståndet mellan mun och sång. Släpp taget med händerna, och rösten stannar kvar där. Bara på en scen där båda händerna är fria börjar sången som sjungs med hela kroppen på riktigt."},"ICON-1530":{"nm":"Notställ","de":"När det uppslagna arket lutar snett ställer sig noterna på rad i spelarens ögonhöjd. Även när nästa takt kommer vid en enda gest vacklar inte stödet. Bakom någons framförande finns alltid en tyst plats."},"ICON-1531":{"nm":"Köksträdgård","de":"Vänd jorden och dra fårorna, och små löfteslinjer uppstår på marken. De första dagarna efter att fröet grävts ner verkar som om inget händer, men en morgon skjuter mjuka hjärtblad upp genom jorden. En syn som bara den som väntat får se."},"ICON-1532":{"nm":"Bördig köksträdgård","de":"Samma frö, men i denna jord blir bladen dubbelt så stora. Stick ner ett finger, och mörk, mjuk mylla följer med ända upp under naglarna. Att växa väl var, i slutänden, ett verk som den osynliga marken under fötterna utfört i tysthet."},"ICON-1533":{"nm":"Växthus","de":"Under ett glastak flyter årstiderna en takt långsammare. Även när frost faller utanför är det fuktigt av högsommarens ånga därinne. För de köldkänsliga har någon stilla fångat solljuset under taket."},"ICON-1534":{"nm":"Örtland","de":"Stryk med fingertopparna över bladen, och doften hälsar först. Basilika, rosmarin, mynta — för varje namn man säger fastnar en annan doft på fingrarna. Ett enda litet land förvandlar hela köket med värme."},"ICON-1535":{"nm":"Fruktträdgård","de":"Om våren böjer sig grenarna av blommornas skugga, om hösten av fruktens tyngd. Klättra upp i stegen, plocka en frukt, ta en tugga, och ett helt års solljus lagrat som sötma brister i munnen. Det är som ett svar trädet räcker en människa."},"ICON-1536":{"nm":"Svampstock","de":"Borra hål i en fälld stock och plantera myceliet, och det döda trädet föder fram något på nytt. Några dagar senare, den morgon hattarna spirar i klasar, börjar ett nytt liv tyst där man trodde allt var slut."},"ICON-1537":{"nm":"Bikupa","de":"Lägg örat nära, och du hör en låg, flitig surrning därinne. Tusentals vingslag samlas för att knappt bli till en enda sked sötma. En dags möda med att flyga mellan blomsterängar samlas här, klibbig och gyllene."},"ICON-1538":{"nm":"Hönshus","de":"Innan gryningen bryter fram rasslar de som sitter på pinnen först till. Stick handen in i det varma halmet, och du får tag i ett ägg som fortfarande håller kvar sin värme. Platsen som först bebådar morgonen dukar också först morgonbordet."},"ICON-1539":{"nm":"Betesmark","de":"Ett vidsträckt fält där doften av gräs blandas med doften av solsken. Över ryggarna som sakta idisslar innanför hägnet glider molnens skuggor förbi. Här, där inget behöver skyndas, flyter till och med tiden långsamt, som betande."},"ICON-1540":{"nm":"Ostmakeri","de":"Nyss mjölkad mjölk hårdnar sakta genom koagulering och lagring. Vänta några månader på en hylla sval som en grotta, och en djup smak sipprar in i den vita massan. Ost är ett namn som bara ges till mjölk som inte hastat."},"ICON-1541":{"nm":"Tofuverkstad","de":"Blötlägg bönorna, mal och koka dem, och den råa bönmjölken blir nötig. En enda droppe saltlag samlar det utspridda till mjuk tofu, och pressas det försiktigt får det raka kanter. Här finns en hand som lugnar ett splittrat sinne till form."},"ICON-1542":{"nm":"Krukterrass","de":"I ett solbelyst hörn av gården samlas låga lerkrukor tätt intill varandra och solar sig. Lyft ett lock, och doften av åldrad tid strömmar fram. Smaken av den pasta mormor jäste är, i grund och botten, att äta upp åren en sked i taget."},"ICON-1543":{"nm":"Kvarn","de":"När stenarna vrider sig med ett dån löses säden upp till mjöl. Vitt damm svävar genom solljuset, och människor som väntar på att knåda en balja risbullar väntar på sin tur. Byns festdag brukade alltid börja just vid denna tröskel."},"ICON-1544":{"nm":"Bageri","de":"Genom springan i ugnsluckan sipprar doften av smör och socker ut. När den jästa degen börjar gyllenbrunas saktar stegen förbi butiken omedvetet ner. En enda nybakad brödlimpa bär på en värme ingen kan motstå."},"ICON-1545":{"nm":"Gatuköksvagn","de":"Presenningen fladdrar i vinden, och tteokbokki-buljongen sjuder ihop. En kväll av att svälja pappersmuggens buljong till en enda fiskkakespett, en plats som smälter bort kyla och hunger på en gång. En liten tröst i slutet av gränden."},"ICON-1546":{"nm":"Västkök","de":"Pannan värms upp och olivoljan fräser. Med en enda vridning på värmen kan en sås tjockna eller brännas vid. Här, där till och med balansen av färger på tallriken vägs, blir en måltid till ett omsorgsfullt iscensatt verk."},"ICON-1547":{"nm":"Kinesiskt kök","de":"Över en häftig låga snurrar woken hit och dit som i dans. I det korta ögonblick lågorna slår upp fångas ingrediensernas doft in helt och hållet. Snabbt och hett — i det enda andetaget man missar om man tvekar döljer sig hemligheten bakom kinesisk matlagning."},"ICON-1548":{"nm":"Kafé","de":"Tryck upp dörren, och doften av kaffebönor och stilla musik möter dig först. En fönsterplats, en latte som svalnar, en uppslagen anteckningsbok. För att låta dig hämta andan mitt i en hektisk dag har staden gömt små rum som detta här och där."},"ICON-1549":{"nm":"Konditori","de":"Inne i glasmontern står färgglada tårtor på rad och väntar på gäster. I samma ögonblick gaffelspetsen delar grädden lyfter mungiporna sig först. En liten, söt ordination som gör även en sorgsen dag uthärdlig med en enda bit."},"ICON-1550":{"nm":"Charkuteributik","de":"Under det röda ljuset ligger köttet prydligt längs fibrerna. Vid ett enda ord — \"det här är gott idag\" — glider kniven till exakt rätt tjocklek. Kvällsbordets mättnad börjar tyst med denna hand som håller samma plats varje dag."},"ICON-1551":{"nm":"Fiskberedningsbänk","de":"En arbetsbänk där gryningens fisklukt blandas med isens kyla. Fjäll flyger och händerna domnar, men blicken som väljer ut det färskaste stannar aldrig upp. Här får det som just kommit upp ur havet sin väg till bordet."},"ICON-1552":{"nm":"Saltfält","de":"Fånga havsvattnet, så sköter solen och vinden resten. Vänta några dagar tills vattnet torkar, och vita kristaller gror på botten som stjärnor. En handfull salthet är i själva verket en gåva som havet och himlen sakta skapat tillsammans."},"ICON-1553":{"nm":"Tångtorkställning","de":"På en lång lina hänger tång och kombu sida vid sida och gungar i vinden. Det som är tungt av havsvatten mörknar till djupgrönt medan det torkar. Havets mest sparsmakade smak, formad tillsammans av solljus och salt havsbris, hänger här."},"ICON-1554":{"nm":"Liten brygga","de":"Träplankor halvt nedsänkta i vattnet gungar lätt under fötterna. Precis rätt plats att förtöja en enda liten båt vid. Att ge sig av långt bort och att komma tillbaka helskinnad börjar och slutar båda vid denna enda plats."},"ICON-1555":{"nm":"Hamnmagasin","de":"Öppna den träport som saltvinden format, och nät, tunnor och rep travas ända upp till taket. Last på väg till en fjärran resa och last som just anlänt vilar en stund under samma tak. En plats som en transitstation där avfärd och återkomst flyktigt möts."},"ICON-1556":{"nm":"Fyr","de":"Först när nattens hav blir som mörkast börjar den äntligen sitt arbete. Det roterande skenet skär genom dimman och säger: \"Här finns en väg.\" En hög väktare som, för någons trygga hemkomst, till slutet vägrar att somna."},"ICON-1557":{"nm":"Skeppsvarv","de":"Res kölen och foga in spanten, och ett skepps stomme tar form. På en gård där hammarslagen ekar hela dagen drömmer ett skepp som ännu inte känt vattnets smak om sin första resa. En plats som blir stark först för att kunna ge sig av."},"ICON-1558":{"nm":"Inspelningsbås","de":"När dörren stängs försvinner varje ljud utifrån på ett ögonblick. Allt man hör bortom hörlurarna är sin egen andning och takten. I detta lilla rums stillhet föds äntligen en röst som får darra fritt."},"ICON-1559":{"nm":"Musikrum","de":"Ackord som sipprar genom dörrspringan fyller korridoren. Någon känner efter tonstegen, någon räknar takten. En plats där klumpiga och inövade toner får blandas, ett vänligt klassrum där varje sång tar sina första steg."},"ICON-1560":{"nm":"Pianorum","de":"Öppna klaviaturlocket, och ett tunt lager damm ligger på de vita tangenterna. I samma stund fingrarna rör vid dem sprider sig en klar klang genom hela rummet. Om det finns kvällar som inte känns ensamma trots att man är ensam, är det nog tack vare detta enda piano."},"ICON-1561":{"nm":"Dansrum","de":"Tryck ner med tårna, och golvet trycker tillbaka. Medan speglarna på de fyra väggarna kopierar samma rörelse fyra gånger, memorerar kroppen koreografin en halv takt före rytmen. Rummet där svett och andetag dröjer längst — rörelserna som växer upp här går ut på scenen."},"ICON-1562":{"nm":"Gymrum","de":"Vikten ljuger aldrig. Just för den ärligheten — att exakt så mycket du lyfter krediteras dina axlar — söker sig människor till mig varje gryning. Det som sakta ristas in i spegeln är inte muskler, utan de timmar man uthärdade utan att ge upp."},"ICON-1563":{"nm":"Yogarum","de":"Andas djupt in, och det känns som om trägolvet sväller med dig. Ett rum där man sakta viker ihop en dag som kommit rusande; på en enda matta återvänder alla till sin egen andnings takt. Även ett hjärta i brådska lägger sig ner här en stund."},"ICON-1564":{"nm":"Sminkrum","de":"Alldeles innan man kliver ut på scenen blir människor här för en stund någon annan. När glödlamporna runt spegeln värmer ansiktet jämnt, fastnar darrningen i puderdonets spets och smiter tyst undan bakom kragen. Platsen där förvandlingen både börjar och slutar."},"ICON-1565":{"nm":"Kostymrum","de":"Innan ett enda scenplagg är färdigt sätts kläderna som hänger här på och av dussintals gånger. En docka som snurrar med häftstift instuckna, sömlinjer dragna med krita. Bakom glittret finns alltid spåren av någons nålarbete kvar."},"ICON-1566":{"nm":"Studiokuliss","de":"Bara den sida kameran visar behöver se äkta ut — det lärde jag mig tidigt. Gå runt bakom plywoodskivan, och där finns bara en tom stomme. Att bära upp framsidans prakt är alltid uppgiften för de osynliga reglarna."},"ICON-1567":{"nm":"Fotostudio","de":"Det första knepet är att kasta ljus från tre håll för att sudda ut skuggorna. Huvudljuset lyfter fram ansiktet, fyllnadsljuset skuggan, bakljuset hårtopparna. I det ögonblick slutaren faller fångar en enda vit bakgrund dagens finaste leende."},"ICON-1568":{"nm":"Konserthall","de":"I mörkret under det höga taket bär jag alltid samma löfte: att när ridån går upp håller till och med de tomma platserna andan som en enda person. För det enskilda ögonblicket när det första slaget faller står jag tyst tom hela året."},"ICON-1569":{"nm":"Fanträffsbås","de":"Avståndet mellan hand och hand är exakt ett bord brett. En kort hälsning, en darrande autograf, ett ord som aldrig riktigt sades passerar på rad. I detta lilla bås möts en kär känsla som odlats länge äntligen ansikte mot ansikte."},"ICON-1570":{"nm":"Säng","de":"Det var alltid jag som först tog emot dagens slut. När benen tunga av övning och darrningen som blivit kvar bakom scenen väl har lagt sig, börjar morgonen på nytt med lätta tåsteg. Jag säger godnatt och håller dig utan ett ord."},"ICON-1571":{"nm":"Våningssäng","de":"Mellan övre och undre våning förenar fem stegpinnar två personer. Låga röster delade sedan lyset släckts, självlysande stjärnor fästa i taket. Att det trånga boendet blir som allra rymligast beror på historierna som klättrar upp och ner för stegen varje natt."},"ICON-1572":{"nm":"Hylla","de":"Vad man ställer upp visar vem man är. Ett mottaget brev, en första pokal, en bleknad inträdesbiljett radar upp sig sida vid sida. Jag är inte möbler för att skryta, utan en plats som stilla visar upp minnen man inte kunnat kasta."},"ICON-1573":{"nm":"Skrivbord","de":"Med sångtextboken uppslagen dras nya rader på nytt över utsuddade märken. Pappersmuggar hopade under natten och en enda melodi som med nöd och näppe räddats. Det tröga arbetet att flytta hjärtat till ord äger alltid rum tyst på denna platta yta."},"ICON-1574":{"nm":"Stol","de":"\"Sätt dig en stund\" är förvånansvärt ömsint sagt. Hur länge mötet än drar ut eller övningen fortsätter, bär ryggstödet tyst en människas vikt. Ju längre någon stått, desto varmare välkomnar de mig — det vet jag."},"ICON-1575":{"nm":"Soffa","de":"För att göra om det sena boendet till ett vardagsrum räcker jag ensam. Klämmer man sig ihop tillsammans och tittar på underhållning, somnar en av er förr eller senare mot armstödet. Den nedsjunkna mittplatsen bevisar det hemmets värme."},"ICON-1576":{"nm":"Bord","de":"Sätt sig runt mig, och ingen sitter längst fram. Nykokt gryta och skedars klingande, dagens händelser samlas till mitten. När en enda rund yta breder ut sig sätter sig till och med en splittrad dag ner tillsammans igen."},"ICON-1577":{"nm":"Garderob","de":"Varje gång årstiden vänder forsar gamla historier fram inifrån. Scenkostymer och vardagskläder axel mot axel, kläderna väntar sin tur bakom den stängda dörren. Bara genom att öppna dörren avgörs äntligen vilken dag man ska bära idag."},"ICON-1578":{"nm":"Spegel","de":"Beröm som brist ger jag tillbaka med samma ärlighet. Platsen för sista kontrollen innan man kliver ut på scenen; framför mig ordnar folk sina miner och rätar på hållningen. Den mest uppriktiga vännen säger aldrig ett enda ord."},"ICON-1579":{"nm":"Sminkbord","de":"I varje liten låda sover ett annat ansikte. En burk för scenen, en för vardagen, en sparad specialutgåva. Sätt dig framför spegeln, och du börjar sakta med att bestämma vem du ska bli när du kliver ut idag."},"ICON-1580":{"nm":"Matta","de":"Känslan bara fötter först möter avgör rummets temperatur. Spåren efter att sitta i ring och äta snacks och rulla runt blir kvar som ludd. En möbel som arbetar från den lägsta platsen och värmer det kalla golvet en handsbredd varmare."},"ICON-1581":{"nm":"Gardin","de":"Hur mycket morgon som ska släppas in bestämmer jag. Dras jag lätt åt sidan strömmar solljuset in långt, stängs jag helt blir till och med sovmorgon förlåtligt. Att stå mellan fönster och rum och stilla reglera ljusmängden är alltid uppgiften anförtrodd mig."},"ICON-1582":{"nm":"Lampa","de":"Samma rum blir en helt annan tid på dygnet beroende på ljusets färg. Gult ljus förlänger kvällen, vitt ljus väcker gryningen skarpt. En handflatestor trollkarl som med en enda strömbrytare listigt ändrar dagens stämning."},"ICON-1583":{"nm":"Väggklocka","de":"Sekundvisarens ljud hörs bara i ett tyst rum. Ju djupare övningen blir, desto mer glömmer man mig, tills man plötsligt tittar upp och finner att det redan är gryning utanför fönstret. Utan att någonsin klandra tiden som runnit förbi pekar jag bara tyst mot nästa streck."},"ICON-1584":{"nm":"Vas","de":"Även när blommorna vissnar lämnar jag inte platsen tom. Ett kärl som en stund rymmer en mottagen känsla; så länge det finns en hand som byter vatten förblir bordet ljust. Även tom står jag i form av att vänta på någon."},"ICON-1585":{"nm":"Posterram","de":"Att hänga ett älskat ansikte på väggen kräver också omsorg. En plats solen inte når direkt, en enda spik satt perfekt i våg. Ett papper varsamt lagt bakom glas är den första att hälsa mig varje morgon när jag stiger in i rummet."},"ICON-1586":{"nm":"Fotokortstavla","de":"Om man ska sortera alfabetiskt eller efter utgivningsordning — redan det lyckliga dilemmat är där fanskapet börjar. En enda tom ruta är platsen för en favorit man ännu inte mött. Allteftersom den fylls kort för kort blir tavlan till min egen lilla krönika."},"ICON-1587":{"nm":"Lightstick-hållare","de":"Batteriet ur, handtaget upp. Det finns till och med ett knep i vinkeln man lutar och ställer den på. Väntande på nästa jubel som ska komma släcker stickan sitt ljus just här och lägger sig prydligt ner. Vilar man gott lyser man ljusare."},"ICON-1588":{"nm":"Pokalhylla","de":"Främsta raden ges åt den äldsta. Från en liten tävlings statyett till en stor scens bägare radar de upp sig, inte efter höjd utan efter hjärtats ordning. Varje gång jag putsar dem fastnar darrningen från den dagen på scenen på fingertopparna igen."},"ICON-1589":{"nm":"Picknickkorg","de":"Öppna locket, och doften av vårsol sipprar ut först. Gimbap, en termos och en enda filt travade prydligt, redo att ge sig av mot fälten. Stegen hos den som bär mig blir alltid, av någon anledning, en handsbredd lättare än vanligt."},"ICON-1590":{"nm":"Liten kruka","de":"En handsbredd fönsterbräde räcker för mig. Ett litet grönt som tålmodigt härdar ut även om man ofta glömmer att vattna. I ett hörn av ett upptaget skrivbord breder jag ut ett blad till varje dag och skickar tyst dagens hälsning."},"ICON-1591":{"nm":"Stor kruka","de":"Medan min höjd växer, växer människan med mig. När de breda bladen som tar upp ett hörn av vardagsrummet fångar solljuset och kastar skugga smyger sig årstiden in i rummet också. En belöning bara den som inte glömmer att vattna känner till."},"ICON-1592":{"nm":"Doftljusset","de":"I samma ögonblick veken tänds sjunker rummets luft ett steg ner. Doften sprider sig sakta och värmer bort och skickar ut gårdagens kvarvarande trötthet. Med en enda liten låga avslutas en hektisk dags slut som en tyst ritual."},"ICON-1593":{"nm":"Minikylskåp","de":"Öppna dörren sent på natten, och en kall burk läsk hälsar mig välkommen. Ett litet surrande brummande gör det tomma boendet lite mindre ensamt. Jag klarar inget stort hushåll, men för att ta hand om en hungrig gryning finns inget som mig."},"ICON-1594":{"nm":"Slaghåvshuvudbonad","de":"I samma stund den sätts på huvudet följer ett sommarfält med upp på axlarna. Det runda nätet filtrerar solljuset milt, och med varje steg svajar gräsdoften sakta. En hatt som sveper in en hel årstid, fin nog även om man inte fångar en enda trollslända."},"ICON-1595":{"nm":"Insamlingspåse","de":"Hängd vid midjan blir den en följeslagare i insamlandet. Dra åt öppningen lätt, så smiter det man fångat inte ut igen — det första knepet man lär sig ute på fälten. En enda lätt tygpåse rymmer sirligt en dags skörd i sin famn."},"ICON-1596":{"nm":"Insektsobservationsburk","de":"Att lufthål är det viktigaste för en gäst som bara stannar en stund, det vet jag. En liten andningsväg borrad i locket, ett enda grässtrå lagt på botten. Att släppa tillbaka den till gräset när observationen är klar hör till paret också."},"ICON-1597":{"nm":"Nålask för preparat","de":"Det finns skicklighet redan i den enda vinkel man sätter en nål snett i. För djupt och den går sönder, för grunt och den vinglar, så man måste fördela fingertoppens kraft med precision. En ask som stilla rymmer omsorgen hos den som vill betrakta ett litet liv länge."},"ICON-1598":{"nm":"Terrarielock","de":"Att vakta gränsen mellan inne och ute är mitt jobb. Stängs det för hårt kvävs det, lämnas det för löst tappar det bort sig, så jag lämnar alltid en springa som ett streck. Att skydda är tydligt något annat än att stänga in."},"ICON-1599":{"nm":"Fjärilsmatarskål","de":"Lägg bomull indränkt i sockervatten i mitten, och vingarna samlas kring den. Knepet är att hålla den grund och bred, på ett djup där små fötter inte sjunker. En enda skål samlar tyst ihop de gäster som stannar till en stund i en solig trädgård."},"ICON-1600":{"nm":"Insektslockande lampa","de":"Lämnad svagt tänd i mörkret samlas små vingar kring ljuset. Håll ljusstyrkan dämpad, platsen långt från människor. En ytterst vänlig lockare som stillar den surrande sommarnatten till betydligt tystare."},"ICON-1601":{"nm":"Insektsdekal","de":"Sex ben och ett par antenner – i en papperslapp inte större än en nagel sover ett litet liv. Fäst den lätt i hörnet av ett anteckningsblock, så breder en handsbredd äng tyst ut sig mellan sidorna."},"ICON-1602":{"nm":"Fångsttillståndsbricka","de":"Innan håven lyfts frågar den vuxna först: hur många, och hur långt. Denna lilla bricka drar en öm gräns mellan uppspelt nyfikenhet och ett löfte att hålla."},"ICON-1603":{"nm":"Betesburk","de":"Öppna locket och en fiskig, sval gryningsdoft stiger upp. Det som lockar fisken är kanske inte betet, utan ett hjärta som vet hur man väntar stilla tills flötet darrar."},"ICON-1604":{"nm":"Flötlåda","de":"Ett litet skåp där färgglada flöten ligger och sover, fack för fack. Några är en stilla sjös morgon, andra en stridströms middagstimme. För varje uttryck vattnet bär finns en passande partner prydligt hopvikt."},"ICON-1605":{"nm":"Fiskelinespole","de":"Linda inte lös lina runt fingrarna. Rulla upp den prydligt på detta runda redskap, så löses även trasslet stillsamt upp. Det liknar handen som ordnar en dag som blivit slapp."},"ICON-1606":{"nm":"Krokutlossare","de":"Bara den som stuckit sig på att dra ut en fastnad krok med bara händer känner igen detta redskap. En väg som gör mindre ont, både för den lilla varelsen och för mina fingertoppar. Omtanke börjar alltid i sådana obetydliga detaljer."},"ICON-1607":{"nm":"Musselspadeskydd","de":"Ett enda lager som sveper in spadbladet nyss grävt upp ur tidvattenslammet. Så att lera och saltvatten inte gnager på eggen läggs en tunn, mjuk vila varsamt in mellan havet och redskapet."},"ICON-1608":{"nm":"Tidvattenskort","de":"När vattnet stiger och när det sjunker undan berättar ett handflatestort kort tyst för dig. En liten kalender där någon skrivit ner det gamla löftet månen och havet gett varandra."},"ICON-1609":{"nm":"Akvarieborste","de":"Sopa försiktigt bort den gröna algen som fastnat på glasväggen, och ljuset sipprar tillbaka in i den lilla världen under vattnet. Att göra någons dag klarare flyter oftast lika tyst som detta."},"ICON-1610":{"nm":"Akvarietemperaturchip","de":"En enda siffra blinkar, och när den stannar på rätt gradtal blir fiskarna äntligen lugna. En ruta värme varken för kall eller för het. Omsorg når ända in i det osynliga."},"ICON-1611":{"nm":"Havsdjursobservationsrör","de":"En liten gäst som stannar en stund inuti det genomskinliga röret. Räkna stilla ryggfenorna och skicka den sedan tillbaka till havet. Att observera är inte att äga, utan att låna en liten stund."},"ICON-1612":{"nm":"Fossilborste","de":"Det som väcker stenens ådring, sovande i tiotals miljoner år, är inte en hammare utan en mjuk borstspets. Inför en tid som skulle smulas sönder om man skyndade sig blir varsamhet den djupaste artigheten."},"ICON-1613":{"nm":"Utgrävningspenselhätta","de":"När penselspetsen torkar ut faller inte ens jorden av rent. En liten hätta håller penselns andedräkt fuktig. En hand som vårdar sina redskap tar utgrävningens första steg."},"ICON-1614":{"nm":"Jordlagerplatta","de":"I en handsbredd jord ligger hundratals år lagrade, veck på veck. Skopa den stilla upp på denna platta, så tecknar tidens mönster, osynliga fram tills nu, sina linjer och stiger sakta fram."},"ICON-1615":{"nm":"Benfragmentbricka","de":"Lägg de utspridda fragmenten fack för fack, så trevar ett liv som en gång kastades för vinden sig sakta tillbaka till sin plats. Att restaurera är att ömt fråga efter en förlorad ordning."},"ICON-1616":{"nm":"Restaureringstejp","de":"En smal, enkel remsa som fogar samman det trasiga stället. Den bemödar sig inte att gömma ärret, utan omfamnar och håller det ömt fast. Den bevisar stilla att även det som gått sönder kan bli helt igen."},"ICON-1617":{"nm":"Namnskyltsskydd","de":"Ett enda blad som varsamt täcker skylten bakom glaset så att den inte bleknar. Det bär önskan om att den korta meningen om vem som levde, och var, ska kunna läsas tydligt ännu långt in i framtiden."},"ICON-1618":{"nm":"Magasinsbricka","de":"Ett djupt rum där skatter som aldrig trätt fram i ljuset ligger och sover. Allt däri bär en liten namnbricka – så att de aldrig glöms bort, även utan att stå på en ljus plats."},"ICON-1619":{"nm":"Museidonationskuvert","de":"Någon räcker tyst över det de samlat ett helt liv. Det som ligger i detta kuvert är inte föremål, utan ett hjärta som burits länge. Att dela blir den mest bestående utställningen, som lyser över någon."},"ICON-1620":{"nm":"Exemplarnummerchip","de":"Precis där du samlade in det tilldelar du stilla ett litet nummer. När, och var, du mötte det första gången. En upptäckt som inte skrivs ner skingras snart som morgondimma."},"ICON-1621":{"nm":"Meteorsplitterflaska","de":"En splittra som föll och strimmade natthimlen är fångad inuti en glasflaska. En enda ljusstråle som slocknade innan du ens hann önska dig något glittrar nu igen, varsamt, i din hand."},"ICON-1622":{"nm":"Snäckvindspelssnöre","de":"Träd snäckskal, insamlade ett och ett vid stranden, på en tråd och häng den under takfoten. Varje gång vinden drar förbi, med ett lätt skrammel, följer den sommarens hav tyst med in i huset."},"ICON-1623":{"nm":"Regnbågsdroppe","de":"En enda droppe som samlas darrande på en bladspets efter regnet klarnat. Inuti den runda formen ryms hela himlen och alla sju färger i en cirkel. Ibland rymmer det allra minsta den vidaste utsikten."},"ICON-1624":{"nm":"Dimsamlarflaska","de":"Jag tog med mig en flaska full av gryningsdimma från bergssluttningen. Håll den i handen och den blir sval, disigt vitgrå. En liten, öm girighet att en stund ha kvar vid din sida det som inte kan hållas fast."},"ICON-1625":{"nm":"Daggkopp","de":"En liten kopp som fångar daggen gräset samlat droppe för droppe under natten. Knappt en enda klunk, men morgonens klaraste, renaste del samlas där i stillhet."},"ICON-1626":{"nm":"Brisrosettspänne","de":"En rosett knuten i exakt den form vinden lämnade efter sig i förbifarten. Fäst den i håret, och vid varje steg följer en mild bris efter, mjukt svajande. Vårdagens lätthet, stilla fäst i ett enda spänne."},"ICON-1627":{"nm":"Vågljudskapsel","de":"Håll den stilla mot örat och det avlägsna havets vågor rullar in. Det är som om någon varsamt förseglat i en liten kapsel det ljud man en gång bar inom sig i ett snäckskal som barn."},"ICON-1628":{"nm":"Sandstjärnbit","de":"Ta en handfull sand på nattstranden, och stjärnsmulor blandas in och glittrar. Om de föll från himlen eller slipades fram av vågorna är det ingen som bryr sig om att fråga."},"ICON-1629":{"nm":"Öväderchip","de":"Öns himmel ändrar sig flera gånger om dagen. Anteckna klart, dimma och skur prydligt på ett litet chip, så kan du breda ut gårdagens himmel igen idag."},"ICON-1630":{"nm":"Klipptrappsats","de":"Ett trappsteg, och ännu ett, för att gå upp och ner för den branta sluttningen. Sätt ihop de utspridda delarna, och även en klippa blir en avslappnad promenadväg. Att bana en väg är att i förväg lägga ut någons nästa steg."},"ICON-1631":{"nm":"Jordvägsmönsterrulle","de":"En rulle som tagit avtryck av en mjuk jordvägs själva ådring. Rulla ut den med ett svep, och en lantlig stig som gör att du vill gå barfota breder tyst ut sig under fötterna."},"ICON-1632":{"nm":"Stenvägsmönsterchip","de":"Mönstret från flisstenarna som en gång täckte de gamla gränderna ryms intakt i ett litet chip. Vid varje steg, klapp klapp, väcks en gammal bys fotsteg till liv igen vid dina tår."},"ICON-1633":{"nm":"Strandstaketbit","de":"En enda sektion av det låga staket som rests i sanden för att vågorna inte ska ta sig över. En liten, tystlåten gränsvakt som står där och drar en öm linje mellan havet och sanden."},"ICON-1634":{"nm":"Gräsreparationslapp","de":"En bit grönt som varsamt läggs över en plats trampad kal. På några dagar tar gräsen varandra i hand och fyller igen den tomma platsen. Naturen vet alltid hur den läker sig själv."},"ICON-1635":{"nm":"Vattenvägspåle","de":"En påle som i förväg talar om vägen vattnet ska rinna. Så att regnvattnet inte irrar omkring, ovisst vart det ska, står en liten vägvisare nedstucken i marken tyst kvar även regniga dagar."},"ICON-1636":{"nm":"Liten brodel","de":"En enda del av en liten bro som förenar bäckens två stränder. Mellan hitsidan och dit bortom börjar löftet om att man alltid kan korsa över tyst just med denna lilla del."},"ICON-1637":{"nm":"Utsiktsräckeshätta","de":"På öns högsta punkt, en enda avslutande detalj som sveper in räckets ände. Den stöttar och skyddar tyst den plats som oftast rörs vid av händerna hos dem som samlats för att blicka bort i fjärran."},"ICON-1638":{"nm":"Lägereldsunderlag","de":"Innan veden läggs på, en plats som håller den så att glöden inte skingras. Ovanför den brinner nätterna av pratstunder och blickar mot stjärnorna varma, länge, länge."},"ICON-1639":{"nm":"Tapetprovrulle","de":"Ett rums stämning börjar vid en enda vägg. Att rulla ut en liten rulle för att välja färg är att tyst skissa, i förväg, precis vilka slags dagar du vill leva härifrån."},"ICON-1640":{"nm":"Golvprovchip","de":"Känn först med fingertopparna hur golvet dina bara fötter ska röra vid känns. Varmt eller svalt – på detta enda lilla chip hänger tryggheten i de dagar du kommer att leva härifrån."},"ICON-1641":{"nm":"Takkroksset","de":"I samma stund du hänger en enda krok i bjälken blir det tomma taket en plats som väntar på någon. En vindpinne, eller en blomkruka? Denna lilla järnkrok bär vikten, men vad som ska hängas är upp till den boendes hjärta att bestämma."},"ICON-1642":{"nm":"Fönstertoningsfilm","de":"Middagsljuset är för ärligt, så du klär fönstret i en tunn, enda hinna. Solljuset kommer in som det är, men kanterna mjuknar, och allt i rummet blir milt aprikosfärgat. Inte en avskärmning, utan ett vänligt sätt att låta ljuset flyta ut."},"ICON-1643":{"nm":"Dörrklockeskydd","de":"Med orden att även klockan en gäst trycker på behöver kläder satte någon på ett runt skydd. Det håller regnet borta, håller dammet borta, och är framför allt den lilla runda mun som först av alla ger hälsningen: \"här bor någon.\""},"ICON-1644":{"nm":"Gästboksställ","de":"Ett ställ rest upp så att var och en som kommer skriver sitt namn och går vidare. Innan bläcket torkat flyter en rad hälsningar från pennspetsen. När besökta fotsteg travas rad för rad blir den tomma anteckningsboken snart husets tjockaste album."},"ICON-1645":{"nm":"Möbelplaceringsnål","de":"Skrivbordsplatsen du tvekat om att flytta – en enda nål trycker fast den i golvet och avgör saken. En liten spik som varsamt håller fast möblens fötter. En plats, en gång vald, blir en man fäster sig vid, nickar trägolvet tyst."},"ICON-1646":{"nm":"Förvaringsetikettram","de":"Vad som ligger var kan lådan aldrig säga. Så en namnlapp sätts in i en fyrkantig ram för att tala i dess ställe. I samma stund en enda etikett faller på plats återfår de rörig­a facken sina namn och blir lugna."},"ICON-1647":{"nm":"Rumsdoftpinne","de":"Doften som fuktar pinnens spets sprider sig sakta uppåt. Lavendel den ena stunden, en regnvåt äng den andra. När en osynlig tråd av doft byter ut rummets luft löses en dags trötthet upp ur axlarna på den som kommit hem."},"ICON-1648":{"nm":"Fröpåseklämma","de":"Fröna som köptes på våren men aldrig riktigt såddes kläms nu ihop stadigt, påse och allt, med en klämma. Om ens ett enda frö smiter ut blir nästa säsong en rad kortare. Inuti den lilla klämman sover nästa års trädgård hel."},"ICON-1649":{"nm":"Såbricka","de":"Fyll varje fack med jord för att skapa det unga skottets första rum. Ett liv per hål, förstaårselever som växer prydligt på rad. Titta ner, och en morgon där det gröna klungvis ropar upp närvaro börjar på nytt varje dag på brickan."},"ICON-1650":{"nm":"Vattningsindikatorpinne","de":"\"Jag är törstig.\" Eftersom krukan inte kan tala sätts en liten skylt ner i jorden för att sända signalen i dess ställe. När färgen ändras är det dags att vattna. Den minsta tolken mellan växt och människa ryms helt i denna handsbreda pinne."},"ICON-1651":{"nm":"Uppbindningssnöre","de":"En växande stjälk kan vackla under sin egen tyngd, så du binder den varsamt fast vid en påle med ett mjukt band. För hårt och den kvävs, för löst och den faller – handen som binder behöver just rätt mått av ömhet. Även det som växer upp behöver någon vid sin sida."},"ICON-1652":{"nm":"Insektsnät","de":"Ett fint vävt nät spärrar tyst av de små munnar som siktar in sig på ömtåliga blad. Det släpper igenom vind och solljus och viker bara undan det som skadar, en osynlig grindvakt. Att trädgården är fridfull beror på omtanken vävd in i dessa täta maskor."},"ICON-1653":{"nm":"Solljusmätarkort","de":"Hur mycket sol faller här? Du reser upp ett enda kort i rabatten och frågar tyst. Ju djupare färgen blir, desto mer ljus har den fångat idag. Denna lilla papperslapp skiljer ut en plats åt barnet som älskar solsken och den som trivs bäst i skugga."},"ICON-1654":{"nm":"Jordsyratestremsa","de":"Håll en teststicka mot jorden, och från rosa till blått yppar marken sitt inre i färg. Där det varken är för surt eller för bittert andas rötterna som lättast. Jordens osynliga känslor läses av, ruta för ruta."},"ICON-1655":{"nm":"Skördekorgsetikett","de":"Är dagens skörd sallad eller körsbärstomater? Du fäster en namnlapp på varje korg. På en skördemorgon tung av jorddoft och grönt blir korgen, i samma stund etiketten sätts på, det första vägmärket på vägen till bordet."},"ICON-1656":{"nm":"Frölagringsburk","de":"Du samlar årets skördade frön i en glasburk och skickar dem till nästa vår. Stäng locket, och tiden pausar en stund, medan de små kornen väntar på sin tur i mörkret. Det är en burk som ett brev skickat över en hel årstid."},"ICON-1657":{"nm":"Ympningstejp","de":"Håll en avskuren gren och en ny mot varandra, linda dem i tejp, och sakta blir de två till en enda kropp. Sav flödar åter över brottet, såret läker sakta. Att foga samman är, till syvende och sist, att ta emot varandras ådring."},"ICON-1658":{"nm":"Beskärningssaxhätta","de":"Du drar en liten hätta över saxens vassa spets. Medan handen som gallrat grenarna vilar ska eggen förbli skarp och handen förbli oskadd. Med orden att även ett avslutat redskap behöver pyjamas lägger trädgården sina verktyg omsorgsfullt till ro."},"ICON-1659":{"nm":"Blomfrösorteringslåda","de":"Balsamin, portlak, underbara natt – frön olika till namn och färg får var sitt eget rum i skilda fack. Blandas de kan man i vår inte skilja vem som är vem. De små avdelarna i lådan skissar i förväg upp ritningen för en trädgård som ännu inte blommat."},"ICON-1660":{"nm":"Krukbricka på hjul","de":"Sätt på fyra hjul, och även en tung kruka ger sig av för att följa solskenet. Östfönstret på morgonen, skuggan vid middagstid. Det gröna som en gång satt fast av sin egen tyngd rullar iväg, jagande ljuset hela dagen på jakt efter den allra bästa platsen."},"ICON-1661":{"nm":"Rankstyrband","de":"En ranka trevar sig fram i tomma luften, ovetande vart den ska, och bandet leder den tyst in på rätt väg. Uppåt, och ännu högre upp. Ge den ett fäste, och märkligt nog griper växten tag i den handen. Även det som växer upp behöver en vägvisare."},"ICON-1662":{"nm":"Blomspråkskorthållare","de":"Kortet instucket vid en blomma bär de ord just den blomman vill förmedla. Hortensian säger uppriktighet, tusenskönan säger renhet. Så att en promenad genom rabatten blir en vandring i att läsa brev lånar en liten hållare tyst ut röst till den tysta blomman."},"ICON-1663":{"nm":"Trädgårdsskylthätta","de":"Så att regn och vind inte suddar ut bokstäverna sätter du en klar hätta över trädgårdsskylten. \"Tomater här\", \"basilika här\". Namn som annars kunnat blekna förblir skarpa, så att trädgården, även efter ett helt år, inte glömmer en enda av sina egna."},"ICON-1664":{"nm":"Gödselsked","de":"När man ger jorden näring bränner girighet bara rötterna. Så en sked, precis så mycket. Den lilla skeden skopar upp rätt mängd och påminner dig – ett hjärta som odlar väl kommer alltid från fingertoppar som vet vad lagom är."},"ICON-1665":{"nm":"Dimmunstycke","de":"Vrid munstycket, och vattenstrålen skingras nedåt som dimma. Ett ömtåligt blad, tidigare sliten av en hård stråle, lyfter mjukt huvudet under daggliknande droppar. Samma vatten blir en helt annan hälsning beroende på hur det ges."},"ICON-1666":{"nm":"Fodermått","de":"En kopp, två koppar. Du mäter en väns måltid med omsorg, inte på ögonmått. För mycket och de lämnar kvar, för lite och de blir ledsna, så du räknar ut precis rätt mängd. Kärlek kommer ibland i mätandets skepnad."},"ICON-1667":{"nm":"Fällningsborstöverdrag","de":"Under fällningssäsongen sveper ett överdrag omsorgsfullt in den mjuka fjunet som fastnat i borsten. Sätt hättan på borsten efter putsningen, och nästa dag börjar lika fluffig och fräsch. Glansen hos den man delar liv med växer tyst fram ur sådana små omsorger."},"ICON-1668":{"nm":"Klosaxhätta","de":"Du sätter ett litet lock över klosaxens vassa spets, så att det avslutade redskapet inte river sönder andra saker i lådan. När omsorgens stund är över fullbordar det att lägga verktyget till ro ett helt varv av vård."},"ICON-1669":{"nm":"Halsbandssmycke","de":"Häng ett enda glittrande smycke på halsbandet, och den vanliga promenadvägen blir lite mer speciell. En liten utsmyckning som glimmar i solen. Den behöver inte vara påkostad – den är märke nog om att denna lilla vän är djupt älskad av någon."},"ICON-1670":{"nm":"Djurhälsokort","de":"Åt vännen bra idag, är det något som gör ont någonstans? Du skriver en rad om dagen om din husdjursväns dag på kortet. När tillståndet hos en familjemedlem som inte kan tala läggs ner i skrift växer också den omsorgsfulla omtanken sig grundligare och tryggare."},"ICON-1671":{"nm":"Sovkuddöverdrag","de":"Du klär sovkudden i nya, luftiga kläder. Dra av tyget nött av rullande och gnuggande, och doften av solblekt fjun stiger sakta upp. Att hålla platsen de ligger mest på renast är en daglig omsorg för den man delar liv med."},"ICON-1672":{"nm":"Rabattstaketpinnar","de":"Tryck ner små pinnar längs rabattens kant för att resa ett lågt staket. Inte ett strängt \"gå inte över\", utan en öm gräns som säger att härifrån är blommornas plats. Med en linje att hålla kan de växa tryggt innanför den."},"ICON-1673":{"nm":"Förtroendegodisburk","de":"Även den blyga lilla spetsar öronen vid ljudet av att denna burk skakas. Inuti ligger en handfull godis som öppnar hjärtan. Eftersom små löften vinner över ord när man ska bli nära går det skramlande ljudet fram först."},"ICON-1674":{"nm":"Promenadloggbricka","de":"Vilken väg idag, och hur långt? Du knyter fast anteckningen på brickan som en söm. Insamlade fotsteg blir en karta, och insamlade kartor blir minnen. Varenda dag ni gått tillsammans travas prydligt upp på denna lilla bricka."},"ICON-1675":{"nm":"Fågelmatskål","de":"Ställ skålen i fönsterkarmen, strö ut några hirskorn, och namnlösa gäster flyger in en efter en. Det knackande ljudet av picking, fladdrandet av vingar. Det är ett litet bord där en enda given handfull varje morgon för med sig en liten konsert."},"ICON-1676":{"nm":"Ekorreobservationsburk","de":"Inuti det genomskinliga kärlet möter du ekorrens runda ögon. Kinderna proppfulla av ekollon, huvudet på sned – vilken syn. Under löftet att titta en stund och snart släppa den fri byter du en kort hälsning med en liten bit av vildmarken."},"ICON-1677":{"nm":"Tassavtrycksform","de":"Du häller mjuk gips för att gjuta ett litet tassavtryck. Medan du väntar på att det ska stelna pausar även gårdens tid en stund. Det handstora avtrycket, dömt att försvinna när de växer, lyfter den vita formen upp som en evighet och lägger det varsamt i dina två händer."},"ICON-1678":{"nm":"Linsskydd för nattkikare","de":"Du stänger ett litet lock över linsen som blickar in i natten. Så att glaset som såg stjärnor och bon väntar på nästa natt utan ett enda dammkorn. Även ögon som ser mörkret tydligt behöver ett litet kommatecken av vila under dagen."},"ICON-1679":{"nm":"Boskyddsmarkering","de":"Upptäcker du ett bo bland grenarna reser du en markering istället för att gå närmare. \"En fågelfamilj bor här, var vänlig och tyst.\" Att vaka utan att tränga sig på – just det ömma steget bakåt är det som gör boet allra tryggast."},"ICON-1680":{"nm":"Djurljudsinspelarchip","de":"Gräsdungens sång, kvittret under takfoten, nattens syrsor – du fångar dem inte i chipet så mycket som lånar dem en stund. En liten ljudlåda som, när den spelas upp igen, väcker till liv till och med luften från just det ögonblicket. Så att allt som en gång hördes aldrig riktigt försvinner."},"ICON-1681":{"nm":"Kikaröverdrag","de":"Precis innan en fågel lyfter håller skogen andan ett ögonblick. I den stillheten vakar ett enda tygstycke draperat över linsen över fjärrsyns skärpa, orörd av minsta fingeravtryck."},"ICON-1682":{"nm":"Skogsstigskamerarem","de":"Varje gång du klättrar den branta skogsstigen slår kameran lätt mot bröstet. Den dunkande pulsen och slutarens klick svänger i samma takt, och denna enda rem håller de stunderna stadigt tryckta mot ditt bröst."},"ICON-1683":{"nm":"Naturguidekort","de":"Även ett enda grässtrå har ett namn, berättar kortet tyst. När det du gick förbi ovetande får en benämning börjar bergsstigen plötsligt myllra varmt av bekanta ansikten."},"ICON-1684":{"nm":"Segellagningslapp","de":"Även tyget som tar emot vinden med hela sin kropp bär ärr. Med en enda liten lapp lagd varsamt över det trasiga stället vinner seglet åter rätten att omfamna det öppna havet."},"ICON-1685":{"nm":"Knopövningsbräda","de":"Uppåt, nedåt, ett varv till – ordningen handen memorerat blir en knop. En natt när stormen bankar mot däcket binder just denna enda procedur samman människa och skepp till ett."},"ICON-1686":{"nm":"Ankarkedjehätta","de":"Förringa inte denna lilla hätta som träs över kedjans ände. Rost växer i smyg inifrån, så en enda hätta som ställer sig mot havsvinden förlänger tyst ankarets livslängd."},"ICON-1687":{"nm":"Kursmarkeringsflagga","de":"En dag så tät av dimma att vägen framför suddas ut talar en enda flagga om vägen i dess ställe. En enda färgfläck som fladdrar i vinden löser äntligen upp den vilsegångna rorsmannens stelnade axlar."},"ICON-1688":{"nm":"Hyttnyckelring","de":"Uppe på det gungande havet hänger en liten ring på den trånga hyttdörren. Så länge nyckeln håller sin plats är ett rum att återvända till aldrig låst för dig."},"ICON-1689":{"nm":"Vattentätt kartfodral","de":"I regnet suddar en papperskarta ut vägen först av allt. Medan ett enda blad förblir torrt inuti det genomskinliga fodralet tappar även en genomblöt resa aldrig riktigt riktningen."},"ICON-1690":{"nm":"Skeppslampveke","de":"Oljan veken sakta suger upp blommar till slut ut i en låga. En enda ljuspunkt på däck, och vid den lilla flämtningen kommer natthavets ofattbara avstånd tyst lite närmare."},"ICON-1691":{"nm":"Nödsignaltyg","de":"På ett avstånd ingen röst når går handen som viftar en röd trasa högt över ordens räckvidd. Detta enda tygstycke skär genom vinden och ropar i ditt ställe att någon här lever."},"ICON-1692":{"nm":"Havsvindsriktningsnål","de":"Den som vet varifrån vinden blåser bestämmer kursen. Vid den enda riktning en liten nål tyst pekar ut lutar sig ödet för hela dagens segling."},"ICON-1693":{"nm":"Fällbart spadeöverdrag","de":"Fäll ihop bladet och täck över, och även den flitiga spaden hämtar andan en stund. Det sista handen som grävt upp all jorden gör är att vårda morgondagens egg så att den inte blir slö."},"ICON-1694":{"nm":"Fickkompassfodral","de":"Nålen pekar alltid mot norr utan att darra, men det som skyddar den nålen är ett stadigt fodral. Ju fler gånger man gått vilse, desto ömmare bär man riktningen inom sig."},"ICON-1695":{"nm":"Lägerdisknät","de":"Du hänger de diskade tallrikarna i nätet för att torka i morgonsolen. En dag i lägret börjar med ljudet av fukt som torkar bort, och just den obetydligheten fyller tältet med trygghet."},"ICON-1696":{"nm":"Campingtillståndskort","de":"Tillåtelsen att stanna en natt på detta berg. I samma stund ett enda pappersark ligger i din hand blir även den främmande skogen din allierade en stund och tar tyst emot ditt lilla tält."},"ICON-1697":{"nm":"Stigflaggsnöre","de":"Bind en flagga vid varje vägskäl, så skingras inte återvägen i mörkret. En enda liten markering lämnad av den som gick före puttar tyst på ryggen hos de steg som följer efter."},"ICON-1698":{"nm":"Vattentät tändsticksask","de":"En tändsticka drunknar i en enda droppe och tystnar för alltid. Förseglad i en ask dit inte en vattenpärla kan tränga in väntar gnistan torr och stilla, bara för den allra kallaste natten."},"ICON-1699":{"nm":"Bärbart vattenfilter","de":"Även vatten grumligt nog att göra en tveksam klarnar när det passerat detta filter. En liten anordning som lägger tvivlet åt sidan innan törsten – tron att man kan dricka är i sig en klunk av lugn."},"ICON-1700":{"nm":"Nödfiltspaket","de":"Hopvikt ryms den i en handflata; utvecklad blir den en människas värme. Så att ordet \"nödläge\" väger lite lättare väntar filten i ett hörn av väskan, alltid redo att bli varm."},"ICON-1701":{"nm":"Nattmarkeringsarmband","de":"En bergsstig har sjunkit in i mörkret, och ett enda handled sprider ett stilla sken. Det smala bandet som röjer var och en plats knyter samman dem som vandrar tillsammans med en osynlig, öm tråd."},"ICON-1702":{"nm":"Gruvhjälmsklistermärke","de":"Klistermärket på hjälmen är gruvarbetarens andra namnskylt. I den djupa gruvgången där även ljus är dyrbart känner du varmt igen en kamrat på den lilla bilden som fångas av lampskenet."},"ICON-1703":{"nm":"Malmådernål","de":"Där du har hittat en åder sätter du stilla ner en nål. En enda punkt som lyser ensam i mörkret talar vänligt om för nästa person att börja gräva just här."},"ICON-1704":{"nm":"Sprickmätare","de":"Att mäta sprickan som klyver väggen är ett långsamt, ihärdigt tålamod. Har den vidgats en handsbredd sedan igår? Den lilla siffran linjalen visar fångar ett ras innan det kommer."},"ICON-1705":{"nm":"Avgnidningspapper för ruinmönster","de":"Du lägger papper över mönstret ristat i sten och knackar bläcket sakta, sakta. I stunden då en beröring från tusen år sedan stiger fram i svart korn, sätter avgnidningen den flydda tiden mittemot dig en stund."},"ICON-1706":{"nm":"Antikt myntfodral","de":"Den lilla metallbiten, sövd och skyddad mot rost, bär den sista rösten från en försvunnen nation. En hel tidsålder bor i ett enda mynt, som sakta åldras i det genomskinliga fodralet."},"ICON-1707":{"nm":"Kristallskärvsställ","de":"Även en kristall som fängslar ljus inom sig behöver något att luta sig mot. I stunden den vilar stilla på ett litet ställ, breder det ömtåliga tinget äntligen ut hela sin glans."},"ICON-1708":{"nm":"Grottkartfragment","de":"En sönderriven karta visar listigt bara halva sin hemlighet. Fram till dagen du hittar den återstående biten håller det här enda bladet resten av vägen halvt dold någonstans i grottan."},"ICON-1709":{"nm":"Repnedfirningskarbin","de":"För att anförtro din kropp nerför klippan måste du först lita fullt på den här karbinhaken. Att hänga sin tyngd på en enda kall järnbit — tillit är, till sin natur, just så tung en sak."},"ICON-1710":{"nm":"Utgrävningstillstånd","de":"Ett enda pappersark tydligt stämplat med lov att gräva i marken. För att väcka det som ligger begravet, be först om lov — utgrävning lär tyst vägen att börja med hövlighet."},"ICON-1711":{"nm":"Vindskyddspaket","de":"Res det med ryggen mot vinden, och en fyrkant av stillhet öppnas mitt i den blåsiga slätten. Bakom detta enda skikt skyddas en liten gnista, och den trötte får en stunds vila."},"ICON-1712":{"nm":"Sandstormsskydd för glasögon","de":"Hur våldsamt sanden än virvlar måste åtminstone synen bevaras till slutet. Ett tunt överdrag över glasögonen blir modet att hålla ögonen öppna och gå vidare, även genom stormen."},"ICON-1713":{"nm":"Regnbesöksbricka","de":"Regnvatten droppar från tårna på gästen som har kommit. En bricka som tyst ställts vid ingången tar emot de kalla, våta fötterna tyst och varmt."},"ICON-1714":{"nm":"Värmeböljans kylbricka","de":"En liten bricka som mjukt kyler middagshettan. Hängande från väskan bär den sin svalka, och just när svetten börjar pärla räcker den dig en handfull skugga."},"ICON-1715":{"nm":"Köldknäppens handvärmarbälte","de":"Ett varmt bälte som lindas ett varv runt midjan. När handvärmarens hetta sprider sig uppåt ländryggen blir även den bittra midvinterslätten en aning mer uthärdlig."},"ICON-1716":{"nm":"Fuktabsorberande påse","de":"Fukten gnager på tingen utan ett ljud. Medan en liten påse i lådan tyst dricker upp fuktigheten behåller det du håller kärt sin form, torr och hel."},"ICON-1717":{"nm":"Lerskoöverdrag","de":"Det finns stunder då enbart skorna måste förbli rena även när du vandrar genom leran. Det här tunna skyddet som håller leran borta gör stegen som korsar hemmets tröskel så mycket lättare."},"ICON-1718":{"nm":"Sjödimmelampskydd","de":"När havsdimman försöker svälja lampan hel, samlar det här skyddet tyst ihop det spridda ljusets korn. Även i den disiga gryningen vägrar en enda hamnfyr till sista stund att slockna."},"ICON-1719":{"nm":"Blixtvarningsnål","de":"När mörka moln hänger lågt ger en enda nål varning först. Ordet att böja sig lågt innan blixten slår ner — ödmjukhet inför naturen lär man sig alltid bäst i förväg."},"ICON-1720":{"nm":"Receptbokmärke","de":"Ett litet bokmärke instucket mellan sidorna i en uppslagen kokbok. När du famlar dig tillbaka efter raden du tappade bort framför spisen, vaknar mors husmanskost också till liv på den sidan."},"ICON-1721":{"nm":"Kryddmätarpinne","de":"Mamma sa alltid bara \"en nypa\". Ögonmått kunde aldrig vara exakt, ändå vacklade hennes handlag aldrig. När du mäter salt med den här pinnen inser du att det som mognat längre än något mått inte var uppskattning, utan kärlek."},"ICON-1722":{"nm":"Jäslocksband","de":"Visste du att även krukan andas? När det här bandet omfamnar locket tätt börjar insidan och utsidan sakta tala med varandra. Först efter de där dagarna utan brådska förtjänar väntan äntligen namnet smak."},"ICON-1723":{"nm":"Mognadsetikettbricka","de":"En liten bricka med datumet det gjordes prydligt nedskrivet. Bokstäverna bleknar medan det som finns inuti bara fördjupas. Att skriva ner det som för att glömma, och plötsligt en dag ta fram det igen — mognad är ett löfte som hålls just så."},"ICON-1724":{"nm":"Buljongsil","de":"Klar buljong kommer först efter att ha silats, och silats igen. Se silen hålla tillbaka bitarna och bara låta essensen flyta igenom, och det gamla kökets ordspråk — att djup samlas där något tagits bort — når dig genom fingertopparna."},"ICON-1725":{"nm":"Degjäsningsduk","de":"Du breder försiktigt en duk över degen. Medan jästen flitigt sväller under det dunkla lär du dig för första gången ömheten hos det som växer tyst på osedda platser."},"ICON-1726":{"nm":"Ingrediensputsningsnål","de":"En liten nål som delar salladslökens fibrer och håller fast vitlöken stadigt. Att förbereda är som en första hälsning till råvarorna, så ju mer omsorgsfullt du putsar, desto ljusare glöder kvällsbordet en nyans till."},"ICON-1727":{"nm":"Anrättningstång","de":"Var den sista biten ska läggas på tallriken — i slutändan bestämmer den här tången. I det korta ögonblicket en skicklig hand tvekar en halv takt i luften, blir en måltid stillsamt till en målning."},"ICON-1728":{"nm":"Isolerande matlådeöverdrag","de":"Matlådan man fick vid skolporten skulle hålla sig varm ända till lunchklockan ringde. Värmen som hålls fångad i det här överdraget svalnar inte, lika djup som hjärtat hos den som stått vid spisen sedan gryningen."},"ICON-1729":{"nm":"Middagsinbjudan","de":"\"Kom och ät hos oss någon gång.\" Finns det ett vänligare sätt att säga något på? Utan några stora löften, bara att sitta vid samma bord — den äldsta inbjudan koreanskan kan erbjuda ryms i detta enda kort."},"ICON-1730":{"nm":"Bordsreservationsbricka","de":"Du skriver ditt namn och håller platsen. Medan en liten bricka binder ett tomt bord till någon en stund, närmar sig den avtalade tiden, långsam som fotsteg."},"ICON-1731":{"nm":"Smakbedömningskort","de":"Ansikten som tar en tugga och allvarligt delar ut stjärnor. Den ärliga raden prydligt nedskriven på det här kortet är det varmaste tjatet som finns för att göra nästa rätt ännu godare."},"ICON-1732":{"nm":"Tacksamhetsband för matlåda","de":"Du virar ett band runt den fint urtömda matlådan och skickar tillbaka den. Även den som aldrig lyckades säga tack knyter, i alla fall i den här knuten, det hjärta de inte kunde uttala."},"ICON-1733":{"nm":"Allergimärkningsbricka","de":"Den här lilla brickan vaktar tyst någons bord. Att tydligt ange vad som finns i är ett annat namn för gästfrihet — en omsorg som når ända in i det osynliga."},"ICON-1734":{"nm":"Smakminnessked","de":"Smaken som dröjt kvar på tungan var, i själva verket, den dagens landskap. När en enda sked på ett ögonblick bär dig tillbaka till ett barndomskök, verkar det som om minnet är något hjärtat, inte magen, öser upp och håller kvar."},"ICON-1735":{"nm":"Dagens meny-mynt","de":"Vad ska vi äta idag. Inför världens svåraste fråga förlorar vi varje gång. Vänd på det här myntet och lämna menyn åt ödet, och hjärtat blir, förvånansvärt nog, lätt och glatt."},"ICON-1736":{"nm":"Gemensam bordsklocka","de":"Ring klockan en gång, och familjen som spridit sig i sina rum samlas på ett ställe. Klockan över det runda bordet är den kärvaste översättningen av orden \"det är klart, kom fort.\""},"ICON-1737":{"nm":"Dessertordningskort","de":"Det söta kommer alltid sist. Det här kortet håller det löftet som ingen minns vem som gav. En liten, öm värd för bordet, som sparar aptitens höjdpunkt till en enda tugga dessert."},"ICON-1738":{"nm":"Prutningsmynt","de":"Mitt i marknadens hjärta möts \"ge mig lite avslag\" och \"jag går redan back\" i vänskaplig strid. Det här myntet är kvittot från en gammal stamkund, där köpslående till sist alltid slutar i skratt."},"ICON-1739":{"nm":"Lagerkontrollnål","de":"Du sveper tyst över lagerhyllorna, hittar de tomma fälten och sätter i en nål. Att veta vad som finns kvar och vad som tagit slut — hushållningens stora arbete börjar alltid med denna lilla kontroll."},"ICON-1740":{"nm":"Ståndstädborste","de":"På kvällen efter marknadens slut lägger sig ljudet av att sopa ett tomt stånd lågt över butiken. I fingertopparna som torkar rent en plats att fylla igen imorgon vilar en flit som knyter ihop dagen prydligt."},"ICON-1741":{"nm":"Dagens rekommendationskort","de":"\"Det här är gott idag.\" Ett kort butiksägaren smyger fram. I den rekommendationen, som stillsamt puttar på axeln hos en kund osäker på vad hen ska välja, ryms en dags stolthet prydligt samlad."},"ICON-1742":{"nm":"Stamkortshållare","de":"Fyll tio, och en är på huset. Den här hållaren, vars stämpelfält fylls sakta, är ett annat ansikte för ordet \"stamkund\" — för att komma ofta betyder, i slutändan, att man älskar det."},"ICON-1743":{"nm":"Bytesbokklämma","de":"En klämma som samlar och håller ihop protokollen över det som bytts och lämnats tillbaka. Ju mer som gått fram och tillbaka, desto tjockare blir liggaren, och med den tjockleken växer också förtroendet som byggts upp med grannarna."},"ICON-1744":{"nm":"Slutsåld-etikett","de":"I stunden den här etiketten sätts på den allra sista, fylls hjärtat märkligt nog. Det är en kort avsked, som \"farväl\", till ett ting som far iväg till någons bord, till ett hörn av ett rum."},"ICON-1745":{"nm":"Reserverad varukorg","de":"En korg med din namnlapp håller en plats på hyllan. Den där enda platsen, avsatt i förväg, säger tyst till dig när du kliver in: \"Jag har väntat på dig hela tiden.\""},"ICON-1746":{"nm":"Inslagningsbordsmatta","de":"Mattan som ligger över inslagningsbordet är en scen för fladdrande händer. Under den korta stund pappret viks och snöret knyts prydligt, glider ett vanligt ting stilla in i att bli någons present."},"ICON-1747":{"nm":"Besökslöftslapp","de":"\"Jag kommer förbi imorgon.\" En lapp skriven i en rad och smygande instucken i dörrspringan. Även när ni missat varandras ansikten rider löftet på ett enda ark, anländer före personen och väntar tyst."},"ICON-1748":{"nm":"Grannens presentkorg","de":"En korg räckt över muren kommer alltid med förevändningen \"jag gjorde lite för mycket\". Koreansk värme korsar över till andra sidan just så, spelande likgiltig under sken av överflöd."},"ICON-1749":{"nm":"Bynyhetslåda","de":"Byns nyheter, stora som små, samlas prydligt inuti den här lådan. Vem som just flyttat in, vems hus som håller fest — några pappersark samlas för att förmedla grannskapets stilla puls."},"ICON-1750":{"nm":"Tack-för-besöket-stämpel","de":"Du trycker fast tacksamheten för att någon kom med en enda stämpel. Det där bläckmärket som spritt sig i pappret stannar kvar längre än orden \"jag ska inte glömma.\""},"ICON-1751":{"nm":"Vänlighetskort","de":"Ett kort där du tyst skriver ner den vänlighet någon visade idag och skickar tillbaka den. I en by som bryr sig om att sätta små ömheter i ord, kretsar det goda ständigt runt och kommer tillbaka."},"ICON-1752":{"nm":"Ursäktsbrevsigill","de":"Precis som ett äpple som mognat rött kan en ursäkt bara ges fram efter att den mognat tillräckligt. Det här sigillet, tryckt fast på kuvertet, är märket av det mod som bar en svårsagd ursäkt ända till slutet."},"ICON-1753":{"nm":"Gemensam uppgiftstavla","de":"Ett enda schema, uppdelat i kolumner över vem som tar vad. Arbete som är för tungt ensam blir mycket lättare när namnen delas över det — alla som arbetat axel mot axel vet det."},"ICON-1754":{"nm":"Grannsmakband","de":"Du markerar tyst vad en granne tycker om med band i olika färger. Att minnas någons smak är den tystaste bekännelsen av alla — att man värdesätter den personen, utan att någonsin säga det."},"ICON-1755":{"nm":"Inbjudningsring för namnskylt","de":"En enda ring på namnskylten tillkännager \"tar emot gäster idag\". Det är en handflatestor markör, men på den hänger ett hjärta öppnat på vid gavel, färdigt med sina förberedelser att välkomna någon."},"ICON-1756":{"nm":"Festivalinträdesarmband","de":"Ett blekt band buret i flera dagar, för kärt för att ta av. Först när det spändes fast om handleden började festivalen på riktigt. Inuti det sover, bevarad hel, en dag som aldrig riktigt tog slut, ens efter att den tog slut."},"ICON-1757":{"nm":"Fyrverkeribiljetthållare","de":"Just innan natthimlen brister, håller biljetten i den här hållaren ditt fladdrande hjärta stadigt fast. Det är ett löfte hållet tills handflatan svettas, alltsammans för det ena ögonblicket det första fyrverkeriet blommar med en knall."},"ICON-1758":{"nm":"Månskådningstallrik","de":"Det fanns nätter då det kändes som om man ösat upp hela fullmånen i en skål. Lägg färsk frukt och songpyeon vackert på den här tallriken och buga för månen, och ett runt hjärta når ända till himlens rand."},"ICON-1759":{"nm":"Vinterfestivalvantnål","de":"Även när händerna domnar i snön fortsätter vantarna att glida av handlederna. Först när den här nålen fästs stadigt vid manschetten kan du äntligen springa runt vinterfestivalen efter hjärtats lust."},"ICON-1760":{"nm":"Vårhälsningskort med frön","de":"Några frön som sover inuti kortet väntar var och en på sin vår. Begrav dem i jorden, och de gror ofelbart, som ett löfte — det verkar som om varje början spirar ur en enda liten, fast punkt."},"ICON-1761":{"nm":"Sommarstrandsstämpel","de":"En våg trycker sitt märke stadigt i sanden och drar sig sakta tillbaka. Trots att den vet att det snart suddas ut, lämnar den ändå ett litet spår som säger att någon var här. Sommaren stämplar alltid en gång, tydligt, och driver sedan bort med den salta doften."},"ICON-1762":{"nm":"Höstskördeband","de":"Handen som bundit säden knyter till sist ett band vackert. En enda knut som samlar ett års svett med omsorg. Även när fälten töms ger hösten en hälsning till, i sin vackraste färg, som en solnedgång."},"ICON-1763":{"nm":"Minnesfotopratbubbla","de":"\"Tack för att du kom ända hit.\" En hälsning som aldrig riktigt sagts högt sväller rund uppe på pappret. En rund liten hjärtbit, som mjukt lånar en röst åt tystnaden frusen i ett fotografi."},"ICON-1764":{"nm":"Festivalkartnål","de":"En markör som någon satt i så att du inte ska gå vilse på de vida ängarna. Även när fötterna springer i förväg mot folkmusikens ljud, leder den här enda nålen stilla dig, den vilsna, till den utlovade platsen."},"ICON-1765":{"nm":"Albummasternyckel","de":"Det som är låst är inte skivan utan tiden förseglad inuti den. Skälvningen från den första inspelningen, gryningen från den sista mixen. Vrid nyckeln sakta, och dörren till det rummet, känt endast av dess skapare, gnisslar upp."},"ICON-1766":{"nm":"Låtlistkort","de":"Ordningen på låtarna på ett enda ark är, i själva verket, hjärtats ordning. Var det ska knyta sig i halsen, var man ska hämta andan — pappret vet redan allt. En rysning som stiger innan man ens hört den första tonen."},"ICON-1767":{"nm":"Ljudkontrollbricka","de":"Bara den som spolat tillbaka samma avsnitt hundra gånger fäster den här brickan. En gång till, bara en gång till. Bredvid godkännandestämpeln gömmer sig en natt då någon tvivlade på sina egna öron ända till gryningen."},"ICON-1768":{"nm":"Förbeställningsetikett","de":"Ett löfte att vänta på något som ännu inte ens finns i världen. I stunden etiketten sätts på reserveras tyst en tom plats under någons namn. Även en spänd väntan har en nummerlapp."},"ICON-1769":{"nm":"Förstaupplagesigill","de":"Det liknar den gamla handlingen att täcka en kruka med hanji och försegla den med klister. Ett enda ark som lovar att bevara tingen precis som de först var. Vetandes att det försvinner i stunden man drar av det, dröjer blicken kvar allt längre vid dess prydliga fason."},"ICON-1770":{"nm":"Comeback-kalenderbricka","de":"Lägg till en cirkel på kalendern, och nätterna fram till den dagen krymper en ruta. Återkomstdatumet står klart och tydligt på den lilla brickan i din hand. För den som väntar räknas tiden just så, för hand."},"ICON-1771":{"nm":"Konceptfotoficka","de":"Innan nästa koncept tränger undan det förras färg, sluter ett genomskinligt ark försiktigt in dess korn. Så att det inte glöms bort när säsongen vänder, vaktar det försiktigt gårdagens nyans, hörn och allt."},"ICON-1772":{"nm":"Teaseravslöjandemynt","de":"Just innan slöjan lyfts, ett litet mynt hållet i handflatan. I stunden du räcker fram det öppnas den låsta första scenen en handsbredd mot världen. Ett avslöjande är, i slutändan, en fråga om vem som räcker ut handen först."},"ICON-1773":{"nm":"Skivdisplayställ","de":"I stunden ett enda lågt ställ lyfter en skiva lätt, blir en vanlig platta till stjärnan i skyltningen. En öm birollsinnehavare, som tyst från bakom stöttar den vinkel där ljuset faller vackrast."},"ICON-1774":{"nm":"Debutshowcasepass","de":"Ett enda pass präglat med orden \"vi visar det för första gången.\" Från den långa korridoren bakom scenen till den första applåden från salongen, bär det här passet dig över debutens skälvande tröskel."},"ICON-1775":{"nm":"Scenmärkesbricka för första framträdandet","de":"Du känner efter brickan fastsatt på golvet med tåspetsen. En enda ruta kroppen känner igen först, även utan att titta. I stunden du landar exakt på den inövade platsen blir darrningen i fingertopparna äntligen en tydlig rörelse."},"ICON-1776":{"nm":"Tackordskort","de":"Även den vanliga frasen \"det är helt tack vare er\" är inte längre vanlig när den skrivs med darrande handstil. Några rader nedtecknade i förväg av rädsla att känslorna ska få en att glömma. Uppriktighet lutar sig ibland mot ett enda kort."},"ICON-1777":{"nm":"Profilfotobokningsschema","de":"Ett ark med datumet du ska stå framför linsen prydligt nedskrivet. Ett schema för att sakta förbereda ditt allra bästa ansikte. För varje ruta som fylls i blir också nätterna framför spegeln längre."},"ICON-1778":{"nm":"Fanklubbsanmälningslapp","de":"En anmälningslapp där du blygt skriver ditt namn och ditt hjärta på en rad. Att säga att man tycker om något är alltid svårt, men den här enda lappen stavar orden åt dig, prydligt. En första signatur på beslutet att vara tillsammans."},"ICON-1779":{"nm":"Debutpresentkontrollark","de":"En hand som går igenom varje sak och tänker på personen som ska ta emot den. Är hörnen skadade, har något hjärta gått förlorat? En present är redan älskad en gång, innan den ens räckts över, och ger sig av."},"ICON-1780":{"nm":"Scenavslutningsmarkör","de":"Just innan ridån faller, en markör placerad där den sista posen kommer till vila. Inte en signal om slutet så mycket som en liten punkt som knyter ihop slutet vackert. Bara en scen väl avslutad öppnar nästa."},"ICON-1781":{"nm":"Intervjuväntenål","de":"En nål som tyst bevarar tystnaden innan frågorna börjar. Under den korta stillheten då man väljer svar i huvudet säger den här lilla markören vänligt i ditt ställe: \"Inte än, men snart.\""},"ICON-1782":{"nm":"Debutminneskuvert","de":"Likt det gamla hjärtat som tryckte ett dyrbart brev, kuvert och allt, i handen på den som gav sig av, håller ett enda skikt med omsorg fast minnet av en första scen. Den dag du öppnar det, långt i framtiden, forsar den dagens skälvning också ut."},"ICON-1783":{"nm":"Sångandningssugrör","de":"Öva på att skicka andan lång, i en enda ström, genom det smala rörets ände. Sång är, i slutändan, väl behärskad andning — det här lilla sugröret säger det tyst till dig varje morgon. Vinden före ljudet."},"ICON-1784":{"nm":"Taktträningsklickbricka","de":"Tick, tick, tick — den ärligaste vännen i världen. Den tyglar dig när du rusar och puttar din rygg när du släpar efter. Att rista takten in i kroppen är som ett långt samtal med den här robusta brickan."},"ICON-1785":{"nm":"Dansliniekontrollband","de":"Var fingertopparna stannar, var axeln öppnar sig — du spårar rörelsens linje med ett enda band. En väldragen danslinje förblir rak och prydlig även där salongen inte kan se."},"ICON-1786":{"nm":"Ansiktsuttryckskort","de":"Det där talesättet, att även leendet måste läras in. Ett ark som noga skriver ner ögonvinkeln och läppens höjd, bit för bit. Uttrycket spegeln inte lyckades lära dig, berättar det här kortet vänligt i dess ställe."},"ICON-1787":{"nm":"Rapflödesanteckning","de":"\"Vila en takt här, häll ut allt där\" — en anteckning som ritar upp ordens vattenväg i förväg. Ju snabbare passagen är, desto tydligare måste andningsvägen vara. I de hastigt ritade pilarna lever och andas en versrads rytm."},"ICON-1788":{"nm":"Röstvärmeklistermärke","de":"Även rösten har varma dagar och kalla dagar. En liten markör du väljer efter färg och sätter fast för dagens ton. Genom att värma och kyla i tur och ordning vaknar ljudet varje dag till en aning annorlunda temperatur."},"ICON-1789":{"nm":"Vilorutinmynt","de":"Ett mynt tryckt i din hand med orden att vila väl också är en förmåga. Räck fram det, och du kan stanna upp en stund utan skuldkänsla. För den som sprungit oavbrutet är att stanna det modigaste valet."},"ICON-1790":{"nm":"Tillväxtmålsnål","de":"En liten nål satt i med orden \"låt oss försöka nå hit.\" Även om den ser avlägsen ut, nästan utom räckhåll, växer du ett steg mot den varje dag. Ett mål är som ett ömt löfte som vinkar långt bortifrån."},"ICON-1791":{"nm":"Veckoutvärderingskuvert","de":"Du samlar en veckas svett och tårar prydligt i ett enda kuvert och räcker över det. Det som gick bra och det som återstår ligger sida vid sida inuti. Att öppna det är en liten läxa given till nästa veckas jag."},"ICON-1792":{"nm":"Scendekorationsdelburk","de":"Bakom den glittrande scenen bor namnlösa delar. En skruv, en ring samlas för att låta stjärnorna sväva i taket. Öppna burken, och den är full av den lilla, tålmodiga hängivenhet som tyst bär upp all prakt."},"ICON-1793":{"nm":"Kostymkoncepttavla","de":"Genom att fästa tygbitar och färger en efter en provar du i förväg en dräkt som ännu inte finns i världen. En scendräkt fulländad först på tavlan. Fantasin går alltid ett steg före nålen."},"ICON-1794":{"nm":"Färgprovningsbricka","de":"Samma plagg bär ett helt annat ansikte beroende på ljuset. Vilken färg som ler ljusast med den personen hittar du genom att hålla upp brickor en efter en. Att passa ihop är en upptäckt efter lång jämförelse."},"ICON-1795":{"nm":"Skosnörsprovtavla","de":"Det som bär upp ett stadigt steg på scenen är, förvånande nog, ett litet snöre. Så det inte lossnar, men inte heller skaver. Den ömmaste av eftertankar, gjord på den lägsta platsen, väljande bland snören utlagda efter sitt korn."},"ICON-1796":{"nm":"Accessoarkontrollkuvert","de":"Ju mer något glittrar, desto skarpare syns en enda skavank. En hand som håller smycket från kuvertet upp mot ljuset och granskar det noga. Ett hjärta som ser efter det lilla ända till slutet är det som vaktar scenen."},"ICON-1797":{"nm":"Hårfärgsprov","de":"Ett litet prov för att i förväg pröva en ny säsong på håret. Färgen som tonat bara en enda lock viskar tyst om nästa koncepts första intryck. Förändring börjar alltid på ett handflatestort ställe."},"ICON-1798":{"nm":"Nagelkonceptkort","de":"Ett ark som i förväg bestämmer de små bilderna som ska målas på tio fingertoppar. Så att konceptet lyser igenom svagt även i en enda gest, kläs varje minsta detalj kärleksfullt i en berättelse."},"ICON-1799":{"nm":"Stilbytesbiljett","de":"\"Ska jag bli en lite annorlunda person idag än igår?\" — en enda biljett som gör den raden möjlig. Hår, kläder eller stämning, den här biljetten öppnar den spännande dörren till ett nytt utseende."},"ICON-1800":{"nm":"Storleksjusteringsetikett","de":"En etikett som omsorgsfullt noterar var man ska ta in och släppa ut tills det sitter perfekt. Likt den gamla handen som lagade ett barns kläder stygn för stygn, gör den här lilla justeringen scenen en handsbredd bekvämare."},"ICON-1801":{"nm":"Miniatyrskiss-kort","de":"Ett blad som ännu inte fått färg. Ovanför de grova blyertsstrecken anas stilla vart nästa scen ska flyta. Mer spännande än det färdiga är alltid denna ofullbordade första rad, viskar det tysta redigeringsrummet."},"ICON-1802":{"nm":"Samtyckesmärke för filmning","de":"\"Är det okej att bli fångad här?\" Istället för ord fäster du en liten rund markering över hjärtat. En enda liten dekal sluter ett ömt löfte mellan kameran och hjärtat."},"ICON-1803":{"nm":"Platsnål för fotovägg","de":"En liten nål instucken i ett hörn av väggen. Den markerar i förväg vem som ska stå var. Var nålen sätts stannar ett leende och blir till ett enda fotografi."},"ICON-1804":{"nm":"Klippvalsbricka","de":"Ett finger som pekar ut just en enda bland hundratals bilder. I samma stund som denna bricka läggs ner, har alla de undanlagda uttrycken levt för just den bilden. Att välja liknar alltid ett stilla avsked."},"ICON-1805":{"nm":"Bakom-kulisserna-kuvert","de":"Allt som hände bakom kameran samlas här. Vik igen fliken och skratt, felklipp och sömniga gäspningar somnar tillsammans. Det man kommer att älska mer än själva programmet är ofta det som ligger inuti."},"ICON-1806":{"nm":"Redigeringsanteckning","de":"\"En sekund till här, och sänk musiken lite.\" En lapp full av röd text. Någons noggrannhet justerar videons andetag med en enda takt. Finslipning växer fram ur just sådana små handgrepp."},"ICON-1807":{"nm":"Uppladdningsschema-tagg","de":"En liten märkning på en video som klockan sju imorgon bitti stiger ut i världen helt av sig själv. Även när alla sover håller löftet sig vaket. En tid inställd i förväg vet aldrig hur man kommer sent."},"ICON-1808":{"nm":"Miniatyrram-skydd","de":"Ett skydd som sveper in den bäst lyckade första bilden. Det viker hörnen prydligt så att varken fingeravtryck eller damm kan nå dem. Innan det visas bevaras ett första intryck så här varsamt."},"ICON-1809":{"nm":"Filmlängdsbricka","de":"En liten bricka som mäter hur många minuter som filmades idag. Längre är inte bättre, kortare inte lättare. Att veta rätt längd är redigeringens första knapp."},"ICON-1810":{"nm":"Korrekturblad för hejaramsor","de":"Ett papper att kontrollera en gång till innan man ropar av full hals. Ett fel bokstav och tusen röster splittras. Bakom hejaropet har en osynlig hand av korrekturläsning redan farit fram."},"ICON-1811":{"nm":"Förvaringsficka för fankonst","de":"En teckning någon ritat hela natten. Ett genomskinligt litet hem erbjuds så att den inte ska skrynklas. Som om det som ritats med hjärtat måste hållas med hjärtat för att bestå, omfamnar fickan den utan ett ord."},"ICON-1812":{"nm":"Sorteringssnöre för fanbrev","de":"Ett snöre som prydligt binder samman de högar av brev efter avsändare. Med varje knut ordnas en dags längtan. Här finns en hand som inte vill låta ett enda brev glida undan, även om den inte kan svara på alla."},"ICON-1813":{"nm":"Anmälningslista för merchbyte","de":"\"Finns det någon som vill byta med mina?\" Ett papper där man skriver ner sitt nervösa hjärta och räcker fram. Av den enda anledningen att man gillar samma sak blir två främlingar vänner för en liten stund."},"ICON-1814":{"nm":"Platsbricka för gruppheja","de":"En bricka som tilldelar platser där personer i matchande färger ska sitta sida vid sida. När spridda hjärtan samlas i en sektion börjar publiken sjunga som en enda enorm person."},"ICON-1815":{"nm":"Kvitto för födelsedagsreklam","de":"Ett enda kvitto man håller i handen efter att ha satt upp kärlek på en jättetavla. Det som inte står skrivet bredvid beloppet är den omsorg som samlats hela natten. Detta papper förblir beviset på en hyllning riktad till bara en person."},"ICON-1816":{"nm":"Omslag till meddelandebok","de":"Ett omslag som sveper in en bok samlad av mångas handstil. Öppna den och de olika händerna vecklar sig samman till ett hjärta. Utsidan är prydlig, men insidan är full av ett varmt sorl."},"ICON-1817":{"nm":"Medlemsnål för fanklubb","de":"En liten nål som bara delas ut till dem som ropar samma namn. I samma stund den fästs på bröstet förvandlas en ensam förtjusning till ett löfte delat av många. Samhörighet har en sådan rund form."},"ICON-1818":{"nm":"Digital hejapollett","de":"En ljuspunkt som fjärran händer viftar med bortom skärmen. Avståndet är ofantligt, men takten densamma. Det är beviset på att hejarop alltid når fram, även från osynliga platser."},"ICON-1819":{"nm":"Sliten nyckelbit","de":"En kantstött metallbit. Ingen minns längre vilken dörr den en gång öppnade. Det som överlever den låsta platsen är alltid den oanvändbara halvan av en sådan nyckel."},"ICON-1820":{"nm":"Karta över hemlig gång","de":"Ett gammalt papper som tecknar en stig gömd bakom murgrönan. Genvägar känner bara de som redan känner dem. I samma stund kartan viks ut vänder den vanliga ön stillsamt ansiktet mot en scen för äventyr."},"ICON-1821":{"nm":"Kryptolösningskort","de":"Ett kort som för tillbaka virrvarrsspridda bokstäver till sina rätta platser. När en rad faller på plats vinkar nästa hemlighet. Även en knut som verkade olöslig börjar, trots allt, med första bokstaven."},"ICON-1822":{"nm":"Snöre till förseglad låda","de":"Ett snöre bundet hårt som för att säga: öppna inte. Bara den som knöt det vet vad som sover inuti knuten. Viljan att lösa upp och viljan att skydda ligger bundna sida vid sida i denna enda tråd."},"ICON-1823":{"nm":"Ruinpusselbit","de":"En liten bit lossnad från en uråldrig stenmur. Sätt den på plats igen och någons hantverk från tusen år tillbaka väcks till liv vid fingertopparna. Att samla det som är spritt är arbetet att foga samman tiden på nytt."},"ICON-1824":{"nm":"Ösagnsurklipp","de":"Ett papper där gamla berättelser som drivit omkring på ön skrivits av för hand. Om de är sanna eller inte spelar knappt någon roll. En berättelse buren från mun till mun blir i sig själv en årsring i öns historia."},"ICON-1825":{"nm":"Dold märkessten","de":"En sten lagd som av en slump vid vägkanten. Bara ett invigt öga ser den stillsamt peka ut riktningen. Ju djupare en hemlighet man vill gömma, desto vanligare ansikte bär den där den står."},"ICON-1826":{"nm":"Gåtkuvert","de":"Ingenting står skrivet på utsidan. Denna korta stund alldeles innan sigillet bryts är den mest spännande. Innan svaret ligger i handen lever fortfarande varje möjlighet kvar inuti kuvertet."},"ICON-1827":{"nm":"Lupplock för detektiv","de":"Ett litet lock som stillsamt passas över förstoringsglasets spets. När man inte tittar igenom får linsen vila i tysthet. Att se väl kräver att man först skyddar väl, en läxa detektiven lär sig tidigt."},"ICON-1828":{"nm":"Biljett till öns ringbuss","de":"En enda biljett för att stiga på bussen som kretsar runt ön. Slutstationen är åter startpunkten. På en väg som vänder tillbaka dit den började ser landskapet lite nytt ut varje gång."},"ICON-1829":{"nm":"Cykeluthyrningstagg","de":"En tagg som hänger från styret på en lånad cykel. En kort frihet beviljas tills den lämnas tillbaka. När stunden av att skära genom vinden tar slut samlar denna tagg stillsamt in det löftet igen."},"ICON-1830":{"nm":"Ombordstigningsbiljett för liten båt","de":"En ombordstigningsbiljett för att kliva på en liten båt. På det gungande däcket kommer ö och ö varandra närmare. Att korsa vattenleden för alltid med sig lite spänning och lite sjösjuka på samma gång."},"ICON-1831":{"nm":"Kärrhjulssprint","de":"En sprint som håller kärrhjulet stadigt på plats. Denna lilla metallbit får en tung last att rulla. Den minst synliga delen är ofta den som tyst bär den största tyngden."},"ICON-1832":{"nm":"Linbanepollett","de":"En rund pollett man släpper i linbanan som skär genom luften. I samma stund fötterna lämnar marken samlas hela ön i en enda vy. Ju högre man stiger, desto mer generöst blir landskapet."},"ICON-1833":{"nm":"Ombordband för luftballong","de":"Ett band man bär runt handleden innan man kliver ner i korgen. När lågan sväller och marken avlägsnar sig blir hjärtat lättare med. Att lyfta betyder att lägga ner sin tyngd för en liten stund."},"ICON-1834":{"nm":"Tillkallningsbricka för vattentaxi","de":"En liten bricka för att tillkalla en taxi som springer över vattnet. Lyft handen och en båt kommer skärande genom strömmen. Det som stakar ut en väg där ingen finns är, till syvende och sist, modet hos den som ropar först."},"ICON-1835":{"nm":"Inträdespass för vandringsled","de":"Ett pass som räcks över vid den första porten in i berget. Härifrån är det tåspetsarna som bestämmer vägen. Toppen kan vara långt borta, men bara den som passerat ingången utlovas den utsikten."},"ICON-1836":{"nm":"Nyckel till hamnförvaringsskåp","de":"En liten nyckel som öppnar ett skåp nere vid kajen. Med lättade händer efter att ha lämnat bördan betraktar man havet. Att ha en plats att lägga ner saker för ett tag lånar en modet att resa långt bort."},"ICON-1837":{"nm":"Lock till picklingsburk","de":"Ett burklock som stänger inne allt som är syrligt. Väl förseglat behåller sommarens gurkor sin knapriga friskhet ända till vintern. Hemligheten att besegra tiden börjar, visar det sig, med att stänga saker väl."},"ICON-1838":{"nm":"Etikett för torkställ","de":"En namnlapp fäst på det som breds ut för att torka på sikten. Anteckna vad som lagts ut och när, så faller väntan inte i oordning. Även i solens och vindens tid krävs sådant som turordning."},"ICON-1839":{"nm":"Rökflisspåse","de":"En påse fylld med bitar av doftande trä. Öppna munnen på den och en doft som en lägereld hälsar näsan först. En smak fördjupad av rök öppnar sig sakta, bara för den som vet hur man väntar."},"ICON-1840":{"nm":"Konserveringsetikett","de":"En etikett fäst på en kruka, som en önskan om att den ska stå sig hela året. Dagen den lagades in och omsorgen skrivs ovanpå. Mat som sparas länge bär alltid med sig en liten lapp som försöker minnas den dagens handlag."},"ICON-1841":{"nm":"Jäsningsklockstagg","de":"Jäsning litar inte på klockan. Den mäter tiden med doft istället för minutvisare. I samma stund en syrlig lukt når näsan nickar taggen stillsamt: \"nu är det klart.\" Även väntan har sin egen skala av streck."},"ICON-1842":{"nm":"Sorteringsnål för kylskåpshylla","de":"Här står kylskåpets lilla trafikpolis. Grönsaker överst, tillbehör nederst, gårdagens rester längst fram. Sätt fast en nål och handen som alltid famlade vid dörren finner snart vägen."},"ICON-1843":{"nm":"Värmeband för matlåda","de":"Mamma svepte ett band runt matlådan så att värmen inte skulle fly innan lunch. Lossa bandet och under det immiga locket ligger morgonens omsorg fortfarande varm och väntar på mig."},"ICON-1844":{"nm":"Mognadsflaska för sås","de":"God krydda har aldrig bråttom. Den ger sojasås och vitlök tid att sakta genomsyra varandra. I flaskans mörker fördjupas smaken långsamt, och lerkrukans långsamma vishet flyttar in i en liten flaska."},"ICON-1845":{"nm":"Säsongssyltetikett","de":"Jordgubbe på våren, aprikos på sommaren, fikon på hösten. En enda etikett skriver säsongen prydligt på burken. Öppna locket mitt i vintern, och fjolårets solljus smälter sakta fram, en sked i taget."},"ICON-1846":{"nm":"Märkestavla för samlarnivå","de":"Man behöver inte ens räkna hur många man samlat, för märkestavlan skryter i ens ställe. För varje tom ruta som fylls höjs axlarna en aning. Detta är ingen siffra, utan ett spår trampat ut på tåspetsarna."},"ICON-1847":{"nm":"Kort för oupptäckt plats","de":"En plats ännu inte mött. Silhuetten på kortet räcker fram ett löfte, konturen bara svagt tecknad. Att vara tom betyder snart att bli fylld, så förväntan väntar alltid på dig i form av ett frågetecken."},"ICON-1848":{"nm":"Fullbordandestämpel för katalog","de":"Ljudet av stämpeln som landar med en duns i sista rutan. Slå igen katalogen, öppna handflatan, och en droppe röd bläck sitter kvar där som en medalj för fullbordan. Den djupa lättnaden som bara den som samlat till slutet känner."},"ICON-1849":{"nm":"Sällsynthetsfärgbricka","de":"Även samma form berättar en annan historia när färgen skiljer sig. En enda bricka drar stillsamt linjen mellan vanligt och dyrbart. Samlarens öga dröjer alltid länge inför just den subtila nyansskillnaden."},"ICON-1850":{"nm":"Bytesvoucher för dubblett","de":"Ännu en, igen. Den dag du plockade upp din tredje av något du redan hade, räckte denna voucher stillsamt fram sin hand. Som en snäll tröst om att dubbletter, om de omfamnas istället för att kastas, en dag återvänder som något dyrbart."},"ICON-1851":{"nm":"Nummerskylt för samlarlåda","de":"Numrera varje låda och förrådet blir ett litet bibliotek. Nummer 17 rymmer vårens fynd, nummer 23 det som plockades upp vid havet. Jag är ett tyst register som ordnar spridda minnen en rad i taget."},"ICON-1852":{"nm":"Utställningsguide för placering","de":"En utställning byggs till hälften av placeringen. Höga saker längst bak, lysande saker i mitten. Följ guiden och flytta med handen, och den stökiga hyllan hämtar snart andan som ett litet galleri."},"ICON-1853":{"nm":"Dammvippa för samlarobjekt","de":"Ju mer man älskar en sak, desto bättre lägger sig dammet på den. Med den mjuka borstspetsen, försiktigt, sopar man bort även skulden av att inte ha tittat på den så länge. Under städningen glittrar de sovande minnena till igen, för ett ögonblick."},"ICON-1854":{"nm":"Utökningsvoucher för förvaringsplats","de":"Samla länge nog, och platsbrist blir ett lyckligt bekymmer. Den tysta lättnaden av att se en hylla till läggas till. Detta är ingen girighet, utan beviset på hur mycket man älskar."},"ICON-1855":{"nm":"Vänkod-inbjudningskort","de":"Att räcka fram denna kod är den mest ömsinta inbjudan av alla, att säga \"kom och lek med mig.\" Hjärtat som ryms i några siffror. Först när vännen som fått den sätter foten på ön börjar en berättelse bara för er två."},"ICON-1856":{"nm":"Nyckel till gemensamt förråd","de":"Förrådsdörren öppnas aldrig av en enda. Ett lås som bara vrids när två händer, dina och mina, möts. Ett delat rum bär alltid ett delat löfte, upphängt där i form av en nyckel."},"ICON-1857":{"nm":"Hittegodstagg","de":"Även en förlorad sak är dyrbar för någon. Att skriva en enda rad, \"den är här,\" och hänga upp den. Taggen är ett litet snöre som stillsamt återknyter ett kortvarigt förlorat hjärta med sin ägare."},"ICON-1858":{"nm":"Hjälpsignalflagga","de":"Att be om hjälp är inte svaghet utan mod. När flaggan hissas kommer någon springande någonstans ifrån. Det som sprids snabbast på denna ö är inte rykten, utan händer som sträcks ut mot varandra."},"ICON-1859":{"nm":"Nödkontaktarmband","de":"En liten trygghet buren runt handleden. Vad som än händer kommer numret skrivet här springande före alla andra. En tyst följeslagare, bortglömd i vanliga dagar, som blir den mest pålitliga i stunden av behov."},"ICON-1860":{"nm":"Uppgiftsfördelningsbricka","de":"Vem som handlar och vem som lagar mat: dela ut brickorna och det finns inget att bråka om. Det första steget i att skapa något tillsammans börjar med att vänligt bestämma vars och ens del."},"ICON-1861":{"nm":"Samarbetsblad","de":"Det man aldrig skulle vågat ensam blir möjligt, som magi, när många samlas. När namnen fyller bladet ett efter ett krymper de tomma rutorna och skrattet växer. Samarbete växer stillsamt i utrymmet mellan rutorna."},"ICON-1862":{"nm":"Uppförandekort för besök","de":"När man kliver in i någon annans hem blir man försiktig redan från tåspetsarna. Det som står på kortet är inga stora regler, bara små, varma löften som \"ställ skorna i rad, hälsa först.\""},"ICON-1863":{"nm":"Avslutningsklocka för fest","de":"Även glädjen behöver ett slut för att nästa ska kunna längtas efter. När klockan ringer \"ding,\" samlar alla sina saker med motvilliga miner. En fest som vet hur man skiljs väl dröjer sig kvar längst i hjärtat."},"ICON-1864":{"nm":"Hörnband för madrass","de":"Hur slätt man än breder ut lakanet vill hörnen alltid lyfta sig. Tack vare ett band som håller fast alla fyra hörn stadigt vaknar sängen varje morgon lika prydlig som ett hotellrum."},"ICON-1865":{"nm":"Knappsnöre för täckeskrage","de":"Jag är knappsnöret som håller fast täckets krage. Hur mycket du än vänder och vrider dig genom natten håller jag hårt så att kragen inte kan fly. Ett täcke utan en enda skrynkla när man vaknar, det är belöningen för mitt nattskift."},"ICON-1866":{"nm":"Fästklämma för madrasskydd","de":"Toppmadrassen försöker glida iväg så fort den får chansen. Varje gång biter klämman hårt i hörnet och håller platsen. En tyst envis liten sak som håller sängen i ordning från ett osynligt hörn."},"ICON-1867":{"nm":"Skrynkelutjämnare för lakan","de":"De fina skrynklor lakanet samlar under natten liknar på något sätt hjärtats veck. Liksom tyg som blir slätt med ett enda svep av utjämnaren, önskar jag att en tilltufsad dag kunde strykas ut lika varsamt."},"ICON-1868":{"nm":"Ventilerande madrassbotten","de":"Även en madrass behöver rum att andas. När bottnen öppnar en luftväg nedanför tömmer fukten ut och torrhet sipprar in. God sömn börjar stillsamt just i den luft som bär upp din rygg."},"ICON-1869":{"nm":"Blixtlåsskydd för påslakan","de":"Det där midnattskaoset när fyllningen ständigt stack ut när man bytte påslakan. Täck blixtlåset med en flik en gång, och du vaknar aldrig mer av att fastna med foten. En stor frid, buren av en liten flik."},"ICON-1870":{"nm":"Klumpförebyggande kudde-pad","de":"Kuddens fyllning samlar sig snart på ena sidan och bildar en liten kulle. När paddet stadigt håller emellan bevaras plattheten ända till slutet. Tack vare den återvänder en nyaktig fjädrighet ofelbart varje natt."},"ICON-1871":{"nm":"Elastisk lakanshake","de":"Ett lakan försöker alltid sakta skala av sig åt ena hållet. Haka fast hörnen och dra det spänt, och det rubbas inte hur mycket du än vänder dig genom natten. Spänsten blir så stillsamt grunden för djup sömn."},"ICON-1872":{"nm":"Bytestagg för örngott","de":"När man plötsligt inte kommer ihåg om man tvättade örngottet idag, svarar en enda tagg tydligt. Ett schema man ständigt glömmer av att sova och sova igen, denna lilla markering kommer flitigt ihåg i ditt ställe."},"ICON-1873":{"nm":"Bokmärke för drömdagbok","de":"En dröm som sprids genom fingrarna i samma stund man vaknar, fångar bokmärket på den sida det markerat. Öppna den och gårdagens hav och himmel finns fortfarande kvar, en liten bro varsamt lagd mellan sömn och skrift."},"ICON-1874":{"nm":"Vitt brus-sten","de":"En alltför tyst natt väcker en snarare. När småstenen släpper loss ett ljud som mjukt prasslande regn sjunker hjärtat sakta i takt med det. En liten sten som stillsamt tröstar tystnaden."},"ICON-1875":{"nm":"Temperaturkänslig sömnbricka","de":"Om pannan är het eller tårna kalla medan du sover, vakar brickan stillsamt bredvid dig. Tack vare en nattväktare som mjukt hittar precis rätt temperatur för din kropp flyter sömnen på utan uppvaknande ända till gryningen."},"ICON-1876":{"nm":"Klämma för mörkläggningsgardin","de":"Morgonsolen är så flitig att den ständigt tränger sig in genom gardinspringan. Bit ihop båda ändarna hårt med klämman, och rummet blir mörkt igen som mitt i natten. En pålitlig medbrottsling för ännu en sovmorgon."},"ICON-1877":{"nm":"Månskensprojektor","de":"Släck lampan och en måne stiger upp över taket. Det dämpade skenet stativet kastar upp förvandlar rummet till en liten nattlig himmel. Känslan av att somna medan man ser upp mot månen, bevarad rakt vid sänggaveln."},"ICON-1878":{"nm":"Hängare för sömndoftpåse","de":"En påse fylld med lavendel och doften av gräs svänger sakta vid sänggaveln. När doften sipprar fram till näsan löses axlarna sakta upp, och en enda doftpåse bjuder in sömnen före kudden."},"ICON-1879":{"nm":"Vaggvisenål för speldosa","de":"Vrid upp fjädern stillsamt och en liten melodi vecklar ut sig. Vaggvisan som snurrar fram från nålens spets liknar precis den takt mormor klappade din rygg med. Varje ton gör ögonlocken sakta tyngre."},"ICON-1880":{"nm":"Fuktväxtmugg","de":"Jag är en mugg som odlar växter i klart vatten istället för jord. Betraktar man de fina rötterna sväva i vattnet känns till och med luften i rummet en aning fuktigare. En liten grön brunn, samlad ovanpå skrivbordet."},"ICON-1881":{"nm":"Uppsamlingsflaska för drömfragment","de":"Drömmar som runnit bort i sömnen har ingen form, och när man vaknar läcker de genom fingrarna. Att stoppa ett fragment på väg att försvinna med korken, hålla fast det till morgonen, viljan att minnas börjar på en så liten plats."},"ICON-1882":{"nm":"Sängbrickbord för glasögon","de":"I samma stund man tar av sig glasögonen och lägger ner dem, sjunker märkligt nog en hel dags trötthet med. Denna lilla plats vid sänggaveln finns till för att ta emot just den rörelsen. En bricka som stillsamt gör världen suddig innan sömnen."},"ICON-1883":{"nm":"Underläggsring för nattduksbord","de":"Ett enda runt märke som en vattenmugg lämnar kan verka obetydligt, men för nattduksbordets träfibrer är det en skada. En liten ring man sätter fast för att förhindra det. En omsorgsfull hjärta arbetar alltid stillsamt på just sådana osynliga platser."},"ICON-1884":{"nm":"Vikhjälpare för täcke","de":"Även att vika ett täcke fyrkantigt och prydligt har sin fiber. Rätta hörnen efter detta hörnriktande redskap, och även ett tilltufsat hjärta jämnas ut en gång. En ordnad plats är den mest prydliga hälsningen som öppnar dagen."},"ICON-1885":{"nm":"Sänggavelkrok för laddsladd","de":"En krok upphängd vid sänggaveln för att jag avskydde hur laddsladden gled ner på golvet genom natten. Sladden som stillsamt fylls med kraft medan du sover väntar, fulladdad, på dina fingertoppar på morgonen."},"ICON-1886":{"nm":"Sänggavelkorg för snacks","de":"En korg som samlar favoritsnacks inom räckhåll. En omtänksam förberedelse gjord i förväg för en sen kvällshunger som kommer. Det prasslande ljudet av att plocka en bit i mörkret är på något sätt varmt."},"ICON-1887":{"nm":"Bokstödsvinge för sänglektyr","de":"En vinge som varsamt håller upp den öppna sidan så att man inte tappar raden även när sömnigheten kommer smygande. Den sida man stängde precis innan ögonen föll igen väntar på dig på samma ställe imorgon natt."},"ICON-1888":{"nm":"Stensockel för väckarklocka","de":"Även väckarklockan som väcker morgonen behöver en egen plats som inte vacklar. Den runda stensockeln tar emot dess tyngd stadigt och håller sin plats som ett löfte som inte glider undan ens när gryningen kommer."},"ICON-1889":{"nm":"Upphängningsspik för sovmask","de":"En spik för att hänga upp sovmasken, så att tyget som blockerat ljuset hela natten kan andas under dagen. Att ge en torr plats åt ett tyg som fullgjort sin plikt: den lilla omsorgen sipprar in så här obefläckat."},"ICON-1890":{"nm":"Ficklampsklämma för sänggavel","de":"En klämma som håller det lilla ljus man behöver vid midnatt riktat åt vilket håll man vill. Bit fast ficklampan vid sängkanten, och handen som famlat i mörkret blir betydligt lugnare. En handrörelse som bestämmer ljusets riktning."},"ICON-1891":{"nm":"Uppknytningssnöre för avskiljningsgardin","de":"Ett uppknytningssnöre som håller gardinen som delar ett gemensamt rum. Det är bara ett tunt tygstycke, men bortom det ligger någons privata natt. En vänlig gräns som vaktar varandras sömn i ett delat rum."},"ICON-1892":{"nm":"Delningsbräda för gemensamt eluttag","de":"En träbräda gjord så att flera kan dela på det enda eluttaget. Den sprider elen jämnt så att ingens natt förblir mörk. Att bo tillsammans börjar, trots allt, med att dela just sådana små saker."},"ICON-1893":{"nm":"Eftergiftssten för belysningsstyrka","de":"När ljuset är för starkt skjuter man över en sten istället för ord. \"Kan du dämpa det lite?\" Denna lilla sak förmedlar den enda meningen åt dig. Den mildaste begäran i ett delat rum."},"ICON-1894":{"nm":"Eftergiftspollett för uppvakningstid","de":"En liten bricka som räcks över till handflatan hos den som ska vakna först. Vem som får sova längre i gryningen och vem som vaknar tidigare avgör denna pollett utan gräl. Hjärtat som bestämmer eftergiftens ordning med fingertoppen."},"ICON-1895":{"nm":"Nummerring för delad klädhängare","de":"Nummerringar tilldelade galgar som delas av många. Så att ingen blir förvirrad om vems plats som är vems, skapar en enda liten siffra stillsamt ordning. En vänlig linje dragen i en vardag som lätt blandas ihop."},"ICON-1896":{"nm":"Trappstegsskydd för våningssäng","de":"Ett skydd som passas över trappsteget upp till översängen. Så att en bar fot varken känns kall eller halkig, ser det till säkerheten på ett enda steg. Denna lilla omsorg vid stegens topp bär tryggt upp drömmarna där uppe."},"ICON-1897":{"nm":"Hängararm för gemensamt toalettpapper","de":"En armformad hållare för att hänga upp det gemensamma badrummets toalettpapper. Den är placerad så att vem som helst lätt kan dra loss ett blad med en hand. Det kan verka obetydligt, men det är en handrörelse som gör mångas morgnar smidiga."},"ICON-1898":{"nm":"Turordningsbricka för doftförfriskare","de":"En bricka som noterar vems tur det är att fylla på doftförfriskaren. Även en svag doftslinga är ett löfte om att turas om att ta ansvar. En god doft kommer inte gratis, den blommar på någons tur."},"ICON-1899":{"nm":"Handtag för delad nattlampa","de":"Handtaget på en nattlampa som många tänder och släcker tillsammans. Handen som var vaken längst samlar in ljuset sist. Ett tyst löfte mellan dem som delar rum, om att dela ett mjukt sken."},"ICON-1900":{"nm":"Kopphåla i soffarmstöd","de":"En rund kopplats urholkad i soffans armstöd. Man kan sätta ner glaset ur handen en stund utan att oroa sig för att spilla. En viloplats behöver ett ställe att ställa ett glas på innan hjärtat äntligen kan sträcka ut sig i ro."},"ICON-1901":{"nm":"Dragkedjedrag för innerkudde","de":"En liten drag fäst i blixtlåset som öppnar och stänger kuddens innerfoder. En enda ring sparar besväret med att byta tvätt. Fingertoppar som tar hand om även det osynliga inre — hemmets ömhet gömmer sig alltid just där."},"ICON-1902":{"nm":"Kudde för soffryggstöd","de":"En kudde som fyller springan i ryggstödet och stöttar ländryggen. Den fyller den tomma platsen så att ryggen inte värker även efter en lång stund sittande. Bekvämligheten som kroppen känner igen först, med en suck av \"ja, just det\", i samma stund du lutar dig tillbaka."},"ICON-1903":{"nm":"Hörnband för sittdyna","de":"Ett band som greppar dynan i hörnen — den som annars smög sig i väg varje gång man satte sig. Det håller den fast på en och samma plats så att den inte glider. Prydlighet börjar med just en sådan liten, envis fastsättning."},"ICON-1904":{"nm":"Skyddsremsa för kuddsöm","de":"Det ställe på en kudde som slits fortast är alltid hörnsömmen. En skyddsremsa läggs i förväg runt just den platsen och skyddar den från att spricka upp. Ett hjärta som vill ha kudden kvar länge är lika stadigt som sömmen själv."},"ICON-1905":{"nm":"Fjärrkontrollsficka för soffspringa","de":"Fjärrkontrollen som ständigt försvann mellan kuddarna har äntligen fått ett eget hem. En liten ficka instoppad i soffans springa. Att veta att det man trodde var borta alltid finns just där är en större trygghet än man anar."},"ICON-1906":{"nm":"Snodd för hoprullad pläd","de":"Ett snöre för att rulla ihop och knyta fast en pläd. Värmen som annars sprids ut när plädet ligger utfällt samlas prydligt inför nästa kväll. Även värme kan, om man tar hand om den så här, plockas fram och läggas över igen imorgon."},"ICON-1907":{"nm":"Knapp till fotpallsöverdrag","de":"En knapp som fäster fotpallens överdrag — delen som slits fortast av fötterna som vidrör den — så att det blir lätt att byta. Det där lilla klicket när knappen träs igenom förlänger tygets livslängd. En vilja att använda saker länge är grundlig i de små detaljerna."},"ICON-1908":{"nm":"Glidskydd för soffben","de":"Även en tung soffa får inte repa golvet. En mjuk hätta dras över de fyra bennens ändar och smyger försiktigt fram för att skona trägolvet. Möbler som är varsamma ända ner till tårna vinner av någon anledning mer tillgivenhet."},"ICON-1909":{"nm":"Samlingsställ för fjärrkontroller","de":"Ett ställ som ställer upp, sida vid sida på samma plats, alla fjärrkontroller som brukade rulla och skingras hit och dit. När de långa och korta pinnarna står prydligt i rad sänks rummets stämning genast en aning, till något lugnare."},"ICON-1910":{"nm":"Laddningskrok för handkontroll","de":"En krok där handkontrollen hängs upp och laddas efter en glad omgång spel. Medan den hänger och tyst fyller på sin energi vilar även händerna en stund. Denna korta paus förbereder nästa runda med gott mod."},"ICON-1911":{"nm":"Pjäspåse till brädspel","de":"En liten påse som rymmer pjäser i alla färger. Bitarna som väntar tillsammans i påsen på nästa runda skramlar varje gång man skakar den. Vid det ljudet vaknar förväntan om \"en runda till?\" allra först."},"ICON-1912":{"nm":"Tärningsskål","de":"En skål avsedd enbart för att kasta tärningar. Turen som annars studsade av bordet och försvann hålls nu kvar av kanten. I det korta ögonblicket då tärningarna rullar och stannar håller allas andetag ett gemensamt uppehåll."},"ICON-1913":{"nm":"Kortlekband","de":"Ett band som håller en kortlek samlad så att korten inte skingras. Innan de blandas är just den ordningen ett löfte i sig. I gesten att lossa bandet och breda ut korten börjar äntligen berättelsen om en ny omgång."},"ICON-1914":{"nm":"Kabelklämma för konsol","de":"En klämma som greppar och kammar ner de trassliga sladdarna bakom konsolen. Den städar tyst upp röran på en plats man knappt ens kan se. Prydlighet fullbordas alltid tyst, precis så här, bakom ryggen."},"ICON-1915":{"nm":"Poängvred","de":"Ett litet vred man vrider för att visa poängen. Klick, för varje steg siffran stiger följer jubel med. Även utan att räkna i huvudet minns fingertopparna alltid dagens resultat först."},"ICON-1916":{"nm":"Ställ för spelbräde","de":"Ett ställ som lutar upp spelbrädet och ställer in vinkeln så att alla som sitter runtomkring kan se brädet på en blick. Så att ingen behöver sträcka på halsen breder det tyst ut en rättvis utsikt för alla."},"ICON-1917":{"nm":"Dragbägare för spelordning","de":"En bägare man sticker handen i för att dra om spelordningen. Den enda pinne man famlar sig till och griper avgör vem som börjar. I det korta ögonblicket då man lutar sig lite mot turen darrar alla tillsammans inuti den runda bägaren."},"ICON-1918":{"nm":"Fackindelad tallrik för tilltugg","de":"En fackindelad tallrik för att servera tilltugg efter sort. Med uppdelade platser kan var och en välja sin favorit utan att händerna krockar. Omtanken om dem man ska dela med finns i varje fack."},"ICON-1919":{"nm":"Tekannevärmare","de":"En värmare som sveps kring tekannans axlar för att bevara värmen. Den sluter om kannan så att teet inte kallnar medan det sakta drar. Fingertopparnas önskan att servera en varm kopp varm ända till sista droppen."},"ICON-1920":{"nm":"Vilplatta för tepåse","de":"En avlägg där en färdigdragen tepåse lyfts upp för att vila en stund. Den fångar upp även den sista droppen så att inget spills. En plats som ger även bladet som gjort sitt en prydlig avslutning."},"ICON-1921":{"nm":"Markeringsring för gemensam mugg","de":"Sex likadana muggar på pentryts hylla. Istället för att fråga vems som är vems trädde vi på ringar i olika färger. Ett litet märke binder tyst samman sex personer, var och en med sin egen smak, till samma plats vid samma bord."},"ICON-1922":{"nm":"Popcornkorg att dela","de":"Medan den vandrar från hand till hand hälsar den söta ångan först. Om det finns något som märkligt nog aldrig tycks minska hur mycket man än öser upp med handen, så är det känslan av en kväll som delas sittande tillsammans."},"ICON-1923":{"nm":"Sockerbitstång med hållare","de":"Knäpp en kantig sockerbit med tången ner i tekoppen. Att se de vita hörnen sakta lösas upp och försvinna — ett oskyndat sätt att njuta av sötma, inlärt först vid mormors tebord."},"ICON-1924":{"nm":"Halkskydd för bricka","de":"Även om brickan lutar håller koppen sin plats. Precis som allt annat som tyst håller emot underifrån, uthärdar mattan ensam ögonblicket av en nästan-halkning och håller till sist tyst om det."},"ICON-1925":{"nm":"Sugrörsställ i koppform","de":"Ställ sugröret rakt upp och varken drycken eller sinnet kommer i olag. En eftermiddag då skrivbordet blir prydligt av en så enkel resning, håller koppen en liten pelare och bär tyst upp de tröga timmarna."},"ICON-1926":{"nm":"Smulfångare för kakor","de":"Knaprigt, i samma stund en kaka smulas sönder samlas de fallna bitarna här. Att ta emot även spåren efter den godaste tuggan — bordets tysta avslutning, mild ända till sista smulan."},"ICON-1927":{"nm":"Fotoklämsnöre","de":"Polaroidbilder nyps fast en efter en med klämmor på ett snöre som hänger som en tvättlina. Medan dagens leenden fladdrar och torkar i vinden blir en bit av väggen ett litet, ljust utställningsrum för minnen."},"ICON-1928":{"nm":"Minnesnystan-spole","de":"En spole där trasslig tråd retts ut och lindats prydligt. Sådant som fortsatt, knutet vid varje ställe det gått av. Om man likaså sakta spolar tillbaka minnet, ett varv i taget, blir en väg man trodde blivit kortare lång igen."},"ICON-1929":{"nm":"Spikhålskydd","de":"Ett litet runt lock som döljer ett spikhål. Täck varsamt även det lilla ärr som blir kvar efter att något som en gång hängde där tagits ner, och väggen får åter ett slätt ansikte, som om inget hänt."},"ICON-1930":{"nm":"Instickningsram för gruppfoto","de":"Ett gruppfoto på sex personer, tagna med axlarna tätt intill varandra. I samma stund bilden skjuts in i ramen förseglas den dagens skratt och värme tillsammans. En ram är den hand som allra tystast stannar upp en flyende dag."},"ICON-1931":{"nm":"Korkanslagstavla","de":"En brun skiva tätt full av häftstiftshål. Ett löfte man inte får glömma, någons lapp med uppmuntran, dagens att-göra-lista — allt sätts upp lager på lager. En pålitlig vägg vid skrivbordet som minns i huvudets ställe."},"ICON-1932":{"nm":"Upphängningsknut för krans","de":"Även en krans som hängs på dörren kräver fingerfärdighet. Knuten måste knytas hårt så att den inte lossnar under den blåsiga årstiden. Hjärtat som hälsar någon välkommen blir alltid stadigt först på den plats ingen ser."},"ICON-1933":{"nm":"Pendelöverdrag för väggklocka","de":"Ett tygöverdrag som sveper kring den tickande pendeln och håller dammet borta. Även arbetet att mäta tiden får omsorg på det här sättet. Skydda den varsamt från att slitas ner, så stannar väggklockan hos oss lite längre."},"ICON-1934":{"nm":"Klistermärkessamlingstavla","de":"Klistermärken som brukade ligga utspridda i varje låda samlas nu på en tavla och ställer upp sig i rad. En favoritkaraktär, en glittrande stjärna, ett blad handskrift. När den lilla samlarglädjen ordnas prydligt blir även sinnet ordnat."},"ICON-1935":{"nm":"Sammanbindningssnöre för vimpelgirlang","de":"Ett snöre som binder samman färgglada flaggor till en rad. Vare sig det är födelsedag eller välkomstfest, i samma stund snöret sträcker sig över taket förvandlas ett vanligt rum till ett festhus. Att fira är att foga samman ett brutet hjärta."},"ICON-1936":{"nm":"Korkunderlägg för vattenkokare","de":"Ett enda korkblad som bär upp den heta vattenkokarens botten. Så att bordet inte ska bli bränt famnar det den hettan helt själv. En liten omtanke som tyst bär upp värmen så att ingens spår lämnas kvar."},"ICON-1937":{"nm":"Smulbricka för brödrost","de":"Smulorna som faller från det gyllenbrynta brödet trillar ner på brickan. Dra bara ut den och skaka av, så är det klart. Den tar emot den jäktiga morgonen utan ett ord och gör sig ren igen inför nästa måltid."},"ICON-1938":{"nm":"Rundgångsring för mikrovågsugn","de":"På den snurrande ringen ritar tallriken sakta ett helt varv. Den rotationen, som gör att maten värms jämnt, väcker gårdagens kallnade ris till liv igen som en ångande varm måltid."},"ICON-1939":{"nm":"Kokplattelock för miniinduktionshäll","de":"Hur oljan än stänker åt alla håll förblir kokplattan alltid ren. Ett enda lock skiljer den hetsiga hettan från handen. De osynliga tingen som ställer sig i vägen håller köket som en plats där ingen bränner sig."},"ICON-1940":{"nm":"Ångventil för riskokare","de":"Ett väsande ljud när ångan släpps ut. Tack vare en liten ventil som varsamt släpper ut det uppdämda trycket öppnar det nykokta riset locket med sitt mjukaste ansikte. Under ångtiden finns ingen brådska."},"ICON-1941":{"nm":"Sleveställ","de":"Ställ sleven som rört om i soppan rakt upp. Ett litet hjärta som inte vill spilla en enda fläck på diskbänken. Kökets prydlighet börjar alltid från just sådana oansenliga, obetydliga platser."},"ICON-1942":{"nm":"Silikongrepp för kastrullhandtag","de":"Sätt silikonet på det brännheta kastrullhandtaget och handen bränns inte. Ett lager som skjuts in mellan hettan och handflatan. Det vakar över den som lagar varm mat, från den allra närmaste platsen."},"ICON-1943":{"nm":"Kalkfilter för vattenkokare","de":"Även vatten som kokas varje dag samlar på sig en svag beläggning. Ett tätt nät filtrerar tyst bort kalken och häller upp bara en klar kopp. En flitig hand som vakar över teets första klunk från en osynlig plats."},"ICON-1944":{"nm":"Klämben för äggklocka","de":"Tre minuter till, säger äggklockan och biter sig fast i bordskanten med sina klämben. Medan nudlarna kokar står den stadigt på sina små ben och räknar tickande fram dagens mest efterlängtade ögonblick."},"ICON-1945":{"nm":"Droppkopp för bestick","de":"Vatten rinner droppande från nysköljda bestick. När droppkoppen tyst samlar upp den fukten blir bordet snart torrt. Prydlighet är en mild flit som tar hand om varenda droppe vatten."},"ICON-1946":{"nm":"Tallriksställ med fack","de":"Ställ tallrikarna upprätt, uppdelade i fack. Servisen som tidigare skrapade mot varandra i en stapel får nu var sin egen plats. Ordning är, till syvende och sist, att ge var och en ett eget fack där de inte krockar."},"ICON-1947":{"nm":"Parningsring för ätpinnar","de":"Träd de ensamma ätpinnarna som förlorat sin partner på ringen och para ihop dem igen. En ensam pinne mister snart sin nytta, så denna lilla ring håller ordning i lådan genom att binda dem sida vid sida."},"ICON-1948":{"nm":"Kopphängare i trädform","de":"Häng koppen en och en på ett ställ som grenar ut sig som kvistar. Medan fukten torkar på varje upp-och-nervänd kopp står ett hörn av köket tyst som ett litet, prydligt träd."},"ICON-1949":{"nm":"Handtag för bestickbricka","de":"En bricka där sked, ätpinnar och gaffel ligger sida vid sida i fack. Grip handtaget och lyft ut alltihop på en gång, så blir det lätt som en plätt att duka bordet. Ordningens skönhet finns alltid även i lådan."},"ICON-1950":{"nm":"Torkbräda för upp-och-nervända glas","de":"Ställ de diskade glasen upp och ner så faller vattendropparna, plopp, plopp. Medan de sakta torkar vid ett solbelyst fönster återfår glaset lugnt sin ursprungliga genomskinlighet inför nästa klunk."},"ICON-1951":{"nm":"Rengöringskam för gaffeltinnar","de":"Dess fina tänder kammar varsamt bort mat mellan gaffelns tinnar. Tack vare en beröring som tar hand om även de smalaste springorna börjar nästa måltid alltid med en felfri, ren första tugga."},"ICON-1952":{"nm":"Filttassling för staplade skålar","de":"Stapla skålar och porslinet skramlar skarpt mot varandra. Ett enda filtblad instoppat mellan dem tystar friktionen. Hemligheten bakom ett långt liv tillsammans ligger i att göra varandra lite mjukare."},"ICON-1953":{"nm":"Upphängningssnodd för tesked","de":"Häng den nätta teskeden på snodden och fäst den på väggen. Aldrig begravd i en låda glimmar den alltid inom räckhåll — ett litet redskap som stolt gör anspråk på sin rättmätiga plats. Även hushållsarbete har sin fasta plats för allt."},"ICON-1954":{"nm":"Facklåda för kylskåp","de":"Dela in kylskåpsfacket i sektioner och varje ingrediens får sitt eget lilla hus. Sådant som tidigare blandats bort och glömts finner sin plats, och varje gång man öppnar dörren ser man med ens klart vad som finns var."},"ICON-1955":{"nm":"Ställklämma för frysbag","de":"Greppa en halvfull frysbag med klämman och ställ den upprätt. Så att den inte välter och läcker, så att den är lätt att hitta nästa gång. Även i den kalla frysen bor den skarpsinniga, ordningsamma vishet en driven hemmafru har."},"ICON-1956":{"nm":"Åtdragningshylsa för flasklock","de":"En flaska som inte stängs ordentligt tappar snart sin kolsyra. Den enda handledsvridningen som drar åt locket ordentligt låser in doften och bruset intakt ända till nästa morgon. Skicklighet lyser i de små tingen."},"ICON-1957":{"nm":"Halkskydd för äggfack","de":"Ett underlägg som håller de runda äggen i fack så att de inte rullar iväg och går sönder. Önskan att hantera det ömtåligaste med störst varsamhet sitter litet och milt i ett hörn av kylskåpsdörren."},"ICON-1958":{"nm":"Utvidgningsremsa för kylskåpsficka","de":"Töj kylskåpsdörrens ficka lite åt sidan och skapa ett fack till. För när hushållet växer måste utrymmet växa med det. I skickligheten att bredda en trång plats speglas en driven hemmafrus hjärta."},"ICON-1959":{"nm":"Presslock för matrester","de":"Ett lock som varsamt trycks ner över kvarblivna tillbehör. Det vakar tyst över dem så att de inte torkar ut eller drar åt sig andra lukter. En omtänksam hand tar väl vara på även det som blir över av en enda måltid."},"ICON-1960":{"nm":"Riktningsspjäll för kylluft","de":"Åt vilket håll ska kylan strömma? Ett litet spjäll bestämmer tyst riktningen. Vrid den osynliga vindens väg lite med fingertoppen, och kylan når ända in i det djupaste inre hörnet."},"ICON-1961":{"nm":"Fuktabsorberande kudde för grönsakslåda","de":"I det mörkaste hörnet av kylskåpets grönsakslåda håller jag tyst fukten under mig. Det lilla miraklet att gårdagens slokande blad blir spänstigt igen till morgonen. Även om ingen märker det är det alltid jag som svarar för friskheten."},"ICON-1962":{"nm":"Rullstoppkant för läskburk","de":"Fäst tyst vid bordskanten fångar den foten på en burk som var på väg att rulla iväg. En dryck som nästan spilldes, ett bord som nästan behövt torkas. Hushållets trygghet börjar med en så liten, obemärkt kant."},"ICON-1963":{"nm":"Sysslohjul","de":"Idag, vem diskar, vem sorterar återvinningen. Ett enda snurr på pilen och varje gnabb löses smidigt upp. I ett hus där fem trängs ihop är turordning den mildaste sortens fred."},"ICON-1964":{"nm":"Silikonband för kopptillhörighet","de":"Fem likadana koppar, och en morgon full av undran över vems som är vems. Trä på ett handledsstort färgband och det lilla löftet \"den här är min\" blir tydligt, vilket smyckar frukostbordet med mild ordning."},"ICON-1965":{"nm":"Portionsring för skål","de":"På en hektisk dag blir markeringarna inuti skålen en pålitlig vän. Ett fack för ris, ett för tillbehör. Varken för lite eller för mycket — en mild linje som tyst visar precis hur mycket man ska äta idag."},"ICON-1966":{"nm":"Tångburk för godisdelning","de":"Räck fram hela påsen och stället handen vidrört blir kvar, pinsamt. Portionera ut en i taget med tång, och först då blir allas andel lika stor. Delande passar bättre med prydliga händer än med hela nävar."},"ICON-1967":{"nm":"Namnskyltshållare för kannvakt","de":"Att koka vatten föll alltid på samma händer. Sedan vi började hänga namnskyltar i tur och ordning på hållaren bredvid kannan har en varm kopp te blivit tillgivenhet som bryggs i skift."},"ICON-1968":{"nm":"Uppmaningsbricka på stekspade","de":"Ett litet \"lämna inget kvar\" hänger i miniatyr från stekspadens spets. Det kan låta som tjat, men det finns ingen elakhet i det — för andan från det gamla köksbordet, där varje måltid var dyrbar, bor här."},"ICON-1969":{"nm":"Personlig bestickpåse med krok","de":"Bestick skramlar inte längre löst i lådan. I samma stund varje uppsättning läggs i sin egen påse och hängs på väggen ställer sig de fem familjemedlemmarnas platser upp sida vid sida. En liten ordning bär upp varje dags lugn."},"ICON-1970":{"nm":"Korkbricka för bordsplats","de":"Lägg korkbitar på bordet och det blir tydligt vem som sitter var. Platsen man alltid tar, ansiktet vid sidan man alltid möter. En fast tilldelad plats är det tystaste beviset på orden \"vi lever tillsammans.\""},"ICON-1971":{"nm":"Uppsamlingskrok för förkläde","de":"Förklädet som avslutat diskningen kastas inte hipp som happ. Rullat ihop och upphängt på kroken är det fräscht och redo för nästa morgons grepp. En tanke på nästa person bor i denna lilla knut."},"ICON-1972":{"nm":"Vikpåse för engångstofflor","de":"Den dag gäster kommer viker jag ut mig, hela påsen. De prydligt inpackade engångstofflorna hälsar nyanlända fötter med mjuk värme. Gästfrihet börjar alltid tyst redan i hallen."},"ICON-1973":{"nm":"Pappersstump-ficka för tops","de":"När topsen är förbrukade och bara pappersstumparna finns kvar, samlar jag omsorgsfullt ihop ändarna. Att göra plats även åt det som annars skulle kastas. Jag vet att hemligheten bakom ett prydligt skrivbord är just sådan här obetydlig omtanke."},"ICON-1974":{"nm":"Trådrullebunt för symappa","de":"Bind samman de färgade trådarna så att rullarna inte lossnar och trasslar. En knapp som lossnat, en manschett som blivit vid — den här enda bunten lagar dem på nolltid. Handsömnad som tyst räddar kvällen inför en viktig dag."},"ICON-1975":{"nm":"Individuellt inslagen tvålbit","de":"En vackert individuellt inslagen tvålbit läggs fram i varje gästrum. En handflatestor kropp tvättar bort dagens damm med en enda handfull lödder. Renlighet börjar alltid på så här små platser."},"ICON-1976":{"nm":"Vikbar duschmössekapsel","de":"Vik ihop vecken och den ryms i handflatan; vik ut den och den sluter varsamt om håret. Så att en nystylad frisyr inte rasar ihop av en enda dusch. Denna enda hinna vakar över morgondagens prydlighet."},"ICON-1977":{"nm":"Skyddshylsa för tandborste","de":"Borsten är känsligare än man tror. En enda hylsa över dess spetsar hindrar även dammet i väskan från att nå fram. Att skydda det osynliga — hygienens verkliga uppgift, inlärd på varje resa."},"ICON-1978":{"nm":"Enstycksplock för bomullsrondeller","de":"Bomullsrondeller kommer bara ut fint om man tar dem en i taget. Häll ut hela högen och mer går till spillo. \"En i taget, med omsorg\" — det är sminkbordets tysta regel."},"ICON-1979":{"nm":"Ihopfällbar miniskohorn","de":"Ihopvikt ryms den i fickan, uppfälld ligger den mot hälen. Jag är stolt över att utföra ett ganska stort jobb med min lilla kropp. Även på en morgon då man försovit sig var det alltid jag som lät skorna tas på utan att skadas."},"ICON-1980":{"nm":"Enstrångad tandtrådsrulle","de":"Linda upp en enda tråd tandtråd prydligt och klipp av just så mycket man behöver när stunden kommer. En rulle inte större än en nagel, men aldrig frånvarande i arbetet att vakta ett strålande leende. Även ett leende har osynliga förberedelser."},"ICON-1981":{"nm":"Locköra för vattenkokare","de":"Så att ångan från det kokande vattnet inte bränner handen, klämmer jag fast mig på locket. Ett handsbrett mellan hettan och handflatan. Det lilla avståndet värmer tryggt någons stressiga morgon."},"ICON-1982":{"nm":"Silikonunderlägg för strykjärn","de":"Det farligaste ögonblicket är när man för en kort stund släpper strykjärnet mitt i strykningen. Ställ det upprätt på silikonunderlägget och varken bord eller kläder bränns. Att stryka ut veck avslutas först på underlägget."},"ICON-1983":{"nm":"Stöldskyddskrok för klädhängare","de":"Så att ett upphängt plagg inte lättvindigt glider av, håller kroken sin mun stängd hårt. En liten väktare som vakar vid sidan av det värdefulla plagget i garderoben. Att skydda är en så tyst syssla."},"ICON-1984":{"nm":"Kalksil för kanna","de":"Min uppgift är att tyst filtrera bort kalken som driver omkring i det kokande vattnet. Först efter att ha silat bort även den osynliga bottensatsen blir en kopp te klar. Omsorg gror alltid på platser ingen ser."},"ICON-1985":{"nm":"Halkskyddsremsa för klädhängare","de":"En klädhängare virad med halkskyddsremsa tappar inte ens det lättaste siden. Den som en gång sett ett plagg falla till golvet och skrynklas vet vad denna smala lilla remsa är värd."},"ICON-1986":{"nm":"Sladdklämma för strykjärn","de":"En lös sladd fastnar i foten och får någon att snubbla. Ett enda grepp med en klämma binder den prydligt samman. Att förebygga olyckor börjar alltid med så här liten, obetydlig ordning."},"ICON-1987":{"nm":"Bottenskål för vattenkokare","de":"Jag sätter kannan stadigt i mitt spår så att den inte vinglar. Att stå på sin rätta plats är detsamma som att vara trygg. Det finns en anledning till att varmt vatten värms på samma plats varje morgon."},"ICON-1988":{"nm":"Klämben för byxhängare","de":"När klämbenen greppar byxbenets fåll ordentligt bildas inte en enda skrynkla. Ett välstruket plagg blir väl omhändertaget från den stund det hängs upp. En prydlig passform fullbordas inne i garderoben."},"ICON-1989":{"nm":"Upphängningskrok för hårfön","de":"Läggs fönen var som helst trasslar sladden snart till sig. Häng den raskt på kroken och handfatet blir rymligare, morgondagen lättare. En prydlig plats löser lite på en stressig dag."},"ICON-1990":{"nm":"Glasunderlägg för minibar","de":"Ställ det stilla under glaset och droppar sprider sig inte över bordet. Omtanken i ett enda underlägg lämnar inga runda märken efter sig. Prydlighet är omtanken att inte lämna några spår."},"ICON-1991":{"nm":"Stör ej-skylt för dörrhandtag","de":"En skylt hängd på dörrhandtaget viskar tyst \"vilar just nu.\" Att vakta ett enda andetags tupplur i slutet av en lång dag. Även ett kommatecken behöver någon som vaktar det med omsorg."},"ICON-1992":{"nm":"Skyddshuv för rumsservicelarm","de":"Tack vare huven runt knappen trycks den inte av misstag ner om ett klädesplagg stryker förbi. Så att man ringer klart och tydligt bara när det verkligen behövs. Ett litet lock gör ett hektiskt hotellrum betydligt prydligare."},"ICON-1993":{"nm":"Isklämben för minibar","de":"Ta is med bara handen och den är kall och glider ständigt undan. Klämbenen tar hand om den uppgiften stadigt istället. Bakom starten på ett svalt glas döljer sig en osynlig hjälpande hand."},"ICON-1994":{"nm":"Nyckelkortsspringa för hotellrum","de":"Stick in kortet i springan och rummets ljus tänds med ens. Jag är bara en liten springa, men jag är den första gesten som öppnar ett rum att lägga av dagens trötthet i. Ljuset tänds på nytt på platsen dit man återvänder."},"ICON-1995":{"nm":"Förseglingsring för flaskhals","de":"Om förseglingsringen på flaskhalsen är hel betyder det att ingen ännu rört den. Ett litet löfte som bevisar att allt är precis som det var från början. Tillit börjar med en obruten försegling."},"ICON-1996":{"nm":"Broschyrställ","de":"Ställ broschyren på lut och förbipasserande blickar stannar av sig själva. Informationens blygsamma hållning, väntande på att fällas upp. Bara genom att synas gör den någons väg en bit lättare."},"ICON-1997":{"nm":"Platt kapsylöppnare för minibar","de":"Diskret gömt i ett hörn av den platta kroppen finns ett spår för att öppna kapsyler. Liten som den är sköter den sitt jobb prydligt. Den svala första klunken av en flaska öppnas alltid med just detta lilla chip."},"ICON-1998":{"nm":"Överdrag för dimmervred","de":"Vrid varsamt på det överdragna vredet och rummets ljusstyrka ändras sakta. Klart, och sedan dämpat. Att välja ljuset vid sänggåendet är en ritual som avslutar dagen med ömhet."},"ICON-1999":{"nm":"Hjulkil för resväska","de":"Kläm den lätt under hjulet och resväskan rullar inte iväg av egen vilja. Även på en sluttande stationsperrong håller bagaget sin plats. Tryggheten på en avresa blir stadig genom just denna lilla kil."},"ICON-2000":{"nm":"Vikbräda för packning","de":"Lägg en skjorta eller ett par byxor ovanpå och de viks prydligt och kantigt. Så att väskans innehåll inte rasar ihop, så att man kan kliva ut oskrynklad i den ankomna staden. Väl packat bagage hjälper resan redan innan man ger sig av."},"ICON-2001":{"nm":"Säkerhetsskåpets låsvred","de":"Vrid på vredet och en liten regel glider sakta inåt. Att lämna sina värdesaker är ett löfte om att helt släppa taget om oron, bara för en natt. Låset finns där inte som ängslan, utan som ett annat namn för sinnesro."},"ICON-2002":{"nm":"Resväskans handtagsskydd","de":"I varje sliten, handnött fläck är någons avresa inristad. Håll i detta skydd, lika nött som milen det släpats genom, och du förstår tyst att att lämna, trots allt, är ett ord som bär på återkomsten."},"ICON-2003":{"nm":"Necessärens hängklämma","de":"Häng necessären på handfatets kant och det trånga rummet vinner en handsbredd. Att ordningen i en väska börjar med en enda liten klämma vet handen som rest långt redan."},"ICON-2004":{"nm":"Laddarens multiuttagsklämma","de":"Samla flera kablar i ett enda uttag. Under en natt då man väntar på att laddningen ska bli full finns här en liten hand som ömt håller de spridda sladdarna samlade på ett ställe."},"ICON-2005":{"nm":"Resväskans namnbrickssnodd","de":"Bland identiska svarta väskor låter en enda rem dig känna igen din egen. Att hänga upp ett namn är ett ömt tecken på att detta bagage har en väg tillbaka till någon."},"ICON-2006":{"nm":"Väggmonterad laddsladdshållare","de":"En liten platta på väggen vid sängens huvudgärd håller laddsladden prydligt på plats. Den första natten i ett främmande rum, när ett bekant sken tänds, blir även den platsen ett hem för en stund."},"ICON-2007":{"nm":"Bagagepallens fällbara ben","de":"Fäll ut de hopfällda benen och väskan lyfts en handsbredd från det dammiga golvet. En koffert som ställts ner, ännu opackad, bär tyst på en oavslutad resa och väntar på nästa morgon."},"ICON-2008":{"nm":"Nyckelkortsfack","de":"Kortet måste sättas i för att rummets belysning ska tändas. Ljus som bara lyser medan du bor där – en resenärs dag värms av precis den ljusstyrka som detta lilla fack tillåter."},"ICON-2009":{"nm":"Nyckelkortssnoddens ögla","de":"Häng det enda kortet runt halsen och båda händerna blir lediga. Att binda oron för att tappa bort något vid en enda rem är en liten klokhet som länge ärvts av resenärer med tungt bagage."},"ICON-2010":{"nm":"Receptionens ringklocka","de":"Tryck på den och någonstans vid receptionen ljuder en klar klocka. För att det aldrig ska kännas pinsamt att be om hjälp ligger klockan alltid vänligt inom en handräckning."},"ICON-2011":{"nm":"Incheckningens nummerklämma","de":"Ta kölappen du fått i slutet av kön och fäst den. Att även väntan har sin tur – ordning växer ur ett litet löfte om att tyst värna varandras tid."},"ICON-2012":{"nm":"Rumsnyckelns tofs","de":"En tofs som hänger vid nyckelns ände svänger sakta vid varje steg. Att smyga in en gnutta charm i det praktiska är något bara den som känner glädjen i fingertopparna kan unna sig."},"ICON-2013":{"nm":"Dörrklockans skyddskåpa","de":"Sätt kåpan över dörrklockan och middagens stillhet förblir obruten. En liten omtänksamhet för att skydda någons djupa sömn – även tystnad är något som någon skapat med omsorg."},"ICON-2014":{"nm":"Rumsnummerlapp för dörrhandtaget","de":"En lapp som hänger på dörrhandtaget bär rumsnumret tydligt. Några siffror avgör platsen jag ska återvända till i kväll, och i en främmande korridor blir den en liten fyr."},"ICON-2015":{"nm":"Nyckelkortets magnetremsa","de":"Håll den svarta remsan mot dörrspringan och låset glider sakta upp. En tid då en osynlig signal öppnar en dörr – det som en gång kändes som magi har nu blivit vardag i handflatan."},"ICON-2016":{"nm":"Incheckningsstämpelns dyna","de":"Varje gång stämpeln sänks ner tar dynan emot bläcket jämnt. För att bekräftelsens enda streck ska förbli tydligt finns en hand som tyst stödjer från en osynlig plats."},"ICON-2017":{"nm":"Bagagevagnens hängstång","de":"En enda stång på bagagevagnen håller klädpåsen utan en skrynkla. Till de ting som bär en tung dag i vårt ställe vill man ibland räcka ett ord av tack."},"ICON-2018":{"nm":"Kofferthandtagets namnbricka","de":"Häng en liten bricka på kofferthandtaget. Så länge namnfältet förblir tomt lever en rysning av spänning kvar – den här väskans nästa resmål är ännu inte bestämt."},"ICON-2019":{"nm":"Bagagevagnens hjulstoppkil","de":"Kila fast en kloss under hjulet så vagnen inte rullar iväg i en sluttning. Arbetet med att skydda stillheten är ibland den mest pålitliga andra sidan av trygghet."},"ICON-2020":{"nm":"Bagageremmens spänne","de":"Dra åt remmen hårt så en väska svullen av resminnen inte spricker. Även när resan tar slut krymper inte minnenas volym, så spännet håller den tyngden ända till slutet."},"ICON-2021":{"nm":"Bagagevagnens krokskydd","de":"Skyddet över vagnens krok lämnar inte ett enda märke på kläderna. Ett sinne som förutser även osynliga repor – god gästfrihet fulländas i just sådana små detaljer."},"ICON-2022":{"nm":"Resväskans namnbricksficka","de":"En liten ficka på väskans sida rymmer en namnbricka. Att skriva ner vems den är är som att i förväg rista in rätten att mötas igen även om den kommer bort."},"ICON-2023":{"nm":"Bärhandskarnas klämma","de":"När man bär tungt bagage håller klämman fast handskarna så de inte glider av. Att skydda händerna och att göra jobbet bra kommer, till syvende och sist, från ett och samma hjärta."},"ICON-2024":{"nm":"Bagagenätets överdrag","de":"Dra nätet över och de små bagagedelarna sprids inte åt alla håll. Varje tätt maskstygn ser till att inget litet kommer bort i den hektiska flytten."},"ICON-2025":{"nm":"Bagagevagnens anteckningshållare","de":"En lapp instucken i vagnens handtag bär rumsnumret. Vanan att skriva ner vart man ska – ju upptagnare händerna är, desto tystare lutar de sig mot en enda rad text."},"ICON-2026":{"nm":"Serveringsbrickans tallrikskupa","de":"Lyft den silverfärgade kupan och ångan stiger upp på en gång. Hjärtat som täcker maten så den inte kallnar är omtanke i sin renaste form, en önskan att lämna över värmen precis som den är."},"ICON-2027":{"nm":"\"Stör ej\"-skylt för dörrhandtaget","de":"Häng den här skylten på dörrhandtaget och även fotstegen i korridoren blir försiktigare. Orden \"väck mig inte\" – även vilan blir hel först när någon vakar över den."},"ICON-2028":{"nm":"Rumsservicens servettring","de":"Trä pappersservetten genom den runda ringen för att forma den prydligt. En måltids stil börjar med denna lilla ögla – omsorg visar sig tydligast i de minsta detaljerna."},"ICON-2029":{"nm":"Serveringsbrickans halkskydd","de":"Lägg en matta på brickan och tallrikarna glider inte. Att hålla dem på plats även mitt i gungandet – även den stilla stabiliteten bär på någons omsorgsfulla design."},"ICON-2030":{"nm":"Frukostbeställningens dörrbricka","de":"Häng frukostbeställningsbrickan på dörrhandtaget och morgondagens frukost är utlovad i förväg. Att skriva ner den första måltiden redan i kväll är ännu ett ansikte hos ett ömt, förväntansfullt väntande."},"ICON-2031":{"nm":"Serveringsbrickans benstöd","de":"Fäll ut brickans ben och även på sängen blir det ett riktigt bord. En morgonservering mottagen där man ligger – ett litet stöd gör ett vanligt rum till en lyxig scen."},"ICON-2032":{"nm":"Tekannans värmehölje","de":"Dra höljet över tekannan och vattnets värme dröjer sig kvar länge. Precis som de gamla nätterna man samlades kring brasan känner önskan om att bevara värme ingen tid."},"ICON-2033":{"nm":"Städbegärans dörrmärke","de":"Häng städbegärans märke på dörrhandtaget för att lämna en tyst signal. En begäran som förmedlas utan ett ord – bakom ett städat rum ligger löftet om en osynlig hjälpande hand."},"ICON-2034":{"nm":"Serveringsbrickans kryddställ","de":"Hållaren griper fast så kryddburkarna inte välter. Att hålla smakens balans även på en gungande bricka är denna lilla fästanordnings tysta uppgift."},"ICON-2035":{"nm":"Bokningsanteckningsställ","de":"Ställ upp bokningslapparna och ordningen läses av på en blick. Så att inte ens upptagna händer blir förvirrade är det ett litet ordningsredskap som håller ett enda blad tydligt upprätt."},"ICON-2036":{"nm":"Sevärdhetskartans nålbräde","de":"Sätt nålar i kartan och markera en efter en de platser du vill besöka. Varje nål en förväntan ännu obesökt – resan börjar redan i samma stund kartan vecklas ut."},"ICON-2037":{"nm":"Taxiflaggans klämma","de":"När man vinkar till en taxi reser klämman den lilla flaggan rak. En signal flaggan ropar ut i stället för en höjd hand – även på gatan måste ett kall vara tydligt för att nå fram."},"ICON-2038":{"nm":"Concierge-klockans handtag","de":"Tryck på handtaget och en klar klocka når fram till conciergedisken. En välkomnande signal som säger fråga om vad som helst – i en främmande stad den tryggaste enskilda uppmaningen."},"ICON-2039":{"nm":"Bokningsnumrets klämbräde","de":"Kläm fast bokningsnummerlappen på klämbrädet så den syns tydligt. Så att den utlovade platsen inte förväxlas är det en liten flit som håller en rad siffror prydligt fastspänd."},"ICON-2040":{"nm":"Broschyrställ för utflykter","de":"Ställ ut turbroschyrerna och en resenärs hand stannar av sig själv. I varje blad man tar upp en efter en ligger landskapet av ännu ej färdade vägar tyst vikt."},"ICON-2041":{"nm":"Kartstämpelns stöd","de":"För de första stegen in i entrén håller det stämpeldynan på kartan stadig. När bläcket inte flyter ut blir inte heller vägen förvirrande. En plats som tyst bär tyngden så en liten vägvisning kan stå rak."},"ICON-2042":{"nm":"Paraplyförvaringens namnbricka","de":"En eftermiddag när regndroppar droppade från takskägget hänger man ett nummer på varje paraply. När den som kommit tillbaka efter regnet kommer för att hämta sitt eget ropar brickan tydligt fram det fuktiga minnet."},"ICON-2043":{"nm":"Informationsdiskens klockhållare","de":"Ring en gång, ding, och någon kommer glatt springande från andra sidan. Den lilla klockan som hänger vid diskens hörn är den vänligaste tolk, den förmedlar även de ord man inte riktigt fick fram."},"ICON-2044":{"nm":"Schampopumpens munstycke","de":"Öppna handflatan och tryck lätt, och skum blommar ut med ett puff. Den enda dosen då doften sprids genom badrummet. Klockan som väcker en sömnig morgon mest skonsamt börjar just här."},"ICON-2045":{"nm":"Tvålkoppens avrinningsbricka","de":"En bricka som tyst låter vattnet som samlats under tvålen rinna bort. Så den inte blir mjuk, inte blir slaskig. En liten, öm omtanke för att hålla det som slits ner lite varje dag kvar vid din sida en handsbredd längre."},"ICON-2046":{"nm":"Badsaltsskopa","de":"Skopa en sked pulver och lös upp det i varmt vatten, och färg och doft sprids sakta ut. Medan du rör om med handleden blir badkaret en liten sjö, och dagens trötthet sjunker stilla ner i den."},"ICON-2047":{"nm":"Tvålnätspåse","de":"Fånga en tvålbit i nätet och gnid, och mjukt skum stiger upp och fyller handflatorna. En tyst alkemist i badrummets hörn, som förvandlar det sträva till det milda."},"ICON-2048":{"nm":"Tandborstens hygienlock","de":"Önskan om att det som rör vid munnen alltid ska vara rent. Ett litet lock som mjukt sveper om borstens spets tar hand om även det osynliga. Renlighet skapas av just sådana små detaljer, staplade på varandra."},"ICON-2049":{"nm":"Bomullspinnsburkens lock","de":"En burk där vita pinnar ligger prydligt i rad, och ett lock som rundar över toppen. Öppna med ett pock, stäng med ett klick. En öm punkt för badrummets ordning, avslutad med ett litet ljud."},"ICON-2050":{"nm":"Badoljans droppflaska","de":"Luta den lätt och doftande olja faller droppe för droppe. Glansen och den svaga doften som sprids i badkaret. För blygsam för att vara lyx, för öm för att vara vardag – en enda droppe."},"ICON-2051":{"nm":"Hygienbrickans fack","de":"Över en bricka indelad i fack hittar varje liten flaska sin egen plats. Sådant som ser rörigt ut utspritt och prydligt samlat. En enda avdelare håller ordningen i en hektisk morgon."},"ICON-2052":{"nm":"Bastuns timglasstativ","de":"Ett ömt löfte om att åtminstone värma ryggen medan hela sanden rinner ner. När timglaset, lutat mot sitt stativ, tickande räknar tiden, vilar en människa en stund i den täta ångan, utan att vara någon alls."},"ICON-2053":{"nm":"Fårörad bastuhandduk","de":"Rulla ihop handdukens ändar och res dem käckt som fårlurvar, och ansiktet i spegeln mjuknar sakta. Mitt i den heta ångan, en liten ritual i badhuset där vem som helst för en stund återvänder till barndomen."},"ICON-2054":{"nm":"Bastuns vattenskopa","de":"Fyll skopan med vatten och slå det över de heta stenarna – väs – och ångan skjuter upp mot taket. I det ögonblicket sjunker hela kroppen ner i en varm dimma, och gammal trötthet löses sakta upp i svettdroppar."},"ICON-2055":{"nm":"Fotbadets temperaturmätare","de":"Doppa stickan i vattnet och markeringarna talar sakta till dig. Varken för hett eller kallt, just den rätta temperaturen. Innan tårna doppas i, fingret som först frågar efter vattnets mående."},"ICON-2056":{"nm":"Bastustenstång","de":"En nyss upphettad sten kan man inte ta med bara händer. När tången griper stadigt och lyfter flyttas hettan till ett säkert avstånd. Även försiktighet är en färdighet, säger bastun tyst."},"ICON-2057":{"nm":"Bastumatta","de":"Lägg en på det heta golvet och platsen där ryggen vilar blir mycket mjukare. En matta som ordlöst tar emot en dag genomsyrad av svett. Vila kommer, till syvende och sist, från rätt avstånd till golvet."},"ICON-2058":{"nm":"Fotbadssaltpåse","de":"Håll en handfull grovsalt, lös upp den i varmt vatten, och tröttheten smälter sakta bort från tårna och uppåt. När den salta ångan sveper om vaderna stannar äntligen upp en dag av vandrande."},"ICON-2059":{"nm":"Bastuns doftstensfat","de":"Droppa några droppar parfym på den upphettade stenen och den varma doften sprids sakta genom bastun. Blunda, och är detta en skog eller ett blomsterfält? Den kortaste resan man kan göra, genom näsan."},"ICON-2060":{"nm":"Värmekuddens hölje","de":"Ett tyg som sveper tätt om den uppvärmda kudden för att hålla värmen länge. Precis som ett hjärta som kramar den hårt så den inte ska svalna, vakar värmen på magen över dig hela natten."},"ICON-2061":{"nm":"Doftpinnar för aromdiffusor","de":"Tunna pinnar suger upp doften och låter den sakta sippra genom rummet. En svag doft som smyger in med varje andetag. Sättet ett rum sakta kommer att likna den personens doft."},"ICON-2062":{"nm":"Solsängens vinkelvred","de":"Vrid sakta på handtaget och ryggstödet fälls mjukt bakåt. Lite mot solen, lite mot skuggan. Att känna sig fram till den bekvämaste vinkeln är en beräkning helt och hållet din egen."},"ICON-2063":{"nm":"Poolkantens halkskyddslist","de":"En halkskyddslist som löper runt hela vattenkanten. Så att små fötter som kommer plaskande och rusande av glädje kan stanna tryggt är det en dold mållinje av säkerhet, tyst lagd utom synhåll."},"ICON-2064":{"nm":"Badringens ventilögla","de":"En ögla omsorgsfullt knuten vid den lilla ventilen som håller luften instängd. Så att ventilen, när den dras ur ringen, inte flyter iväg på vattnet. En klokhet som förebygger en obetydlig sommarförlust i förväg."},"ICON-2065":{"nm":"Poolens trappstegsskydd","de":"Ett skydd som mjukt sveper om änden av trappan ner i vattnet. Så att bara fötter inte skrapas mjukar det upp det första steget ner i vattnet. Ty varje början bör alltid vara försiktig."},"ICON-2066":{"nm":"Solsängskuddens remögla","de":"En ögla man hakar och binder remmen i så att kudden inte glider av. Ett litet löfte om att hålla sin plats även när vinden blåser. En enda knut håller fast eftermiddagens lättja precis där."},"ICON-2067":{"nm":"Poolbrickans dryckeshållare","de":"En bricka för att stoppa in ett dryckesglas snyggt vid poolkanten. En plats som förblir orubbad även vid ivrigt plaskande. Att lägga svalkan inom räckhåll förlänger en het sommareftermiddag."},"ICON-2068":{"nm":"Klämma för våt baddräkt","de":"Ta upp den droppande baddräkten och lämna den tyst åt vinden. Medan den torkar i solen står klämman stilla och håller fast. Ett tyst, ömt väntande inför nästa bad."},"ICON-2069":{"nm":"Parasollfotens tyngd","de":"En tung vikt som placeras vid stångens fot så parasollet inte vajar i vinden. Att skuggan stannar kvar på ett ställe länge beror helt på denna tyngd. Pålitlighet gömmer sig ofta på den lägsta platsen."},"ICON-2070":{"nm":"Poolens temperaturflytbricka","de":"En liten bricka som guppar på vattnet och tyst avslöjar temperaturen. Rodnar om det är för kallt, mjuknar om det är lagom. En söt liten spåman som läser vattnets humör med bara en färg."},"ICON-2071":{"nm":"Tälttofs för blixtlåset","de":"Dra till i den lilla tofsen som hänger vid blixtlåsets ände och tältöppningen glider mjukt upp. Ett handtag som genast fastnar även när fingrarna famlar i mörkret. Den vägleder ömt in och ut i den djupa natten."},"ICON-2072":{"nm":"Tältsnörets fjärilsnål","de":"En nål som biter fast snöret i fjärilsform och håller det stadigt. Tyget som fladdrade i vinden blir äntligen stilla. En campingnatt vaktas tyst av just sådana små, dugliga knutar."},"ICON-2073":{"nm":"Glampingmadrassens luftventil","de":"Sätt munnen till den och puffa, puffa, och madrassen sväller sakta upp. Fyll den och stäng ventilen ordentligt, golvet blir mjukt, och en plats att lägga kroppen på under stjärnhimlen är äntligen klar."},"ICON-2074":{"nm":"Tälttakets upphängningskrok","de":"En krok som hängs från tälttaket för att hänga en lykta eller en näsduk på. En hushållsvishet som sparsamt utnyttjar även det lilla utrymmet ovanför huvudet. Det är som att hänga upp en enda stjärna i taket i stället för på himlen."},"ICON-2075":{"nm":"Sovsäckens rullband","de":"Ett band som lindas och spänns fast så den hoprullade sovsäcken inte vecklas ut. En bädd som krymper liten igen till morgonen. Att göra sig redo att lämna är att vika ihop förra nattens värme prydligt."},"ICON-2076":{"nm":"Tältingångens skobricka","de":"En bricka som ställs vid tältets ingång för att hålla skorna prydligt samlade. Smuts utanför, rent inuti. Med bara en tröskel delar den ömt in och ut – en liten campingartighet."},"ICON-2077":{"nm":"Glampinglyktans upphängningskrok","de":"En böjd krok för att hänga upp lyktan. Häng den här och ljuset sprids runt inne i tältduken. Platsen där man hänger upp en enda glöd i mörkret blir vårt vardagsrum i natt."},"ICON-2078":{"nm":"Tältventilens rullklämma","de":"En klämma som rullar upp och håller ventilationsfönstret. Öppna en smal väg för brisen och luften inne i tältet blir mycket friskare. En enda liten springa skapar tyst utrymme att andas hela natten."},"ICON-2079":{"nm":"Tältgolvets skyddsmatta","de":"En matta som läggs på tältgolvet för att stänga ute jord och fukt. Ett lager som breder ut en torr bädd även ovanpå gräset. Så att du stannar i naturen men inte blir genomblöt av den ger den tyst en hjälpande hand vid din sida."},"ICON-2080":{"nm":"Skivstångens låsring","de":"En ring som spänns fast i vardera änden av skivstången så viktskivorna inte glider av. Ett litet lås som helt litar på tyngden hos den som lyfter. Först när säkerheten håller stadigt förnyas gränsen med ytterligare ett steg."},"ICON-2081":{"nm":"Kettlebellhandtagets skydd","de":"I det sista setet där järnet gnagde i handflatan försvinner smärtan tack vare detta enda lilla skydd. Att hålla ut till slutet är svårare än att lyfta tyngden – det vet handen först, i det avslutande ögonblicket."},"ICON-2082":{"nm":"Viktskivans låskil","de":"Om skivan vinglar ens obetydligt rasar hållningen redan innan lyftet börjar. En kil, tunt indriven i springan, håller centrum utan ett ljud. Stadga börjar alltid tyst på den osynliga platsen."},"ICON-2083":{"nm":"Skivstångens låsklämma","de":"Fingertopparna som spänner fast låset får inte tveka. Det där lilla klickande ljudet av låsning bär upp hela nästa rörelse. Kroppen lär sig först att sätta sin tillit till en enda klämma."},"ICON-2084":{"nm":"Viktskivans färgmarkering","de":"En bricka färgad olika efter vikt – handen känner igen den först, även om man inte kan läsa siffran. Rött är tungt, blått är lätt; att minnas vikten genom färg. Kroppen mäter, förvånansvärt nog, sin styrka genom ögonen."},"ICON-2085":{"nm":"Kettlebellens golvskydd","de":"Tack vare stödet som breddar ytan mot golvet blir inte trägolvet märkt av gropar. Träningens spår behöver bara synas i svett och muskler. En liten omtanke om att inte lämna sår ens under fötterna ligger inbäddad här."},"ICON-2086":{"nm":"Skivstångens mittmarkering","de":"Märket inristat mitt på stången är referenspunkten för balansen mellan vänster och höger. En hand som griper exakt om mitten halverar vinglet. I samma stund man vet var mitten är kan man äntligen lyfta tryggt."},"ICON-2087":{"nm":"Förvaringsställ för viktskivor","de":"Använda skivor går tillbaka till sin plats. Synen av dem hängande prydligt efter vikt på stället är en tyst omtanke om nästa person. Ett städat utrymme är den mest pålitliga säkerhetsanordningen, tror någon."},"ICON-2088":{"nm":"Viktskivans stoppkant","de":"Olyckan där en skiva på golvet rullar iväg och krossar fotryggen kommer alltid i ett ouppmärksamt ögonblick. Stoppkanten spärrar tyst just det ögonblicket. Stora olyckor kommer inte från stora platser – de rullar in genom en liten springa."},"ICON-2089":{"nm":"Bänkens ryggstödskudde","de":"Om kudden som stödjer ryggen är för hård blir redan andningen ytlig. Den där gränsen mellan lagom fast och lagom mjuk är en balanspunkt bara den som suttit länge kan känna sig fram till med fingertopparna."},"ICON-2090":{"nm":"Stativets höjdjusteringspinne","de":"Med en enda pinne som bestämmer höjden passar stången perfekt oavsett vems axlar den vilar på. Människor med olika längd som vänskapligt delar samma utrustning – ett litet justeringshål skapar den ömma jämlikheten."},"ICON-2091":{"nm":"Maskinens remskiveskydd","de":"Inne i skyddet som omsluter remskivan snurrar kabeln ljudlöst runt och runt. En del som döljer friktionen inuti och bara ger handen mjukheten. En bra anordning avslöjar aldrig till slut den möda den offrat."},"ICON-2092":{"nm":"Bänkens halkfria fötter","de":"Halkfria fötter monterade på de fyra bensändarna håller bänken stadigt fäst vid golvet. Bara när den inte vinglar kan man lägga in hela sin kraft med lugnt sinne. Stabilitet börjar, till syvende och sist, med lite friktion vid foten."},"ICON-2093":{"nm":"Stativets skivstångskrok","de":"Kroken där stången vilar måste alltid finnas på en höjd inom räckhåll. Platsen där en trött arm till sist sakta lägger ner stången – den handsbreda positionen avslutar tryggt dagens träning."},"ICON-2094":{"nm":"Maskinens viktpinnhandtag","de":"Handtaget man sätter i pinnen med för att välja vikt måste vara slätt så det inte skadar naglarna. Även i det korta ögonblicket man byter vikt anas en finish som tyst tagit hänsyn till fingertopparna."},"ICON-2095":{"nm":"Bänkens vinkellåsspak","de":"Om spaken som låser ryggstödets vinkel sitter löst rasar hållningen sakta samman. Vissheten i det ögonblick den låser fast med ett klick. Varje morgon när dörrarna öppnas kontrollerar den ansvarige först just detta ljud."},"ICON-2096":{"nm":"Stativets säkerhetsstöd","de":"I det värsta ögonblicket när skivstången slinker ur händerna tar säkerhetsstödet emot den tyngden i ditt ställe. Med ett stöd, osynligt, alltid väntande där nere, kan en människa äntligen tänja sig ända till sin gräns."},"ICON-2097":{"nm":"Maskinkabelns ändlock","de":"Det lilla locket som samlar kabelns ände är den sista knuten mot upplösning. Att binda ihop trådarna prydligt så de inte sprids – finishens värdighet vilar alltid i den obemärkta ändpunkten."},"ICON-2098":{"nm":"Magnesiapåse","de":"En handfull vitt pulver som gnids på händerna för att sudda ut halkighet. Osynligt som sminket bakom scenen, men stabiliteten i varje rörelse idag börjar just i denna handfull. Förberedelse börjar alltid vid fingertopparna."},"ICON-2099":{"nm":"Greppträningsklämma","de":"En liten klämma som tyst upprepar att gripa och släppa bygger styrkan i greppet. Greppstyrka växer långsammare än de stora musklerna, så detta är också en övning i att stilla lägga otåligheten åt sidan."},"ICON-2100":{"nm":"Fingerspridningsband","de":"Ett band som träs mellan fingrarna för att sakta sprida dem utåt. En hand som bara använt gripmusklerna återfår sin spridande kraft. Lika mycket som att gripa hårt kräver även att stilla släppa taget övning, säger handen."},"ICON-2101":{"nm":"Kritpulverlock","de":"Om pulverlocket sitter bara lite löst blir hela väskan vit av krita. Ett litet lock som sluter tätt förhindrar den lilla olyckan innan den ens sker. Allt handlar, som alltid, om proppen."},"ICON-2102":{"nm":"Knäskyddslinda","de":"Ett band som lindas runt knäet för stöd måste stanna vid precis rätt tryck. För hårt och blodet stryps, för löst och det gör ingen nytta, så en van hand känner sig tyst fram till det ömtåliga mellanrummet ur minnet."},"ICON-2103":{"nm":"Elastiskt motståndsband","de":"Det elastiska bandet som sträcks ut och fjädrar tillbaka väcker sovande muskler utan en enda vikt. Motstånd behöver inte vara tungt. Även vid ett milt drag svarar kroppen alltid ärligt."},"ICON-2104":{"nm":"Ankelviktspåse","de":"En sandpåse som spänns fast runt ankeln drar ner varje steg med skön tyngd. Lägg till lite vikt, och även en vanlig promenad blir riktig träning. Det är en liten klokskap som smyger in lite möda i vardagen."},"ICON-2105":{"nm":"Handledsrulle","de":"En rulle du sakta vevar upp för att lyfta en vikt som hänger i ett snöre. Handleden är den minsta, mest bortglömda leden, och det här enkla redskapet väcker tyst till liv den styrka som glömdes bort."},"ICON-2106":{"nm":"Greppträningsboll","de":"En gummiboll du knådar i handen låter träningen fortsätta stilla även vid skrivbordet. Styrka som byggs i lediga stunder varar längre än styrka som pressas fram på en gång. Uthållighet växer alltid ur sådana här små saker."},"ICON-2107":{"nm":"Pulsbältesspänne","de":"Om spännet på bröstbältet sitter bara lite fel, hoppar siffrorna. Även att lyssna på sitt eget hjärta börjar med en fast tillslutning. Varje mätning börjar till syvende och sist med en tät, glappfri anpassning."},"ICON-2108":{"nm":"Pulsklämma","de":"En klämma som mjukt biter tag i fingertoppen och tyst räknar pulsen. Sätt på den, håll andan lugn, och hjärtats rytm stiger tydligt fram på en liten skärm. Kroppen berättar alltid sanningsenligt om sitt tillstånd."},"ICON-2109":{"nm":"Pulsbandsfodral","de":"Fodralet som förvarar pulsmätaren är litet men känner igen sin egen familj. Ju lättare en liten pryl är att tappa bort, desto mer behöver den ett hem att komma hem till. Att förvara väl är också en form av ömhet."},"ICON-2110":{"nm":"Tempoflaggnål","de":"En liten flaggnål som märker ut löparens mål. En enda punkt bestämd i förväg – \"bara hit\" – bär tunga fötter hela vägen fram. Målsnöret i hjärtat är alltid ett man planterar med egen hand."},"ICON-2111":{"nm":"Pulslampshätta","de":"En liten lampa som tyst blinkar i takt med hjärtslagen. Betraktar man rytmen när den tänds och släcks, rörs hjärtat på nytt av tanken att livet självt kunde vara något så regelbundet."},"ICON-2112":{"nm":"Varvräknarpärlband","de":"Man räknar sina varv med pärlor som knuffas över en i taget. Man behöver inte hålla siffran i huvudet – fingrarna minns åt en. Överlåt räknandet till händerna, så kan sinnet vila helt i rörelsen."},"ICON-2113":{"nm":"Syremätarklämma","de":"En klämma som sätts på fingertoppen läser tyst av syret i blodet. När andningens osynliga djup stiger fram som en siffra, inser man på nytt att kroppsvård i grunden bara handlar om att se noga efter."},"ICON-2114":{"nm":"Pulszonsfärgband","de":"Ett band som delar in träningsintensitet efter färg visar på en blick hur hårt man jobbar just nu. Blått är avslappnat, rött är gränsen. Färgen blir ett tyst löfte, ett vänligt, enkelt språk i sig."},"ICON-2115":{"nm":"Mätgelékapsel","de":"En liten gelékapsel som mäter kroppens tillstånd rymmer en hel dags information i ett enda korn. Vad som än döljer sig i det genomskinliga skalet, finns önskan att lära känna sig själv lite bättre också där inuti."},"ICON-2116":{"nm":"Svetthandduksknagg","de":"Vanan att alltid hänga den på sin egen krok istället för att kasta den var som helst håller hela rummet i ordning. Precis som denna, som reserverar en plats dit handduken kan återvända, lyser ordning alltid i de små detaljerna."},"ICON-2117":{"nm":"Vattenflasklockssnöre","de":"Det korta snöret på vattenflaskans lock förhindrar missödet att locket rullar iväg. Klokskapen i att binda fast något lättförlorat vid kroppen – ett litet snöre samlar tyst undan en hel dags besvär."},"ICON-2118":{"nm":"Solfjäderblad","de":"Ett solfjäderblad som väcker en bris när det viks ut helt. Precis som gamla solfjädrar som svalkade svetten på heta dagar, ger det enklaste redskap den svalaste trösten. En enda vindpust blomstrar alltid ur fingertopparna."},"ICON-2119":{"nm":"Kylhandduksficka","de":"En liten ficka som förvarar en handduk som blir kall när den fuktas. Ett enda tygstycke som svalkar hettan sover prydligt där inne, sjunker sedan mjukt ner mot en trött nacke och för tyst bort middagshettan."},"ICON-2120":{"nm":"Droppfat","de":"Ett fat som ställts fram i förväg för att fånga platsen dit hopsamlade droppar faller. Att skapa en plats att fånga det som droppar, istället för att klandra det för att rinna ner. Ett köks vänlighet dröjer sig alltid kvar så här, utan ett ljud."},"ICON-2121":{"nm":"Fläktriktningsblad","de":"I det ögonblick den raka strömmen av luft svänger lätt åt sidan längs ett litet blad, hämtar det kvava, heta övningsrummet äntligen andan. Att ändra flödet handlade alltid om en så liten vinkel som denna."},"ICON-2122":{"nm":"Pannband","de":"Blir luggen blöt under ansiktstvätten rasar hela dagen samman. Det här bandet, som lyfter håret mjukt bort från pannan, ger personen framför spegeln fem torra minuter. Man märker det först när det saknas."},"ICON-2123":{"nm":"Dryckesmuggklämma","de":"När en mugg vinglar farligt vid skrivbordskanten griper den här klämman tyst tag om ena sidan. En dag som gick utan spill beror, påminner klunken av vatten en om, på att någon höll fast kanten i ens ställe."},"ICON-2124":{"nm":"Vädringshake","de":"Ett helt stängt fönster kväver, ett vidöppet fönster fryser. Det här hakhandtaget minns exakt den lagom öppningen däremellan. Vädring är i grunden en fråga om hjärtat – att lämna saker lagom öppna."},"ICON-2125":{"nm":"Korkkantskydd","de":"Det är alltid det vassa hörnet som gör ont när man stöter emot det. Så man skär till en bit kork och kapar varje kant. En plats insvept mjukt gör inte längre ont i någons knä."},"ICON-2126":{"nm":"Bolsterhandtag","de":"Att bära en lång kudde är besvärligare än man tror. Fäst ett enda band, och den ryms bekvämt i en hand. Konsten att lyfta något tungt lätt beror på var man sätter handtaget."},"ICON-2127":{"nm":"Bältesspänne","de":"Det finns dagar man snör midjan ett hack hårdare och dagar man släpper efter ett hack. Den som känner dagsformen mest ärligt är detta lilla spänne. En bit metall som tyst antecknar kroppens uppriktighet."},"ICON-2128":{"nm":"Kvartsblocksstöd","de":"Ett block sågat i fyra delar bär upp golvet stadigt. Varken för högt eller för lågt – precis den balansen. Det visar tyst att att stödja är att sänka sig själv för att lyfta det som vilar ovanpå."},"ICON-2129":{"nm":"Äggkuddöverdrag","de":"Man klär en äggrund kudde i en klädnad som sitter perfekt. Blir den svettig drar man bara av den och tvättar. Hushållet vet att ju mer något rör vid huden dagligen, desto mer behöver det ett rent lager att byta till."},"ICON-2130":{"nm":"Nivelleringskil","de":"Lutar golvet bara det minsta vacklar allt man mödosamt byggt upp. Skjut in en enda tunn kil i springan, och världen återfår sin vågräta jämvikt. Att räta upp något kräver ingen stor gest."},"ICON-2131":{"nm":"Remändsknop","de":"Man knyter en fast stoppknop så att remmens ände inte fransar och slokar. Ett snöre med en prydligt avslutad ände håller länge. En enda liten knop lär en att avslutningen är svårare än början."},"ICON-2132":{"nm":"Knäskyddsdyna","de":"Den skarpa värken varje gång knäet möter ett hårt golv. En enda dyna som viks ihop och ut smyger sig mjukt in mellan knä och golv. Det är en ömhet som stöder någons knä i deras ställe."},"ICON-2133":{"nm":"Halkskyddsbotten","de":"Även det stadigaste block är oanvändbart om det glider. De fina räfflorna ristade i bottenplattan biter sig fast i golvet. Hemligheten bakom det som står stadigt döljer sig alltid på undersidan, dold för blicken."},"ICON-2134":{"nm":"Riktstavsklämma","de":"Man radar stavarna raka och nyper fast dem med en klämma. Den som är van vid att raka upp saker känner igen den – den märkliga, lilla tillfredsställelsen som växer fram ur att lägga det skeva sida vid sida."},"ICON-2135":{"nm":"Hamstringsremsögla","de":"När baksidan av låret drar så det slinker ur en ett ljud, når den här öglan fram till tåspetsen handen inte når. Dit man inte kunde nå ensam bygger ett enda band en bro för benet."},"ICON-2136":{"nm":"Tåspridardyna","de":"Även tårna, instängda i skor hela dagen, behöver en vilostund. På en dyna som sprider isär dem sträcker foten äntligen ut sig. En kväll som lossar en, med start längst bort."},"ICON-2137":{"nm":"Hållningsvinkelmätare","de":"Med bara ögat går det inte att avgöra hur många grader hållningen har fjärmat sig. När mätaren tyst avslöjar vinkeln reser sig kroppen äntligen rak. En skala som visar den lutning man inte kunde se."},"ICON-2138":{"nm":"Bäckenriktningskil","de":"En slö eftermiddag, bäckenet stelnat, förskjutet åt ena sidan. Man stöttar med en enda kil och återfår sakta sitt centrum. Det handlar inte om att tvinga rakt, utan om att hjälpa saker hitta rätt plats igen."},"ICON-2139":{"nm":"Axelöppnarspänne","de":"Ett band som mjukt rätar ut hopsjunkna axlar. Dra åt spännet och en böjd rygg öppnar sig sakta. Andas djupt med axlarna vidöppna, och först då framträder en scenbugningens hållning."},"ICON-2140":{"nm":"Ryggradsstödskil","de":"Lägg dig på rygg, och ryggraden tecknar sin naturliga kurva. En kil som tyst stöder den kurvan utan att kämpa emot. Att vila väl börjar med att erkänna den kurva kroppen föddes med."},"ICON-2141":{"nm":"Vriststräckningskil","de":"Att sträcka vristen kändes alltid lite otillräckligt. Stötta med rätt kil, och man sträcker sig skönt ner till ett djup man annars inte nådde. En liten sluttning som hjälper en nå lite längre."},"ICON-2142":{"nm":"Handledsstöd","de":"När en handled böjd framför tangentbordet börjar stickas, glider stödet tyst in under den. De första att ta hand om händer som arbetar länge är just sådana här anspråkslösa, lågt liggande föremål."},"ICON-2143":{"nm":"Handledslindning","de":"Innan man lyfter något tungt lindar man en gång runt handleden. En trygghet som växer för varje varv. Vanan att linda in sig i förväg innan skadan sker är den tysta hemligheten hos den som tränar långsiktigt."},"ICON-2144":{"nm":"Armbandsmobilficka","de":"Var man skulle ha telefonen under löprundan var alltid ett bekymmer. Den här fickan som spänns fast på underarmen tar bort det bekymret. Springer man med en favoritlåt fäst vid armen känns vägen ett gott stycke kortare."},"ICON-2145":{"nm":"Greppfjäderskydd","de":"Ett skydd över änden av greppträningsredskapets fjäder så att den inte sticker i handflatan. Genom allt knådande och släppande håller den lilla proppen freden mellan hand och metall. En omtanke på en osynlig plats."},"ICON-2146":{"nm":"Handskfingerborg","de":"Mormors sömnadskunniga fingrar bar alltid en fingerborg. Den här fingerborgen fäst vid handskens spets skyddar fingertoppen. Önskan att skona händer som slitit länge är påfallande lik, även över generationsgränser."},"ICON-2147":{"nm":"Valkskyddsdyna","de":"Valkarna i handflatan är fingeravtryck lämnade av möda. En dyna lagd ovanpå gör nästa repetition möjlig. Genom att svepa in den hårdnade platsen på nytt hänger man i en gång till."},"ICON-2148":{"nm":"Halkskyddstejp för handflatan","de":"Glider handflatan ständigt tappar man det man kämpat för att hålla fast. Linda på den skrovliga tejpen, och hand och redskap blir en enda kropp. Kraften att inte tappa greppet kommer, förvånande nog, från friktionen."},"ICON-2149":{"nm":"Armsvettband","de":"Innan svetten som rinner under träningen når handleden suger det här bandet på underarmen upp den först. Att svettas är inget att skämmas för – ett genomvått tygstycke vittnar tyst om det."},"ICON-2150":{"nm":"Handskstorkställ","de":"Kastar man dem hur som helst är nästa morgon en plåga, men hänger man dem prydligt torkar brisen dem mjuka under natten av sig själv. Doften av väl torkade handskar öppnar morgondagen fräsch och ny."},"ICON-2151":{"nm":"Dragkedjedrag","de":"Med genomvåta händer går det inte att få tag i en liten dragkedja. Fäst ett enda drag, och det går undan i ett enda ryck. En obetydlig liten ögla räddar en hel förvirrad minut."},"ICON-2152":{"nm":"Andningslapp","de":"Man sätter en andningslapp på kroppens hetaste punkt. Den instängda hettan smyger tyst ut genom lappen. Att öppna ett enda litet andningshål mitt i den kvävande hettan."},"ICON-2153":{"nm":"Innersulelapp","de":"Man skär ut endast den slitna delen av en gammal innersula och sätter i en ny bit. En hand som inte slänger allt, utan bara byter ut det som gör ont. En liten lagning under foten lättar dagens alla steg."},"ICON-2154":{"nm":"Strykmärke med matchnummer","de":"Man trycker fast ett ryggnummer i tyget med ett strykjärn. Medan värmen svalnar sätter sig siffran stadigt i tyget. Startstämpeln som gör dem som bär samma nummer till ett lag."},"ICON-2155":{"nm":"Skotåförstärkning","de":"En förstärkningskappa på tån håller tyst stången mot ödet hos en sko vars spets ständigt stöts emot. Den plats som slits först görs starkast. Ju längre en sko ska hålla, desto stadigare är den redan från tåspetsen."},"ICON-2156":{"nm":"Träningsbyxornas dragsnörknut","de":"I det ögonblick man drar åt midjesnöret och knyter det, sluter det lösa plagget sig tätt mot kroppen. Den här fasta knuten, som inte löser upp sig, håller allt på plats genom de mest intensiva rörelserna."},"ICON-2157":{"nm":"Halkskyddsband för ankelstrumpa","de":"Besväret med en ankelstrumpa som ständigt rullar ner i skon. Ett enda band håller fast den där glidningen. En strumpa så liten att man knappt tänkte på den håller äntligen sin plats."},"ICON-2158":{"nm":"Armhålssvettskydd","de":"En dyna placerad i förväg där svetten sipprar fram som mest. Genomsvettas den syns ändå inte ett spår på plaggets utsida. De som arbetar tyst utom synhåll håller scenen prydlig."},"ICON-2159":{"nm":"Skoklackögla","de":"Sätter man på skon och drar lätt i klacköglan glider foten rakt in. Den korta bekvämligheten som sparar en från att huka sig ner. En hektisk morgon gör en sådan här ögla verklig nytta."},"ICON-2160":{"nm":"Massagepistolhuvud","de":"Man byter huvud efter vilken punkt som ska knådas. Varje knut i muskeln har sin egen passande form. En kväll som väljer precis rätt styrka av tröst åt axlar som stått ut med dagen."},"ICON-2161":{"nm":"Laddstation för massagepistol","de":"Även handen som ska lösa upp hela kroppen hela dagen vaknar först när den är laddad. Medan det röda ljuset skiftar till grönt får man vila en stund. När blinkandet upphör närmar sig tyst turen att åter smeka stela axlar."},"ICON-2162":{"nm":"Massagepistolstyrkevred","de":"Svagt, lite till, precis där. Medan fingertopparna vrider på ratten prutar de tyst med den egna kroppen. Dagens löfte – att bara bli stark i den mån det gör ont – står tydligt skrivet mellan de små strecken."},"ICON-2163":{"nm":"Hållarring för vibrationsboll","de":"Även en boll som rullar bra behöver en plats att stanna på ett tag. Den här runda hållaren vaggar tyst hjärtat som vill rulla iväg, och håller dess plats tills nästa tur kommer. Även vila är en del av träningen."},"ICON-2164":{"nm":"Handtagshätta för akupressurpinne","de":"Med bara en liten hätta på änden smälter smärtan i handflatan sakta bort. Mellan hårdhet och hud behövs alltid ett mjukt lager. En öm liten sträcka som först rundar av den plats som möter huden."},"ICON-2165":{"nm":"Jordnötsrullepåse","de":"En liten påse som förvarar en jordnötsformad rulle. Rullar den fram ur ett hörn av väskan följer gårdagens beslut att äntligen ta hand om kroppen med. En liten påse minns löftet."},"ICON-2166":{"nm":"Fotrullestativ","de":"Vacklar platsen man anförtror fötterna åt, vacklar avslappningen med. Det här stativet som håller upp rullen griper stadigt tag i golvet och skapar en plats där två trötta fötter kan luta sig tryggt. Trygghet kommer från det som inte vacklar."},"ICON-2167":{"nm":"Rullkärneplugg","de":"En liten plugg som täcker en tom kärna. Det osynliga inuti måste fyllas för att utsidan inte ska falla samman. Den plats ingen någonsin ser medan den rullar bärs tyst upp av denna tysta del."},"ICON-2168":{"nm":"Massagepinnehätta","de":"En rundad hätta över änden av pinnen. Så den inte nöts, inte river – att skydda spetsen är i grunden vägen att behålla den nära länge. Önskan att svepa den plats som slår emot först på mjukast möjliga sätt."},"ICON-2169":{"nm":"Tejprullskniv","de":"Dra till med en hand så klipps tejpen ren och prydlig. Det finns ett litet knep även i att knyta och avsluta, och det här bladet känner till känslan av ett städat slut. Ett rent avslut gör nästa steg lättare."},"ICON-2170":{"nm":"Tejpändeshätta","de":"En hätta som tyst trycker ner änden så den inte lossnar. Vem som helst kan börja, men att hålla fast ända till slutet är alltid svårt. Den lilla handen som håller fast den sista biten tar tyst ansvar för dagens avslut."},"ICON-2171":{"nm":"Handledskompressionsärm","de":"Linda ett enda lager runt en överansträngd handled, och smärtan kommer en takt försenad. Som en hand som tyst håller ens egen, blir kompression ibland det ömmaste skydd som finns. Det handlar inte om att snöra åt, utan om att hålla upp."},"ICON-2172":{"nm":"Ankelstödsspänne","de":"Det korta klicket när spännet knäpps igen lugnar sinnet. Sveper man ankeln stadigt, sipprar ett mod fram som säger att det kanske går bra att ta ett steg till. Ett litet ljud blir en trygg start."},"ICON-2173":{"nm":"Knäkompressionsremsspänne","de":"Knäet blir stadigare ju mer man drar åt remmen. Ska inte lossna, men inte heller göra ont – någonstans däremellan finns precis rätt hack. Spännet glömmer aldrig den platsen, gång på gång."},"ICON-2174":{"nm":"Fingertejpsax","de":"En liten sax som exakt klipper av tejpen lindad runt en knoge. Rundad i spetsen så den inte river huden. Ju mer ett redskap är till för att vårda, desto ömmare slipas dess blad – den här saxen visar det tyst."},"ICON-2175":{"nm":"Upprullare för elastisk binda","de":"En upprullare som prydligt vinder tillbaka en utrullad elastisk binda. En hand som noggrant rullar ihop det den använt trasslar inte till det nästa gång heller. I varje prydligt rullat lager finns dagens ordning inbäddad."},"ICON-2176":{"nm":"Skenbensskyddsrem","de":"Ett band som binder fast dynan som skyddar framsidan av skenbenet. Sinnet som först ser efter platsen som riskerar att träffas är i sig en förberedelse. Går man ut på planen med benen stadigt fastknutna krymper rädslan i hjärtat till hälften."},"ICON-2177":{"nm":"Armbågsskyddsklämma","de":"En liten klämma som griper fast så skyddet inte glider ner. Så obetydlig som att nypa i ett papper, men lossnar den rasar allt löst. En enda liten fästpunkt håller fast en hel dags trygghet."},"ICON-2178":{"nm":"Stretchögleshandtag","de":"Griper man öglan och sträcker kroppen lång, ser man fingertoppar som nått ett stycke längre än igår. Det är inte bara musklerna som töjs ut när man drar. Ett stelnat sinne öppnar sig också lite, under tiden."},"ICON-2179":{"nm":"Tåspridare","de":"Sprider man isär tårna som varit instängda i skor hela dagen kommer en bris in i det trånga utrymmet. Vissa saker i världen blir bekväma först sedan de varit isär ett tag. Även tåspetsarna behöver rum att andas."},"ICON-2180":{"nm":"Vadavslappningskil","de":"Stoppad kilformat under vaderna löses benen sakta upp. En enda sned vinkel låter en hel dags tyngd sakta rinna bort. Att luta sig lätt bakåt och ligga ner – det är ibland den mest bekväma hållningen av alla."},"ICON-2181":{"nm":"Nackavslappningsstöd","de":"Man lägger nacken över det och sluter ögonen en stund. Det här lilla stödet viskar stilla till axlarna, från samma plats som alltid, att det är okej att lägga ner det tunga huvudet en stund. Även att luta sig kräver mod."},"ICON-2182":{"nm":"Stretchstavshätta","de":"En enda hätta som täcker änden av en långsträckt stav. Är spetsen mjuk kan man känna sig trygg oavsett var den vidrör. Oavsett vem den sträcks mot, att runda av kanterna först – omtanke börjar alltid tyst så här."},"ICON-2183":{"nm":"Akupressurdyna med knoppar","de":"Lägger man kroppen på de knottriga knopparna rinner dagen ut vid varje intryckt punkt. Vid den gränsen mellan smärta och lindring löses axlar stela hela dagen sakta upp, som om de kapitulerar."},"ICON-2184":{"nm":"Andningstimglas","de":"Ett tyst löfte att dra ut andetaget långt tills det allra sista sandkornet fallit. Den tunna sandströmmen räknar tyst rytmen av in- och utandning. Även ett upptaget sinne lägger sig till ro en stund under tiden."},"ICON-2185":{"nm":"Fotsulestöd med akupressurboll","de":"Man stöttar en boll mitt under fotsulan och trycker stadigt ner. Till fötterna som burit hela kroppen hela dagen ger det lilla stödet tyst plats och säger att det nu är deras tur att bäras upp. Även det som bär upp har stunder att vila."},"ICON-2186":{"nm":"Axelavslappningssnöre","de":"Ett snöre med ögla man hakar över axeln och drar i. Sträcker man linan mot en stel punkt löses en knuten led upp, ett hack i taget. Det visar att även att bli fri behöver något att hålla i handen."},"ICON-2187":{"nm":"Banlinskiva","de":"En enda rund led i banlinan som delar vattnet. En vänlig gräns dragen över vattnet så man inte krockar med simmaren bredvid. Små skiljeväggar som vaktar allas egen väg för dem alla framåt sida vid sida, ända till slutet."},"ICON-2188":{"nm":"Banlinespänningskrok","de":"En krok som drar banlinan spänd och håller den. För löst och den böjer sig i vågorna, för hårt och den brister. Att hitta rätt spänning liknar att stålsätta sig själv – man famlar alltid efter något mittemellan."},"ICON-2189":{"nm":"Färgad banlinshätta","de":"En liten hätta målad i olika färg för varje bana. Ett märke färglagt så man känner igen sin egen väg på en blick, även på håll. Att hindra någon från att gå vilse med bara en färg – vägledning börjar i grunden med just en så liten vänlighet."},"ICON-2190":{"nm":"Upphängningsskiva för banlina","de":"En skiva för att hänga upp banlinorna prydligt när de inte används. I handen som ordnar linorna fint inför nästa start, ligger tyst en lugn beslutsamhet att avsluta dagen väl."},"ICON-2191":{"nm":"Banlinevinda","de":"Man vevar handtaget runt och runt för att rulla in den långt utrullade linan. Att samla ihop det som spritts ut kräver alltid tålamod. Ett varv, sedan ett till – ett avslut fullbordas så här, sakta, utan brådska."},"ICON-2192":{"nm":"Banlineändklämma","de":"En klämma som biter fast så knuten i linans ände inte löses upp. Den låter inte ens en lös tråd glida iväg. Det krävs en hand som vakar ända till slutet för att en lång lina ska hålla sin prydliga form utan att repas upp."},"ICON-2193":{"nm":"Banlinflytpärla","de":"Banlinans flytpärla som guppar upp på vattnet. För att inte sjunka har den fyllt sig själv med luft. Viss lätthet kommer ur en tomhet fylld med möda, visar det böljande vattnet upp om och om igen."},"ICON-2194":{"nm":"Banummerflagga","de":"En liten flagga som visar banans nummer. En enda tygbit som fladdrar i vinden säger tydligt: \"här är din plats.\" En liten men omisskännlig vägvisare som leder en rakt in på sin väg utan att gå vilse."},"ICON-2195":{"nm":"Banlinekoppling","de":"En krok som förbinder en banlina med nästa. Med en enda krok som knyter ihop en avbruten väg blir vattenleden äntligen fullständig. Att koppla samman är i grunden en liten metallbits arbete med att tyst sträcka ut en hand mellan det som skilts åt."},"ICON-2196":{"nm":"Startblocksfotplatta","de":"Fotplattan på startlinjen tar emot hela tyngden av det första språnget. De 0,1 sekunderna man sparkar ifrån med kraft – fastheten tårna trycker mot skjuter igång ett helt lopp. Varje uppstigning startar från en plats att stå stadigt på."},"ICON-2197":{"nm":"Starthandtagsstång","de":"Stången händerna griper hårt om precis innan startsignalen. Man måste förankra ett skälvande hjärta någonstans, annars vacklar starten. Bara att ha något att hålla i gör nästa rörelse desto tydligare och stadigare."},"ICON-2198":{"nm":"Ryggsimsflagglina","de":"En flagglina som säger till den som simmar med blicken mot taket att väggen närmar sig. En vänlighet som varnar i förväg för det man inte kan se. Med en enda signal som vakar över ens rygg blir det sista draget tryggt."},"ICON-2199":{"nm":"Vändväggsdyna","de":"En mjuk dyna lagd på väggen där man byter riktning. Så det inte gör ont ens vid en hård träff, dämpar den vändpunkten mjukt. På vägen tillbaka ligger alltid någons tysta omtanke utlagd först."},"ICON-2200":{"nm":"Målgångsplatta","de":"I samma ögonblick fingertopparna vidrör är allt över. Slutet på en lång, andfådd väg kommer i slutänden ner till just denna enda lätta knackning. Ankomst är inget storslaget, utan att träffa exakt rätt punkt, svarar plattan tyst."},"ICON-2201":{"nm":"Startplattans glidremsa","de":"Alla håller andan en gång när de står vid kanten av backen. Ta dig förbi den korta rädslan och glid nedåt – plask – och skrattet brister ut tillsammans med vattenstänket. En start börjar alltid ett litet steg bortom rädslan."},"ICON-2202":{"nm":"Vändmarkeringskon","de":"När du tvekar vid en vägskäl talar den här lilla spetsen till dig först. Vänd här, säger den, gå inte vilse. Någon ser den enda färgen och hittar sin riktning igen och går vidare."},"ICON-2203":{"nm":"Startblockskil","de":"Den halva takten strax innan språnget, när kroppen hukar som lägst. Där finns ett litet fotstöd som håller vinkeln så att tårna inte glider. Varje stund av att stiga högt föds ur denna lutning."},"ICON-2204":{"nm":"Väggkantsskydd","de":"Så att det inte gör ont även om man stöter i det under leken har hörnet gett efter med sin skärpa och blivit runt. Önskan om att du inte ska skada dig har slipats och slipats tills den sitter fast på väggen. Det ömmaste skyddet är oftast just så tyst."},"ICON-2205":{"nm":"Livbojskrok","de":"Till vardags är det bara en plats där något hänger. Men i samma stund någon faller i vattnet är det just hit en hand först sträcks. Det finns en sorts trygghet i världen som är bäst när den aldrig behöver användas."},"ICON-2206":{"nm":"Räddningskrokstång","de":"En lång arm som på ett enda tag sluter ett avstånd som annars vore omöjligt att nå. När handen inte räcker till blir den här kroken en hand i dess ställe. Räddning är, till syvende och sist, konsten att räcka sina fingertoppar till någon långt borta."},"ICON-2207":{"nm":"Poolduschhuvud","de":"\"Skölj av dig innan du går ner.\" Som badvaktens ständiga replik forsar en vattenstråle över huvudet. Med ett enda kallt stänk sköljs dagens damm bort, droppe för droppe."},"ICON-2208":{"nm":"Halkskyddsplatta","de":"Fint upphöjda räfflor så att bara fötter inte halkar. Från en plats ingen ser håller den tyst fotsulorna på plats. Den fastaste säkerheten gömmer sig alltid på de oansenliga ställena."},"ICON-2209":{"nm":"Djupmärkningsskylt","de":"Innan du sätter foten i vattnet talar siffran om djupet först. En plats som skulle skrämma dig om du gick in omedveten lugnar sinnet så fort du läst den. Det denna skylt gör är att hjälpa till med en liten förberedelse."},"ICON-2210":{"nm":"Säkerhetslina med flytbojar","de":"Färgglada linor som guppar på vattnet och delar av zonerna. Så här långt är det säkert, lovar flötena, hand i hand. Tack vare gränsen kan man äntligen simma fritt med ett lugnt sinne."},"ICON-2211":{"nm":"Desinfektionsfotbad","de":"Ett litet kärl där bara fötter dröjer ett ögonblick innan de går ner i vattnet. Där rymmes en kort ritual av att bli ren, från tårna och uppåt. Renlighet börjar alltid med den här sortens omsorg, ett steg i taget."},"ICON-2212":{"nm":"Halkvarningskon","de":"En enda gul kon saktar stillsamt ner stegen. \"Det är blött här, var försiktig.\" En omtanke given i färg istället för ord. Den lilla varningen vakar tyst över dagen för någon som nästan halkade."},"ICON-2213":{"nm":"Väggförbandsskåp","de":"Det vita skåpet på väggen öppnas sällan. Men just i den stund det öppnas blir det någons lättnad. En nödsituation väntar alltid tyst på den allra närmsta platsen."},"ICON-2214":{"nm":"Ytskumhåv","de":"Den lyfter tyst bort löven och dammet som driver på ytan. Klarhet kommer inte av sig själv, så någons hand måste ösa upp det en gång varje dag. Bakom det stilla vattnet finns en flitig håv."},"ICON-2215":{"nm":"Bassängrobotslang","de":"Även en natt när alla sover vandrar den sakta omkring och famlar sig fram längs botten. Den mest trogna arbetaren under timmarna ingen ser. Morgonens klarhet är spåret denna slang har ritat hela natten."},"ICON-2216":{"nm":"Klordoseringsbehållare","de":"Även att hålla vattnet klart har sin exakt rätta mängd. För mycket och det blir frätande, för lite och det grumlas – balansen ligger däremellan. En osynlig hand ställer tyst in den graderingen varje dag."},"ICON-2217":{"nm":"Vattenprovflaska","de":"Man samlar en klunk vatten i en liten flaska och frågar efter dagens tillstånd. För ögat ser det likadant ut, men siffrorna ljuger inte. Trygghet är något som bekräftas en gång om dagen, precis så här."},"ICON-2218":{"nm":"Flytbrädekratta","de":"En lång kratta som samlar ihop brädor och flytande skräp som driver på vattnet. En hand som räfsar samman det som spritt sig påminner ändå om hjärtat. Även oreda blir ordnad så fort man sopar en gång."},"ICON-2219":{"nm":"Avloppsgaller","de":"Ett tätt nät som vaktar passagen där vattnet rinner ut. Det skiljer tyst mellan vad som ska släppas fram och vad som ska hållas kvar. Även att låta något gå kräver ett filter, viskar det lilla nätet utan ord."},"ICON-2220":{"nm":"Vattentermometerboj","de":"En liten spanare som guppar på vattnet och avläser temperaturen. Kallt eller lagom, den vänliga omsorgen berättar det innan kroppen ens vidrört vattnet. Den första tryggheten vid nedstigning börjar alltid med den här bojen."},"ICON-2221":{"nm":"Poolskyddsvinda","de":"Ett handtag som rullar ihop det breda skyddet och lägger det åt sidan. Ett verktyg som vet när det ska bredas ut och när det ska dras in känns på något sätt pålitligt. Under vilan är det som att bädda ner vattnet under ett täcke."},"ICON-2222":{"nm":"Skimmerkorg","de":"Korgen dit flytande skräp till sist samlas efter att ha drivit på ytan. Tack vare ett kärl som tar emot bottenfallet på en osynlig plats förblir ytvattnet alltid klart. Bakom renheten hopar sig mödan."},"ICON-2223":{"nm":"Torkställ för badmössor","de":"Man hänger en vattendränkt badmössa upp och ner. Medan den droppar en droppe i taget hämtar mössan sakta andan. Att torka är, till syvende och sist, bara ett annat namn för väntan."},"ICON-2224":{"nm":"Axelbandsögla för baddräkt","de":"En liten ögla som håller fast bandet så det inte glider av axeln. Från en osynlig plats rätar den tyst ut bärarens hållning. Prydlighet fullbordas alltid ovanpå så här obetydliga stöd."},"ICON-2225":{"nm":"Förvaringspåse för badmössor","de":"En påse där blöta badmössor en efter en hittar sin plats. Ett litet bo som samlar det som lätt sprids ut i en enda famn. Att ordna är en öm vana att inte förlora saker."},"ICON-2226":{"nm":"Bröstinlägg för baddräkt","de":"Ett enda inlägg som ligger stilla inuti plagget. Osynligt utifrån rätar det ändå sakta ut bärarens axlar. Viss trygghet fylls tyst inifrån, inte utifrån."},"ICON-2227":{"nm":"Namnlappsklämma för badmössa","de":"En liten klämma som fäster en namnlapp vid kanten av badmössan. Bland likadana saker säger den tydligt: \"den här är min.\" En enda markering och förväxlingen tar genast slut."},"ICON-2228":{"nm":"Dragkedjeögla för baddräkt","de":"\"Kan du dra upp dragkedjan på ryggen?\" Den platsen man aldrig når själv drar den här lilla öglan upp i en hands ställe. En öm räckvidd som hjälper till med det sista hacket."},"ICON-2229":{"nm":"Utplattningsbräda för badmössa","de":"Man rätar ut och stöttar en badmössa som fastnat i vanan att rulla ihop sig. Ett stöd som tyst hjälper det skeva att återfå sin form. Det måste finnas en hand som rätar till för att något ska bli fyrkantigt och rätt igen."},"ICON-2230":{"nm":"Midjesnöre för baddräkt","de":"En spännare som omsluter midjan precis lagom och håller den så den inte glider ner. Varken för stramt eller för löst – just den rätta mängden. Bekvämlighet bor alltid någonstans däremellan."},"ICON-2231":{"nm":"Vändklämma för badmössa","de":"En klämma som griper en avig badmössa och vänder den rätt i ett enda tag. Känslan av att vända det uppochnervända till rätta är faktiskt ganska skön. Ordningens lilla njutning kommer just från sådana obetydliga stunder."},"ICON-2232":{"nm":"Handtagsrem för simbräda","de":"En rem som lindas kring handen så du inte tappar simbrädan. Även när strömmen knuffar dig är det en stor tröst att ha något att hålla i. Darrningen från dagen du lärde dig sparka finns fortfarande kvar i den här remmen."},"ICON-2233":{"nm":"Spännrem för pullboj","de":"En rem som håller bojen stadigt fastspänd mellan benen. Först när den inte lossnar kan man äntligen fokusera enbart på tekniken. På det som hålls väl fast fördjupas dagens träning en handsbredd i taget."},"ICON-2234":{"nm":"Väggkrok för simfenor","de":"När simfenorna hänger sida vid sida på väggen ser de precis ut som en flock änder som vilar vid vattnet. Fötter som just avslutat sitt simmande skakar av sig vattnet och väntar på morgondagen. Även pausen har något runt och gulligt över sig."},"ICON-2235":{"nm":"Hörnskydd för simbräda","de":"Ett litet skydd draget löst över simbrädans hörn. Så att det inte gör ont vid en stöt, så att det inte fördärvas av slitage, omsluter det spetsen. Hemligheten att behålla något länge ligger i att vårda det från hörnen och inåt."},"ICON-2236":{"nm":"Förvaringsnät för simfenor","de":"Simfenor som liknar simhud solar sig inuti nätet. Som änder som just kommit upp ur vattnet och torkar sina fjädrar torkar de sakta i nätet. En avslappnad tupplur inför nästa simtur."},"ICON-2237":{"nm":"Namnlapp för pullboj","de":"Man fäster en namnlapp på varje boj för att tydligt märka ägaren. Ju fler som delar en plats, desto lugnare känns det när det är klart vems något är. En enda liten lapp skapar ordning."},"ICON-2238":{"nm":"Dräneringsställ för simbräda","de":"En plats stöttad på sned så att vattnet som samlats i simbrädan sakta rinner av. Man måste tömma det man tagit upp för att bli lätt, viskar stället tyst. Torkningens första steg är att stötta rätt."},"ICON-2239":{"nm":"Remspänne för simfenor","de":"En liten del som spänner fenremmen så den sitter tätt om foten. För löst och den glider av, för hårt och det gör ont – det där känsliga lilla utrymmet. För att glida fram lätt som en simfotad and behövs precis denna marginal."},"ICON-2240":{"nm":"Rytmchip för simsparkar","de":"Ett litet chip som anger takten varje gång du sparkar. Ett, två, tre – när rytmen väl satt sig i kroppen blir vattnet nästan till sång utan att man märker det. Det här chippet lär dig stillsamt att även simning har en takt."},"ICON-2241":{"nm":"Påse för blöt baddräkt","de":"Inne i väskan som lämnar poolen är det alltid jag som tar plats först. Låt de andra sakerna ge mig sneda blickar, vad kan jag göra åt det – det blöta måste hållas för sig så att alla förblir torra. Karantänrummet för fukt, det är den ömma posten jag har."},"ICON-2242":{"nm":"Vattenvridbräda","de":"Fukt har för vana att smita iväg så fort man trycker på den. Ett fast tryck, sedan ett till – först när man lägger tyngd på den ovanpå brädan kapitulerar den. För den som aldrig fått användning för sin handledsstyrka finns knappast en bättre scen än denna."},"ICON-2243":{"nm":"Avdelare för simväska","de":"Packar man allt i ett enda fack smittar det blöta och det torra av varandra. Arbetet med att stillsamt kila sig emellan och dra en linje. Om en enda avdelare räcker för fred kanske försoning trots allt är en förvånansvärt enkel sak."},"ICON-2244":{"nm":"Vattentät skopåse","de":"Den sväljer sandiga skor hela utan att ändra en min. Vad som än pågår inuti ska utsidan förbli torr – det är den artighet vattentätheten håller fast vid. En tystlåten påse är välkommen överallt."},"ICON-2245":{"nm":"Dräneringspropp för simväska","de":"Vrid på proppen och dagen som samlats i väskans botten rinner rakt ut. Städningen efter en glad lekstund handlar alltid om det här enda lilla hålet. Även konsten att låta något rinna bort kräver design."},"ICON-2246":{"nm":"Absorberande dörrmatta","de":"Den ligger tyst framför entrén och tar emot fukten från varje fot som kommer in. Även om ingen märker det vet trägolvet – att ingen halkade idag heller. På en tyst plats bor en tyst belöning."},"ICON-2247":{"nm":"Fat för blöt badmössa","de":"När en avkastad badmössa förlorar sin plats håller jag upp den. Kallad ett fat fast jag bär vattendroppar istället för mat, men om det handlar om att skapa en plats åt någon kan även ett understöd bära huvudet högt."},"ICON-2248":{"nm":"Torkklämma för handduk","de":"Uppgiften att bita hårt fast i en handduk uppe på klädstrecket. Min stolthet är en envishet som inte släpper taget hur mycket vinden än retas. Tills den blivit mjuk och torr i solen släpper ett grepp som en gång tagits aldrig först."},"ICON-2249":{"nm":"Upphängningskrok för vattentät påse","de":"I samma stund den hänger på kroken får den drivande påsen äntligen en adress. Även om det bara handlar om att dingla, med en enda kvadrat av väggen lånad, finns det något lika betryggande som en plats där man aldrig behöver frukta att gå förlorad?"},"ICON-2250":{"nm":"Inträdesarmband för rutschbana","de":"Spänningen av att tyst vänta på sin tur är helt bunden i det här enda lilla bandet. Först när det spänns fast runt handleden börjar rutschkön svalla, så kanske inträde bara är konsten att binda ett löfte om handleden."},"ICON-2251":{"nm":"Mattbit för vattenrutschbana","de":"Folk springer glatt över den utan att ana springan under fötterna. Utlagd så att ingen ska halka avslöjar den sin existens först när just den biten saknas. Det finns ganska många saker i världen som bara minns genom den tomma plats de lämnar efter sig."},"ICON-2252":{"nm":"Vattentätt band för skåpnyckel","de":"Att skydda en skåpnyckel från vattnet är mitt livslånga uppdrag. Bunden kring en handled plaskar jag med, men just den där nyckeln håller jag skinntorr. Tappar man mig hittar man inte ens sina kläder, så nog är jag en tungt ansvarig tjänsteman."},"ICON-2253":{"nm":"Startsignalpanel för rutschbana","de":"I den korta stund då rött slår om till grönt hoppar allas hjärtan högst upp på rutschbanan i takt. Rätten att ge klartecken för start – vem hade anat att en så liten signalpanel kunde rymma så mycket spänning."},"ICON-2254":{"nm":"Spänne för flytväst i lugna floden","de":"Spännet som håller stadigt fast en kropp som guppar nedför den lugna floden. Först efter det klicket vågar man äntligen slappna av och överlämna sig åt strömmen. Trygghet börjar ibland med ett så litet lås som detta."},"ICON-2255":{"nm":"Signalflagga för vågpool","de":"Den varnar alla i förväg om när vågorna är på väg. Flaggan uppe betyder jubel, flaggan nere betyder en stunds andhämtning. Lustigt att det som håller takten vid den svallande poolen är en enda bit tyg."},"ICON-2256":{"nm":"Nummerhalsband för rutschkö","de":"Bär man numret på sin plats i kön runt halsen blir det aldrig någon förväxling. En enda nummerlapp avgör vems tur det är – ordning, verkar det, börjar ofta med ett så litet halsband som detta."},"ICON-2257":{"nm":"Laddningsmynt för armband","de":"Håll det lätt mot armbandet och laddningen är klar. I en tid då man rör sig genom vattnet utan kontanter eller kort spelar detta lilla mynt hela plånbokens roll. Ju lättare handleden, desto lättare hjärtat."},"ICON-2258":{"nm":"Greppskydd för vattenkanon","de":"Ett vattenkanonhandtag är som bäst när man griper hårt. Tappa ett enda skydd och glöm siktet – det bara snurrar runt i handen, och utgången av ett vattenkrig mitt i sommaren hänger på just detta lilla ändstycke."},"ICON-2259":{"nm":"Sandslottsform","de":"Fyll den med blöt sand, tryck fast, vänd upp och ner, och ett litet torn reser sig. Ingen förstår hjärtat som fortsätter bygga trots att det vet att allt kommer rasa, bättre än jag. För sandens arkitekt är formen själva ritningen."},"ICON-2260":{"nm":"Sandkrattans tänder","de":"Dra den som en kam genom sanden och prydliga fåror blir kvar. Trots att den vet att vågorna snart suddar ut mönstret fortsätter tänderna flitigt dra sina linjer. Det finns en särskild charm i att med omsorg skapa det som är dömt att försvinna."},"ICON-2261":{"nm":"Ankarvikt för parasollstång","de":"Den står tyst vid foten så att parasollet inte blåser bort i vinden. Att bevara skuggan är inte det praktfulla tygets uppgift utan den tungt nedgrävda viktens. Den osynliga tyngden är alltid den mest pålitliga."},"ICON-2262":{"nm":"Handtag till sandsikt","de":"Skaka och sikta sanden så finns bara skal och små skatter kvar i handen. Ta tag i handtaget och vicka på – hälften av skattjakten på stranden avgörs av just denna sikt."},"ICON-2263":{"nm":"Musselformad sandform","de":"Fyll den med blöt sand, knacka lätt, och handstora musslor blommar på rad längs stranden. Man kan inte äta en riktig mussla, men den här formen kan vem som helst skapa. En anspråkslös liten sommarmagi."},"ICON-2264":{"nm":"Vinkeljusteringspinne för parasoll","de":"Varje gång solen flyttar sig måste parasollet vrida på huvudet och följa efter. Dra ut pinnen och sätt tillbaka den, så flyttar sig skuggan omärkligt. Kärnan i konsten att undvika ljuset ligger i denna lilla vinkel."},"ICON-2265":{"nm":"Bladskydd för sandspade","de":"Trä det över den vassa spadspetsen och väskan blir säker. Lägg grävandets tapperhet åt sidan för en stund, för med ett enda skydd blir den en mild leksak. Att kunna dölja sin skärpa är också en form av omtanke."},"ICON-2266":{"nm":"Hörnklämma för strandmatta","de":"När vinden försöker lyfta mattans hörn biter jag hårt fast. Att hålla en enda plats på sanden handlar till syvende och sist om alla fyra hörnens envishet. En fladderfri eftermiddag är de små klämmornas förtjänst."},"ICON-2267":{"nm":"Klädkrok för parasollskugga","de":"Häng den lättvindigt på parasollstången och blöta kläder torkar i skuggan. Undan solen, ut i vinden – ett provisoriskt klädstreck upprättat av en enda krok. Även på stranden bor hushållets visdom."},"ICON-2268":{"nm":"Vattentät halsficka för mobil","de":"Bär man en telefon om halsen finner man modet att fotografera även under vattnet. Att skydda önskan om att fånga ännu en bild, torr och säker. Som livvakt åt minnen är den rätt så pålitlig."},"ICON-2269":{"nm":"Vattentät påse för blöta kläder","de":"Den tar emot dina ombytta, blöta kläder helt utan knot. Att inte låta en enda droppe nå resten av packningen är dess stolthet, så den håller munnen hårt stängd och vaktar ett hörn av väskan. En prydlig avslutning börjar med mig."},"ICON-2270":{"nm":"Vristrem för badsandal","de":"Den omsluter varsamt vristen så den barfota sandalen inte glider av. Spring hur mycket du vill över sanden, en enda rem räcker för trygghet. En pålitlig följeslagare till varje steg, obemärkt men alltid nära."},"ICON-2271":{"nm":"Vattentätt korthölje för halsen","de":"Den bär biljetter och kort om halsen och följer med ut i vattenleken. Plaska loss av hjärtans lust utan oro att tappa något, för den skyddar korten med sin egen kropp. En pålitlig livvakts hållning."},"ICON-2272":{"nm":"Imskyddstrasa för simglasögon","de":"Torka av simglasögonens immiga insida en gång med tyget, och världen under vattnet blir skarp igen. Ett enda litet tygfodral är nyckeln som öppnar en grumlad syn."},"ICON-2273":{"nm":"Borste för blöt sand","de":"Den sopar varsamt bort även sanden mellan tårna. Den sista handen som städar upp spåren efter en glad tur genom havet, precis vid dörren hem. En enda sopning med borsten, och en hel dags sand tar äntligen farväl."},"ICON-2274":{"nm":"Vattentät myntficka med dragkedja","de":"Den låser in några mynt tätt bakom dragkedjan. Blöt eller ej, skramlet är detsamma, så nödpengarna till kiosken vaktas ända in i mål. Liten men en riktigt sparsam och kapabel ficka."},"ICON-2275":{"nm":"Handduksrulleband","de":"Rulla ihop en handduk, bind den med ett enda band, och den fäster direkt vid väskans rem. Händerna fria, handduken på axeln. Hemligheten bakom lätt packning inför vattenlek gömmer sig i detta lilla knyte."},"ICON-2276":{"nm":"Nyckelringskapsel för vattentätt band","de":"Den avslutande knappen på bandet som skyddar en nyckel från vattnet. Först när kapseln klickar igen vågar man äntligen kasta sig i poolen med lugnt sinne. En liten men felfri punkt som tar ansvar för låsningens sista steg."},"ICON-2277":{"nm":"Snorkelns munstyckesplugg","de":"Bita fast, och luftvägen öppnas, och havslandskapet kommer rakt intill ögonen. En liten plugg som låter dig andas även under vattnet. Vem visste att det kunde vara så spännande att låna ut en andetag."},"ICON-2278":{"nm":"Imskyddsdyna för dykmask","de":"När maskens insida immar igen förlorar även synen under vattnet sin glans. En enda dyna håller den imman borta, så en klar sikt är verket av detta osynliga lager."},"ICON-2279":{"nm":"Tåklämma för simfenor","de":"Den spänner fentåspetsen så den sitter exakt om foten, så du sparkar vattnet utan slack. För att kraften i en enda sparkrörelse inte ska läcka bort knyter klämman tyst en stram liten knut vid tån."},"ICON-2280":{"nm":"Remöverdrag för dykmask","de":"Den omsluter mjukt maskens rem så den inte river i håret. Ett enda lager omtanke som suddar ut den där stickande stunden varje gång man tar av sig masken. Det ett litet överdrag tar hand om är, förvånande nog, ömhet."},"ICON-2281":{"nm":"Tömningsventil för snorkel","de":"Även i konsten att hålla andan finns en tyst springa där vatten sipprar in. En liten ventil styr varsamt tillbaka den strömmen och vaktar utrymmet att andas in ända till sista stund. Havet minns just denna obetydliga flit med störst tacksamhet."},"ICON-2282":{"nm":"Förvaringskrok för simfenor","de":"När fenorna hänger prydligt på en enda krok fäst i väggen sänker sig ett ordnat lugn även över det stökiga utrustningsrummet. Att lägga något på sin plats är det tystaste löftet inför nästa dyk."},"ICON-2283":{"nm":"Näsdyna för dykmask","de":"En enda dyna som varsamt trycker mot näsan. Tack vare denna lilla ömhet som hindrar vattnet från att tränga in behåller ansiktet sitt uttryck även i det kalla havet."},"ICON-2284":{"nm":"Toppskydd för snorkel","de":"Skyddet som rundar av snorkelns spets trycker tyst tillbaka vattnet när vågor sköljer över. Ju osynligare en dels arbete är, desto djupare bär den upp säkerheten i en enda andetag."},"ICON-2285":{"nm":"Halkfri remsa för fensula","de":"En smal remsa fäst på simfenans sula. Den är den enda friktionslinjen tårna griper tag i för att inte halka på ett blött däck. Säkerhet börjar alltid tyst i så här små strukturer."},"ICON-2286":{"nm":"Ventilskydd för syrgastub","de":"Ett lock som täcker ventilen på en tub fylld till brädden med luft. Så att damm inte kan lägga sig, så att luftvägen förblir ren. Att täcka över handlar om att i förväg ta hand om nästa persons allra första andetag."},"ICON-2287":{"nm":"Munstyckesskydd för andningsregulator","de":"Platsen som möter läpparna måste alltid vara den renaste. Detta enda skydd över munstycket vaktar tyst andningens ingång mot salt vind och sand."},"ICON-2288":{"nm":"Dragkedjeögla för våtdräkt","de":"En kort dragögla fäst vid våtdräktens dragkedja. Den är en omtänksam detalj tillagd så att även händer domnade av kallt vatten kan dra upp den i ett enda drag. Även att knäppa igen kläder bär spår av någons omsorg."},"ICON-2289":{"nm":"Skyddskapsel för luftmätare","de":"Skyddskapseln som omsluter glaset på mätaren som visar hur mycket luft som återstår. För siffrorna får aldrig bli otydliga. Ju mer en visare läser av livet självt, desto omsorgsfullare torkas och täcks den."},"ICON-2290":{"nm":"Spänne för viktbälte","de":"Människor spänner vikt om midjan för att sjunka ner i djupet. I den korta stund då ett enda spänne öppnas och stängs samlas valet mellan att stiga och att sjunka stilla vid fingertopparna."},"ICON-2291":{"nm":"Handledsrem för dykarlampa","de":"I det becksvarta vattnet håller en enda rem bunden om handleden lampan stadigt fast. Släpper man taget följer ljuset ändå med. Att inte förlora ett litet skimmer mitt i mörkret är just därför så tryggt."},"ICON-2292":{"nm":"Ordningsklämma för andningsslang","de":"En liten klämma som samlar spridda slangar till en enda. Förhindra trassel i förväg, så famlar inte händerna ens i ett kritiskt ögonblick. Att ordna är en tyst vänlighet mot ens framtida jag."},"ICON-2293":{"nm":"Fingerspetsförstärkning för dykhandske","de":"Förstärkningstyg lagt över varje fingerspets. Ställena som drar i linor och greppar klippor slits alltid först, så ett extra lager lades dit för att i förväg möta det slitaget med omtanke."},"ICON-2294":{"nm":"Basring för syrgastub","de":"En enda basring som håller en tung tub upprätt. Den famnar rund om en tyngd som annars lätt skulle välta och ger balans i sin runda omfamning. Att stötta är att erbjuda sin sida så att något inte ska falla."},"ICON-2295":{"nm":"Finneskydd för surfbräda","de":"Ett skydd som omsluter den vassa spetsen på brädans fena. Så att man inte skadar sig när man går på sanden läggs det vågskärande knivbladet en stund att vila. Under vilan får vem som helst gärna bli lite trubbig."},"ICON-2296":{"nm":"Spetsskydd för paddelblad","de":"Ett skyddande lock som vaktar spetsen på paddelbladet. Det hindrar skråmor från klippor att störa vattnets flöde. Vårdar man spetsen bär ett enda tag längre fram."},"ICON-2297":{"nm":"Greppöverdrag för kajakpaddel","de":"Ett grepp virat runt platsen där handflatan möter paddeln. Det polstrar mjukt stället där blåsor brukade bildas, så att händerna inte hinner ogilla paddeln ens medan man kämpar uppströms."},"ICON-2298":{"nm":"Förvaringsburk för surfvax","de":"En liten plåtburk som rymmer en klump vax. Den magi som fäster fötterna vid brädan hämtas alltid ur denna handflatestora dosa. Med en prydlig liten burk börjar dagens förberedelser."},"ICON-2299":{"nm":"Ankelögla för leash","de":"Öglan som spänner fast linan som förenar ankel och bräda. En enda knut som lovar att inte släppa taget om dig ens när en stor våg sveper förbi. Förbindelse är ett löfte att hålla fast så att man inte driver alltför långt bort."},"ICON-2300":{"nm":"Luftplugg för paddelbräda","de":"En bräda som stelnar när den fylls med luft, och pluggen som stänger inne den andan. Öppna den och den viks platt, stäng den och den reser sig på vattnet. En enda liten plugg rymmer en dag som sväller och sjunker ihop."},"ICON-2301":{"nm":"Kajaksätets dynrem","de":"En rem som binder fast dynan vid sätet. För ryggen och midjan som paddlar länge i sittande ställning håller den mjukheten på plats så att den inte glider bort. Även bekvämlighet behöver en fast knut."},"ICON-2302":{"nm":"Surfingbrädans nosskydd","de":"Ett skydd som omsluter brädans för. Det är stoppning fäst vid nosen, där kollisioner är vanligast, så att den ska bli den som slits ner först. Att lägga mjukhet just där vid platsen som leder är ett löfte om att använda den länge."},"ICON-2303":{"nm":"Vattentäta väskans spänne","de":"Ett spänne man viker och spänner fast två, tre gånger om för att inte släppa in en enda droppe. Att hålla det dyrbara torrt tar alltid ett handgrepp till. Den där sista fasta åtdragningen blir ett lugn i sinnet."},"ICON-2304":{"nm":"Futsalmålets nätbit","de":"En bit av nätet som en gång skakade i mållinjen. Tråd för tråd minns den jublet från stunden bollen fyllde det. I varje knut bodde ett mål, och i varje sliten fläck lever den dagens match ännu kvar."},"ICON-2305":{"nm":"Fotbollens pumpmunstycke","de":"Ett pumpmunstycke som blåser liv i en tömd boll. Läret som rullade omkring, alldeles platt och modlöst, studsar och fjädrar upp igen. Att fylla den är att resa en stannad lek på fötter igen."},"ICON-2306":{"nm":"Hörnflaggans fot","de":"En fot som ställer flaggan rak i planens hörn. Det är ett litet märke för gränsen, men med just den punkten får jordplanen äntligen formen av en arena."},"ICON-2307":{"nm":"Benskyddets fästrem","de":"En rem som binder benskyddet fast om vaden. Den håller stadigt fast den plats som ofta tar emot smällar, så att varje steg förblir orädd även mitt i hårda närkamper."},"ICON-2308":{"nm":"Dobbutbytespinne","de":"En pinne för att byta ut en sliten dobb mot en ny. De små tänderna vid tåspetsen som griper tag i gräset. För att inte halka måste man ibland bygga om alldeles från marken och upp."},"ICON-2309":{"nm":"Fotbollens ventilhatt","de":"En liten ventilhatt som försluter bollens andningshål. Den vaktar öppningen så att luften du fyllt på inte läcker ut. Att bevara spänsten liknar att inte tappa skärpan fram till nästa match."},"ICON-2310":{"nm":"Linjemarkeringskon","de":"En kon som drar linjer på marken för att dela upp vägen. Hit och inte längre är vårt lag, därifrån är motståndarnas. En liten kon förvandlar en rörig öde tomt till en lekplats med regler."},"ICON-2311":{"nm":"Futsalskons dammborste","de":"En borste som sopar bort jord och damm som fastnat i futsalskornas skåror. När matchen tar slut har även skorna samlat på sig en dags jord. Handen som borstar av är en tyst tacksägelse till fötterna som sprang så väl."},"ICON-2312":{"nm":"Målvaktshandskarnas torkhängare","de":"En hängare som torkar och håller målvaktens handskar. Det är platsen där de svettvåta händerna vilar en stund, lika många som skotten de stoppat. Inför nästa match torkar det våta, och det hårda hjärtat mjuknar sakta."},"ICON-2313":{"nm":"Basketkorgens näthakar","de":"De små hakarna som häktar fast nätet i ringen. Tack vare dem hörs det där mjuka svischet när bollen far igenom. Det klara ljudet av ett poäng börjar i själva verket vid just dessa små krokar."},"ICON-2314":{"nm":"Basketbollens luftsläppare","de":"Ett verktyg som släpper ut lite luft ur en alltför hård boll. För mycket spänst gör studsen vild. Att lätta på trycket precis lagom. En boll med god känsla föds alltid ur den där rätta balansen."},"ICON-2315":{"nm":"Målplattans sensordyna","de":"En sensordyna fäst bakom målplattan. Den läser av ögonblicket bollen vidrör den, tydligt, i siffror. Även det ögonblick ögat missade minns denna lilla känsel, så att domslutet blir desto rättvisare."},"ICON-2316":{"nm":"Dribblingskoner","de":"Hinderkoner uppställda längs dribblingsbanan. I slalomen mellan dem växer fotarbetet fram. Att stå i vägen är också en vänlighet, som lär ut hur man smiter förbi ännu bättre."},"ICON-2317":{"nm":"Basketbollens ventilborste","de":"En liten borste som rengör bollens ventilhål. Om damm täpper till går inte nålen in, så man rengör från den osynliga öppningen först. Innan man fyller på ska man alltid tömma och torka rent."},"ICON-2318":{"nm":"Fingertejprulle","de":"En rulle tejp som lindas om fingrarna. Den håller en stukad led stadigt, och skänker modet att gripa bollen igen. Att linda en skada är en liten förklaring om att man inte tänker sluta."},"ICON-2319":{"nm":"Ryggnummerklämma","de":"En klämma som fäster ryggnumret vid tröjan. I stället för ditt namn löper en siffra över planen. I det där ena fasta greppet som håller det på plats, står tydligt skrivet vem som spelar idag."},"ICON-2320":{"nm":"Skottövningens målring","de":"En målring som sätts in i korgen för att snäva in träffytan. Den krymper platsen bollen måste träffa, och tränar upp förmågan att uthärda missar. Kastar man mot den där smala porten tillräckligt länge lär sig fingertopparna till slut precision."},"ICON-2321":{"nm":"Basketskons sultorkare","de":"Innan du kliver in på planen böjer du knäna och torkar sulorna först. För att du inte vill lämna en enda halkning på trägolvet. Sätt det första steget med rena tåspetsar, och dagens du blir lite stadigare än gårdagens."},"ICON-2322":{"nm":"Volleybollnätets spännkrok","de":"Spänst syns inte med blotta ögat. Men i stunden kroken drar linan hela vägen och stannar, delar nätet planen i två med en handsbredd av spänning. En balans hållen av en osynlig hand väcker matchen."},"ICON-2323":{"nm":"Antennfästklämma","de":"Antennen som ständigt vajade i vinden står plötsligt rak med en enda klämma. Något litet som håller emot en stor sväng. Handen som tyst säkrar en enda kabel bakom scenen rör sig med precis lika mycket hjärta."},"ICON-2324":{"nm":"Liberons västhängare","de":"Försvarsspecialistens väst i avvikande färg hänger på väggen och väntar på nästa match. Inte iögonfallande, men ett namn som bär upp hela planen: liberon. Där, på den lägsta platsen, finns ögonen som ser längst."},"ICON-2325":{"nm":"Knäskyddspåse","de":"Ju mer man rullar över golvet, desto oftare tar knäna emot smällar. Den lilla påsen som prydligt förvarar skydden vet: bara den som först lär sig falla väl svävar till slut längst."},"ICON-2326":{"nm":"Volleybollens tryckmätare","de":"Man kan inte känna det med en knäpp på fingertoppen. Mätarnålen darrar svagt och pekar på ett enda streck. Att mäta en enda bolls andetag är matchens första knapp. Ur ärligt tryck föds en ärlig bana."},"ICON-2327":{"nm":"Dodgebollinjetejp","de":"En enda cirkel dragen med tejp på planens jordgolv. Dess inre och yttre delar ett halvdags universum av kull. Handen som drog linjen vet: regler är själva starten på leken."},"ICON-2328":{"nm":"Domarvisselns hållare","de":"När den skarpa vissselsignalen tystnar läggs den stilla tillbaka på sin plats på hållaren. Platsen som hör domarens andetag allra närmast. Rättvisa börjar alltid med den lilla uppgiften att hålla sin egen plats."},"ICON-2329":{"nm":"Passningsövningens väggmål","de":"I gryningen, utan någon att ta emot, sänder du fingertopparna tusentals gånger mot målet på väggen. Väggen är den mest överseende lagkamraten. Bollen den skickar tillbaka reser en trött dig på fötter igen."},"ICON-2330":{"nm":"Nätets höjdmätarstav","de":"Om nätet är så lite som ett finger för lågt går matchen snett. I stunden du lyfter mätarstaven blir rättvisa inte en siffra utan en daglig vana. Osynlig precision vakar över planen."},"ICON-2331":{"nm":"Startblockets vinkelpinne","de":"I den kurade positionen, vinkeln där tåspetsarna möter blocket, just den graden avgör starten. Med en enda pinne fixerar du blocket och lugnar andningen. Starthållningen följer tyst med ända fram till mållinjen."},"ICON-2332":{"nm":"Banans nummerflagga","de":"En liten flagga rest i varje bana viftar sitt nummer i vinden. Alla springer åt samma håll, ändå har var och en sin egen väg. Banan rymmer sida-vid-sida-likhet och olikhet på samma gång."},"ICON-2333":{"nm":"Stafettpinnens ändpropp","de":"Inför stunden den ska möta den sista löparens hand rundar ändproppen av kanterna. I en stafett är det viktigaste inte hastigheten, utan handen du räcker till nästa person."},"ICON-2334":{"nm":"Måttbandets hängare","de":"Måttbandet som antecknat resultaten hängs på väggen så att det inte trasslar. Platsen där gårdagens och dagens avstånd hänger sida vid sida. Tillväxt kommer alltid först som en liten skillnad i siffror."},"ICON-2335":{"nm":"Kurvmarkeringskon","de":"En liten kon placerad på kurvans insida viskar vägens avsikt. Skär inte för långt in, sprid inte ut för långt. Den som svänger väl leder till slut längst fram."},"ICON-2336":{"nm":"Mållinjebandets klämma","de":"Bandet som först ska nudda ett bröst håller klämman spänt och väntande. En lina som finns till för att brytas. Den härdar ut vinden hela dagen för någons enda sekund."},"ICON-2337":{"nm":"Startpistolens hölje","de":"Fram tills signalens smäll ljuder sover pipmynningen under sitt hölje. Ett kärl för ljudet som håller starten inneslutet. Ju djupare tystnaden, desto längre bär ekot av det första skottet."},"ICON-2338":{"nm":"Häckens höjdjusteringspinne","de":"Varje gång du höjer ribban ett steg flyttas pinnens plats med. Och rädslan växer med precis lika mycket. Ändå avvägar fötterna en aning högre punkt varje gång och springer vidare."},"ICON-2339":{"nm":"Varvräknarens vridskiva","de":"När du tappar räkningen på hur många varv som återstår vrider du skivan ett steg. Det lilla klicket av en krympande siffra ger benen ny kraft. Handen som räknar den återstående sträckan håller din fart."},"ICON-2340":{"nm":"Stavhopparens förvaringsställ","de":"En lång, svajande stav behöver en egen plats att luta sig mot. Eftersom det är ett redskap som måste böjas för att hoppa högt reser man den med extra omsorg. Väl förvarad spänst bär det högsta hoppet."},"ICON-2341":{"nm":"Sandgropens jämnkratta","de":"Sakta krattar du jämnt även de fotspår föregående idrottare lämnat. Sandgropen blir plan igen, som för första gången, varje omgång. Handen som suddar ut spår för någons hopp finns där, tyst och trofast."},"ICON-2342":{"nm":"Ansatslöpningens avståndsmarkering","de":"Ett steg för kort duger inte, och ett steg för mycket heller inte. Avståndsmarkeringen på marken visar ärligt var du ska sätta foten. Ett bra ansatslopp är ingen hänsynslös girighet utan lugn beräkning."},"ICON-2343":{"nm":"Diskusgrepp","de":"Halkar fingrarna är kastet redan kastat innan du ens kastar. Greppets skrovliga yta som omsluter diskusen håller rotationen i schack. Släppögonblicket börjar alltid i greppets känsla."},"ICON-2344":{"nm":"Kulstötningens vaggring","de":"En vaggring håller stilla den tunga järnkulan så att den inte rullar iväg. En liten bo som bevarar stillheten just före kastet. Ju mer explosiv kraften ska bli, desto fastare måste dess viloplats vara."},"ICON-2345":{"nm":"Spjutspetsskydd","de":"En keps trädd över den vassa spjutspetsen höljer den i mjuk tystnad. När ett redskap som ska flyga långt ligger stilla och tyst tyglas faran av omtanke. Säkerhet lever även i förvaring."},"ICON-2346":{"nm":"Höjdhoppsribbans hållhake","de":"Så att ribban inte faller ens vid en lätt beröring håller haken den med exakt balans. Platsen som ansvarar för den där darrande gränsen mellan klarat och missat. Rättvisa bor i de små detaljerna."},"ICON-2347":{"nm":"Landningsmattans hörnfäste","de":"Lyfter landningsmattans hörn kan någon skadas. Fästet trycker ner alla fyra hörnen stadigt. Så att kroppen som flög högst landar säkrast, stöttar det osynligt underifrån."},"ICON-2348":{"nm":"Kastcirkelns gränstejp","de":"Gränsen för kastplatsen dras med en enda tejplinje. Om du kliver på den linjen eller ej avgör om ett resultat lever eller dör. Den smala enkla linjen där frihet och regler möts, ett löfte."},"ICON-2349":{"nm":"Balansbommens gummifot","de":"Så att den smala balansbommen inte vinglar biter gummifoten stadigt tag i golvet. Den darrfria balansen som utspelar sig ovanpå är, i sanning, skapad av den osynliga fastheten där nere."},"ICON-2350":{"nm":"Räckets greppvirning","de":"Så att handflatan inte halkar lindar du en virning om räckets grepp. Hemligheten bakom den snurrande rotationen ligger inte i briljans utan i en hårt knuten hand. Svetten som droppat på mattan vet det."},"ICON-2351":{"nm":"Ringarnas höjdhake","de":"Om de två remmarnas höjd skiljer sig med bara en handsbredd rasar övningen samman. Haken håller tyst den balansen. Först ovanpå en exakt avpassad höjd kan den fria flykten börja."},"ICON-2352":{"nm":"Bygelhästens greppöverdrag","de":"Överdraget som omsluter greppet håller blåsor borta från handflatan. Under den snurrande, kretsande rörelsen finns en hand som skavts och läkts otaliga gånger. Skydd är ett milt löfte inför nästa övning."},"ICON-2353":{"nm":"Barrens avståndspinne","de":"Med en pinne ställer du in avståndet mellan de två barrarna exakt. Det tomma rummet kroppen ska korsa blir själva scenen. Fingertopparna vet det först: ovanpå ett exakt avstånd föds det djärvaste hoppet."},"ICON-2354":{"nm":"Hästens fjäderlock","de":"I ögonblicket du sparkar av mot brädan skjuter fjädern kroppen mot himlen. Locket omsluter den studsande kraften stramt. Den kortaste ansatsen skapar den längsta flykten genom luften."},"ICON-2355":{"nm":"Magnesiumpåse","de":"Det vita pulvret du gnider på händerna är en liten amulett som utplånar halkighet. Den korta riten att doppa handen i påsen och ta ut den lugnar rädslan. Även nervositet tyglas till slut vid fingertopparna."},"ICON-2356":{"nm":"Gymnastikbandets handledslindning","de":"När du lindar bandet om handleden dras även hjärtats snören åt samtidigt. Att i förväg hålla fast en led som annars skulle vackla. En väl bunden handled tillåter tyst en djärvare rotation."},"ICON-2357":{"nm":"Trapetsens säkerhetsring","de":"Just innan du kastar kroppen ut i tomrummet blir säkerhetsringen en osynlig hand. Först när rädslan för att falla försvinner kan du flyga längst. Tillit fullbordar flykten."},"ICON-2358":{"nm":"Tennisbollburkens lock","de":"Under locket som försluter burkens mynning sover nya bollar och håller sitt tryck. Det lilla poppet av att öppna en burk väcker matchens förväntan. En försegling är ett löfte som bevarar fräschören."},"ICON-2359":{"nm":"Rackettrådens spänningsklämma","de":"Klämman biter fast strängens spänst och släpper inte ända in i det sista. En enda strängs spänning avgör bollens studs. Den osynliga känslan börjar vid just den lilla klämman."},"ICON-2360":{"nm":"Tennisbanans linjesopare","de":"När matchen slutar sopar du sakta längs banans vita linjer. Sopa bort jorddammet och linjerna blir skarpa igen. Att bana väg för nästa match, den sista omsorgen som återupplivar banan."},"ICON-2361":{"nm":"Racketramens skyddskant","de":"Ett varv runt racketramen, och även hårda kollisioner tas emot mjukt och rundat. Jag vet att kanten är platsen som slits först. Eftersom mitt jobb är att ta på mig den slitningen i ditt ställe, står jag idag också längst ut."},"ICON-2362":{"nm":"Inomhusluftens temperaturchip","de":"Den kalla gryningsvinden som forsar in när dörren öppnas läser ett handflatstort chip av innan någon människa hinner. Att förnimma den innan din näsa ens hinner huttra, det är den tystaste hälsning som öppnar dagen i en tom idrottshall."},"ICON-2363":{"nm":"Baslinjeplattan","de":"För idrottaren som tvekar var tån ska sättas räcker en enda linje dragen på marken. Linjen man inte får korsa blir just startlinjen för det längsta hoppet, plattan viskar det ordlöst."},"ICON-2364":{"nm":"Tennisbollskorgens hängare","de":"Den rymmer dussintals bollar i en enda mun och tappar inte en enda. Att samla ihop det som spridits över banan och lämna det vidare till nästa övning, en hand som tyst arbetar i hörnet hänger här också idag."},"ICON-2365":{"nm":"Rackethandtagets ändpropp","de":"I stunden du knäpper fast den på handtagets ände vilar racket äntligen tryggt i din handflata. En enda liten propp skiljer halka från trygghet. Täpp igen änden ordentligt, så blir den första svingen fast."},"ICON-2366":{"nm":"Sidoplanens handdukklämma","de":"Även när vinden blåser hårt håller den munnen hårt stängd och står emot vid sidan av planen, så att den möjsamt urvridna handduken inte flyger iväg. Även att bevaka en kort andhämtningspaus har någons skickliga fingertoppar rört vid."},"ICON-2367":{"nm":"Fjäderbollens fjäderrätare","de":"Bara en enda fjäder i oordning och flykten vacklar. Räta försiktigt ut den skrynklade vingen, och fjäderbollen görs redo att flyga rakt igen. Att komma långt börjar alltid med små sådana här justeringar."},"ICON-2368":{"nm":"Fjäderbollsrörets propp","de":"Så att fjäderbollarna radade på led inte mjuknar, vrider du fast rörets ände hårt. Jag har sett länge nog för att veta att en enda fuktberöring får en fjäder att sjunka ihop. Att förvara väl är redan en del av matchen."},"ICON-2369":{"nm":"Pingisbollens rullstöd","de":"Den lilla bollen som rullade förbi hämtar andan en stund ovanpå mig. Att stilla stötta den så att den inte trillar av, det är den rundaste formen av omtanke, given vid bordets sida."},"ICON-2370":{"nm":"Bordtennisrackets gummiroller","de":"Rulla rollern lugnt över gummiytan och gammalt damm lyfter medan klibbigheten väcks till liv igen. Rotationen måste leva för att bollen ska kurva. Rackets kondition idag vaknar med just denna enda ömma skötsel."},"ICON-2371":{"nm":"Nätets höjdmätsticka","de":"Är nätet så mycket som en handsbredd högre förändras spelets karaktär. De som vägrar lita på ögonmåttet till slut tar fram mig mot det. Rättvisa, tycks det, kommer bara från en höjd mätt exakt efter regeln."},"ICON-2372":{"nm":"Fjäderbollens hastighetschip","de":"Fjäderbollens fart genom luften räknar jag tyst ut. När den tidigare osynliga farten sjunker ner till en tydlig siffra blir tränarens nästa ord desto klarare. Det är arbetet att göra en aning till ett faktum."},"ICON-2373":{"nm":"Pingisbollens förvaringskapsel","de":"Lägg en rund boll varsamt i kapseln, och repor och damm viker undan på avstånd. I hopp om att den ska hålla sig oskadd till nästa match, är det hjärtat som ger bort ett helt litet rum."},"ICON-2374":{"nm":"Badmintonrackets stränghängare","de":"Häng upp de slaka strängarna prydligt, så famlar inte nästa hand i tur. Ordning är trots allt som en vänlig lapp skriven i förväg till morgondagens jag. Idag underlättar för imorgon."},"ICON-2375":{"nm":"Bordtennisrackets kantskydd","de":"Kanten där gummit lätt lossnar omfamnar jag tyst med en enda rand. Om randen spricker rubbas till och med bollens karaktär. Att skydda kanten blir till slut att skydda en enda poäng."},"ICON-2376":{"nm":"Squashbollens värmepåse","de":"En kall boll studsar knappt alls. Före matchen, en påse som värmer och vaggar den varm som en handflata. Den lilla värmen som förs över till handen bestämmer i förväg andningen och rytmen för en omgång."},"ICON-2377":{"nm":"Lacrossenätets maskklämma","de":"När en maska i nätet sakta börjar lossna biter jag tyst tag i just den maskan. Nätet måste vara spänt för att bollen ska stanna kvar. Här finns handen som håller ihop hela matchen från en osynlig plats."},"ICON-2378":{"nm":"Squashrackets spetsskydd","de":"Ju hårdare du svingar mot väggen, desto mer gråter racketen först från spetsen. Linda den gråtande spetsen varsamt, och den spelar med dig en säsong till. Den som vet att spara på spetsen håller till slut racketen länge."},"ICON-2379":{"nm":"Hockeyklubbans bladskydd","de":"Trä skyddet över det vassa bladet, och äntligen kan både väska och fingertoppar slappna av. Att tyst söva ett farligt föremål, det är den gamla artighet man visar först när man packar ihop klubban."},"ICON-2380":{"nm":"Cricketbollens polerduk","de":"Gnid den röda bollen med duken och en sida håller ljuset som en spegel. Bowlern vet med fingertopparnas känsla att bollen kurvar när glansen lever. Även i den omsorgsfulla poleringen bor en tyst strategi."},"ICON-2381":{"nm":"Lacrossebollrörets lock","de":"Så att de hårda bollarna inte rullar iväg som de vill, vrider du fast rörets mynning stadigt. Att lugnt samla det som lätt sprids ut på ett ställe, grundprincipen för god skötsel är alltid såhär liten."},"ICON-2382":{"nm":"Squashväggens målmärke","de":"Ett litet mål fäst i väggen samlar den vacklande spelarens blick till en enda punkt. Den enda punkten som avgör vart du ska sikta, till och med den breda väggen krymper till en tydlig prick framför denna lilla bit."},"ICON-2383":{"nm":"Hockeyklubbans greppslida","de":"Flytta greppet handen känner till över på en obekant ny klubba, och i samma stund blir redskapet på en gång ditt. En liten slida som låter dig klä på förtrogenheten direkt, det är genvägen till att bli hemmastadd."},"ICON-2384":{"nm":"Fältmålets näthängare","de":"Först när nätet hängts på målet blir ett mål verkligen ett mål. Det var alltid nätet som höll fast, ända till slutet, det korta ögonblicket en boll fyllde det. På platsen som fångar formen av det utbrytande jublet finns jag."},"ICON-2385":{"nm":"Skridskoskenans skydd","de":"Med bar skena vågar man inte ta ett enda steg utanför isen. Lämnar du isen, trä på mig, snälla. Att tyst söva skärpan är också en etikett skridskoåkare länge upprätthållit."},"ICON-2386":{"nm":"Skridskoskons snörhängare","de":"De avtagna stövlarnas långa snören hänger du prydligt, rem för rem. Snören lösta så att de inte trasslar öppnar nästa isstund mjukt. Dagens avslut blir, just så, förberedelsen för morgondagen."},"ICON-2387":{"nm":"Skridskoskenans handduk","de":"På en skena just av isen samlas små droppar likt daggpärlor. Torka bort den fukten varsamt, och rosten går förbi. Att tyst samla in de spår kylan lämnat, det är min dag."},"ICON-2388":{"nm":"Skridskoskons ankeldyna","de":"Vacklar ankeln en enda gång rasar hela glidningen samman. En dyna som omsluter den stadigt och håller fotfästet fast. Den där graciösa balansen på isen börjar alltid först, osynligt."},"ICON-2389":{"nm":"Skridskoskyddets förvaringspåse","de":"En liten påse i väskans hörn för att varsamt lägga in skenskyddet. Vanan att packa det som behövs, utan att missa något, håller utrustningen vid liv länge. En ordnad väska är själva den första scenen av en god glidning."},"ICON-2390":{"nm":"Skridskoskons sulklämma","de":"Så att innersulan i stöveln inte tyst glider ur läge håller den fast under foten. Rubbas platsen du sätter ner foten på, rubbas även hoppet. Handen som griper den lägsta platsen hjälper till slut det högsta hoppet."},"ICON-2391":{"nm":"Skridskoskyddets spänne","de":"Så att skyddet inte glider av spänner du fast det hårt med en ögla. Jag vet att ett löst skydd till slut inte är något skydd alls. En enda väl fastspänd ögla vaktar den skenan ända till slutet."},"ICON-2392":{"nm":"Skridskoskons snörlåscap","de":"Dra snörena hårt och lås dem med capsen, och nu lossnar de aldrig mer. Att knyta ihop utan en enda glipa, ordentligt ända från tåspetsen, det är den stadigaste knuten som knyts innan det första steget på isen."},"ICON-2393":{"nm":"Skridskoskenans torkduk","de":"Från en skena som just avslutat en glidning samlar du tyst in den samlade fukten. Jag vet att en skena lämnad våt gråter. Bara en skena torkad mjuk och torr ritar nästa kurva tydligt på isen."},"ICON-2394":{"nm":"Skidstavens handtagslock","de":"Omslut stavhandtagets ände mjukt, och den gripande handflatan blir desto bekvämare. Kraften som skär genom snöfältet kommer, till slut, från just den stadigt hållna platsen. Ett litet lock bär upp en lång utförsåkning ända till slutet."},"ICON-2395":{"nm":"Snowboardbindningens pinne","de":"I stunden den lilla pinnen som länkar bräda och fot lossnar stannar berget framför dig. En bit svår att upptäcka men den första att kontrollera, denna fasta förbindelse blir frihet på snöfältet."},"ICON-2396":{"nm":"Skidkantens spetsklämma","de":"Så att den vassa kanten inte river upp insidan av väskan biter du varsamt tag i spetsen. Att lugna skärpan till sömns, det är den vänliga avslutningen given efter en god åktur nerför berget."},"ICON-2397":{"nm":"Snowboardens nosskydd","de":"Omslut brädans nos ordentligt, och även en frontal kollision sprids mjukt ut. Att tyst vakta platsen som slår emot först, modet inför en brant utförsbacke börjar just här."},"ICON-2398":{"nm":"Skidpjäxans spännskydd","de":"Så att spännet inte skadas i mötet med kall snö täcker du det varsamt. Ännu ett lås som vaktar låsmekanismen, detta lilla skydd förlänger stillsamt pjäxans säsong lite till."},"ICON-2399":{"nm":"Snowboardleashens ögla","de":"Så att brädan inte kan fly långt även om den lämnar din hand, länkar jag ankel och bräda med en enda lina. Så att du, även om du tappar greppet, ändå aldrig förlorar den för gott, det är en tyst ögla av trygghet, hängd vid änden av ett långt rep."},"ICON-2400":{"nm":"Skidsulans skrapspets","de":"Det gamla vaxet som stelnat fast på sulan skrapar du bort, jämnt och smidigt. Bara genom att sopa rent det gamla väcks ny glid till liv. En sula omsorgsfullt tillredd öppnar nästa snöfält desto snabbare."},"ICON-2401":{"nm":"Snowboardnosskydd","de":"Innan brädan skär genom snön är det nostippen som först rör vid världen. Varje stöt tas emot av den här lilla gummibiten. Längst fram, sliten utan att någonsin skryta om det – någons utförsåkning glider fram över denna trubbiga hängivenhet."},"ICON-2402":{"nm":"Skidstavskorgring","de":"Just som staven är på väg att sjunka djupt ner i snön känner denna runda ring efter marken i dess ställe. En cirkel som tyst stöttar ett steg som nästan slant. Osynlig håller den sig ändå nära, som en hand som hindrar dig från att glida."},"ICON-2403":{"nm":"Kantvaxborstlock","de":"När putsningen är klar täcks borsten varsamt innan pulvret hinner torka. Att försegla dagens mjukhet så att inte en enda strå kommer i olag. Så att när du öppnar den nästa gång väntar gårdagens omsorg precis som den var."},"ICON-2404":{"nm":"Öronvärmarkrok","de":"Minns du? Öronvärmarna som glömdes bort en stund bredvid väskan när våren kom. Ändå är de de första som kallas fram natten då nyheten om första snön hörs. Det finns en särskild plats att hänga årstiden på, och den här kroken glömmer aldrig det löftet."},"ICON-2405":{"nm":"Brynstensfodral","de":"För att vässa en kniv måste man först väta stenen – en ordning lika inövad som mormors handlag. Även ett verktyg som tämjer slöhet behöver en plats att vila på, så det här lilla huset rymmer brynstenen och väntar på nästa putsning."},"ICON-2406":{"nm":"Vaxblockspåse","de":"Själva ämnet som skapar en lysande glidfärd ligger tätt packat och sover inuti. En kompakt tyngd, som håller om en hårdnad klump. Glidfärden löses alltid ur denna stilla vikt och sprider sig ut över snöfältet."},"ICON-2407":{"nm":"Handvärmarpåseögla","de":"På en vinterpromenad är det platsen fingrarna först famlar efter i fickan. Den ger ett fast hem åt den lilla värmen som tinar frusna händer. Ju kallare dagen är, desto snällare blir denna lilla ögla."},"ICON-2408":{"nm":"Slipstensstöd","de":"Om den vacklar blir eggen skev, så den fäster sig själv stadigt först. Ett stöd som aldrig rör sig, allt för att ansvara för någon annans precision. Någons raka eggkant står på denna tysta stadga."},"ICON-2409":{"nm":"Halsvärmarclips","de":"På en kall, blåsig skolväg, i samma stund som halsvärmaren börjar glida ner – klick, fast i kragen. Även värme måste hålla sin plats för att verkligen värma. Ett litet klickljud håller fast morgonens värme."},"ICON-2410":{"nm":"Vaxstrykjärnsöverdrag","de":"Medan ytan som arbetat så hett svalnar, skyddar ett enda tygstycke den tyst från damm. Ett verktyg som tar hand om ett annat som förberett glidfärden. Omsorgen fortsätter så här, i tysthet."},"ICON-2411":{"nm":"Kantoljepennlock","de":"Öppnas den en gång och torkar ut, kan du inte dra nästa linje. Att stänga den är alltså detsamma som att öppna nästa – det här lilla locket förseglar fuktigheten vid spetsen och lovar i förväg morgondagens penndrag."},"ICON-2412":{"nm":"Pompongtopp","de":"Hundratals trådar utgår från denna enda punkt och sprids i takt, alla på en gång. Svajandets prakt börjar alltid från en stadigt fäst plats. Nedanför scenen, den första knuten som får läktaren att svalla i vågor."},"ICON-2413":{"nm":"Ljusstavsrem","de":"Efter två timmars hejande, i samma stund som du nästan tappar din ljusstav, för det här bandet den tillbaka i din hand. Önskan att inte förlora den ens när den faller. Den ömma oron har format en ögla runt din handled."},"ICON-2414":{"nm":"Sittdynefällbeslag","de":"Att fara upp och sätta sig ner igen dussintals gånger under hejandet. Under tiden viker det här lilla beslaget prydligt ihop dynan och vaktar din plats. Även i en uppspelt folkmassa finns en hand instoppad som tar hand om någons plats."},"ICON-2415":{"nm":"Hejabandanaögla","de":"Den dag samma mönster breder ut sig över hela läktaren binder ett enda tygstycke tiotusentals hjärtan till en enda färg. Den första punkten där den vågen börjar är denna lilla ögla – platsen där ett hejarop som varit ensamt blir till oss."},"ICON-2416":{"nm":"Klapparhalva","de":"Klappar man ensam blir det ett litet ljud; samlas det på läktaren blir det en våg. Den ena halvan som ärligast känner sanningen att den bara ljuder när den möter en annan. I stunden din klapp möter min växer hejaropet."},"ICON-2417":{"nm":"Hejaskylthörnskydd","de":"Den lindar det vassa hörnet runt, så att personen bredvid inte blir skadad. Även i ett hänfört vinkande finns omtanke instoppad för varandra. Ett hejarop blir varmare där det är så här runt."},"ICON-2418":{"nm":"Bandflaggstångshållare","de":"Även när fladdrandet stannar av står stången rak och väntar på nästa jubelrop. En plats som vilar stilla en stund för att kunna svaja igen. Mellan det ena ropet och det andra, en kort tystnad där bandet hämtar andan."},"ICON-2419":{"nm":"Ropsolfjäder","de":"Så att en persons rop ska nå ända till scenkanten smalnar solfjäderformen av ljudets väg. En mun som alltid grubblar mer över hur budskapet ska nå fram än över hjärtats storlek. En form skapad av längtan att nå lite längre."},"ICON-2420":{"nm":"Pinsbaksideslock","de":"Innan den fästs på bröstet och efter att den tagits av, börjar och slutar märkets vila här. Ett litet hus som tryggt bäddar ner den vassa baknålen. Även en glittrande punkt behöver en plats att ligga ner och vila en stund."},"ICON-2421":{"nm":"Poängtavlesifferbricka","de":"Den bär omsorgen från en tid då varje mål byttes in för hand. Före den digitala eran ristades utgången in en ruta i taget av mänskliga fingertoppar. En bricka där även en enda siffra rymde någons spänning."},"ICON-2422":{"nm":"Taktiktavlemagnetpjäs","de":"Efter tränarens fingertoppar byter försvar och anfall plats. Varje bild i huvudet innan matchen ritas först upp i dessa små prickars förflyttning. Utgången spelas ut en gång i förväg, på tavlan."},"ICON-2423":{"nm":"Poängtavlebländskärm","de":"Så att de bländande siffrorna inte ska sudda ut en spelares blick, skär skärmen bort ljuset. Även ljusstyrka måste ibland skuggas lagom för att göra sitt jobb. På den ljusaste platsen, en skugga som arbetar allra tystast."},"ICON-2424":{"nm":"Poängvändarring","de":"Varje gång ett blad vänds byts siffran och jublet stiger för att följa med. Ett spår från den analoga tiden, då resultaten förnyades genom handens känsla. En tid då hjärtat vändes om, i samma stund som poängen vändes om."},"ICON-2425":{"nm":"Taktiklinjepennfodral","de":"Varje rörelseväg ritad på klädkammarens whiteboard kommer från den här pennan. Ett litet, stadigt fodral som ruvar på matchens skiss. I tystnaden inför drabbningen, platsen som bär flest ord."},"ICON-2426":{"nm":"Poängräknarklickare","de":"Varje tryck lägger till en ruta, räkningen stiger med ett tydligt klick. Lämna siffrorna åt fingrarna, så kan hjärtat vändas helt mot spelet. En liten rytm som lättar bördan av att räkna."},"ICON-2427":{"nm":"Poängtavlekabelskydd","de":"Bakom det strålande ljuset ligger alltid trassliga, ostädade sladdar. Arbetet med att prydligt täcka över det oredan. Först när det osynliga hålls i ordning kan det synliga äntligen lysa."},"ICON-2428":{"nm":"Taktiktavlesuddborste","de":"När en omgång är slut rensas ytan för nästa bild. En ny strategi kan bara någonsin börja på en tom yta. Suddborsten är i själva verket det första penseldraget i nästa spel."},"ICON-2429":{"nm":"Poängflaggklämma","de":"Den håller fast en flagga på väg att blåsa bort i vinden och släpper inte taget. Så att det fladdrande tyget behåller sin plats. Även arbetet med att kungöra resultat för världen behöver först en hand som håller stadigt."},"ICON-2430":{"nm":"Domarvisselsnörklämma","de":"Vid en enda vissling stannar matchen och flyter igen. En liten knut som fäster den auktoriteten stadigt vid halsen. Fram till visslan ljuder är det också klämmans uppgift att hålla tystnaden prydligt bunden."},"ICON-2431":{"nm":"Måttbandsrulle","de":"Den samlar den uppmätta längden tillbaka in i sig själv. Att mäta är, i slutändan, upprepningen av att rulla ut och rulla in. Ett handtag som utan knot hjälper den enkla resan tur och retur, och som snurrar varje gång bakom precisionen."},"ICON-2432":{"nm":"Domslagsflaggfodral","de":"Flaggan som beslutsamt skilde inne från ute viks prydligt ihop och vilar när matchen är slut. Även den tydliga signalen hämtar andan en stund inför det som kommer. Även beslutsamhet har sin tysta vila."},"ICON-2433":{"nm":"Stoppursögla","de":"Den hänger den flytande tiden på en enda plats, inte på handleden. Stilla innan mätningen, sedan iväg i samma stund den kallas – en station för tiden. Ett litet hem för sekunder, som håller andan och väntar på startsignalen."},"ICON-2434":{"nm":"Linjeritarhjul","de":"Var den än rullar lämnas en tydlig vit stig kvar. Reglernas gränser ristas så här in i marken, ett prydligt varv i taget. Innan matchen börjar, hjulet som lämnar det första fotavtrycket på planen."},"ICON-2435":{"nm":"Domarkortsficka","de":"I beslutets ögonblick sover kortet som dras fram ur bröstfickan här. Väntrummet för ett domslut som håller tyst ända till det visas. En ficka alltid redo och väntande, i hopp om att aldrig behöva dras fram."},"ICON-2436":{"nm":"Vågloddstöd","de":"Arbetet med att väga är ärligt bara på ett golv utan minsta skakning. Ett stöd som bär loddet medan det erbjuder sin egen kropp platt och stilla. Det första steget mot exakt mätning börjar alltid på en stilla plats."},"ICON-2437":{"nm":"Startklickare","de":"Vid ett enda ljud sparkar alla fötter samtidigt loss från marken. Starten är ytterst kort, men handen som skapar den korthetens ro är lugnare än någon annan. En hand som löser upp startlinjens skälvning med bara ett enda klick."},"ICON-2438":{"nm":"Konbas","de":"Namnet är okänt, men uppgiften är tydlig – den bär tungt upp mitten av en arena som liknar en scen. I mitten där alla lyser finns alltid ett osynligt ben som tyst härdar ut."},"ICON-2439":{"nm":"Bukandningsbältesspänne","de":"Att god klang inte kommer från strupen utan från ett djupt andetag, det vet midjan först. Ett spänne som låter handflatan känna magen svälla och sjunka. Sångens startpunkt ligger alltid under detta enda andetag."},"ICON-2440":{"nm":"Andningsfjäderbricka","de":"När fjädern gungar lätt vid din andedräkt är det ett tecken på att andningen är jämn. Den ger stillsamt form åt den osynliga andningen och lär ut sångens grund. En övning som med ögonen lär sig andetaget före den första tonen."},"ICON-2441":{"nm":"Andningstimglas","de":"Inuti glaset rinner sanden ner som ett andetag. Andas in, håll en stund, andas långsamt ut – kornen räknar takten åt dig. Betrakta den ljudlösa fallande sanden en stund, och innan du vet ordet av faller din splittrade andning i led."},"ICON-2442":{"nm":"Ljusövningsstativ","de":"Tänd veken, och rösten darrar med den fladdrande lågan. Någon skar fram denna plats med omsorg, för att en stund hålla den lilla darrningen stilla. Lika tjockt som stearinet som stelnat och byggts upp, så mycket samlas här av nätterna man sjöng ensam."},"ICON-2443":{"nm":"Magtryckkuddrem","de":"Istället för att lägga en hand på magen trycker ett enda band tyst mot den platsen. Det spänns när andan sväller och lossnar mjukt när allt är tömt. En tyst liten följeslagare vid din sida, som hjälper kroppen minnas takten först."},"ICON-2444":{"nm":"Andhållningsballonglock","de":"Blås inte ut hela ballongen på en gång. Länge, långsamt, driv den ända till slutet. Medan du biter i locket och släpper ut luften når den ner till lungornas allra djupaste del. En sång flyger, i slutändan, lika långt som andetaget du höll ut."},"ICON-2445":{"nm":"Andningshandtag","de":"Ju mer hjärtat vacklar, desto mer vill handen gripa tag om något. Ta tag i detta handtag och axlarna sjunker ner av sig själva, inandningen blir en handsbredd längre. Att lära sig greppa är att lära sig samla sig själv, det vet handflatan först."},"ICON-2446":{"nm":"Magmuskelvibrationsögla","de":"Haka bandet på öglan så sprider sig en mild vibration till mitten av magen. Styrka samlas tyst just på den platsen som darrar när du skrattar högt. Ett stadigt centrum växer alltid långsamt så här, på en plats ingen ser."},"ICON-2447":{"nm":"Andningsräknarskiva","de":"Ett, två, tre – varje gång skivan klickar ett steg vidare ristas djupet av det dragna andetaget in. Lägg till ett steg och sången håller en fras längre. På denna lilla skiva antecknas tyst den lungkapacitet du byggt idag."},"ICON-2448":{"nm":"Tungövningsskedbricka","de":"Platserna där tungspetsen ska landa är tydligt inristade på brickan. Hur man rullar, knäpper till och pausar en stund. Bakom ett uttal som flyter fram mjukt döljer sig otaliga gryningar då tungan lärde sig sin väg utantill så här."},"ICON-2449":{"nm":"Munformspegelklämma","de":"Klämman håller varsamt fast munformen som speglas i spegeln. 'A' är rund, 'i' sträcker sig långt åt sidorna. En tyst lektion bara mellan dig och spegeln, där klangens form finslipas medan du möter ditt eget ansikte rakt på."},"ICON-2450":{"nm":"Uttalskorksäl","de":"En liten säl skuren i kork sitter i skrivbordets hörn och lyssnar på uttalet. Nätter då 'r' ständigt slinter och modet sjunker säger sälens runda ögon tyst: Det är okej, låt oss försöka en gång till."},"ICON-2451":{"nm":"Textandningsnål","de":"Var i texten man ska andas – det berättar den här nålen först. Sätt den i slutet av en rad, och den platsen blir sångens ömma komma. För att sjunga fritt behöver även en mening ett litet mellanrum att andas i."},"ICON-2452":{"nm":"Diktionshakstöd","de":"Stötta hakan bara lite, och uttalet som höll på att spridas ut hittar sin plats. Tydligt tal är inte munnens verk ensamt – det byggs av haka, strupe och andedräkt tillsammans. Detta lilla stöd hjälper tyst till med den knepiga balansen."},"ICON-2453":{"nm":"Vokalmunformsstativ","de":"A, e, i, o, u – ett stativ som ställer upp, precis som de är, vägarna dessa fem vokaler tar ut ur munnen. Ställ det stilla bredvid spegeln och forma klangens skelett varje dag. Varje sångs stomme börjar, i slutändan, från dessa fem vokaler."},"ICON-2454":{"nm":"Tungvrickarkort","de":"Ett kort så trassligt att tungan snubblar när man läser det och skrattet till slut bryter ut. Det är verkligen okej att göra fel – att göra fel är själva övningen. Varje gång du tar dig förbi denna busiga mening vaknar ännu ett ljud klart och tydligt."},"ICON-2455":{"nm":"Läpplösningspropp","de":"En uppvärmning som fladdrar läpparna för att väcka en stel mun. Bit i proppen och släpp ut luften länge, så lossnar de sovande läpparna mjukt upp. Den minsta, snällaste uppvärmningen för att öppna första frasen varsamt."},"ICON-2456":{"nm":"Textavsnittsgummiband","de":"Linda ett gummiband runt avsnittet som ständigt fastnar. Varje gång du ser den platsen på handleden dyker dagens berg att bestiga upp i tanken. Ju svårare takten är, desto oftare tittar du på den, desto längre bär du den i hjärtat."},"ICON-2457":{"nm":"Halsvärmesjalskrok","de":"Så att strupen inte ska bli hes i den kyliga gryningsluften vid årstidsskifte hängs sjalen stadigt på kroken. Först från en varmt insvept hals löses en klar klang äntligen ut. Att vårda rösten börjar alltid med att först vårda halsen."},"ICON-2458":{"nm":"Stämbandsvibrationsspets","de":"När rullens spets sakta rullar längs halsens sida vaknar stämbanden som sovit hela natten sakta till liv. En lätt vibration löser upp den stela spänningen, och den tveksamma första tonen blir mjukare. En beröring som värmer kroppen innan sången."},"ICON-2459":{"nm":"Nynningskoppunderlägg","de":"Med läpparna slutna, nynnande sakta, omslut en ångande varm kopp med båda händerna och strupen värms med. En låg nynning sprider sig i cirklar över underlägget. En sång börjar så här, från en klunk ljummen värme."},"ICON-2460":{"nm":"Halstablettkapsel","de":"För dagar då strupen sjunker skrovlig och sträv samlas karameller stilla inuti kapseln. Rulla en i munnen strax innan du går upp på scen, och sval mint öppnar den täppta strupen svalt. Lite tröst för nödfall, förvarad i en egen liten burk."},"ICON-2461":{"nm":"Ångkompresspåse","de":"Linda påsen, fint genomdränkt av varm ånga, runt halsen, och platserna som stelnat av lång övning smälter mjukt bort. Med samma sköna värme som en nystruken handduk erbjuder den tyst en takts vila åt trötta, försjunkna stämband."},"ICON-2462":{"nm":"Stämbandsvilotimglas","de":"Det tysta löftet att inte tala idag räknas mjukt ut av smala sandkorn. Att sluta munnen en stund och spara på rösten. Den tystnaden, som också är den bästa omsorgen av alla, flyter sakta här."},"ICON-2463":{"nm":"Läpptrillpropp","de":"En läpptrilla som rider upp och ner på tonerna medan läpparna fladdrar lätt. Bit varsamt i proppen och den egensinniga skälvningen samlar sig till något betydligt jämnare. Ett handflatestort litet redskap som mjukt fäster den första knappen i röstbildningen."},"ICON-2464":{"nm":"Halsfuktarspray","de":"Så att strupen inte ska torka ut på en torr scen, tryck på locket och spraya en fin dimma. Ta ett djupt andetag av den fuktade luften, och den uttorkade rösten återfår sin klara glans igen."},"ICON-2465":{"nm":"Röstlösningsboll","de":"Håll den fint darrande bollen stilla i handflatan, och vibrationen stiger mjukt uppåt genom armen till strupen. En rund, vänlig uppvärmningskamrat som sakta skakar liv i röstorgan som stelnat av spänning."},"ICON-2466":{"nm":"Formationsmärke","de":"En liten markör fäst i scengolvet. Här är din plats, där borta är min. När flera samlas för att teckna en enda bild håller den tyst alla på plats – ett osynligt löfte om att ingen sprids ut."},"ICON-2467":{"nm":"Rörelsepilbricka","de":"En pilspetsformad bricka pekar tydligt mot nästa stegs riktning. Var man ska svänga, var man ska stanna – golvet talar om det först, så att ingen tappar bort vägen. En rörelseväg är en karta som tåspetsarna memorerat genom otaliga steg."},"ICON-2468":{"nm":"Formationsmittnål","de":"Den enda punkten som tyst blir referens när många samlas. Kring denna nål ritas en cirkel rund, och formationen öppnar sig vid. Även spridda rörelser hittar sin ordning med bara en enda mittpunkt."},"ICON-2469":{"nm":"Korsningskil","de":"Där två vägar möts på en enda plats slås en kil fast stadigt ner. Så att de inte krockar, så att de inte korsar och kolliderar. Även i det andlösa, flyktiga ögonblicket då man passerar varandra tappar ingen bort vägen."},"ICON-2470":{"nm":"Utgångsflagga","de":"När den sista tonens eftersvall dör bort glider man tyst ut åt det håll flaggan pekar. Att gå ut får inte vara mer stökigt än att gå in. Även scenens avslutning har en riktning utlovad i förväg."},"ICON-2471":{"nm":"Avståndsmåttbandsklämma","de":"Håll fast måttbandets ände stadigt med klämman, och en handsbredd efter en annan blir ofelbart exakt. Även avståndet mellan människa och människa jämnas till prydligt, som mätt med en linjal. En vacker scen föds alltid ur så här omsorgsfulla fingertoppar."},"ICON-2472":{"nm":"Uppställningsögla","de":"Haka snöret på öglan och dra det spänt i en enda linje, så blir den tunna linjen normen alla ska stå jämsides efter. Att en rad ser så prydlig ut beror på just denna raka, osynliga linje."},"ICON-2473":{"nm":"Rörelsevägsprickbit","de":"Bitar som tyst ritar en väg på golvet med prickad linje. Gå längs dessa svaga märken, och du går inte vilse ens i mörkret. Medan prick efter prick fogas samman, smälter spridda fotsteg samman till ett enda flöde."},"ICON-2474":{"nm":"Positionsgolvstift","de":"En häftstift tryckt in i golvet så att du inte glömmer din plats. Även i becksvart mörker famlar tårna sig fram till den lilla knölen och hittar den ofelbart. Först när du stannar exakt på den punkten strömmar ljuset äntligen ner över dig."},"ICON-2475":{"nm":"Halsisoleringsband","de":"Om hakan följer med skälver och splittras rösten också. För att lära sig röra bara halsen medan huvudet hålls stilla lindas bandet på. Bakom en rörelse som verkade så fri finns denna tysta övning i isolering."},"ICON-2476":{"nm":"Axelfixeringsklämma","de":"Så att axlarna inte ska rycka upp av egen vilja hålls kudden stilla med en klämma. Så att kroppen tydligt skiljer på var den ska svaja och var den ska stå still. En återhållen linje föds alltid ur sådana små grepp om stadga."},"ICON-2477":{"nm":"Revbensbältesspänne","de":"Bältet läser tyst av den fina väven i revbenen som vidgas och dras samman igen. Spänn spännet, och andningens rörelse förs klart fram till fingertopparna. Djup, stadig röstbildning har sitt ursprung i denna osynliga rörelse hos benen."},"ICON-2478":{"nm":"Höftgungpendel","de":"Pendeln svänger sakta från sida till sida och berättar tyst om rytmen höfterna tecknar. En handflatestor liten vikt lär utan ord hur kroppens centrum flyttar sin tyngd. Att även svajande har en ådring."},"ICON-2479":{"nm":"Handledsvridningsögla","de":"Haka öglan på handleden och vrid sakta inåt, sedan utåt, och lederna som stelnat hela natten löses mjukt upp. För en rörelse som når levande ända ut i fingertopparna måste handleden först bli smidig. Denna lilla vridning öppnar ett större uttryck."},"ICON-2480":{"nm":"Fotledsmotståndssnöre","de":"Trä ringen på fotleden och dra i snöret, och med varje steg du tar fastnar ett milt motstånd vid tårna. Lika tungt som du trampar, lika tyst byggs styrka i benen. Ett fjäderlätt hopp står alltid på en så här tung övning."},"ICON-2481":{"nm":"Kärnfokussandsäck","de":"Först efter att ha lindat den runt magen förstår man äntligen var kroppens verkliga mitt fanns. Medan tyngden drar i axlarna hittar det vacklande centrumet sakta sin plats, och där den lindas av finns en rak hållning kvar."},"ICON-2482":{"nm":"Ryggradsuppriktningslock","de":"När ett litet lock rör vid en rygg som levt böjd hela dagen känns det som om någon tyst rätar ut dina axlar. Man klarar sig krokig också, men att stå rak är en öm konst man måste lära sig om långsamt igen."},"ICON-2483":{"nm":"Akupressurboll","de":"Tryck hårt på en knuten punkt, och först stinger det, sedan löser det upp skönt. Som värmen från mormors handrygg som gned din rygg som barn, är att lösa upp att stå kvar vid din sida och göra lite mer ont en stund."},"ICON-2484":{"nm":"Spegelvinkelskruv","de":"Vrid den bara en handflatas bredd, och spegeln speglar ett helt annat ansikte. Med ett varv av skruven lutar och rätar världen sig upp igen, så det verkar som om även att möta sig själv kräver ett stilla sikte."},"ICON-2485":{"nm":"Spegelimmetorkpad","de":"Framför en spegel dimmad av het ånga tappar en människa en stund sitt eget ansikte. Ett svep, och ansiktet återvänder. Tack vare denna beröring som sopar bort diset möter jag mig själv igen varje morgon."},"ICON-2486":{"nm":"Stativfotgummi","de":"Vid stativfotens spets avgör en nagelstor gummibit bildens öde. Dess grepp som biter hårt i golvet stillar skakningarna, så en stadig bild börjar alltid tyst från osynlig friktion."},"ICON-2487":{"nm":"Vinkelrutnätsfilm","de":"De tunna rutnätslinjerna på filmen liknar stödhjul för ögat. Ju mer bildkompositionen sitter i handen, desto mer försvinner linjerna sakta, och bara känslan finns kvar. Lärdomens spår blir osynligt ju mognare det blir."},"ICON-2488":{"nm":"Inspelningspedal","de":"För en person med händerna fulla av grejer var det sista fingret alltid tån. Tryck lätt, och inspelningen börjar – bakom kulisserna sköts hushållet så här skickligt, ända ner till tån."},"ICON-2489":{"nm":"Ljusriktningsklämma","de":"Var ljuset ska falla vilar i fingertopparna på denna nagelstora klämma. Att flytta en skugga en handsbredd och lyfta fram en kontur – över den lilla skillnaden tvekar någon länge och grundligt."},"ICON-2490":{"nm":"Videojämförelseskärm","de":"Lägg gårdagen och idag sida vid sida, och först då öppnar förändringen munnen. I samma stund skärmen glider ner blottas ärligt på skärmen avståndet i tid som korsats däremellan."},"ICON-2491":{"nm":"Fjärrkontrollsrem","de":"Vira en rem runt handleden, och oron för att tappa den lättar. En liten säkerhetsanordning gör handen tvärtom friare – en öm paradox där det som binds sätter sinnet fritt."},"ICON-2492":{"nm":"Objektivlock","de":"Medan kameran vilar sluter även linsen tyst sitt öga. I en värld där ett enda dammkorn lämnar ett ärr på bilden är att varsamt täcka över den önskan att spara den länge."},"ICON-2493":{"nm":"Mungipslyftband","de":"Lyft mungiporna lite grann, och ett stelt uttryck löses sakta upp. Ett leende är, till syvende och sist, också en muskel – först lånar man kraft av redskapet, och en morgon ler man strålande av egen kraft."},"ICON-2494":{"nm":"Kindmuskelrulle","de":"Rulla insidan av kinden sakta lös, och orden flyter fram betydligt mjukare. En tyst förberedelse som varsamt väcker ansiktet innan sången. Värm upp uttrycket också, så blir det varmare."},"ICON-2495":{"nm":"Leendevinkelmätare","de":"Kameran vet att även ett leende har sin rätta vinkel. Mätande hit och dit med mätaren inser man till sist – det vackraste leendet blommar ur en uppriktighet som aldrig går att mäta."},"ICON-2496":{"nm":"Ögonbrynsklämma","de":"Rör ett ögonbryn bara en millimeter, och hela hjärtats ådring förändras. En klämma som tyst håller fast uttryckets minsta beståndsdel – skådespeleri är fingertopparnas arbete med att tämja sådan finess."},"ICON-2497":{"nm":"Kindbenssticker","de":"Lyft kindbenet lite och fäst det, och en plats där ljuset dröjer sig kvar uppstår i ansiktet. Djupet som skapas av ett enda nagelstort klistermärke – i scenmakeupen döljer sig hemligheter som denna, osynliga."},"ICON-2498":{"nm":"Blinkögonlapp","de":"Täck ett öga, och hjärtat samlas helt i det som är kvar. Blinkövning är, till syvende och sist, att lära sig gömma hälften på ett vackert sätt. Det finns sannerligen uttryck som blir tydligare för det som täckts över."},"ICON-2499":{"nm":"Munformsmallklämma","de":"Ga, gya, geo... anpassa munformen efter mallen, och det otydliga uttalet blir skarpt. Att varje vokal är en hållning för ansiktet ristar man sakta in i kroppen framför spegeln."},"ICON-2500":{"nm":"Uttrycksvärmepåse","de":"Precis innan man går upp på scen, en varm påse som varsamt värmer ansiktet. Precis som kalla händer stelnar ett framförande, så gör även uttrycket det. En liten sanning bakom scenen: även ett leende behöver förvärmning."},"ICON-2501":{"nm":"Pannglättningsband","de":"Linda bandet runt pannan, så slätas de djupt inristade rynkorna sakta ut. Ett föremål som ger de bekymmersfyllda rynkorna en stunds vila. Under en glättad panna ser en människa lite yngre ut."},"ICON-2502":{"nm":"Manusbläddringsfingerborg","de":"En liten fingerborg man bär på fingertoppen för att vända sidor. Rytmen av att bläddra genom ett tjockt manus, sida för sida, blir innan man vet ordet av berättelsens egen takt. Även läsandet bär på en öm liten handvana."},"ICON-2503":{"nm":"Känslofärgsflagga","de":"Glädje är gul, sorg är blå. Färglägg hjärtat och res en flagga, så tar den osynliga känslan form och fladdrar i vinden. Även känslor kan på så vis tecknas för hand."},"ICON-2504":{"nm":"Replikbetoningsklämma","de":"”Lägg tyngden på det här ordet”, viskar klämman tyst. Samma replik ändrar hela sin innebörd med en enda betoning, så det är en liten markör som håller talets tyngdpunkt."},"ICON-2505":{"nm":"Läskommablock","de":"En kloss som lagts ner för att säga: ”vila en takt här”. Ett komma i replikerna är ingen paus utan ett andetag inför nästa ord. Den som vilar väl talar till slut väl."},"ICON-2506":{"nm":"Andningsmärkesklämband","de":"Bandet stiger och sjunker längs klämman och tecknar andetagets längd inför ögonen. Att se och följa rytmen av in- och utandning – en sångs början öppnas alltid genom att bemästra andningen."},"ICON-2507":{"nm":"Känslotärningspåse","de":"En tärning rullar skramlande ut ur påsen och avgör dagens känsla. Kommer glädje upp, försök vara glad; kommer ilska upp, försök vara arg. Skådespelarövningen blir en lek där hjärtat överlämnas åt slumpen."},"ICON-2508":{"nm":"Manuslutningsställ","de":"Lägg manuset på det snedställda stället, så slipper du böja huvudet. Denna lilla lutning, som håller dig i ögonhöjd, vårdar tyst en nacke stel av lång övning."},"ICON-2509":{"nm":"Viskskärm","de":"Ett märke som säger: viska härifrån och framåt. Sänk rösten bakom skärmen, och publiken håller istället andan och lutar sig fram för att lyssna. Scenens ömma paradox: ju mjukare du talar, desto större blir det."},"ICON-2510":{"nm":"Rollbyteslåda","de":"Vänd på en bricka och rollen du spelar förändras. Idag huvudrollen, imorgon en vän vid din sida. På en ö där man växer tillsammans kommer allas tur att stå mitt på scenen."},"ICON-2511":{"nm":"Blickfixeringsklistermärke","de":"Vila blicken stilla på en liten prick bredvid kameran. I stunden en ostadig blick landar på en punkt vaknar ögonen på skärmen tydligt till liv. En stadig blick börjar, till slut, med att stå still."},"ICON-2512":{"nm":"Vinkelhake","de":"När ett hörn av bilden på något sätt ser skevt ut, håll upp vinkelhaken så framträder svaret. Att räta upp det som är snett. Innan du litar på dina ögon, prova att lita på haken en stund."},"ICON-2513":{"nm":"Objektivets ögonhöjdstöd","de":"Ställ objektivet i en persons ögonhöjd, så ljuger skärmen mindre. Varken uppifrån eller nerifrån – först när ni möts med samma ögon fångas ett oförställt, sant uttryck."},"ICON-2514":{"nm":"Blickledande pilfjäder","de":"Blicken glider dit fjädern pekar. En liten pil som mjukt leder betraktarens ögon. En bra bild pekar vänligt ut vart man bör titta."},"ICON-2515":{"nm":"Rörelsegolvmarkering","de":"Kliv på en punkt i en rörelse man lärt sig utantill, och nästa plats finns genast till hands. Fotstegen som rör sig över scenen är en osynlig väg, skapad genom att foga samman sådana här små markeringar, prickade över golvet."},"ICON-2516":{"nm":"Kameraavståndsmåttband","de":"Mät avståndet mellan motiv och kamera med bandet. I en värld där ett handsbrett skiljer nära från långt bort blir måttbandet en tyst väktare som vaktar gränsen mellan oskärpa och skärpa."},"ICON-2517":{"nm":"Huvudlutningsguide","de":"Hur mycket bör man luta huvudet för att se som ömmast ut? Följ guiden, så förstår du sakta – lutningens vinkel liknar till syvende och sist hur mycket man öppnar sitt hjärta."},"ICON-2518":{"nm":"Ögonkontaktspegelklämma","de":"Sätt en handspegel bredvid kameran med klämman, och du ser dina egna ögon samtidigt som du möter dina. En liten anordning som mjukt lägger en bro av blickar mellan mig i spegeln och dig på skärmen."},"ICON-2519":{"nm":"Inspelningsindikatorlampa","de":"När lampan tänds är det signalen att inspelningen pågår. En enda liten lampa samlar den upprymda inspelningsplatsens spänning till en enhet. Från stunden ljuset tänds faller allas andetag i takt."},"ICON-2520":{"nm":"Reaktionsklockknapp","de":"Tryck på knappen och en klar klocka ringer skarpt och ljust. Som applåder som brister ut efter en bra scen bär denna lilla klocka på någons varma ord: bra jobbat."},"ICON-2521":{"nm":"Snabbhetslottrör","de":"Skaka den och träpinnarna skallrar och väcker stämningen först. Vem som öppnar scenen avgörs av ett enda handledssnärt – den som dras ler generat, de andra andas ut lättade. Även att dela på lyckan har sina egna, omtänksamma regler."},"ICON-2522":{"nm":"Ljudeffektsskallra","de":"Vicka på handleden bara lite, och – kling – ett utrop kilar sig in. Denna lilla klocka fyller igen glappet innan tystnaden hinner bli pinsam. Att räkna skrattets takt, den här ligger alltid ett steg före."},"ICON-2523":{"nm":"Överraskningslock","de":"Innan det öppnas kan ingen gissa vad som finns inuti. Det är lockets enda uppgift. Så att skrik och skratt bryter ut tillsammans i den stund det gungar till, hänger hela spänningen på ett enda gångjärn."},"ICON-2524":{"nm":"Reaktionssolfjäder","de":"Ljudet när den fälls upp blir i sig ett svar. Solfjäderbladen fläktar fram beundran som orden inte hann uttrycka. Mellan gesterna att vika ihop och fälla ut vandrar stämningen fram och tillbaka, och en strimma känsla svajar i vinden."},"ICON-2525":{"nm":"Bestraffningsroulett","de":"Ingen vet i förväg vilket fält nålen stannar på. Ju långsammare hjulet snurrar, desto snabbare slår hjärtat åt andra hållet – klick, och dagens löjliga öde skrivs där det stannar. Några sekunder där även darrningen är rolig."},"ICON-2526":{"nm":"Utropspratbubbla","de":"Håll den högt över huvudet och ”waouu” reser sig som bokstäver. Ett enda pappersark springer om hjärtat och ropar ut det munnen inte hann hänga med i. För även en reaktion behöver lite scenregi."},"ICON-2527":{"nm":"Frysflagga","de":"I stunden flaggan höjs fryser alla exakt där de står. En signal som låser till och med andetagen i en stillbild. När den sänks igen forsar det stillastående skrattet fram på en gång."},"ICON-2528":{"nm":"Klämback för tokiga svar","de":"Ju tokigare svaret är, desto stadigare klämmer man fast och hänger upp det. När de felaktiga svaren på tvättlinan svajar i vinden blir det en scen där misstagen älskas mer än de rätta. En syn av en dag där det är helt okej att ha fel."},"ICON-2529":{"nm":"Hållningskorrigerande ryggstödskil","de":"I stunden du lutar ryggen mot den känner den krökta ryggraden sakta ut sin egen väg. En liten kil som stöttar utan ett ord. God hållning, viskar den tyst bakifrån, blir bekväm först när någon finns där för att stötta den."},"ICON-2530":{"nm":"Bäckenjusteringsblock","de":"En liten fasthet som stöttas under fötterna när tyngdpunkten vacklar. Kroppens balans stiger till slut sakta upp från golvet. En namnlös biroll som håller upp hållningen från en osynlig plats."},"ICON-2531":{"nm":"Magåtstramande balansboll","de":"Placera den mot magen och spänn sakta, och den spridda mittpunkten samlas till en enda punkt. Ju djupare du styr andningen, desto fastare blir bollen, och kroppen återtar, andetag för andetag, den axel den glömt bort."},"ICON-2532":{"nm":"Ryggradskrökningslinjal","de":"Lägg linjalen mot ryggen, och den osynliga kurvan träder fram på skalan. Att stå rak handlar inte om att sudda ut kurvan – utan om att med ömhet läsa av även den minsta böjning."},"ICON-2533":{"nm":"Axelsträckningsslinga","de":"Häng den över axlarna och dra sakta, och det hopsjunkna bröstet öppnar sig på vid gavel. Elastiken viskar alltid: kom tillbaka till din plats, och ryggen, krökt en hel dags slit, rätas sakta ut vid denna milda kallelse."},"ICON-2534":{"nm":"Kärnstimulerande sandsäck","de":"Linda den runt midjan, och de tunga sandkornen väcker den slumrande kärnan. Även en lätt rörelse blir på ett ögonblick allvarligt menad inför denna tyngd. Att man blir starkare ju mer man håller ut, det viskar varje litet korn tyst om."},"ICON-2535":{"nm":"Svansbensstödskudde","de":"En kudde som mjukt stöttar under svansbenet, med en liten lapp hängande i änden. Ett redskap likt en öm liten lapp, skriven och fäst för en dag utmattad av att sitta länge: ”Du får luta dig hit en stund.”"},"ICON-2536":{"nm":"Ländstödstrefot","de":"Stående stadigt på tre ben håller den tyst fast vinkeln som ryggen kan luta mot. Ett stöd som smyger sig in i en hållning på väg att kollapsa. För att hålla upp det som vacklar räcker förvånansvärt nog tre punkter."},"ICON-2537":{"nm":"Hakindragningsklämma","de":"Dra in hakan och stötta den lätt, och den urspårade nacklinjen finner sin plats. Tjatet från en fingerstor klämma är på något sätt ömt. Hur man håller huvudet rakt, det lär detta lilla redskap ut."},"ICON-2538":{"nm":"Fotstegsstege","de":"Bandet utlagt på golvet ritar i tur och ordning ut rutorna fötterna ska trampa i. Trampa ärligt ruta för ruta, och innan du vet ordet av är stegen inristade i kroppen. En väg blir tydligare ju mer den beträds."},"ICON-2539":{"nm":"Riktningskon","de":"Ställ upp den och den är en liten markör som säger: sväng här. Den skänker ett hörn åt fötter som bara någonsin sprungit rakt fram. Även vägen som svänger in bär på en egen, dold rytm."},"ICON-2540":{"nm":"Enbensbalansplatta","de":"I stunden du kliver upp på ett ben lutar plattan lätt. De där sekunderna av att kämpa emot vinglandet är balansens mest ärliga lektion. Tårna som kämpar för att inte falla berättar hela historien."},"ICON-2541":{"nm":"Reaktionsljus","de":"I samma ögonblick signalen tänds tävlar hand och öga om att vara först. Det blinkande ljuset ger inget utrymme för tvekan. En snabb hand rör sig alltid en halv takt före tanken."},"ICON-2542":{"nm":"Sicksackfotmarkör","de":"Små prickar fästa snett på golvet leder fötterna att dansa i sicksack. Svårare än en rak linje är alltid det som korsar sig. Vandra efter prickarna, och de snabba fotstegen mognar skickligt."},"ICON-2543":{"nm":"Balansgångsstång","de":"Sätt fötterna på den smala stången och världen smalnar av till ett enda rep. Som en lindansare som går på luften lägger du hela din koncentration på ett handsbrett bredd. Balansen blir tydligare ju smalare den blir."},"ICON-2544":{"nm":"Studsbollsarmband","de":"Bär det på handleden och en liten boll studsar tillbaka med en smäll. I stunden av att kasta och fånga ristas reaktionshastigheten in i fingertopparna. Snabbhet handlar i grunden om att inte missa det som kommer tillbaka."},"ICON-2545":{"nm":"Snabbfotshularing","de":"Haka fast den vid foten och snurra, så eggar hularingen ständigt vaden vidare. I stunden den stannar faller den, så foten guppar utan uppehåll. Medan man rör sig som i lek mognar fotarbetet smidigt och snabbt."},"ICON-2546":{"nm":"Tåbalanssnurra","de":"En snurra som roterar på handflatan stannar tvärt i det ögonblick den tappar sin mittpunkt. Liksom barndomens dagar av att piska en snurra på gården är balans något som bara kan stå stilla genom att oupphörligt snurra."},"ICON-2547":{"nm":"Vristskyddssnöre","de":"Linda och dra åt vristen, och det vacklande fotfästet blir betydligt säkrare. Ju mer utsatt en plats är, desto ömmare måste den hållas. En enda snörsträng blir tryggheten i ett enda steg."},"ICON-2548":{"nm":"Knävärmarband","de":"Linda det runt ett kallt knä och värmen sipprar in mellan lederna. En stel led blir mjuk först när den värmts. Innan man rör sig, den varmaste morgonhälsning man skänker sin egen kropp."},"ICON-2549":{"nm":"Muskellösande akupressurboll","de":"Tryck stadigt på en spänd punkt, och kulorna smeker knuten sakta. Den märkliga trösten i att det lossnar precis så mycket som det gör ont. Även spänningar handen inte når klappar denna lilla boll bort i dess ställe."},"ICON-2550":{"nm":"Uppvärmningshjul","de":"Väck kroppen från vilket fält hjulet än stannar på. Nacke, axlar, vrister – lämna ordningen åt slumpen och håll hjärtat lätt. När lek smyger sig in i uppvärmningen ler den stela kroppen mjukt först."},"ICON-2551":{"nm":"Ledvärmedyna","de":"Lägg en ångande värmedyna över lederna, och en lättnad likt ett varmt vintergolv sprider sig genom kroppen. Det är stunden då stela leder löses upp i en dåsig lätthet. Först när kroppen värmts gör den sig sakta redo att röra sig."},"ICON-2552":{"nm":"Stretchhandtagsslinga","de":"Grip slingan och dra, och stela muskler sträcks ut på längden. Ett spänt samtal pågår mellan den hållande handen och den uppvecklade kroppen. Ju mer den sträcks ut, desto lättare kommer morgondagens rörelser att kännas."},"ICON-2553":{"nm":"Fotsuleknoppplatta","de":"Stå barfota på knopparna och de slumrande fotsulorna väcks med ett ryck. Som den pirrande känslan av att gå barfota på en grusväg stiger känslan av marken upp från tårna."},"ICON-2554":{"nm":"Skademagnetlapp","de":"Skriv ”överdriv inte” och fäst det på metallskivan. Smärtsamma minnen glöms lätt bort, så du hänger det inför ögonen med en magnet. Även omtanken om kroppen börjar till slut med en enda rad anteckning."},"ICON-2555":{"nm":"Fascierulle","de":"Rulla den knöliga stången sakta, och den fastklamrade fascian löses upp bit för bit. En beröring som mjukt trycker bort knutarna. En hopklumpad dag, uträtad knut för knut på detta vis, blir också mycket lättare."},"ICON-2556":{"nm":"Gånglinjeremsa","de":"Utlagd rakt på golvet ger den fötterna en enda linje att följa. Även en spretig gång, satt på denna linje, rätas snart ut. Rita upp vägen, så vandrar fötterna inte längre vilse."},"ICON-2557":{"nm":"Axelvågstav","de":"Lagd tvärs över axlarna avslöjar den tyst en balans som lutar åt ena hållet. Att vara i våg innebär alltid att sänka den ena sidan och höja den andra. En enda stav pekar milt ut en skev vana."},"ICON-2558":{"nm":"Hjässbalansvikt","de":"För att hindra vikten på hjässan från att falla måste hela kroppen stå rak som en enda linje. Liksom den gamla synen av att gå med en vattenkruka balanserande på huvudet hämtas balansen ända från den högsta punkten och neråt."},"ICON-2559":{"nm":"Hakvinkelstöd","de":"Stötta hakan mjukt, och huvudet som ständigt sjunker återfår sin rätta vinkel. En kort vila lutad mot ett enda stöd. En rak linje är först fullständig när någon håller upp den underifrån."},"ICON-2560":{"nm":"Stegavståndspåle","de":"Pålen som slagits ner i golvet mäter i förväg ut var fötterna bör landa. Ett steg, varken för brett eller för smalt – det ärliga avståndet. Gångens balans börjar tyst vid denna lilla markering."},"ICON-2561":{"nm":"Tåriktningskil","de":"Det tveksamma första steget – tårna tvekar först om vart man ska gå. När denna lilla kil bestämmer riktningen lutar hjärtat mjukt åt samma håll. Att välja sin väg är ingen stor beslutsamhet, utan det handsbrett tårna pekar mot."},"ICON-2562":{"nm":"Ryggresningsbälte","de":"Den där rösten som alltid sa ”räta på ryggen, räta på ryggen” tycks leva kvar inuti detta bälte. Räta sakta upp en böjd dag, och tyngden som vilat på axlarna blir märkligt nog lite lättare. En enda god hållning reser upp även hjärtat."},"ICON-2563":{"nm":"Viktfördelningsplatta","de":"Sju på vänster fot, tre på höger. Var man lägger tyngden avgör balansen. Plattan frågar tyst – åt vilket håll lutar du just nu? Att stå rak är, visar det sig, en ständig justering."},"ICON-2564":{"nm":"Ögonhöjdsmålstolpe","de":"Blicken faller ständigt ner mot tårna. I sådana stunder lyfter en ensam stolpe, rest långt borta, blicken sakta uppåt. Att öva på att se långt är att öva på att gå långt, så i samma stund huvudet lyfts kommer även en plats som verkade oåtkomlig nära."},"ICON-2565":{"nm":"Bugningsvinkelklämma","de":"Femton grader, trettio grader, fyrtiofem grader. Hjärtat bugar lika djupt som midjan viks. Vinkeln på kortet är inte bara en siffra, utan en liten mätare för den uppriktighet man skänker en annan."},"ICON-2566":{"nm":"Handvikningsring","de":"Fäll dina två händer prydligt ihop, och ett flämtande hjärta sjunker lugnt ner på en plats. Denna lilla ring fångar milt de rastlösa, osäkra fingertopparna och sätter tyst hälsningens första hållning."},"ICON-2567":{"nm":"Rörelsepilmagnet","de":"Det första vilsna fötter söker efter, spanande runt, är en pil. En enda riktning som klickas fast med en magnet skär av tvekan och drar mjukt stegen mot dit man måste gå. Även ett vilset hjärta finner till slut en riktning."},"ICON-2568":{"nm":"Utgångsriktningsnål","de":"Vägen ut är svårare än vägen in. Även i släckt mörker lyser denna tydligt glödande nål och pekar tyst ut den sista vägen. Att lämna väl är också en del av scenen – det förstår man först i slutet."},"ICON-2569":{"nm":"Högtidsbugningsband","de":"Det fanns en tid då ordningen på vem som bugade först och vem som bugade sedan var tydlig. Sänk dig i den ordning som står skriven på bandet, så får även artighet en textur, och hövligheten ett flöde. Det är att hålla hjärtats ordning."},"ICON-2570":{"nm":"Fotjusteringsmagnet","de":"Om en person kommer ur takt vacklar hela raden. Som en bricka som klickar fast när tårna är i linje, innebär det att stå tillsammans att mjukt ge efter med sitt eget steg för den bredvid. Fotsteg som faller i samma takt är det tryggaste av allt."},"ICON-2571":{"nm":"Scenbugningshästsko","de":"Även en enda scenbugning har en plats att stå på. Sätt fötterna på märkena, utspridda i en rund som en hästsko, och en första hälsning som ständigt gick fel av nervositet finner äntligen sin form. Att känna sin plats lugnar även darrningen något."},"ICON-2572":{"nm":"Tackgestkort","de":"Tacksamhet som orden inte riktigt kunde rymma flödar ut genom fingertopparna. Att rita ett hjärta, lägga en hand på bröstet – varje gest nedtecknad på kortet blir en översättning där hjärtat skrivits ner i rörelse. Uppriktighet som längtar efter att nå fram har alltid en form."},"ICON-2573":{"nm":"Köavståndspåle","de":"Även att stå i kö har en öm artighet. Som en påle som håller exakt ett handsbrett avstånd till personen framför, börjar väntan med den lilla omtanken att inte trängas mot varandra. Att stå lite ifrån varandra är också att bry sig."},"ICON-2574":{"nm":"Repliksignalring","de":"När nästa replik ständigt dröjer sig kvar på läpparna vänder ett finger tyst blad. De små papperen, trädda på ringen, trycker mjukt ner det bultande hjärtat och öppnar lugnt rutan för vad som ska sägas härnäst. Hur darrande man än är bryts aldrig flödet."},"ICON-2575":{"nm":"Programordningstimglas","de":"Betrakta sandkornen som porlande rinner ner, och nästa turordning ordnar sig lugnt i sinnet. Innan det sista kornet faller lär detta lilla timglas dig att avläsa tiden med ögonen, utan brådska."},"ICON-2576":{"nm":"Mikrofongreppsövningsstav","de":"Innan det sitter i handen väger en tom stav tungt som bly. Greppets vinkel, avståndet till munnen, kraften i handleden – övning, otaliga gånger av att gripa och släppa, blommar en dag plötsligt ut i en enda naturlig rörelse."},"ICON-2577":{"nm":"Uttalsövningspinne","de":"Ga, na, da, ra. Håll pinnen i munnen och rulla ljuden tills tungspetsen blir tydlig. Ett ord som korsar över klart och tydligt är som en blomma som tyst blommar ovanpå hundratals sluddriga, otydliga timmar."},"ICON-2578":{"nm":"Signalflagga","de":"Starta, stanna, vila en takt. En enda ordlös flagga dirigerar scenens andning. Från en plats osynlig för publiken håller en tyst vinkande hand fast varje takt utan minsta glapp."},"ICON-2579":{"nm":"Avsnittsbytesklocka","de":"Ett klart klingande ljud, och scenen ändras. Som klockklangen som spreds över en marknadsplats i skymningen bär detta lilla ljud ett tvekande hjärta lätt över till nästa avsnitt. En övergång börjar alltid med ett ljud."},"ICON-2580":{"nm":"Talandningspendel","de":"Andas in – en, två – och andas långsamt ut. Jämna andningen med pendeln som svänger fram och tillbaka, och ord som forsat ut alltför snabbt finner snart sin takt igen. Talets hastighet var, visade det sig, andningens hastighet."},"ICON-2581":{"nm":"Manusvikbräda","de":"I en enda rörelse av att vika ihop och fälla ut ryms hela dagens ordning intakt. I stunden du fäller ut den nötta brädan ställer sig ett sinne, förvirrat över vad som ska tas upp först, lugnt på rad. Ett enda uppfällande ordnar dagen."},"ICON-2582":{"nm":"Andningstaktstimglas","de":"Andas in tre, håll fyra, andas ut sex. Medan sanden rinner flödar din andning tyst med den. Att räkna varje andetag för sig är det äldsta, ömmaste sättet att sakta vårda ett upptaget jag."},"ICON-2583":{"nm":"Meditationskuddetofs","de":"Tofsen som hänger från kuddens kant svajar stilla utan minsta vind. Sätt dig i skräddarställning, och stillheten från en gammal själ som lugnade sitt sinne på en trätrall glider mjukt intill, dröjer en stund, och går."},"ICON-2584":{"nm":"Andningslugnande handklocka","de":"När en enda vindpust drar förbi gråter ett klart ljud stilla. Hängande som en vindklocka under takfoten släpper den ner en sval, uppfriskande droppe över ett sinne som kokat av oro. Även ljud har kraft att svalka."},"ICON-2585":{"nm":"Rökelsefat","de":"Röken som blir kvar efter brunnen rökelse sjunker sakta ner på tallriken. Som doften som steg upp framför bordet en högtidsmorgon lugnar en enda slinga rök sakta den oroliga luften och fyller rummet med stillhet."},"ICON-2586":{"nm":"In- och utandningspendel","de":"Min andning bärs av en enda vikt som sakta stiger och sjunker igen. Flytande upp när jag andas in, sjunkande när jag andas ut – en dag kroppen glömt hur man andas lär detta lilla ur ut allt från början igen."},"ICON-2587":{"nm":"Meditationsklubba","de":"Slå klockan en enda gång, mjukt, och klangen sprider sig långt ut. Som vindklockans ljud som ringde genom ett bergstempel renar bara stillheten att lyssna, ända tills klangen helt försvunnit i luften, ett hörn av hjärtat."},"ICON-2588":{"nm":"Andningsvägledande fjäder","de":"Håll fjädern stilla framför näsan, och andningsvägen du inte kunde se blir äntligen synlig. En svag skälvning betyder att du andas väl; stillhet betyder att du hållit andan för länge. Det lättaste av allt blir ibland den ärligaste vägvisaren."},"ICON-2589":{"nm":"Sinnesstillande sten","de":"Kiselstenen i din handflata är kall och slät. Som en sten länge rullad vid en flodstrand tills den gett upp alla sina kanter, fingra på den om och om igen, och de vassa delarna av ett kokande sinne slits sakta rundare."},"ICON-2590":{"nm":"Andningstemperaturklämma","de":"Temperaturen vid nästippen berättar tyst andningens djup. Klämman läser stilla av luften som kommer in kall och går ut varm, och visar tydligt inför ögonen den andning man annars aldrig ens känner. Även andningen har ett uttryck."},"ICON-2591":{"nm":"Humörvädertavla","de":"Är mitt hjärta klart idag, eller mulet? I stunden du väljer ett litet klistermärke och trycker fast det på tavlan blir ett humör, svårt att sätta ord på, till ett slags väder och tar en tydlig form. Även hjärtat behöver en väderprognos."},"ICON-2592":{"nm":"Känslofärgstämpel","de":"Glädje är gul, sorg är blå. Välj en färg och tryck den fast på papperet, och hjärtats färgton lämnas kvar som ett märke. Även en känsla omöjlig att sätta namn på – färgen kommer först och känner tyst igen den åt dig."},"ICON-2593":{"nm":"Hjärtkronbladsbricka","de":"Lägg hela dagens hjärta mjukt på ett enda kronblad. Som azaleor som svävar en vårdag, frågar en bricka, lätt och ömtålig, tyst vid en fallande dags slut hur du haft det."},"ICON-2594":{"nm":"Hejapratbubblemagnet","de":"Orden du vill säga dröjer sig ständigt kvar vid läpparna. I stunden du trycker fast pratbubblemagneten når ett uppmuntrande ord, som du inte kunde säga högt, tyst fram till någons slitsamma dag. Så förmedlas hjärtat."},"ICON-2595":{"nm":"Innerhjärtesigill","de":"Ord som inte hann komma ut läggs prydligt i ett kuvert och förseglas. Som en gammal själ som förseglade ett brev med klister vid fingertopparna håller ett enda sigill det innersta hjärtat säkert. Väntande tyst på dagen det ska tas fram och vecklas ut."},"ICON-2596":{"nm":"Känslotemperaturknopp","de":"En sluten knopp, som möter värme, öppnar sig försiktigt lager för lager. Blommande i takt med att hjärtats temperatur stiger – hur uppvärmd jag varit idag vet denna blomma innan orden gör det. Även hjärtat får sin vår."},"ICON-2597":{"nm":"Självberömsspegelband","de":"Lyft spegeln och möt dina egna ögon, speglade där. Det lilla ansiktet, hängande i bandet, visar inte ditt ansikte, utan gårdagens jag, som förtjänar ett ord för att ha härdat ut väl. Tröst var aldrig långt borta."},"ICON-2598":{"nm":"Humöransiktsstämpelset","de":"Ett strålande leende, tårfyllda ögon, en trutande, sur mun. Tryck fast uttrycksstämplarna bestämt och skriv hjärtats dagbok. En dag för överväldigande att sätta i ord talar ett litet ansikte tyst om dagens humör i mitt ställe."},"ICON-2599":{"nm":"Känslotrasselring","de":"Hur trasslig härvan än är, red ut den försiktigt tråd för tråd, och den blir till slut en enda tråd igen. Häng förvirrade, kvävande känslor på ringen en efter en, och även ett hjärta du inte alls kunde förstå finner en tunn tråd att följa."},"ICON-2600":{"nm":"Sömndoftpåsesnöre","de":"Från doftpåsen, hängd vid huvudgärden, sprider sig en svag örtdoft stilla. Som doften av mormor som lade in väldoft djupt i garderoben glider spänningen som varit spänd hela dagen sakta in i sömnen medan du fingrar på snöret."},"ICON-2601":{"nm":"Sömnvändarbricka","de":"En natt då du vred dig och vände dig och först vid gryningen somnade. Vänd liggställningen varsamt, så glider gårdagens oro omärkligt över i morgonens klarhet. Att vila är också en övning, säger den lilla brickan utan ett ord."},"ICON-2602":{"nm":"Månskenshängare för kuddkanten","de":"Häng en flisa ljus som silat in genom gardinspringan vid kuddens kant. En svag flod flyter över det sovande ansiktet, och till och med praktikantens nätter, då mörkret var skrämmande, mjuknade äntligen. Det var den första lilla tröst som någonsin fanns."},"ICON-2603":{"nm":"Blomknoppschip för dagsform","de":"Dagens dagsform är sluten som en blomknopp. Tryck lätt på chipet så öppnar det sig sakta – kroppen vet före dig om natten var god eller inte. Även den tvekan innan den slår ut i full blom är stilla och älsklig."},"ICON-2604":{"nm":"Vekelock för nattlampan","de":"”Släck inte lampan.” För den yngsta, som var rädd för mörkret, satte någon varsamt ett lock över veken. Varken för ljust eller för mörkt, ett litet och ömt löfte att vaka bara tills sömnen kommer."},"ICON-2605":{"nm":"Solrosnål för morgonuppvaknande","de":"Fäst den vid huvudgärden så vänder den sakta huvudet mot den första solstrålen, likt en solros. Även de dagar man inte vill stiga upp finns det en anledning till att ljuset kallar, och den för morgonen åt ett och samma håll."},"ICON-2606":{"nm":"Sömnörtborste för kudden","de":"Doppa lavendel och kamomill i borstens spets och stryk en gång över kudden. Medan doften sipprar in i örngottet löses en hel dags spänning sakta ur axlarna. God sömn börjar med denna lilla doft."},"ICON-2607":{"nm":"Täckeshörnsklämma","de":"Mot gryningen smiter tårna ständigt ut under täcket. Håll hörnet stadigt fast med klämman, så kan värmen inte rymma under natten. Det är en liten fastspänning i stället för ett ”sov gott”."},"ICON-2608":{"nm":"Kiselstenskorg för dagsform","de":"En god gärning om dagen, en handflatestor kiselsten. Ju tyngre stenarna samlas i korgen, desto tryggare känns hjärtat. Att samla vardagliga stunder i handen – så har lyckan alltid räknats."},"ICON-2609":{"nm":"Löftesstjärnkruka","de":"Varje kväll formas dagens föresats till en stjärna och tappas ner i krukan. När den blir full förvandlas krukan till en liten stjärnhimmel. Den en gång tomma mynningen vet: löften lyser först när man samlar dem."},"ICON-2610":{"nm":"Godishängare för små belöningar","de":"En godbit man ger sig själv i slutet av en tröttsam dag. I samma stund man tar en från hängaren och stoppar den i munnen blir allt bra, även om ingen märker det. En liten belöning är den ärligaste uppmuntran."},"ICON-2611":{"nm":"Stämpel för ”Klarat idag”","de":"”Klarat idag.” Doppa i bläck och tryck fast i anteckningsboken. En dag som gått bra och en dag man bara härdat ut fyller en ruta lika mycket. Varje dag behöver inte vara perfekt – man får bara inte sluta trycka stämpeln."},"ICON-2612":{"nm":"Flaggfot för hejarop","de":"Sätt den stadigt i marken, och ju hårdare vinden blåser desto kraftigare fladdrar flaggan. Även det som skakar behöver en hand som håller upp det. En hjärtlig heja på någon bär på så sätt underifrån."},"ICON-2613":{"nm":"Målfrökruka","de":"Ett mål reciteras inte med ord, det grävs ner i jorden. Medan du planterar ett frö, vattnar och väntar, förvandlas otåligheten sakta till rötter. Det som växer i krukan är inte bara grodden."},"ICON-2614":{"nm":"Berömklistermärkestavla","de":"Ett klistermärke för varje sak väl gjord. Ju mer färgglad tavlan blir, desto mer väcks de dagar som obemärkt gled förbi till liv i färg. Som barn visste vi det: beröm blir tydligare ju mer man sätter upp av det."},"ICON-2615":{"nm":"Löftesbandsögla","de":"En hand som trär bandet genom öglan och knyter det. Stadigt så det inte lossnar, men inte för hårt. En föresats är just som denna knut – dras den för hårt går den av, är den för lös glider den tyst upp."},"ICON-2616":{"nm":"Snäckskalschip för små framsteg","de":"Skriv en liten prestation på ett snäckskal du hittat vid stranden. Precis som ett fragment format och slipat av vågorna hela vägen hit, har även din dag rullat länge och glänser nu blank. Allt som uthärdat tiden kommer till slut att glittra."},"ICON-2617":{"nm":"Belöningsmedaljkrok","de":"En hårt förtjänad medalj hängs inte i en byrålåda utan i ögonhöjd. Tyngden på kroken räta ryggen varje morgon. En belöning ska inte gömmas undan – den hängs där för att beskådas."},"ICON-2618":{"nm":"Droppkopp för monsunparaplyet","de":"Monsunregnet rinner droppvis nerför paraplyets spets. Ställ en kopp under och hallen förblir torr. Man kan inte stoppa det som forsar ner, men man kan bestämma var det landar."},"ICON-2619":{"nm":"Kylpåse mot hetta","de":"Bakom scenen en het sommardag, en kylpåse tryckt lätt mot nacken. Den upphettade, stigande hettan sjunker en takt. ”Ta en paus.” En hand som tar hand om mig före hettan gör det är trygg."},"ICON-2620":{"nm":"Fläktbladslåsklämma","de":"Även vingar som snurrat vilt stannar stilla med bara en klämma. Ju kraftigare vind, desto mer behövs något som håller den stadigt fast. Snabbt snurrande ting blir säkra genom vem som håller dem stilla."},"ICON-2621":{"nm":"Torkstav för våta skor","de":"Regnvåta skor gör till och med hjärtat fuktigt över natten. För in staven i skon, så är den torr nog att bära igen till morgonen. Det våta ska inte kastas – det ska torkas varsamt."},"ICON-2622":{"nm":"Lerskraphäll för stövlar","de":"Stövlar täckta av lera från risfälten. Först efter att ha skrapats rena mot hällen får man stiga upp på golvet. Att lämna utomhusets gyttja vid dörren innan man kliver in – en gammal artighet som håller hemmet rent."},"ICON-2623":{"nm":"Sval kakelplatta för sommaren","de":"Bara fötter vet det först. Pressa fotsulan mot kakelbiten på sommarens golv, och middagshettan viker för en handfull svalka. Redan en liten kyla gör en lång årstid uthärdlig."},"ICON-2624":{"nm":"Trösklist mot regn","de":"Bara en list lagd över tröskeln, och regnvattnet kan inte längre ta sig in. En smal linje som skiljer inne från ute. En plats värd att skydda passar bättre med en stram gräns än en stor mur."},"ICON-2625":{"nm":"Fat för myggspiral","de":"En sommarkväll, ställ myggspiralen på sitt fat och en skarp men förtrolig rök stiger. Liksom röken som sakta slocknar i ring, fördjupas natten sakta med. Det är doften från de där tiderna, liggande på pallen och räknande stjärnor."},"ICON-2626":{"nm":"Ögla för kylarmskydd","de":"Täck armarna, brända av solen, med ett armskydd. Fäst det stadigt vid ärmen med öglan, och även middagsarbetet blir uthärdligt. Svalka är den lilla omtanken att skugga en handsbredd där den berör."},"ICON-2627":{"nm":"Handkvast för lövsopning","de":"Sopa ihop de fallna löven som täcker gården med handkvasten. En hel årstid prasslar under fötterna. Att ordna upp något är också att varsamt ta farväl av det som ska lämnas."},"ICON-2628":{"nm":"Fönsterspärrstav för vädring","de":"Kila fast en stav i ett kvavt rum och håll fönstret på glänt. Höstbrisen smyger sig in och för bort den instängda luften. Vädring är det lilla andningshålet som stilla byter det som samlats inne mot det som finns ute."},"ICON-2629":{"nm":"Ekollonspåsepropp","de":"Precis som en ekorre, fyll påsen full med ekollon och tillslut mynningen med proppen. Stadigt, så inget rullar ut. Viljan att skydda det man samlat är den gamla instinkten hos små varelser som övervintrar."},"ICON-2630":{"nm":"Dammpiska för höstsängkläder","de":"Häng ut täcket som täckt dig hela sommaren på gården och piska det raskt med klappan. Doften av solsken sprider sig genom dammet. Att man måste piska ut den gamla årstiden för att kunna bäddas in i den nya – det minns handleden först."},"ICON-2631":{"nm":"Draglist mot vinddrag","de":"Täta den kalla dragen som tränger in genom fönsterspringan stadigt med bara ett snöre. En enda smal linje vaktar rummets värme in i det sista. En stor kyla börjar alltid vid en liten springa – vinterförberedelsen vet det."},"ICON-2632":{"nm":"Lövsil för takrännan","de":"En sil lagd över takrännan. Den silar löven rent och släpper bara vattnet vidare. För att flöda obehindrat måste man bestämma vad som ska passera och vad som ska hejdas, säger höstens takfot."},"ICON-2633":{"nm":"Klämma för torrgräsknippen","de":"Bind fast en knippa knastertorrt gräs stadigt med klämman. En hand som binder samman det som annars sprids. Även där sommarens grönska runnit bort helt, bevaras användbarheten intakt när man samlar ihop det."},"ICON-2634":{"nm":"Temperaturpendel för höstvind","de":"När vinden blåser vaggar pendeln sakta. Efter hur mycket den svänger avgör man hur djup dagens höst har blivit. Temperatur är inte en siffra – den når handen först som något som sakta vaggar."},"ICON-2635":{"nm":"Fickvärmarhållare för ytterjackan","de":"”Kalla händer.” Handvärmarhållaren stoppad i jackfickan värmer sakta de förfrusna fingrarna. Hjärtat som tänker på någon annans köld först ligger alltid tyst gömt i en ficka."},"ICON-2636":{"nm":"Droppkant för fönsterimma","de":"Kanten fångar stilla upp de tårar vinterfönstret fällt hela natten. En liten vattenväg skapad av temperaturskillnaden mellan inne och ute. Ju större skillnaden är, desto mer flödar – det visar gryningsfönstret varje dag."},"ICON-2637":{"nm":"Skyddsgaller för kaminelden","de":"Ställ upp ett skyddsgaller framför den flammande kaminen. Värmen nära, faran precis ett handsbrett bort. Att ha elden intill utan att bli bränd är den mest grundläggande omsorgens avstånd."},"ICON-2638":{"nm":"Hållklämma för vintertäcket","de":"När det tjocka vintertäcket ständigt glider av, håller klämman stilla fast det på plats. Tung värme måste hållas stadigt för att göra rätt för sig. Vinternattens ombonade lugn vaktas på just detta stramt omsorgsfulla vis."},"ICON-2639":{"nm":"Frostskrapa","de":"Skrapa bort frosten som blommat vit på gryningens vindruta med skrapan. Den grumliga sikten klarnar rad för rad. Även det som frusit fast kan till slut skrapas bort, lär vinterns morgonfingertoppar dig."},"ICON-2640":{"nm":"Locköverdrag för värmeflaskan","de":"Dra ett värmehölje över behållaren fylld med hett vatten. Så det inte kallnar under natten sveps värmen in i ännu ett lager. Sättet att hålla värmen länge är, i slutänden, att omfamna den omsorgsfullt med något."},"ICON-2641":{"nm":"Trycklist för dörrtätning","de":"Den kniviga vinden som borrat sig genom dörrspringan tvekar i samma stund den möter dig. En enda list som trycker ner kanten på papperstätningen. Rummets värme skyddar äntligen sina egna – vintern värms genom en sådan liten envishet."},"ICON-2642":{"nm":"Underlagsfat för fotvärmaren","de":"Det runda fatet som ligger under fotvärmaren. Det tar emot all hetta ensamt utan att lämna ett enda brännmärke på golvet. När någons tår värms ljuvligt slöa, avslutas min egen andel av dagen tyst."},"ICON-2643":{"nm":"Ögla för kondensvisketrasa","de":"Så trasan som torkat upp dropparna på gryningsfönstret inte ska tappa sin plats, hänger en ögla på väggen och väntar. Mer än att dricka sig genomblöt, är det att åter vänta torr på morgondagen som är absorptionens sanna hjärta."},"ICON-2644":{"nm":"Torkhängare för vintervantar","de":"Vantarna, klara efter ett snöbollskrig, sträcker ut fingrarna vid sidan av elementet. Synen av dem hängande på hängaren, sakta ångande. I slutet av en eftermiddag med röd nästipp – det är vinterns fridfullaste tvätt."},"ICON-2645":{"nm":"Fjäderpåfyllning för dammvippa","de":"När fjädrarna slitits ut byter man till nya. Stunden då den dammjagande spetsen blir dunig igen. Att även städredskap har sina årstidsskiften – det låter denna lilla påfyllning tyst veta i din handflata."},"ICON-2646":{"nm":"Vridhandtag för trasa","de":"Ett handtag monterat för att skona handleden. En vridning och trasan spottar ut vattnet av sig själv. Farväl till tiderna av att kämpa vid tvättbrädan. I hushållet blir en nypa knep genast till omtänksamhet."},"ICON-2647":{"nm":"Utbytbart borsthuvud för golvborste","de":"När golvborsten är utsliten byter man bara ut huvudet. Skaftet förblir detsamma, och tyngden handen känner igen förblir densamma. I föremål som brukas länge lever en liten, fast ömhet som inte vill slänga hela saken."},"ICON-2648":{"nm":"Refillrulle för dammrulle","de":"När man river av rullens sista blad känns det märkligt tomt. Då sätts en ny kärna i. Det är refillens seglivade, ömsinta löfte att ansvara ända in i det sista för en enda lugghärva på tröjan."},"ICON-2649":{"nm":"Hörnskrapa för damm","de":"Även i hörn kvasten inte når slår dammet sig tyst till ro. Att peta rent hörnet med en smal spets. Omsorgen som når även det osynliga är själva stoltheten i hushållsarbetet."},"ICON-2650":{"nm":"Rensningskam för kvast","de":"Även en kvast som sopat behöver en vilsam beröring. Kamma ut håret intrasslat mellan borsten med denna kam, så gör sig kvasten, sitt arbetspass slutfört, äntligen redo för nästa sopning."},"ICON-2651":{"nm":"Vaxdyna för trägolvet","de":"Lägg ett lager vax längs golvets ådring, och trät minns sakta en glans det länge glömt. Fötter som nästan halkar, nästan inte – en eftermiddag då hela huset ler blankt och nöjt."},"ICON-2652":{"nm":"Dammsopare för dörrspringan","de":"Jag jagar dammet som bor i dörrspringor. Allt som smyger sig in och samlas varje gång dörren svänger, sopar jag upp med min tunna kropp. Ju smalare och djupare springan är, desto säkrare kommer min tur."},"ICON-2653":{"nm":"Dammnätslock för dörrmattan","de":"Så dammet som entrémattan svalt inte läcker ut igen, står ett nätlock som den sista grindvakten. Dammet som lersmutsiga skor bar in från den yttre världen släpps in bara hit och inte längre."},"ICON-2654":{"nm":"Kalkborste för kranen","de":"Den lilla borsten kretsar runt och skrapar bort kalken som smugit sig fast på kranens hals. Ju mer en plats vidrörs av händer varje dag, desto mer måste den glänsa. Det är badrummets artighet som denna lilla borste vaktar."},"ICON-2655":{"nm":"Hårsil för avloppet","de":"Jag fångar stilla håret som flöt mot avloppet. Att avvärja den lilla katastrofen ett stopp innebär med bara ett lock. Den runda, dugliga lilla hjältens dag flyter tyst förbi, alltid under fötterna."},"ICON-2656":{"nm":"Fogskrapa för kakel","de":"Fogen mellan de vita kaklen, mörknad av gamla år – skrapa bort den tiden varsamt med spetsen. När de smala mellanrummen blir rena, drar hela badrummet ett lätt andetag, som nytt."},"ICON-2657":{"nm":"Rengöringsnål för duschmunstycket","de":"Peta upp de tilltäppta hålen i duschmunstycket med nålens spets, och vattnet som bara sipprat länge forsar friskt igen. Det segrande ljudet av morgonens vatten när ett litet stopp löses upp."},"ICON-2658":{"nm":"Förvaringskopp för toalettborsten","de":"Även en toalettborste är hygienisk först när den vilar på en torr plats. Prydligt instucken i den lilla koppen som fångar dropparna väntar den på sin tur. Ett redskaps värdighet syns inte i användningen utan i förvaringen."},"ICON-2659":{"nm":"Svamp mot mögel","de":"Möglet som spridit sig svart i kaklets hörn – till den envisa gästen föreslår svampen artigt att lämna. Efter ett enda torkdrag återvänder badrummet ljust till sin ursprungliga vithet."},"ICON-2660":{"nm":"Imskrapa för spegeln","de":"Framför en spegel gjord grumlig av imma efter duschen drar skrapan ett streck, och ditt tydliga ansikte återvänder. Ögonblicket då du åter möter dagens uttryck som legat gömt bakom immen en stund."},"ICON-2661":{"nm":"Toffelhängare för badrummet","de":"Häng upp de våta tofflorna upp och ner, så rinner vattnet av och insidan torkar skön. Så nästa persons fötter inte blir kalla. En liten hängares omtanke är alltid steget före, redan ute för att möta dig."},"ICON-2662":{"nm":"Nagelborstfodral","de":"Även den lilla borsten som skrubbar smuts under naglarna har sitt eget hem. Instucken snyggt i fodralet torkar den skön och fri från fukt, väntande på nästa handfat. Renlighet börjar alltid tyst med att lägga saker på sin plats."},"ICON-2663":{"nm":"Lock till tandborstens steriliseringskopp","de":"Även en tandborste, som möter munnen två gånger om dagen, behöver en liten fristad. I samma stund locket på steriliseringskoppen knäpps igen, vaktas ett mått renlighet stilla från fukten som svävar i badrummet."},"ICON-2664":{"nm":"Reskapsel för tops","de":"Så tops i resväskan inte går sönder eller sprids, håller en kapsel dem tätt slutna i sin famn. Ju mindre en sak är, desto mer måste man packa den i förväg, så man inte kommer på skam på en okänd väg."},"ICON-2665":{"nm":"Andedräktstest-miniplatta","de":"Andas 'ha' i handflatan och håll den mot miniplattan, och din andedräkt rör vid den och gör den mjölkvit. Det gulligaste beviset på att jag lever här på en kall dag – denna lilla platta antecknar det utan ett ord."},"ICON-2666":{"nm":"Förvaringshus för öronrensare","de":"När en öronrensare reser med i en väska nöts spetsen lätt. Därför gjordes ett litet hus åt den. Där inne, där spetsen inte tar skada även när den bärs runt, sover det fingertoppskänsliga redskapet gott."},"ICON-2667":{"nm":"Vikklämma för näsduk","de":"Klämman biter mjukt fast i en näsduk vikt prydligt i fyra hörn, och håller den från att rufsas till i väskan. Ett enda prydligt vikt tygstycke skänker tyst värdighet oavsett stund man tar fram det."},"ICON-2668":{"nm":"Plåsterfodral","de":"Den dag du skrapar knät, öppna fodralet och plåster av alla slag ställer upp på led och väntar på dig. Ömheten i att göra väsen av även ett litet sår. Ett förbandsskrin ska alltid finnas nära till hands."},"ICON-2669":{"nm":"Fingeravtryckstorkare","de":"Torka bort fingeravtrycken på glaset, och spåren av en tvekande hand försvinner. En handflatestor liten magi, där världen bortom fönstret, grumlig vid varje beröring, blir klar igen."},"ICON-2670":{"nm":"Sorteringsfack för återvinning","de":"Papper hitåt, burkar ditåt. Ett enda fack klyver ett öde som nästan blandats samman. Källsortering är i grunden hjärtat av att dela upp med omsorg, och detta stadiga fack drar den första linjen tydligt."},"ICON-2671":{"nm":"Klistermärkesspade","de":"Även ett klibbigt fastsittande klistermärke ger sig tyst inför mig. För in det platta spadbladet försiktigt under ett hörn, och det lossnar rent utan ett enda märke – ett segerrikt farväl."},"ICON-2672":{"nm":"Skärtänder för maskeringstejp","de":"Inget behov av att leta efter en sax bara för att använda maskeringstejp. Håll den mot tänderna och dra, så knäcks den rent längs strukturen. Den lilla, kvicka bästa vännen som en dekorerande fingertopp håller kärast."},"ICON-2673":{"nm":"Hörnfäste för kantlimning","de":"Ett litet beslag som stadigt håller ett lossnande hörn på plats inifrån. Från en osynlig punkt vaktar det vinkeln tyst. Bakom det som ser rakt ut på ytan finns oftast en sådan dold stötta."},"ICON-2674":{"nm":"Skyddshylsa för klistermärkesark","de":"Så de dyrbara klistermärkesarken inte skrynklas eller blir fuktiga sover de i hylsan, sida vid sida med skyddsfilmen. Bredvid glädjen av att samla följer alltid omsorgen om att varsamt bevara dem."},"ICON-2675":{"nm":"Rengöringsborste för bläckstämpel","de":"Borsten sveper varsamt längs strukturen genom den bläckindränkta stämpeln och skalar bort den gamla färgen. En liten, flitig beröring som rengör i förväg så nästa avtryck blir tydligt."},"ICON-2676":{"nm":"Hållarvinge för klara pärmblad","de":"Så pärmbladen inte glider och halkar ut griper vingarna stadigt om båda sidor. Tack vare att varje blad stannar på sin plats rubbas aldrig fingertoppen som bläddrar sidorna."},"ICON-2677":{"nm":"Förvaringsskopa för pysseldelar","de":"Skopa upp de småspridda pysseldelarna i ett enda svep med den lilla skopan. När besväret av att plocka upp dem en och en är borta, blir tiden man lägger på att skapa något med omsorg desto gladare."},"ICON-2678":{"nm":"Fäste för bokmärkestofs","de":"Så tofsen i bokmärkets ände inte lossnar, binder fästet den stadigt. Även en vägvisare tillbaka till en halvläst sida känns tryggare när dess egen fason hålls prydlig."},"ICON-2679":{"nm":"Locklämma för dekorpennans spets","de":"En klämma som håller locket hårt fast så dekorpennans spets inte torkar ut. Den förhindrar missödet att en glömd, öppen penna stelnar, så färgen alltid flyter fuktig ut som första gången."},"ICON-2680":{"nm":"Utbytesspets för skruvmejsel","de":"Låt skruvmejselns handtag vara som det är, och byt bara ut spetsen i änden. Kryss eller rak, inga problem. Skickligheten att klara många uppgifter med ett enda verktyg ryms stramt i denna lilla spets."},"ICON-2681":{"nm":"Slippapperslindning för hörn","de":"Vira den grova ytan rund och greppbar, så blir handflatan själva verktyget. Svisch, svisch – för varje drag längs fibern rundas det skavande hörnet av, och den slutliga jämnheten känns alltid igen av en människas fingertoppar."},"ICON-2682":{"nm":"Skruvsorteringstratt","de":"Utspridda skruvar passerar den smala halsen och samlas, rullande, på ett ställe. Ljudet av små ting som rullat omkring på skrivbordet och funnit sin plats – det känns som om även ett stökigt sinne ordnas prydligt."},"ICON-2683":{"nm":"Krok i måttbandets ände","de":"Kroken i måttbandets ände är andra handen hos den som arbetar ensam. Haka fast den i ett hörn, så vacklar inte bandet, och handen – och hjärtat – blir lika ärliga som den längd man mätt."},"ICON-2684":{"nm":"Handtagsöverdrag för skiftnyckel","de":"Ett lager draget över det kalla metallhandtaget. I samma stund du greppar det möter en mjuk värme handen i stället för en kyla. Ett verktyg stannar längre vid din sida när det tänker på den som håller det först."},"ICON-2685":{"nm":"Skyddskon för syls spets","de":"En liten kon träs över varje vass spets. Lättnaden av att famla i en låda utan att sticka sig – ju vassare en sak är, desto varsammare sveper man in den, så ingen kommer till skada."},"ICON-2686":{"nm":"Avisoleringsblad för kabel","de":"Skala bara av isoleringen tunt och lämna innerledningen oskadd. I samma ögonblick ett lager varsamt löses upp och en kopparfärgad tråd glimmar fram, vet ett gott blad exakt var det ska stanna."},"ICON-2687":{"nm":"Torkare för vattenpassets bubbelfönster","de":"Bara när den enda bubblan stannar precis i mitten är det verkligen vågrätt. Att torka det lilla fönstret rent liknar den tysta förberedelsen att jämna andningen innan man drar ett streck."},"ICON-2688":{"nm":"Fingerskyddshylsa för spikning","de":"En liten hylsa som sveper tätt om fingret som håller spiken. Slå till utan rädsla, för även om hammaren missar går det bra – den står stramt redo att ta smällen i fingrets ställe."},"ICON-2689":{"nm":"Halkskydd för matskål","de":"Ett lager gummi som stöttar skålen så den inte glider på golvet. Utan att skålen rymmer mitt under den ivriga måltiden, börjar en måltids lugn från en plats som inte vacklar."},"ICON-2690":{"nm":"Hängare för foderskopa","de":"Häng foderskopan på väggen för att torka lätt. En liten ordning som möter handen från samma plats varje måltid – att ha en mun att ta hand om är en så här öm sak."},"ICON-2691":{"nm":"Överrinningsfat för vattenskål","de":"Det fångar stilla upp klunken som skvalpat över kanten på vattenskålen. Tack vare det breda fatet som håller det i förväg, så golvet inte blir vått, förblir marken under fötterna alltid torr och skön."},"ICON-2692":{"nm":"Godistång för utdelning","de":"En tång som plockar upp exakt en godbit och räcker fram den. Även framför en liten mun som väntar med nosen sträckt fram finns det en ömsint fingertopp i delandet som aldrig tappar sin ordning."},"ICON-2693":{"nm":"Rullklämma för fodersäckens öppning","de":"En liten klämma som rullar ihop och biter fast öppningen på en påbörjad fodersäck. Med ett enda klick stängt hejdas fukten, och morgondagens knapriga handfull bevaras helt intakt."},"ICON-2694":{"nm":"Pippropp för vattenflaskan","de":"En propp som passar exakt i vattenflaskans pip. Plopp – den droppande vattendroppen upphör och kanten torkar. Det som täppts till väl läcker inte, och förblir klart samlat länge."},"ICON-2695":{"nm":"Graderad mätkopp för foder","de":"Mät av exakt en kopp längs graderingen. Varken för mycket eller för lite – i handen som rättvist bedömer dagens måltid ryms en liten familjemedlems dag precis lagom."},"ICON-2696":{"nm":"Kantlist för foderspillmatta","de":"En kant som hindrar spillt foder från att korsa mattans gräns. En enda list, höjd bara lätt, samlar stramt ihop de smulor som nästan spreds."},"ICON-2697":{"nm":"Separeringsring för dubbelskål","de":"En liten ring som varsamt skiljer två sammanfogade skålar åt. Handen som kämpat med dem fastklibbade blir lätt. Att skilja väl åt är, visar det sig, också en form av öm omsorg."},"ICON-2698":{"nm":"Bollsamlingstratt för gården","de":"En tratt som samlar ihop bollarna som rullat iväg över gården till en enda plats. En kväll efter mycket lek och stoj – handen som samlar in det som spridits hit och dit kommer naturligt till sinnes."},"ICON-2699":{"nm":"Staketstolpehatt","de":"Sätt en rund hatt över varje staketstolpe. Så spetsarna inte spricker i regn och blåst, har en omsorg som tar hand om och täcker även den minsta detalj sipprat genom hela gården."},"ICON-2700":{"nm":"Vikkrok för lektunneln","de":"En krok för att vika ihop den flitigt använda lektunneln prydligt och hänga upp den. Lägg undan en dag insmord i jord och häng den fint, så lovar en väl undanstoppad lek ovillkorligen en morgondag."},"ICON-2701":{"nm":"Dragsnörskudde","de":"En kudde som mjukt sveper in dragsnörets handtag. Hur hårt man än drar skaver aldrig handflatan. Att handen känns skönare ju längre man håller i den, är tack vare någons lilla omtanke."},"ICON-2702":{"nm":"Skuggduksspänne","de":"Ett spänne som håller skuggduken över gården stadigt spänd. Även middagens svalka måste hållas fast för att stanna kvar. Under skuggan som spännet håller sträckt vilar en lat eftermiddag sig lång och skön."},"ICON-2703":{"nm":"Spadbladsskydd","de":"Ett skydd man varsamt drar över spadens blad efter grävning. Låt det vila efter en dags hårt arbete, så förblir det oslött – redo att möta nästa vårs jord på nytt."},"ICON-2704":{"nm":"Bollramp","de":"En liten ramp där en boll rullar glatt nedför. Längs den lätt lutande sluttningen rusar bollen förtjust. En enda liten lutning skapar en hel dags glädje."},"ICON-2705":{"nm":"Grindregel","de":"En regelring som låser stängselgrinden. Ett litet klick när den slår igen ger sinnesro. En enda stadigt stängd grind bevarar en liten gård som en hel egen värld."},"ICON-2706":{"nm":"Lekbjällersnöre","de":"Skaka lekbjällrans snöre varsamt och ett klart ljud sprider sig. Ding, ding – ett annars tyst rum vaknar till liv, och vid ett enda litet klingande spetsar hela hjärtat öronen."},"ICON-2707":{"nm":"Droppskål för blomkruka","de":"Ett fat som stilla samlar upp vattnet som sipprar ner under en blomkruka. Det håller kvar det överflödande vattnet så fönsterbrädan förblir torr. Även omtanke, när den svämmar över, behöver en plats att samlas upp på."},"ICON-2708":{"nm":"Planteringsspade för plantor","de":"En liten spade för att flytta ömtåliga plantor ner i jorden och varsamt trycka fast dem. Under fingertoppar som försiktigt sätter varje liten planta på plats, lyfter en grön vår sitt huvud även i en handflatestor odlingslott."},"ICON-2709":{"nm":"Odlingsradsmärke","de":"En märkespinne man skriver på och sätter i varje rad för att notera vad som såtts. På jord där ingenting ännu grott, minns en liten namnskylt tyst vad som ska växa."},"ICON-2710":{"nm":"Sil för vattenkannans pip","de":"Ett fint galler i vattenkannans pip. Vattnet som förr strömmade i en enda stråle sprids nu i många trådar som ett milt duggregn. Endast ett mjukt flöde skonar de ömtåliga bladen."},"ICON-2711":{"nm":"Stödpinneklämma","de":"En klämma som varsamt fäster en vinglig stjälk vid sin stödpinne. Bara ett lånat stöd tills det ännu ömtåliga kan stå rakt av egen kraft – att växa kräver ibland ett sådant stöd."},"ICON-2712":{"nm":"Fröpåsklämma","de":"En klämma som håller en påse med kvarvarande frön stadigt stängd. Klick fast, och inte ett enda frö läcker ut. Ett litet löfte om nästa vår bor i detta enda grepp."},"ICON-2713":{"nm":"Doseringsskopa för jord och gödsel","de":"En liten skopa för att ta upp precis lagom mängd jord och gödsel. Varken för mycket eller för lite – en enda avmätt skopa. Först vid exakt rätt mängd kan jorden slutligen göra sitt jobb."},"ICON-2714":{"nm":"Upphängningskrok för blomkruka","de":"En upphängningskrok som lätt låter en blomkruka sväva i luften. Lyft uppåt kommer det gröna en handsbredd närmare sol och vind. Vid fönstret svävar en liten trädgård upp."},"ICON-2715":{"nm":"Skyddsnät för groddar","de":"Ett skyddsnät som varsamt täcker nyss grodda skott. Tills de ännu ömtåliga bladen tål den första kylan och det starka solljuset, är det mest sköra som får omsorg allra först."},"ICON-2716":{"nm":"Kamhängare för päls","de":"En plats där man knackar loss löst hår från kammen och hänger den prydligt. Den rentagna kammen väntar mjukt på nästa varsamma tag. Prydlighet börjar alltid med den lilla vanan att ta hand om sina redskap."},"ICON-2717":{"nm":"Halkring för fottvättbalja","de":"En ring som håller fottvättbaljan stadig så den inte glider. Med baljan stilla under plaskande små fötter, vacklar varken de tvättande händerna eller det tvättade hjärtat."},"ICON-2718":{"nm":"Vägghake för promenadkoppel","de":"En enda krok för att hänga promenadkopplet vid ytterdörren. Från sin plats vid dörren väntar beredskapen att ge sig av alltid där. I samma stund kopplet tas ner följer ett förväntansfullt litet steg med."},"ICON-2719":{"nm":"Skyddshätta för klotrimning","de":"En skyddshätta som skyddar den känsliga liven medan klorna klipps. Bara med en trygg gräns dragen vid exakt rätt punkt kan handen som håller saxen förbli lugn och stadig."},"ICON-2720":{"nm":"Badvattentermometerremsa","de":"En remsa som flyter i badvattnet och visar temperaturen. Den gamla vanan att doppa handryggen för att bedöma lagom värme flyter nu där, tydligt översatt till ett enda färgband."},"ICON-2721":{"nm":"Luddrulle","de":"Ett enda vitt hårstrå på ett svart plagg syns störst av allt precis före scenen. Till ljudet av rullande rör flyttas dagens dammkorn prydligt, remsa för remsa, över på det klibbiga pappret. Renlighet blir så här färdig, en bit i taget, lika mycket som man river bort."},"ICON-2722":{"nm":"Tång för hundpåse","de":"I slutet av en promenad finns en öm stund av att böja sig ner. Håll en påse i tångens spets och händerna förblir rena, hjärtat lätt. Att gå tillsammans rymmer en liten artighet att städa efter sig – och den här tången vet det först av alla."},"ICON-2723":{"nm":"Kant på dörrmatta","de":"Dörrmattans kant är den första välkomsthälsning en fot möter. Låt de våta tåspetsarna stanna här en enda gång, så förblir golvet därinne torrt. Den lägsta platsen av alla, som ordlöst torkar och hälsar var och en som kommer in."},"ICON-2724":{"nm":"Knytsnöre för pälsbjällra","de":"Även att sätta fast en enda bjällra har sin ordning. Vira snöret två varv och för det igenom en gång, så följer ett klart ljud med varje steg. Att göra i ordning är, till syvende och sist, hjärtat som aldrig hoppar över den här lilla avslutningen."},"ICON-2725":{"nm":"Droppficka för hopfällbart paraply","de":"I en lobby efter regnet har slutat, fläckar droppar golvet från det hopfällda paraplyets spets. En enda ficka fångar dem tyst, och ingens fötter halkar. Omtanke håller sig oftast så här nära, utan ett ljud."},"ICON-2726":{"nm":"Väskklämma med krok","de":"En väska som hängts på en stol glider sakta ner om och om igen. Nyp fast den en gång med krokklämman, och båda händerna blir fria från oron att den ska falla. Utflyktens avslappning börjar när man för en stund får glömma sitt bagage."},"ICON-2727":{"nm":"Tygpåse för handvärmare","de":"I en gränd med kall vind bär en tygpåse i fickan sakta värme in i handflatan. Ett mjukt lager som sveper in det heta och värmer det precis lagom. Vinterns ömhet förmedlas alltid genom ett enda tygstycke."},"ICON-2728":{"nm":"Fällbart spegelställ","de":"Fäll upp den och en liten spegel lutar sig till sin egen vinkel. Så att man kan möta sitt eget ansikte utan att hålla den, står stället i ens ställe. Även i den korta stund man rättar till sitt utseende finns en pålitlig biroll vid ens sida."},"ICON-2729":{"nm":"Lockhätta för våtservetter","de":"Det första bladet våtservetter höll alltid på att torka. Klicka fast locket, och fukten stannar kvar ända till det sista bladet. Att bevara till sista biten – hemligheten bakom ett hushåll som räcker länge gömmer sig i sådana små saker."},"ICON-2730":{"nm":"Myntfack för plånbok","de":"När mynt sprids bland sedlarna blir det alltid stressigt vid kassan. Ett enda fack samlar de runda tingen på en sida, och fingertopparna slutar treva. Att ordna är arbetet att ge varje sak sin egen plats och sitt eget namn."},"ICON-2731":{"nm":"Fällbart munskyddsfodral","de":"Vikt och undanstoppat skrynklas munskyddet inte ens i en väska. Ett fodral som rent förvarar det blad man tagit av en stund. Här samlas en enda öm vana: att spara det snyggt undan till nästa gång."},"ICON-2732":{"nm":"Tandskydd för reskam","de":"Kammens tänder i väskan brukade ofta repa de andra sakerna. Sätt på tandskyddet, och kammen är säker, liksom det som packats bredvid. Den som en gång har vårdat sina saker vet: ett enda litet skyddslager håller båda parter oskadda."},"ICON-2733":{"nm":"Fackdelare för byrålåda","de":"Varje gång lådan öppnades vällde de blandade sakerna ut som en suck. Dela in den i fack med en enda klämma, och de små tingen finner äntligen sina egna zoner. En ordnad låda ändrar tyst humöret varje morgon."},"ICON-2734":{"nm":"Myntställ","de":"Ställ upp ett gammalt mynt och det blir i sig en liten utställning. Stället lutar det svagt så att framsidans mönster syns tydligt. Att lyfta sliten tid upp till ögonhöjd – det är här samlandets glädje fördjupas."},"ICON-2735":{"nm":"Sladdvinda för hörlurar","de":"Det finns mornar som gått halvt förlorade åt att nysta upp trassliga hörlurssladdar. Vira den prydligt runt sladdvindan, och nästa gång är den mjuk att ta fram. Lite ordning blir en tyst gåva man smyger till morgondagens jag."},"ICON-2736":{"nm":"Väggkrok för laddkabel","de":"En laddkabel som slingrade sig på golvet blev ständigt nertrampad. Sätt fast en enda krok på väggen för att hänga den, och skrivbordet känns genast mycket rymligare. Att tämja oordning är inget storslaget – det är en plats inte större än en enda spik."},"ICON-2737":{"nm":"Fjärrkontrollshållare","de":"Fjärrkontrollen som ständigt försvann ner i soffspringan har äntligen ett hem att komma tillbaka till. Ställ den i hållaren, och det blir varken letande eller att sitta på den av misstag. Att ha en egen plats blir en liten vila även för ett föremål."},"ICON-2738":{"nm":"Glasögonklämma","de":"Avtagna glasögon gled alltid sakta iväg någonstans. Häng skalmen lätt i klämman, och linserna når aldrig golvet. Önskan att hålla dem repfria till nästa dag bärs i den här lilla hängaren."},"ICON-2739":{"nm":"Sorteringsklämma för nyckelknippa","de":"Ju tyngre nyckelknippan blir, desto suddigare blir det vilken nyckel som hör till vilken dörr. Bind dem med en sorteringsklämma, och fingertopparna känner igen sin match utan att titta. En tyst vägvisare som stilla skapar ordning bland dörrarna man öppnar och stänger varje dag."},"ICON-2740":{"nm":"Anteckningshållare","de":"Nedskrivna lappar brukade lätt falla omkull på skrivbordet. När klämman håller pappret upprätt möter bokstäverna blicken rakt på. Ett sätt att låta den rad man inte får glömma bo på en plats där den alltid syns."},"ICON-2741":{"nm":"Pennhållare","de":"Hur många gånger har man inte böjt ryggen för att plocka upp en bortrullad penna? Ställ den med spetsen ner i hållaren, och avståndet till nästa rad krymper med en handsbredd. En liten väntstation, alltid vaken vid den skrivandes sida."},"ICON-2742":{"nm":"Vändfot för timglas","de":"När ett timglas runnit ut måste någon vända det för att det ska leva igen. Foten fångar det sista sandkornets ögonblick och vänder det jämnt upprätt igen. Handen som vrider tiden tillbaka till början vilar här, ovanpå en liten träbit."},"ICON-2743":{"nm":"Smörbakad potatis","de":"Smöret smälter långsamt över en potatis bakad i sitt skal. När den gyllene ådern sipprar in med ångan, tar den fluffiga insidan tyst emot den smakrika värmen. Det ögonblick då en jordig rotfrukt blir som varmast av allt."},"ICON-2744":{"nm":"Smörgrillad majs","de":"De gula kornen, tätt packade rad efter rad, knastrar på grillen. Låt en klick smör glida över dem och den söta doften stiger upp med ens. Sommarfältets sötma förs rakt in i en enda tugga."},"ICON-2745":{"nm":"Våffla","de":"I varje litet rutmönstrat fack väntar sirapen tyst på att samlas. Krispig utanpå, fluffig inuti – ta en tugga och varm ånga slinker ut. De fyrkantiga facken liknar ett fat som portionerar ut små bitar av lycka."},"ICON-2746":{"nm":"Pannkakor","de":"Jag minns doften av smet som puffade gyllene i pannan. Över de runda kakorna, staplade lager på lager, sjunker smöret sakta ihop och smälter bort. Ett mjukt fat, tyst tillåtet endast en lugn morgon."},"ICON-2747":{"nm":"Choklad","de":"Håll en bit i munnen och den löses sakta upp av kroppsvärmen. Sötman som breder ut sig efter bitterheten släpper varsamt greppet om hjärtats spänning. En sliten dag, en liten brun tröstebit man tar fram ur fickan."},"ICON-2748":{"nm":"Jordgubbstårta","de":"Röda jordgubbar tronar på det vita vispgräddet och bebådar våren först av alla. När gaffeln delar den mjuka snittytan blommar en syrlig doft sakta upp. En dag det finns något att fira, den ömma huvudrollsinnehavaren mitt på bordet."},"ICON-2749":{"nm":"Cheesecake","de":"En tung bit kollapsar rikt på tungan. Den salta eftersmaken tar sötman i handen och lockar fram en tugga till, och en till. En efterrätt som älskare av tät fyllighet stilla njuter av."},"ICON-2750":{"nm":"Banankakor","de":"Doften av mosad banan mognar gyllene inne i ugnen. Ta en tugga och en mjuk sötma sprider sig genom hela munnen. Det varma ögonblick då en väl mogen frukt återföds som en kaka."},"ICON-2751":{"nm":"Chokladkakor","de":"Chokladbitarna i degen smälter rikt medan de gräddas. Bryt den medan den fortfarande är varm, och ett djupt brunt spår fastnar på fingertopparna. Med ett glas mjölk blir det den sortens bit som gör en eftermiddag lite snällare."},"ICON-2752":{"nm":"Kakaonibskakor","de":"Fint krossade kakaobitar knastrar mellan degen. En djup, osöt bitterhet lugnar stilla en vuxen smak. En något allvarlig kaka som bär den råa doften precis som den var innan den förädlades."},"ICON-2753":{"nm":"Grillad ostmacka","de":"Osten dras ut lång som en tråd över det gyllenrostade brödet. Krispigheten utanpå och smakrikedomen inuti läggs ihop i en enda tugga. Den enklaste, ömmaste måltiden som fyller en sen förmiddag varmt och gott."},"ICON-2754":{"nm":"Smörgås","de":"Mellan två skivor bröd packas en dags omsorg lager på lager. Ta en tugga och de upplagrade smakerna hälsar alla på en gång. Ett litet middagsbord i handflatan, redo att bäras med vart som helst."},"ICON-2755":{"nm":"Fattiga riddare","de":"Bröd genomdränkt i äggsmet stektes gyllene i pannan. Kanterna, svällda av smördoft, blir krispiga allra först. Dra ett streck sirap över, och även vanligt bröd blir en helgdagslyx."},"ICON-2756":{"nm":"Svampramen","de":"Svampens djupa doft stiger med ångan över den kokande buljongen. Lyft upp en seg hatt och en jordig sötma sprider sig genom munnen. En något speciell skål som fyller magen med doft innan nudlarna ens hunnit fram."},"ICON-2757":{"nm":"Wokad ramen","de":"På buljongfria nudlar, vända och blandade, ligger en het sås som en glansig hinna. Lyft dem med ätpinnar, och en smakrik, rökig doft sprider sig genom ångan. När man längtar efter en snabb, matig måltid – den mest pålitliga vännen."},"ICON-2758":{"nm":"Ostramen","de":"Lägg en skiva ost över heta nudlar och den sjunker sakta ihop och smälter in. Het buljong möter mjuk smakrikedom och kanterna rundas av. En skål precis rätt för en kväll man vill mjuka upp hettan lite."},"ICON-2759":{"nm":"Curryramen","de":"En rik curryarom slingrar sig kring nudlarna och skickar upp gul ånga. Sörpla i dig en munfull, och en varm hetta värmer inifrån. Nudlar av en glad variation, som lägger till en aning främmande doft till en välbekant buljong."},"ICON-2760":{"nm":"Fisk- och skaldjursramen","de":"Över buljong fylld av hav flyter räkor och musslor upp, runda och fina. En fräsch men djup smakrikedom sipprar in mellan nudlarna. Ett litet trolleri som för havets doft in i en enda skål utan att man behöver resa långt."},"ICON-2761":{"nm":"Gimbap med syltad rättika","de":"Med gul syltad rättika i mitten och ris samlat runtom, binder ett enda blad tång dem alla varmt samman till en rulle. I gryningen inför en utflykt, den ärligaste måltiden som föds på skärbrädan."},"ICON-2762":{"nm":"Tonfiskgimbap","de":"I samma stund en sked majonnäsblandad tonfisk sjunker in mellan riskornen, blir en måltid tillräckligt varm även under en närbutiks sena ljussken. Tröstemåltiden som upptagna händer griper efter oftast."},"ICON-2763":{"nm":"Fruktsallad","de":"Färger samlade från säsongen möts för första gången i en enda skål. Hur rött, grönt och gult kommer överens utan att tvista – det visar frukten först sedan den skurits och samlats ihop."},"ICON-2764":{"nm":"Kycklingsallad","de":"Lätt grillad kycklingbröst läggs prydligt ovanpå gröna bladgrönsaker. På bordet hos någon som förbereder sig för morgondagens scen ligger alltid en så här ordnad tallrik."},"ICON-2765":{"nm":"Tomat- och gurksallad","de":"Mogna tomater och krispig gurka vänds friskt och syrligt. En middag tung av cikadornas sång, ta en pinne full i munnen och sommaren svalnar en takt inuti den."},"ICON-2766":{"nm":"Sallad med grönsallat","de":"Skölj blad nyss plockade i köksträdgården i kallt vatten, och fingertopparna vaknar svalt till liv. Ögonblicket då den vanligaste grönsaken tar den grönaste, friskaste platsen vid bordet."},"ICON-2767":{"nm":"Majssallad","de":"Varje gång ett sött korn poppar till, breder ett solfyllt högsommarfält ut sig framför ögonen. Även i en salladsskål glömmer den gula majsen aldrig sitt eget solsken, till syvende och sist."},"ICON-2768":{"nm":"Coleslaw","de":"När strimlad vitkål tar emot den sötsyrliga såsen mjuknar knaperheten en aning skönare. Dygden hos ett tillbehör: placerat bredvid vilken huvudrätt som helst tävlar det aldrig om uppmärksamheten utan gör bara sin del."},"ICON-2769":{"nm":"Räksallad med lime","de":"Pressa i lite lime och räkans sötma vaknar skarpare till liv. En sur droppe blåser liv i hela tallriken – en liten men avgörande sista touch."},"ICON-2770":{"nm":"Hamburgstek","de":"En tjockt formad köttfärslimpa steks gyllenbrun på en het plåt. Köttsaften som sipprar fram i samma stund kniven vidrör den – måltiden som älskats längst mellan husmanskost och västerländsk mat."},"ICON-2771":{"nm":"Pizza","de":"Den där tuggan där osten dras ut lång, förs från hand till hand bland de många som sitter samlade runtomkring. Först när en rund platta delas i bitar tillsammans blir en samling en riktig samling."},"ICON-2772":{"nm":"Krämig svamppasta","de":"Svampens djupa jorddoft och gräddens mjukhet omfamnar varje enda pastasträng. En kväll med stilla regnljud sprider sig den rika doften sakta ner till tallrikens botten."},"ICON-2773":{"nm":"Räkpasta","de":"Fylliga räkor sautéras lätt i olivolja och blandas samman med pastan. När havets sälta möter pastans enkla renhet, blir en händelselös kväll en aning speciell."},"ICON-2774":{"nm":"Aglio e olio","de":"Vitlök, olja och pasta – bara tre saker. Det finns en smak som blir tydligare ju mer man tar bort, och aglio e olio bevisar det tyst, utan ett enda överflöd."},"ICON-2775":{"nm":"Musselpasta","de":"Buljongen musslorna släpper ifrån sig när de öppnar sina skal sipprar djupt in i varje sträng. Doften av en klunk vitt vin dröjer sig kvar länge på tallriken, som en vårdag som vägrar blekna."},"ICON-2776":{"nm":"Gräddpasta","de":"När den rika gräddsåsen stilla omfamnar pastan, värms ett hörn av hjärtat redan från första tuggan. Tröst som mjukheten bjuder på, och som fördjupas ännu mer en blåsig dag."},"ICON-2777":{"nm":"Tomatpasta","de":"Länge kokt tomatsås breder ut sig röd över pastan. När sötma och syra sakta reducerats och äntligen funnit balans, är den enklaste tallriken den mest pålitliga."},"ICON-2778":{"nm":"Omuraisu","de":"Mjukt ägg täcker det varma riset som ett täcke, insvept varsamt. Skriv bara ett enda namn med ketchup, och den dagens bord blir ett litet brev någon räckt över."},"ICON-2779":{"nm":"Grillad lax","de":"Grilla den långsamt framför lågan tills skinnet blir krispigt. En strimma ånga stiger när det rosa köttet flagar isär längs fibrerna – tålamod belönas alltid ärligt av lax."},"ICON-2780":{"nm":"Bruschetta","de":"Hoppa upp hackad tomat och basilika rikligt på krispigt rostat bröd. Den lätthet det är att plocka upp den med fingrarna och ta en tugga öppnar varmt en samlings första hälsning."},"ICON-2781":{"nm":"Mangosmoothie","de":"Mixa en mogen mango slät och blanda den sval med is. När droppar pärlar på det gula glaset, stiger en dåsig högsommareftermiddag ända upp till sugrörets spets."},"ICON-2782":{"nm":"Lemonad","de":"Häll i nypressad citron, socker och kallt vatten, och skaka om det i muggen. När den gula syrligheten glider svalt nerför halsen, kapitulerar till och med den rasande hettan för en stund."},"ICON-2783":{"nm":"Jordgubbsmjölk","de":"Rör ner mosade jordgubbar i mjölk och ett rosa moln sjunker sakta i glaset. Fingertoppens spänning av att slänga upp kylskåpsdörren som barn hålls hel och odelad i ett enda glas."},"ICON-2784":{"nm":"Bananmjölk","de":"En dryck som redan är ett helt tidsspann av minnen bara i sin runda lilla burkform. Det gula minnet av att sticka i ett sugrör på en bänk i badhuset återuppstår varmt med varje klunk."},"ICON-2785":{"nm":"Blåbärsmjölk","de":"Släpp i lila bär och krossa dem lätt, och den vita mjölken färgas i en svag himmelsblå ton. Den enda handfull små bär förvandlar hela glaset till en helt ny färg."},"ICON-2786":{"nm":"Fruktjuice","de":"Pressa flera frukter ihop och det blir en smak inget enskilt namn kan täcka. En liten kör av sötmor, som blandas och sväller ännu rikare tillsammans."},"ICON-2787":{"nm":"Varm choklad","de":"Vid ett snöigt fönster, håll en varm mugg stilla i båda händerna. Ett brunt glas med ånga som stiger sakta värmer en, från fingertopparna ända till hjärtat."},"ICON-2788":{"nm":"Kaffe","de":"Det är alltid den här enda koppen som tänder ljuset i gryningens övningsrum. När den beska doften stilla knuffar undan sömnigheten, börjar ännu en dags scen tyst, precis så."},"ICON-2789":{"nm":"Laxsushi","de":"Pressa riset i handen och känn av den subtila gränsen mellan fast och mjukt. I samma stund en tunt skuren skiva lax lägger sig varsamt ovanpå, blir en enda tugga fulländningen av en liten omsorg."},"ICON-2790":{"nm":"Pumpagröt","de":"Koka den gula pumpan mjuk och mosa den slät. Med varje sked smälter höstsolen varmt i munnen. Gröten som kommer till en först av allt när man är sjuk."},"ICON-2791":{"nm":"Fiskcurry","de":"Fiskkött, lätt sjudet i kryddor, smulas mjukt sönder inuti currysåsen. Lägg till havets textur i en välbekant skål, och en vanlig kväll ger sig av på en resa en handsbredd längre bort."},"ICON-2792":{"nm":"Friterad räka","de":"Det korta ögonblicket att hålla i svansen, doppa i smet och släppa ner i kokande olja är där allt avgörs. Räkan klädd i gyllene smet lyser som starkast om man äter den innan krispigheten hunnit svalna."},"ICON-2793":{"nm":"Friterad bläckfisk","de":"Runda ringar sväller fylliga i den heta oljan. Den tuggan där knaperhet sveper in segheten passar bäst i det gula skenet vid ett gatukök."},"ICON-2794":{"nm":"Grillad kyckling","de":"Pensla på marinaden och grilla långsamt framför lågan, och skinnet glänser med en fin lyster. En rätt där smaken avgörs av en enda justering av elden – enklast av alla, och just därför den ärligaste."},"ICON-2795":{"nm":"Wokad fläskkött med kimchi","de":"Woka väl mognad kimchi tillsammans med fläskkött, och syrligheten mognar till sötma. En rätt som helt av sig själv ropar på en skål vitt ris – den mest pålitliga följeslagaren vid ett koreanskt bord."},"ICON-2796":{"nm":"Wokad fläskkött","de":"Woka snabbt på hög värme så utsidan bränns knaprig. När den smakrika oljedoften fyller köket, är kvällens meny redan bestämd utan ett ord till."},"ICON-2797":{"nm":"Wokad biff med svamp","de":"Woka doftande svamp tillsammans med nötkött, och vardera smak fördjupas ytterligare. En städad höstmåltid där jord och fält stilla tar varandras hand på en och samma tallrik."},"ICON-2798":{"nm":"Ostdakgalbi","de":"Smält ost rikligt över het kryddad kyckling och dra ut den lång. Samlas många runt en het järnplåt i mitten, och även den sveda hettan löses upp i skratt."},"ICON-2799":{"nm":"Kimchigryta","de":"Ju äldre kimchin är, desto djupare och rikare blir buljongen den ger. Sitt ansikte mot ansikte framför en bubblande lergryta, och ordet \"familj\" värms upp på nytt."},"ICON-2800":{"nm":"Doenjanggryta","de":"Lös upp den smakrika sojabönpastan, tillsätt tofu och zucchini, och låt sjuda sakta och stadigt. Ljudet som bubblar ända till sista droppen i lergrytan är det säkraste tecknet på att man kommit hem."},"ICON-2801":{"nm":"Rättikssoppa med nötkött","de":"En halv dag tillbringad i stillhet framför den svaga lågan, medan man väntade tills rättikan blev genomskinlig. När en sked av den klara buljongen når läpparna, minns man den tidens osminkade middagsbord. Det stillsamma är det som dröjer sig kvar längst."},"ICON-2802":{"nm":"Musselsoppa","de":"I samma stund musslorna öppnar sina skal fördjupas våren inne i grytan. När en handfull havsdoft stiger med ångan, målas ett gryningskök i en kustby fram. I varje öppen springa vilar en salt skvätt av havet."},"ICON-2803":{"nm":"Kanderad sötpotatis","de":"På hemvägen från skolan, gula klumpar i en pappmugg, hållna i handen som en handvärmare. Bit i det gyllenbruna ytterlagret och ångan slår upp inifrån. Det sötsöta, glaserade ytterlagret och den heta insidan – smaken av vinterns ömmaste stund."},"ICON-2804":{"nm":"Wokad aubergine","de":"Ögonblicket då det lila möter oljan och sakta löses upp. Grönsaken som man klandrade för att vara mjäkig visar sig ta emot kryddorna bättre än någon annan. Tar man en tugga är det den mjukt insugna handens smak som når fram först."},"ICON-2805":{"nm":"Braiserad potatis","de":"En kväll då en söt doft spreds genom hela köket medan sojasåsen kokade in. Handen som fyllde matlådans fack med en blank, brun bit. En omsorg som inget recept skriver ner genomsyrar varje litet stycke."},"ICON-2806":{"nm":"Inlagda perillablad","de":"Att lägga in hela sommarens doft för att bära den ända till vinterns bord. Lyft loss ett blad och lägg det på riset, och den gångna årstiden blommar upp i munnen igen. Mellan bladen, lager på lager, sover det årets solsken."},"ICON-2807":{"nm":"Färsk kinakålskimchi","de":"Händer som inte orkade vänta till kimjang massar samman kryddorna samma dag. En fräschör man bara kan njuta av i det ögonblick kryddningen just börjat dra in i de krispiga bladen. Den gröna friskheten före jäsningen är en lyx som bara finns idag."},"ICON-2808":{"nm":"Wokad svamp","de":"Sådant som tyst sköt upp i skogsskuggan efter att regnet klarnat upp. Medan de woks i perillaolja förvandlas jorddoften till en rostad, nötig sötma. Ju tystare något har vuxit i mörkret, desto djupare och rikare blir dess doft."},"ICON-2809":{"nm":"Kryddad spenat","de":"Bladgrönsaken som krymper till en enda handfull när den blancheras, massas samman med fingertopparna. Den anspråkslösa volymen är vårgrönsakens dygd. En grön tallrik räcker för att låta en handsbredd mer vårsol in på bordet."},"ICON-2810":{"nm":"Kryddat sjögräs","de":"Hala strängar, nyss upptagna ur havet, blandas med en syrlig chili-vinägersås. Ett salt sprakande som poppar med varje tugga. En tallrik som för över vågornas gungande konsistens rakt in i skålen."},"ICON-2811":{"nm":"Wokad zucchini","de":"Det finns grönsaker vars sötma växer ju äldre de blir. Skär dem tunt och woka dem med saltade räkor, och även den anspråkslösa zucchinin avslöjar sakta sin egen sötma. Ett gult som löses upp mjukt ända till sista tuggan i munnen."},"ICON-2812":{"nm":"Kimchistekt ris","de":"När den lagrade kimchin nått sitt fulla djup möter den kallt ris i en och samma panna. En skål som blir som allra mest mättande när det som blivit över möter det som blivit över. Den ömmaste räddningen under ljuset i en enrumslägenhet sent på natten."},"ICON-2813":{"nm":"Kycklingcurry","de":"När den gula buljongen täcker det vita riset lyser bordet upp. I en tid då kryddor kändes främmande var detta den yttre världens smak man först blev bekant med. En söndagslunch då kycklingköttet föll isär mjukt och fluffigt."},"ICON-2814":{"nm":"Stekt ris","de":"Resterna längst in i kylskåpet möts i god samvaro i en och samma panna. En givmildhet som tar emot vad som helst med öppna armar. Att samla det spridda på ett ställe – det är hushållandets början."},"ICON-2815":{"nm":"Bulgogi på ris","de":"Kött, marinerat i en sötaktig sås, glider sakta ner över det ångande riset. När huvudrätten från gästbordet sänker sig ner till en enkel vardagsskål blir det speciella ännu ömmare."},"ICON-2816":{"nm":"Bibimbap","de":"Ovanpå det lätt kokta riset sitter fem färger av namul i en rund krets. I fingertopparna som ordnade färgerna med omsorg lever en gammal, finstämd känsla för skönhet. Smaken av samklang som fullbordas först när allt rörs samman."},"ICON-2817":{"nm":"Räkstekt ris","de":"Fylliga räkor lyser rosa mellan riskornen. Woka in en handfull hav, och även en vanlig måltid härmar ett festbord. Sötman som sprider sig i samma stund man biter i är en kärkommen gäst."},"ICON-2818":{"nm":"Kryddstarkt fläsk på ris","de":"Fläskkött, genomdraget av het krydda, möter det ångande riset. Skålen som alltid tog slut först vid lunchtid. En måltids tröst som klappar och lugnar en hektisk dag."},"ICON-2819":{"nm":"Tonfisk och majonnäs på ris","de":"En konservburk, en slinga majonnäs, och en skål varmt ris. Ingredienserna är enkla, men tröst finns det gott om. Smaken av den kvällen, hemligt blandad vid skolbänken efter kvällens självstudier."},"ICON-2820":{"nm":"Curryris","de":"En tjock, gyllene färg fyller tallriken helt. Omsorgen av att röra länge, tills potatisen och morötterna blivit riktigt mjuka. Det väcker minnet av den kvällens samhörighet, då hela familjen kikade ner i samma gryta."},"ICON-2821":{"nm":"Sjögräsbibimbap","de":"Strängar med havsdoft möter gochujang och rörs samman med snabba tag. När den hala, syrliga konsistensen omsluter riskornen, breder sig havet ut i en enda skål – samma hav en dykerska höll andan och dök ner för att hämta."},"ICON-2822":{"nm":"Grillad makrill","de":"Den silverfärgade ryggen tillagas gyllenbrun på grillplattan. Handen som plockade ur benen och lade köttbiten på riset. I en bit av den blårygga fisken vilar en tyst kärlek, den som en gång matade och fostrade på just det viset."},"ICON-2823":{"nm":"Potatispannkaka","de":"Något man rev och stekte i ett bergsbykök i Gangwon på regniga dagar. De sega kanterna och de frasiga topparna lever sida vid sida på samma kaka. Smeten som passar bäst ihop med ljudet av regn mot rutan."},"ICON-2824":{"nm":"Kimchipannkaka","de":"I samma stund den syrliga kimchin möter den oljade pannan fylls hela huset av ett fräsande ljud. En gyllenbrun cirkel som kallar på en skål makgeolli av sig själv. En stamgäst på menyn som bildar par med regnljudet under takskägget."},"ICON-2825":{"nm":"Salladslökspannkaka","de":"Lägg salladslöken prydligt i rad, häll över smeten och stek långsamt. En kaka som pendlar mellan det frasiga och det mjuka. Precis som den varma synen av ånga som steg från ett marknadsstånd på marknadsdag."},"ICON-2826":{"nm":"Zucchinipannkaka","de":"Klä tunt skivad zucchini i smet och stek den gyllenbrun. En ljusgrön cirkel som prydligt vaktade sin plats på minnesbordet. Den omsorgsfulla högtidligheten som bara uppnås genom mycket handarbete."},"ICON-2827":{"nm":"Wokad bläckfisk","de":"Bläckfiskarmarna, klädda i röd krydda, glänser blanka av sitt eget skimmer. Även när pannan pärlar av svett från stark hetta kan man inte lägga ner pinnarna. Den tallriken där svett och glädje trasslar samman."},"ICON-2828":{"nm":"Tteokbokki","de":"Riskakor och fiskkakor sjunker djupt ner i en röd, inkokt gochujangsås. Hela eftermiddagen på snabbmatsstället, där två delade på samlade slantar, ryms i den. En minnenas smak som får munnen att vattnas bara vid namnet."},"ICON-2829":{"nm":"Fiskkakssoppa","de":"En gatustall där fiskkakorna gungar i buljongen, och ångan gör fönsterrutan disig och vit. Håll i ett spett, ta upp buljong i en pappmugg och läppja på den, och en kylig vinternatt blir mycket varmare."},"ICON-2830":{"nm":"Tofu med kimchi","de":"Bredvid det mjuka tofut sitter den hett wokade kimchin sida vid sida. Kallt och varmt, milt och starkt, förenas på en och samma tallrik. Ett par som länge vakat över de vuxnas kvällar."},"ICON-2831":{"nm":"Wokad korv med grönsaker","de":"Röd korv och grönsaker fräser samman i en ketchupfärgad blandning. Facket som alltid tömdes först när man öppnade lunchlådan på idrottsdagen. Den dagens färg förblir alltid lika klar, hur mycket tid som än går."},"ICON-2832":{"nm":"Sötpotatislatte","de":"Fint mosad sötpotatis löses mjukt upp i varm mjölk. En inhemsk sötma skriven med hangul på menytavlan. En dag då fingertopparna fryser, en kopp där värmen sakta sprider sig när man håller den med båda händerna."},"ICON-2833":{"nm":"Majonnäs","de":"En sås som ännu inte anlänt till köket på Glitterön. Den kommer snart att tecknas som en gräddfärgad ikon. (under förberedelse)"}};